-- Poems batch 59
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('5cf8b360-b00d-43b2-a23c-5a99a71f3dc5','十七','王梵志','唐','唐诗','tang','','[]','四大乖和起，諸方請療醫。',53,'全唐诗/poet.tang.50000.json','["四大乖和起，諸方請療醫。", "（「請」，伯三五五八、伯三七一六、伯三六五六卷作「早」。", "）長病煎湯藥，求神覓好師。"]'),
('9bfc26cf-a8cc-4c8f-a3a5-0ba26460da1d','十八','王梵志','唐','唐诗','tang','','[]','親中除父母，兄弟更無過。',24,'全唐诗/poet.tang.50000.json','["親中除父母，兄弟更無過。", "有莫相輕賤，無時始認他。"]'),
('82dd5162-0198-4e46-b85c-5649faaaca61','十九','王梵志','唐','唐诗','tang','','[]','主人相屈至，客莫先入門。',42,'全唐诗/poet.tang.50000.json','["主人相屈至，客莫先入門。", "若是尊人處，臨時自朾門。", "（「朾」，伯三六五六卷作「打」。", "）。"]'),
('adf1f8d1-dc4b-4b3c-b8ba-6b7465a90c46','二十','王梵志','唐','唐诗','tang','','[]','親家會賓客，在席有尊卑。',32,'全唐诗/poet.tang.50000.json','["親家會賓客，在席有尊卑。", "諸人未下筯，不得在前椅。", "（一本作㨳）。", "。"]'),
('18710b54-4136-4448-9a55-380eacb711cc','二一','王梵志','唐','唐诗','tang','','[]','親還同席坐，[知]卑莫上頭（此句原本脫一字，一本作「知卑莫上頭」）。',107,'全唐诗/poet.tang.50000.json','["親還同席坐，[知]卑莫上頭（此句原本脫一字，一本作「知卑莫上頭」）。", "（「知」，據伯三五五八、伯三七一六、伯三六五六卷補。", "）忽然人{火在}責，（「{火在}」，斯三三九三卷作「怪」，伯三五五八卷作「乖」。", "）可不衆中羞。"]'),
('2f124341-5aa2-4b41-8152-bebbb519c90b','二二','王梵志','唐','唐诗','tang','','[]','尊人立莫坐，賜坐莫背人。',70,'全唐诗/poet.tang.50000.json','["尊人立莫坐，賜坐莫背人。", "存坐無方便，（「存坐」，伯三六五六卷作「罇坐」，張錫厚擬作「蹲坐」。", "郭祖怡謂「存」爲「𨀛」省形存聲字。", "）席上被人嗔。"]'),
('5a120593-720e-4811-a28b-b869a9c8bc84','二三','王梵志','唐','唐诗','tang','','[]','尊人對客飲，卓立莫東西。',75,'全唐诗/poet.tang.50000.json','["尊人對客飲，卓立莫東西。", "（「卓立」，斯三三九三卷作「側立」。", "）使唤須依命，弓身莫不齊。", "（「弓身」，伯三五五八、伯三六五六、斯四六六九卷作「躬身」。", "）。"]'),
('6b9190d8-ef3e-467a-a2df-9493b043d99a','二四','王梵志','唐','唐诗','tang','','[]','尊人與須（一本作「酒」。',51,'全唐诗/poet.tang.50000.json','["尊人與須（一本作「酒」。", "）喫，即把莫推辭。", "性少由方便，圓隔（一本作「融」。", "）莫遣（一本作「遺」。", "）知。"]'),
('6317a13a-865d-4deb-84c4-91924df9c4dc','二五','王梵志','唐','唐诗','tang','','[]','尊人同席飲，不問莫多言。',24,'全唐诗/poet.tang.50000.json','["尊人同席飲，不問莫多言。", "縱有文章好，留將餘處宣。"]'),
('bf46c0bf-72a4-484b-8fc5-0a70cd6552be','二六','王梵志','唐','唐诗','tang','','[]','巡來莫多飲，性少自須監。',37,'全唐诗/poet.tang.50000.json','["巡來莫多飲，性少自須監。", "勿使聞狼相，（一本作「使勿聞狼狽」。", "）交他諸客嫌。"]'),
('50614bd2-a7ca-4f3c-b421-65ad0af0dc63','二七','王梵志','唐','唐诗','tang','','[]','坐見人來起，尊親盡遠迎。',24,'全唐诗/poet.tang.50000.json','["坐見人來起，尊親盡遠迎。", "無論貧與富，一概惣須平。"]'),
('5cc79b4d-9303-4ea0-a028-2b6030252028','二八','王梵志','唐','唐诗','tang','','[]','黃金未是寶，學問勝珠珍。',48,'全唐诗/poet.tang.50000.json','["黃金未是寶，學問勝珠珍。", "丈夫無伎藝，（「伎藝」，伯三六五六、斯四六六九作「才藝」。", "）虛霑一世人。"]'),
('d0e1b5a6-e6c2-4554-a336-6b18b9baab73','二九','王梵志','唐','唐诗','tang','','[]','養子莫徒使，先教懃讀書。',24,'全唐诗/poet.tang.50000.json','["養子莫徒使，先教懃讀書。", "說朝乘駟馬，還得似相如。"]'),
('ccd476fd-193d-4ddf-b089-0aad483a8164','三十','王梵志','唐','唐诗','tang','','[]','欲得兒孫孝，無過教及身。',24,'全唐诗/poet.tang.50000.json','["欲得兒孫孝，無過教及身。", "一朝千度打，有罪更須嗔。"]'),
('ee4a0058-8dbe-444e-9e79-3f8750357df8','三一','王梵志','唐','唐诗','tang','','[]','養兒從少打，（「少」，伯三五五八、伯三七一六、伯三六五六卷作「小」。',72,'全唐诗/poet.tang.50000.json','["養兒從少打，（「少」，伯三五五八、伯三七一六、伯三六五六卷作「小」。", "）莫道憐不笞。", "長大欺父母，後迴（一本作「悔」。", "）定無魚。", "（一本作「疑」。", "）。"]'),
('ca2e1181-24cb-43ce-a61a-993cbc991f5c','三二','王梵志','唐','唐诗','tang','','[]','男年七十八，（一本作「十七八」。',61,'全唐诗/poet.tang.50000.json','["男年七十八，（一本作「十七八」。", "）莫遣倚街衢。", "若不行奸盗，相構即榻（一本作「摺」）蒲。", "（「榻蒲」，張錫厚改作「樗蒲」。", "）。"]'),
('ddf504a5-d2bf-4bda-b8c2-f1769dd3828a','三三','王梵志','唐','唐诗','tang','','[]','有兒欲娶婦，須擇大家兒。',50,'全唐诗/poet.tang.50000.json','["有兒欲娶婦，須擇大家兒。", "縱使無姿首，終成有禮儀。", "（「終成」，伯三六五六、斯四六六九卷作「終身」。", "）。"]'),
('51621698-02f0-4aad-bde6-e22b8812a090','三四','王梵志','唐','唐诗','tang','','[]','有女欲嫁娶，不用絕高門。',51,'全唐诗/poet.tang.50000.json','["有女欲嫁娶，不用絕高門。", "但得身超後，（「超」，戴密微校作「紹」。", "「後」，項楚校作「俊」。", "）銀財惣莫論。"]'),
('1fe89a03-4b76-4a45-911b-537ddf8e1474','三五','王梵志','唐','唐诗','tang','','[]','欲得依（一本作「於」。',104,'全唐诗/poet.tang.50000.json','["欲得依（一本作「於」。", "）身吉。", "無過作是非。", "（一本作「莫作非」）。", "但知牢閉口，禍去阿你（一本作埿。", "）來。", "（「阿你來」，斯二七一○、斯三三九三、伯四○九四卷作「阿寧來」，伯三五五八、伯三六五六卷作「自然離」。", "）。"]'),
('d6046728-b612-4778-925c-95523fc47ae5','三六','王梵志','唐','唐诗','tang','','[]','飲酒妨生敬，（一本作「計」。',49,'全唐诗/poet.tang.50000.json','["飲酒妨生敬，（一本作「計」。", "）榻（一本作樗。", "）蒲必破家。", "但看此等色，不久作窮查。", "（本作「茶」。", "）。"]'),
('7e3bc977-d2b8-4bc9-b264-e2d63f9e3e47','三七','王梵志','唐','唐诗','tang','','[]','見惡須藏掩，知賢中華讚陽。',62,'全唐诗/poet.tang.50000.json','["見惡須藏掩，知賢中華讚陽。", "（「唯」，伯三五五八作「爲」。", "「陽」，項楚校作「揚」。", "）但（一本作「若」。", "）能依此語，祕密立身方。"]'),
('496fa7b1-6314-48f1-a674-ed48bbee0270','三八','王梵志','唐','唐诗','tang','','[]','借物莫交索，用了送還他。',75,'全唐诗/poet.tang.50000.json','["借物莫交索，用了送還他。", "損失酬高價，求（一本作我。", "）嗔得也磨。", "（「也磨」，伯三五五八、斯二七一○、伯四○九四卷作「也摩」，斯四六六九卷作「夜摩」。", "）。"]'),
('cf29d3f4-8a04-48fa-8f61-d8b39048e64e','三九','王梵志','唐','唐诗','tang','','[]','借物索不得，貸錢不肯還，',37,'全唐诗/poet.tang.50000.json','["借物索不得，貸錢不肯還，", "頻來論即鬥。（「論即鬥」，郭祖怡校作「即鬥論」。）"]'),
('ca3c37a7-772c-430c-9c7f-5fd9f951c6f0','四十','王梵志','唐','唐诗','tang','','[]','隣並須來往，借取共交通。',25,'全唐诗/poet.tang.50000.json','["隣並須來往，借取共交通。", "急緩相慿仗，人生莫不從。", "。"]'),
('5c2332aa-beaa-465a-adca-56b0eccfa1c6','四一','王梵志','唐','唐诗','tang','','[]','長幼同歡（一本作「欽」。',85,'全唐诗/poet.tang.50000.json','["長幼同歡（一本作「欽」。", "）敬，稱尊莫不尊。", "（一本作「遵」。", "）（「稱尊」，斯四六六九、伯四○九四卷作「知尊」。", "「莫不遵」，斯四六六九作「莫不從」。", "）且能行禮樂，鄉里自稱人。"]'),
('a629dbb8-1e3a-4b59-916f-338e56dee9f7','四二','王梵志','唐','唐诗','tang','','[]','停（一本作「庭」。',94,'全唐诗/poet.tang.50000.json','["停（一本作「庭」。", "）客勿叱狗{右上加卄}，對客莫頻眉。", "供給千餘自，（「自」，斯三三九三、斯四六六九卷作「日」。", "）臨時請不饑。", "（「臨時」，伯三六五六卷作「臨歧」，伯三七一六卷作「臨政」。", "）。"]'),
('f6ce4853-b423-4b66-9233-c4a054bf8eeb','四三','王梵志','唐','唐诗','tang','','[]','親客號不疎，（「號不疏」，伯三六五九、斯四六六九卷作「無疏伴」。',102,'全唐诗/poet.tang.50000.json','["親客號不疎，（「號不疏」，伯三六五九、斯四六六九卷作「無疏伴」。", "）建唤則須唤。", "（「建唤則須唤」，伯三七一六卷作「來即閗須唤」，伯三五五八、伯三六五六、斯三三九三作「唤即盡須唤」。", "）食食甯且休，只可待他散。"]'),
('a8adb1f9-a24b-4e9d-a042-97644eca6b12','四四','王梵志','唐','唐诗','tang','','[]','爲客不呼客，（「不」，伯三六五六卷作「莫」。',41,'全唐诗/poet.tang.50000.json','["爲客不呼客，（「不」，伯三六五六卷作「莫」。", "）去必主人嗔。", "欲得能行事，無過莫避人。"]'),
('4d4125a6-37aa-4f87-92f5-cfa925fbc5e8','四五','王梵志','唐','唐诗','tang','','[]','逢人須歛手，避道莫前盪。',65,'全唐诗/poet.tang.50000.json','["逢人須歛手，避道莫前盪。", "（一本作「湯」。", "）忽若相衝着，（「忽若」，斯三三九三卷作「忽然」。", "）他{弓|一/虫}（鄭本作强。", "）必自傷。"]'),
('c94a2244-f51b-46c5-88db-cf1b01607dc0','四六','王梵志','唐','唐诗','tang','','[]','惡口深乖禮，條中却沒文。',59,'全唐诗/poet.tang.50000.json','["惡口深乖禮，條中却沒文。", "若能不駡詈，即便是賢人。", "（「即便是」，伯三七一六卷作「即是大」，伯三六五六卷作「却便是」。", "）。"]'),
('05adbd3d-d50e-4cbf-881e-bf958afc87ea','四七','王梵志','唐','唐诗','tang','','[]','見貴當須避，知强遠利他。',55,'全唐诗/poet.tang.50000.json','["見貴當須避，知强遠利他。", "（「利」，伯三五五八、伯三六五六卷作「離」。", "）高飛能去綱（按當作「網」。", "）豈得值低羅。"]'),
('820fd09c-d21c-435b-ac7b-e246cae81e70','四八','王梵志','唐','唐诗','tang','','[]','結交須擇善，非識（一本作諳。',32,'全唐诗/poet.tang.50000.json','["結交須擇善，非識（一本作諳。", "）莫與心。", "若知管鮑志，還共不分金。", "。"]'),
('235ecefe-2e1b-4252-9519-a2ac900fad6f','四九','王梵志','唐','唐诗','tang','','[]','惡人相遠離，善者近相知。',34,'全唐诗/poet.tang.50000.json','["惡人相遠離，善者近相知。", "縱使大無雨，陰雲（一本作「雲陰」。", "）自潤衣。"]'),
('f0d92d10-3ccb-4ef8-ac41-f930597c521e','五十','王梵志','唐','唐诗','tang','','[]','有德之（一本作「人」。',42,'全唐诗/poet.tang.50000.json','["有德之（一本作「人」。", "）心下，無才意即高。", "但看行濫物，若箇是堅（鄭本作「堅」。", "）牢。"]'),
('935f4051-5a97-4f50-88d9-812bb9c8a9e2','五一','王梵志','唐','唐诗','tang','','[]','典使頻多擾，（「典使」，伯三七一六、伯三六五六卷作「典吏」。',105,'全唐诗/poet.tang.50000.json','["典使頻多擾，（「典使」，伯三七一六、伯三六五六卷作「典吏」。", "）從少（一本作饒。", "）必莫嗔。", "但知多與酒，火{卄又}不欺人。", "（「火{卄又}」，伯三七一六卷作「㺳火」，伯四○九四卷作「火芆」，張錫厚意當作「火艾」。", "）。"]'),
('6b9a90be-a15f-4ec2-9b86-36856bf2a78d','五二','王梵志','唐','唐诗','tang','','[]','惡人相觸悮，（鄭本作「誤」。',71,'全唐诗/poet.tang.50000.json','["惡人相觸悮，（鄭本作「誤」。", "）彼（一本作「被」。", "）駡必從饒。", "喻若薗中匪，（「匪」，伯三五五八、伯三七一六、伯三六五六卷作「韭」。", "）由如得雨澆。"]'),
('87029902-7ddb-4faa-89bf-216d6c207350','五三','王梵志','唐','唐诗','tang','','[]','駡妻早是惡，打婦更無知。',24,'全唐诗/poet.tang.50000.json','["駡妻早是惡，打婦更無知。", "索强斯得客，可是丈夫兒。"]'),
('036881bb-dd18-4d64-a422-f03c9f3bd3d0','五四','王梵志','唐','唐诗','tang','','[]','有勢不煩意，（「煩意」，伯三七一六卷作「須倚」。',43,'全唐诗/poet.tang.50000.json','["有勢不煩意，（「煩意」，伯三七一六卷作「須倚」。", "）欺他必自危。", "但看木裏火，出則自燒伊。"]'),
('fa9b5bd1-f70d-41da-b13e-96cc4dea229d','五五','王梵志','唐','唐诗','tang','','[]','貧親須拯濟，富眷不煩饒。',82,'全唐诗/poet.tang.50000.json','["貧親須拯濟，富眷不煩饒。", "（「煩」，伯三六五六爲作「須」。", "）情知蘇蜜味，何用更添高。", "（「高」，伯三五五八、伯三七一六、斯二七一○卷作「膏」，伯四○九四卷作「餻」。", "）。"]'),
('7b579402-909a-4aa6-bec6-fac43e2e9143','五六','王梵志','唐','唐诗','tang','','[]','有錢莫掣⿰忄霍，（「⿰忄霍」，伯三七一六、伯三六五六卷作「攉」。',60,'全唐诗/poet.tang.50000.json','["有錢莫掣⿰忄霍，（「⿰忄霍」，伯三七一六、伯三六五六卷作「攉」。", "）不得是（一本作「事」。", "）奢華。", "鄉裏人儜惡，差科必破家。"]'),
('c836e8d1-6fd1-44de-bec4-a32a2c4c238f','五七','王梵志','唐','唐诗','tang','','[]','他貧不得笑，他弱不得欺。',69,'全唐诗/poet.tang.50000.json','["他貧不得笑，他弱不得欺。", "但看人頭數，即須受□□。", "（「但看」二句，伯三六五六卷作「太公未遇日，猶自獨釣魚」。", "末句，項錄作「即須受逢迎」。", "）。"]'),
('bab04345-db9f-4bdf-b919-1353e2312ecb','五八','王梵志','唐','唐诗','tang','','[]','逢迎莫不安，□□欠二爪。',92,'全唐诗/poet.tang.50000.json','["逢迎莫不安，□□欠二爪。", "（「逢迎」二句，伯三七一六卷作「莫不安瓜肉，魚吞在腹裏」。", "）□魚在腸裏，善（鄭本作喜。", "）惡有千般。", "（「□魚」二句，斯五七九四卷作「善惡數千般，人心難可知」。", "）。"]'),
('32a47d4f-ec5a-4a2f-94b6-c83d268718ce','五九','王梵志','唐','唐诗','tang','','[]','在鄉須下意，爲客莫高心。',42,'全唐诗/poet.tang.50000.json','["在鄉須下意，爲客莫高心。", "相見作先拜，膝下沒黃金。", "（「沒」，伯三七一六卷作「投」。", "）。"]'),
('f23ef3e5-4d48-495e-a700-6e1199f24996','六十','王梵志','唐','唐诗','tang','','[]','貧人莫簡棄，有客最須呼。',24,'全唐诗/poet.tang.50000.json','["貧人莫簡棄，有客最須呼。", "但惠封瘡藥，何愁不奉珠。"]'),
('c30d8702-405f-4e38-ad56-0ae39d53c6e4','六一','王梵志','唐','唐诗','tang','','[]','得言請莫說，有語不須傳。',31,'全唐诗/poet.tang.50000.json','["得言請莫說，有語不須傳。", "見事如不見，終身無過{彳|天天/心}。"]'),
('a4a88175-653e-4da7-8810-504245f73419','六二','王梵志','唐','唐诗','tang','','[]','無心莫充保，（「無心」，伯三六五六卷作「無親」。',102,'全唐诗/poet.tang.50000.json','["無心莫充保，（「無心」，伯三六五六卷作「無親」。", "）無事莫作媒。", "（「無事」，伯三七一六卷作「無女」。", "）雖悉鄉人意，（「悉」，伯三五五八、伯三六五六、斯三三九三卷作「失」，斯二七一○卷作「識」。", "）終身無害災。"]'),
('65c41b95-5ceb-417b-ad6e-18b8b601311e','六三','王梵志','唐','唐诗','tang','','[]','雙陸智人戲，園碁出專能。',58,'全唐诗/poet.tang.50000.json','["雙陸智人戲，園碁出專能。", "（「園」，伯三六五六卷作「圍」。", "）解時終不惡，（「時」，斯三三九三卷作「事」。", "）久後與仙通。"]'),
('4f319620-f368-4f9e-a9ad-569a93b22b43','六四','王梵志','唐','唐诗','tang','','[]','逢争不須看，見打莫前僞。',121,'全唐诗/poet.tang.50000.json','["逢争不須看，見打莫前僞。", "（「僞」，伯三六五六卷作「爲」。", "）{扌|厶/貝}即追友勝，（「{扌|厶/貝}」，伯三七一六、伯三六五六作「捐」。", "項楚校作「損」。", "）證能惣不知。", "（「證能」，伯三五五八、伯三七一六、伯三六五六、斯二七一○卷作「能勝」。", "）。"]'),
('270c57f8-3512-4dbb-b5fa-2d0ab86b9289','六五','王梵志','唐','唐诗','tang','','[]','立身存篤信，（「存」，斯三三九三卷作「在」。',42,'全唐诗/poet.tang.50000.json','["立身存篤信，（「存」，斯三三九三卷作「在」。", "）景行勝將金。", "在處人携接，諳知無負心。", "。"]'),
('8582de38-2ed1-4582-8e88-3b93694746b1','六六','王梵志','唐','唐诗','tang','','[]','有恩須報上，得濟莫孤恩。',24,'全唐诗/poet.tang.50000.json','["有恩須報上，得濟莫孤恩。", "但看千里井，誰爲重來尋。"]'),
('382812d7-8b9e-4636-8cff-bd020bee427f','六七','王梵志','唐','唐诗','tang','','[]','知恩須報恩，有恩莫不更。',70,'全唐诗/poet.tang.50000.json','["知恩須報恩，有恩莫不更。", "（「更」，伯三五五八、伯三七一六、伯三六五六卷作「報」。", "）[更]在枯井中，（「更」字據伯三五五八卷補。", "）誰能重來救。"]'),
('bc580bd8-e14e-4375-9554-f1365a68357b','六八','王梵志','唐','唐诗','tang','','[]','元得地恩重，（「元」，伯三六五六卷作「先」。',88,'全唐诗/poet.tang.50000.json','["元得地恩重，（「元」，伯三六五六卷作「先」。", "）酬償勿使輕。", "一湌何所直，感賀百千傾。", "（「百千傾」，斯三三九三卷作「百千金」，伯三七一六卷作「金百傾」，伯三六五六作「百金傾」。", "）。"]'),
('32acdafd-8557-41b2-a060-aceeb93bf5c4','六九','王梵志','唐','唐诗','tang','','[]','蒙人惠一恩，終身酬不極。',49,'全唐诗/poet.tang.50000.json','["蒙人惠一恩，終身酬不極。", "若濟桒（鄭本作桑。", "）下飢，扶論可惜力。", "（「論」，伯三七一六卷作「輪」。", "）。"]'),
('b1d392a6-b139-44e3-aa4d-b7c96951e1a2','七十','王梵志','唐','唐诗','tang','','[]','得他一束絹，還他一束羅。',41,'全唐诗/poet.tang.50000.json','["得他一束絹，還他一束羅。", "計時應大重，（「大」，斯三三九三卷作「有」。", "）直爲歲年多。"]'),
('892c720e-c300-42eb-b7c4-6158eb1a0f84','七一','王梵志','唐','唐诗','tang','','[]','貸人五𥐿米，（「𥐿米」，伯三七一六卷作「斗」。',65,'全唐诗/poet.tang.50000.json','["貸人五𥐿米，（「𥐿米」，伯三七一六卷作「斗」。", "）送還一碩粟。", "（「碩」，伯三五五八、伯四○九四卷作「石」。", "）算時應有餘，剩者充臼直。"]'),
('f18e9a4c-edd6-49a1-a31b-19cacdfcdbee','七二','王梵志','唐','唐诗','tang','','[]','世間難捨割，無過財色深。',24,'全唐诗/poet.tang.50000.json','["世間難捨割，無過財色深。", "丈夫須遠命，割斷闇迷心。"]'),
('5c7f7fe4-a87d-45c9-acb8-a63ed9ecc226','七三','王梵志','唐','唐诗','tang','','[]','煞生最罪重，（「最罪重」，伯三五五八、伯三六五六卷作「罪最重」，伯三七一六卷作「罪甚重」。',82,'全唐诗/poet.tang.50000.json','["煞生最罪重，（「最罪重」，伯三五五八、伯三六五六卷作「罪最重」，伯三七一六卷作「罪甚重」。", "）喫肉亦非輕。", "欲得身長命，無過點續朋。", "（「朋」，伯三七一六卷作「明」。", "）。"]'),
('c48f3d1c-8ca8-4772-a781-66c54d0bb333','七四','王梵志','唐','唐诗','tang','','[]','偷盗須無命，（「須」，伯三七一六、伯三六五六卷作「雖」。',79,'全唐诗/poet.tang.50000.json','["偷盗須無命，（「須」，伯三七一六、伯三六五六卷作「雖」。", "）侵欺罪更多。", "將他物己用，思量得夜魔。", "（「夜魔」，伯三七一六卷作「也磨」，斯二七一○卷作「也磨」。", "）。"]'),
('836a0c7f-7c69-48a9-b45e-d0ce4d9b2006','七五','王梵志','唐','唐诗','tang','','[]','邪淫及妄語，知非惣勿作。',47,'全唐诗/poet.tang.50000.json','["邪淫及妄語，知非惣勿作。", "但之依道行，（「之」，伯三五五八、伯三六五六卷作「知」。", "）萬里無迷錯。"]'),
('bc179525-b637-4f6a-bc25-184d7a7b70bd','七六','王梵志','唐','唐诗','tang','','[]','喫肉多病報，知者不須湌。',41,'全唐诗/poet.tang.50000.json','["喫肉多病報，知者不須湌。", "一朝無諫地，（「諫」，伯三六五六卷作「間」。", "）受罪始知難。"]'),
('387221fb-3a7e-41b9-bc46-739dfdd646bd','七七','王梵志','唐','唐诗','tang','','[]','飲酒是癡報，如人落糞坑。',65,'全唐诗/poet.tang.50000.json','["飲酒是癡報，如人落糞坑。", "情知有不争，（「争」，伯三五五八、伯三七一六卷作「淨」。", "）豈合岸頭行。", "（「合」，伯三七一六卷作「不」。", "）。"]'),
('bb9703f1-247a-4edd-87ac-c3a93460bc9e','七八','王梵志','唐','唐诗','tang','','[]','造酒罪甚重，酒肉俱不輕。',73,'全唐诗/poet.tang.50000.json','["造酒罪甚重，酒肉俱不輕。", "若人不信語，（「語」，伯三七一六、斯二七一○卷作「義」。", "）撿取《日槃經》。", "（「日」，伯三七一六、伯三六五六卷作「湼」。", "）。"]'),
('ba0c061b-ef8b-4300-8c0c-92e6e51e63dc','七九','王梵志','唐','唐诗','tang','','[]','見埿須避道，莫入污却鞋。',51,'全唐诗/poet.tang.50000.json','["見埿須避道，莫入污却鞋。", "（「污却鞋」，斯二七一○、斯三三九三卷作「汗脚鞋」。", "）若知己有罪，莫破戒持齋。"]'),
('847fe556-19f6-46d0-982b-511cfecff1e2','八十','王梵志','唐','唐诗','tang','','[]','相交莫嫉妬，相勸莫蛆儜。',39,'全唐诗/poet.tang.50000.json','["相交莫嫉妬，相勸莫蛆儜。", "一日無常去，王前罷手行。", "（「罷」，項楚校作「擺」。", "）。"]'),
('4b4846e0-cc7d-41b4-8b5d-3532220299f3','八一','王梵志','唐','唐诗','tang','','[]','見病須慈遐，（「須慈遐」，伯三六五六卷作「須慈慜」，伯三五五八、斯二七一○、斯三三九三、伯四○九四卷作「慈須愍」。',108,'全唐诗/poet.tang.50000.json','["見病須慈遐，（「須慈遐」，伯三六五六卷作「須慈慜」，伯三五五八、斯二七一○、斯三三九三、伯四○九四卷作「慈須愍」。", "）諸方速療醫。", "（「速療」，伯三五五八卷作「早爲」，伯三六五六卷作「速爲」。", "）若能行此行，大是不思議。", "。"]'),
('e9c0ab11-2782-4f8f-a423-d42532ce2680','八二','王梵志','唐','唐诗','tang','','[]','經記須平直，心中莫側斜。',24,'全唐诗/poet.tang.50000.json','["經記須平直，心中莫側斜。", "些些徵取利，可可苦他家。"]'),
('5a3e0739-22af-4638-9a28-94fbfec1b0ec','八三','王梵志','唐','唐诗','tang','','[]','布施生生富，（「富」，斯三三九三卷作「福」。',62,'全唐诗/poet.tang.50000.json','["布施生生富，（「富」，斯三三九三卷作「福」。", "）慳貪世世貧。", "若人苦慳惜，却却受辛懃。", "（「却却」，戴密微、項楚校作「劫劫」。", "）。"]'),
('c543c2b0-b82d-49a0-8061-98cc3a0d710e','八四','王梵志','唐','唐诗','tang','','[]','忍辱生端正，多嗔作毒虵。',24,'全唐诗/poet.tang.50000.json','["忍辱生端正，多嗔作毒虵。", "若人不儜惡，必得上三車。"]'),
('56e986d2-9a19-478e-8d29-f280e7cb3f43','八五','王梵志','唐','唐诗','tang','','[]','尋常懃念善，（「善」，伯三七一六、斯三三九三卷作「佛」。',64,'全唐诗/poet.tang.50000.json','["尋常懃念善，（「善」，伯三七一六、斯三三九三卷作「佛」。", "）晝夜受書經。", "（「受」，伯三五五八卷作「愛」。", "）心裏無蛆儜，何愁佛不成。"]'),
('05dc0fb3-dcb5-46ce-889a-6094b3a5fd62','八六','王梵志','唐','唐诗','tang','','[]','六時長禮懺，日暮廣燒香。',44,'全唐诗/poet.tang.50000.json','["六時長禮懺，日暮廣燒香。", "十齋莫使闕，有力煞三場。", "（「三場」，伯三六五六卷作「三長」。", "）。"]'),
('4e81d739-d6bb-45c0-9ec6-958fc3512992','八七','王梵志','唐','唐诗','tang','','[]','持戒須含忍，長齋不得嗔。',51,'全唐诗/poet.tang.50000.json','["持戒須含忍，長齋不得嗔。", "莫隨風火性，參羞悮（鄭本作「誤」。", "）煞人。", "（「羞」，斯三三九三卷作「差」。", "）。"]'),
('b0a0ae54-fbf7-4405-840e-9e6a0cd1f4d6','八八','王梵志','唐','唐诗','tang','','[]','逢師須安拜，（「禮拜」，伯三七一六卷作「頂禮」。',156,'全唐诗/poet.tang.50000.json','["逢師須安拜，（「禮拜」，伯三七一六卷作「頂禮」。", "）過道向前行。", "（「過」，伯三六五六卷作「遇」。", "「行」，伯三七一六、伯三六五六卷作「參」。", "）莫生多別相，（「多別相」，伯三六五六卷作「離別想」。", "項楚校「多」爲「分」。", "）見過不知南。", "（「知南」，伯三七一六、伯三六五六卷作「和南」。", "伯三五五八卷此句作「相見過不知」。", "）。"]'),
('551dce14-03f9-4506-876f-4b6f93afdae9','八九','王梵志','唐','唐诗','tang','','[]','聞鐘身須側，臥轉莫前眠。',59,'全唐诗/poet.tang.50000.json','["聞鐘身須側，臥轉莫前眠。", "（「前」，伯三六五六卷作「纏」。", "）萬一無常去，免至獄門邊。", "（「邊」，伯三六五六卷作「前」。", "）。"]'),
('dd921cba-e509-44f1-952c-e68db03360c2','九十','王梵志','唐','唐诗','tang','','[]','師僧來乞食，必莫惜家嘗。',41,'全唐诗/poet.tang.50000.json','["師僧來乞食，必莫惜家嘗。", "（「嘗」，伯三六五六卷作「常」。", "）布施無邊福，來生不少糧。"]'),
('25959296-7450-4c6a-a409-9ae8bd905113','九一','王梵志','唐','唐诗','tang','','[]','家貧從力貸，不得嬾乖傭。',41,'全唐诗/poet.tang.50000.json','["家貧從力貸，不得嬾乖傭。", "（「傭」，伯四○九四卷作「慵」。", "）但知懃作福，衣食自然豐。"]'),
('95d86c9a-f2c7-4667-9af2-0189edd9a0b1','九二','王梵志','唐','唐诗','tang','','[]','惡事惣須棄，（「棄」，伯三六五六、伯四○九四卷作「去」。',64,'全唐诗/poet.tang.50000.json','["惡事惣須棄，（「棄」，伯三六五六、伯四○九四卷作「去」。", "）善事莫相違。", "知意求妙法，必得見如來。", "（按以上爲原卷王梵志詩第一卷。", "）。"]'),
('d744878a-dcd3-4d05-a253-e9fdfb613f28','九三','王梵志','唐','唐诗','tang','','[]','吾有十畝田，種在南山坡。',24,'全唐诗/poet.tang.50000.json','["吾有十畝田，種在南山坡。", "青松四五樹，綠豆西三窠。"]'),
('9a36bda0-f070-4832-9eba-99e742ef27aa','九四','王梵志','唐','唐诗','tang','','[]','熱即池中浴，涼便岸上歌。',38,'全唐诗/poet.tang.50000.json','["熱即池中浴，涼便岸上歌。", "遨遊自取足，誰能奈我何？", "（以上二首，應合爲一首。", "）。"]'),
('4cf4678a-6b75-44a7-87e5-156ffc27e576','九五','王梵志','唐','唐诗','tang','','[]','我見那漢死，肚裏熱如火。',24,'全唐诗/poet.tang.50000.json','["我見那漢死，肚裏熱如火。", "不是惜那漢，恐畏還到我。"]'),
('04ffdb8a-91e0-44dd-ba56-85bb9aef20a9','九六','王梵志','唐','唐诗','tang','','[]','我有一方便，價值百疋練。',49,'全唐诗/poet.tang.50000.json','["我有一方便，價值百疋練。", "相打長伏弱，（「長伏」，原卷作「長取」，張錫厚改爲「常服」。", "）至死不入縣。"]'),
('b61afa8b-10f4-4870-b142-9041ab40ea39','九七','王梵志','唐','唐诗','tang','','[]','共受虛假身，共稟太虛氣。',49,'全唐诗/poet.tang.50000.json','["共受虛假身，共稟太虛氣。", "死去雖更生，迴來盡不記。", "以此好尋思，萬事淡無味。", "慰俗不如心，時時一倒醉。", "。"]'),
('fd0763cd-9c1f-40c4-8ffb-29614d4e32fa','九八','王梵志','唐','唐诗','tang','','[]','草屋足風塵，牀無破氈臥。',136,'全唐诗/poet.tang.50000.json','["草屋足風塵，牀無破氈臥。", "客來且唤入，地鋪稿薦坐。", "家裏元無炭，柳麻且吹火。", "白酒瓦鉢藏，（「藏」，項楚校作「盛」。", "）鐺子兩脚破。", "鹿脯三四條，石鹽五六課。", "（「課」，項楚、蔣紹愚校作「顆」。", "）看客只甯馨，從你痛笑我。", "（案以上六首錄自鄭振鐸本拾遺。", "爲王梵志詩原卷第三卷。", "惜不全。", "）。"]'),
('c83c1d06-560e-4719-928a-8ea5d4731f03','九九','王梵志','唐','唐诗','tang','','[]','欺誑得錢君莫羨，得了却是輸他便。',32,'全唐诗/poet.tang.50000.json','["欺誑得錢君莫羨，得了却是輸他便。", "來生報答甚分明，只是换頭不識面。"]'),
('fc5faf54-35f7-4c2f-844f-2876144058c0','一○○','王梵志','唐','唐诗','tang','','[]','多置莊田廣修宅，四鄰買盡猶嫌窄。',16,'全唐诗/poet.tang.50000.json','["多置莊田廣修宅，四鄰買盡猶嫌窄。"]'),
('d5456768-67b0-4599-939b-7df6c3bc60f8','一○一','王梵志','唐','唐诗','tang','','[]','造作莊田猶未已，堂上哭聲身已死。',32,'全唐诗/poet.tang.50000.json','["造作莊田猶未已，堂上哭聲身已死。", "哭人盡是分錢人，口哭元來心裏喜。"]'),
('d915039c-dff6-4b2c-a6e4-a61c36581646','一○二','王梵志','唐','唐诗','tang','','[]','衆生頭兀兀，堂住無明窟。',24,'全唐诗/poet.tang.50000.json','["衆生頭兀兀，堂住無明窟。", "心裏爲欺謾，口中佯念佛。"]'),
('88c2de9f-080c-4132-ae80-ae67c4cf2cf8','一○三','王梵志','唐','唐诗','tang','','[]','世無百年人，強作千年調。',77,'全唐诗/poet.tang.50000.json','["世無百年人，強作千年調。", "（《分門古今類事》卷三引《南史》引此詩，「強」作「擬」，「年」作「歲」，「打」作「以」，「限」作「關」。", "）打鐵作門限，鬼見拍手笑。"]'),
('b0fafdfa-ee43-4aff-95e3-9a272137545e','一○四','王梵志','唐','唐诗','tang','','[]','勸君休殺命，背面披生嗔。',24,'全唐诗/poet.tang.50000.json','["勸君休殺命，背面披生嗔。", "喫他他喫汝，循環作主人。"]'),
('b3c94dcf-3b9c-418c-a77d-0e875287713e','一○五','王梵志','唐','唐诗','tang','','[]','他人騎大馬，我獨跨驢子。',24,'全唐诗/poet.tang.50000.json','["他人騎大馬，我獨跨驢子。", "回顧擔柴漢，心下較些子。"]'),
('d3e3a577-c1d8-4f77-9b56-67c1196876bd','一○六','王梵志','唐','唐诗','tang','','[]','家有梵志詩，生死免入獄。',24,'全唐诗/poet.tang.50000.json','["家有梵志詩，生死免入獄。", "不論有益事，且得耳根熟。"]'),
('e75895f4-e2c9-43bd-b4f6-a46834f38975','一○七','王梵志','唐','唐诗','tang','','[]','白紙書屏風，客來即與讀。',244,'全唐诗/poet.tang.50000.json','["白紙書屏風，客來即與讀。", "空飯手捻鹽，亦勝設酒肉。", "（案以上八首並載費袞《梁谿漫志》卷十。", "今從知不足齋本錄出之。", "以上九首除「他人騎大馬」一首外，皆見《雲溪友議》卷下。", "「欺誑得錢君莫羨」一首，《全唐詩續補遺》卷二據《鑑誡錄》卷十收錄，今刪去。", "異文錄如次：二句「得了却」作「究竟還」，三句作「不信但看槽上驢」，四句「换」作「改」。", "）（〖1〗費袞《梁谿漫志》卷十：「山谷以茅季偉事。", "親引梵志『飜襪』之句，人喜道之。", "予嘗見梵志數頌，詞樸而理到，今於此。", "其一曰：『欺誑得錢君莫羨。", "……』又曰：……」）。"]'),
('c817eb30-f7a9-488a-868b-4f4e5c54802b','一○八','王梵志','唐','唐诗','tang','','[]','梵志翻著襪，人皆道是錯。',85,'全唐诗/poet.tang.50000.json','["梵志翻著襪，人皆道是錯。", "乍可剌你眼，不可隱我脚。", "（《全唐詩續補遺》卷二據《詩話總龜後集》四三引山谷語收此詩。", "文字同，今刪去。", "《林間錄》卷下引此詩，「乍可」作「寧可」。", "）。"]'),
('d710a6df-6ef0-40d9-8280-875f4ce41edc','一○九','王梵志','唐','唐诗','tang','','[]','城外土饅頭，餡草在城裏。',114,'全唐诗/poet.tang.50000.json','["城外土饅頭，餡草在城裏。", "一人喫一個，莫嫌沒滋味。", "（此詩又見《冷齋夜話》卷十、《苕溪漁隱叢話前集》卷五六、《詩話總龜》卷三九引《東坡詩話》、《雲臥紀譚》等書。", "）（以上二首黃庭堅引梵志詩。", "）（〖1〗案以上諸詩，鄭振鐸輯本並收之。", "）。"]'),
('b2ee8c1d-b8b9-4855-9890-9cca7b6d3f1d','道情詩','王梵志','唐','唐诗','tang','','[]','我昔未生時，冥冥無所知。',181,'全唐诗/poet.tang.50000.json','["我昔未生時，冥冥無所知。", "天公強生我，生我復何爲？", "無衣使我寒，無食使我飢。", "還你天公我，還我未生時。", "（此首唐釋皎然《詩式》卷一《跌宕格二品·駭俗》中引之，鄭輯本未收。", "）（〖1〗《全唐詩編劇補遺》卷二據《雲溪友議》收此詩，今刪去。", "異文錄如次：首句作「天公未生我」，三句「强」作「忽」，五句「使」作「遣」，六句「使」作「遣」，六句「使」作「令」，七句「你」作「爾」。", "）。"]'),
('23a08063-1768-4410-8b46-8156e9826964','倖門（題擬）','王梵志','唐','唐诗','tang','','[]','倖門如鼠穴，也須留一箇。',411,'全唐诗/poet.tang.50000.json','["倖門如鼠穴，也須留一箇。", "若還都塞了，好處却穿破。", "（此首見陳巖肖《庚溪詩話》卷下。", "鄭輯本亦未收。", "）（〖1〗陳巖肖《庚溪詩話》卷下：「王梵志詩曰：『倖門如鼠穴，……好處却穿破。", "』此言近乎曹相國所謂以獄市爲寄也。", "」〖2〗《太平廣記》卷八十二引《史遺》：「王梵志，衛州黎陽人也。", "黎陽城東十五里，有王德祖，當隋文帝時，家有林檎樹，生癭大如斗。", "經三年，朽爛，德祖見之，乃剖其皮，遂見一孩兒抱胎而□。", "德祖收養之。", "至七歲，能語，曰：『誰人育我？復何姓名？』德祖具以實語之，因名林木梵天，〖「因名林木梵天」，明鈔本《太平廣記》作「因曰：『雙木曰梵，名曰梵天。", "』」語意稍長。", "〗後改曰梵志。", "曰：『王家育我，可姓王也。", "』梵志乃作詩示人，甚有義旨。", "」〖3〗楊慎《升庵詩話》卷四引唐釋道世《法苑珠林》：「梵志出家，白首而歸，鄰人見之，曰：『昔人尚存乎？", "』梵志曰：『吾猶昔人，非昔人也。", "』」按丁福保《歷代詩話續編》亦載之，見第十三冊「吾猶昔人」條。", "）。"]'),
('e96ca118-ac7e-4998-8a4f-675549667ec1','早春泛鏡湖','宋之問','唐','唐诗','tang','','[]','漾舟喜湖廣，湖廣趣非一。',158,'全唐诗/poet.tang.50000.json','["漾舟喜湖廣，湖廣趣非一。", "愉目野載蕪，清心山更出。", "孤烟晝藏火，薄暮朝開日。", "但愛春光遲，不覺舟行疾。", "歸雁空間盡，流鶯花際失。", "遠情自此多，景霽風物和。", "蘆人收晚釣，棹女弄春歌。", "野外寒事少，湖間芳意多。", "雜花因爛熳，暄柳日逶迤。", "爲客頓逢此，於思柰若何？", "（此詩見《永樂大典》卷二二六七「六模」「湖」字「鏡湖」條。", "〖二函二十冊〗）。"]'),
('6f0b5f47-9d4a-459c-8b03-ba673e8abe2d','題謝處士山齋','宋之問','唐','唐诗','tang','','[]','那有唐年客，青山獨閉門。',86,'全唐诗/poet.tang.50000.json','["那有唐年客，青山獨閉門。", "雲泉一少事，琴史皆忘喧。", "在濬人猶縶，遷喬友未言。", "不知幽谷草，何意老王孫？", "（此詩見《永樂大典》卷二五三九「七皆」「齋」字「山齋」條。", "〖三函三十冊〗）。"]'),
('7975ccaa-8e57-4376-891d-d5c7ae7259e1','過中書元舍人山齋','宋之問','唐','唐诗','tang','','[]','元侯松子賓，寓此掖垣職。',172,'全唐诗/poet.tang.50000.json','["元侯松子賓，寓此掖垣職。", "移疾多暇豫，孤齋恣閑息。", "修逕接大野，重巒跨南北。", "具物芬榮時，登攀各可極。", "林間百鳥變，郊外千花織。", "秦嶺似雲橫，周原如黛飾。", "洛中昔遊衍，常聞故園憶。", "清言盡場圃，嘉話數耘植。", "夢想恒載馳，松篁若舊識。", "酒情忽無限，琴意忻有得。", "更閱青谿詩，逾勵丹霞食。", "貴者日已遠，幸君惠容色。", "朅來休潁陽，任予孤且直。", "（同前見《大典》卷二五三九。", "）。"]'),
('3c849e12-8ed1-4b84-a5cc-96b050853f8e','嵩南山九里舊鵲村作','宋之問','唐','唐诗','tang','','[]','弊廬接箕潁，北望嵩山隅。',183,'全唐诗/poet.tang.50000.json','["弊廬接箕潁，北望嵩山隅。", "兹嶺雄且秀，綵翠橫天衢。", "家世事靈嶽，嵒棲安敢渝。", "從俗因迹化，歸静知心愚。", "上違先人訓，下憐菲薄軀。", "自問何功業，謬與賢俊俱。", "執覊翊龍羽，秉筆遊鴻都。", "尸禄負諸己，日使田園蕪。", "常恐白雲意，溘盡黃埃塗。", "妙年負恩德，欲去何踟蹰？", "明主本尚道，黃屋均蓬壺。", "飲惠可冥分，歸事燒金鑪。", "（此詩見《永樂大典》卷三五八○「九真」「村」字「舊鵲村」條。", "〖五函五十冊〗）。"]'),
('0536ef8e-a65a-486f-a71a-46c8a919ece9','敬和吏部韋郎中庭前朱槿之作','宋之問','唐','唐诗','tang','','[]','日給當輪滿，星郎伏奏旋。',78,'全唐诗/poet.tang.50000.json','["日給當輪滿，星郎伏奏旋。", "猶紆起草思，更有落花篇。", "氣與香衣雜，光侵畫壁然。", "徒聞賦君子，無以和神仙。", "（此詩見《分門纂類唐歌詩》殘本第六冊《草木蟲魚類》卷五。", "）。"]'),
('11743a07-f862-4834-bb51-8be0600458e0','','王勔','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.50000.json','["。"]'),
('52f6e867-ec26-466c-b2d8-1e8bf3714236','山名','王勔','唐','唐诗','tang','','[]','麗景斜中嶠，晴華泛晚春。',71,'全唐诗/poet.tang.50000.json','["麗景斜中嶠，晴華泛晚春。", "琴聲抽楚雪，歌曲下梁塵。", "傾蓋彫炎遠，班荆密契新。", "方承綺□暮，烟上洛橋□。", "（見影印本《新編纂圖書類要事林廣記》卷七。", "）。"]'),
('db8234e7-2306-4a20-b88f-4f46ca797d55','太平興龍寺（題擬）','崔融','唐','唐诗','tang','','["\u5e90\u5c71"]','昨度[匡]（厈）山下，春鶯曉弄稀。',487,'全唐诗/poet.tang.50000.json','["昨度[匡]（厈）山下，春鶯曉弄稀。", "今來[湓]（盆）水曲，秋鴈晚行飛。", "國有文皇召，人慙謫傳歸。", "迴行過梵塔，歷覽遍吳畿。", "杏樹栽時久，蓮花刻處微。", "南溪雨颯颯，東峴日輝輝。", "瀑溜天童捧，香爐法衆圍。", "煙雲隨道路，鶯鶴遠驂騑。", "遠上靈儀肅，生公談柄揮。", "一兹觀佛影，暫欲罷朝衣。", "（此詩見《永樂大典》卷六六九九「十八陽」「江」字〖七函、六十四冊〗。", "）（按《永樂大典》卷六六九九「九江府」十一「寺院」引《江州志》。", "「太平興龍寺在虎溪，本晉東林寺。", "太元九年桓伊置，法師慧遠道場也。", "」又引《元一統志》：「東林禪寺，《舊志》載在州境，晉武帝太和十年建，唐號太平興龍寺，最爲廬山之古剎，寺有慧遠袈裟。", "」《江州志》又謂寺有劉孝綽、孟浩然、李白、崔融、錢起、裴休、皇甫冉、杜荀鶴及樂天之詩。", "此詩即自所引錄出。", "〖1〗《吉石庵叢書》影印日本藏古鈔陳舜俞《廬山記》卷四收此詩，題作《遊東林寺》。", "首句作「昨度匡山下」，第三句作「今來湓水曲」，均可訂《大典》之誤，兹據改。", "第十五句作「煙霞隨道路」。", "又詩後附跋云：「元和十三年二月二十九日，曾孫朝散大夫使持節江州諸軍事江州刺史上柱國清河縣開國男賜紫金魚袋能再刊勒。", "」）。"]'),
('619a48e1-e086-431c-87c0-b9c4d3e17c89','寶名','崔融','唐','唐诗','tang','','[]','□城煙雨霽，□苑物華滋。',128,'全唐诗/poet.tang.50000.json','["□城煙雨霽，□苑物華滋。", "池連金水白，人契玉山時。", "珠浦荷如蓋，銅街樹似帷。", "琴歌待明月，丹石有深期。", "（此詩見影印本《新編纂圖增類羣書類要事林廣記》卷七。", "本詩所缺二字，原本較模糊。", "首句缺字似爲「鼎」字，次句缺字，右邊爲「圭」形，左邊已難辨認，疑應爲「桂」字。", "）。"]'),
('9e329eb4-5f0b-47f5-a355-682521e875be','五言夏日游神泉詩（幷序）','韋元旦','唐','唐诗','tang','','[]','聞有濠梁地，駕言幷四美。',120,'全唐诗/poet.tang.50000.json','["聞有濠梁地，駕言幷四美。", "契冥邀異迹，勝會不延晷。", "澗響若琴中，泉華疑鏡裏。", "形隨員月正，制逐規虹起。", "澡流瑩丹心，跂石涼玉趾。", "近焉將安適？行當潤濛氾。", "（此詩見《金石萃編》卷六十一。", "）（按詩題下原署「美原縣尉韋元旦字烜」，碑刻文字係尹元凱所書。", "）。"]'),
('818bcd6f-872a-4749-b0f7-5a2f8d1b8500','五言夏日游神泉詩','賈言淑','唐','唐诗','tang','','[]','詞人擁高節，狎異尋幽賞。',205,'全唐诗/poet.tang.50000.json','["詞人擁高節，狎異尋幽賞。", "𧯆險洞深澗，皦鏡鯀無象。", "形隨澡魄員，氣逐非烟上。", "徙谷縈新溜，分谿疏舊壤。", "冥功兆□□，効奇靈既往。", "共漱□□清，超然□□想。", "（見《金石萃編》卷六十一。", "〖此詩又見孫星衍《續古文苑》卷四，第五句作「形隨隨滿魄鼎」；第九句所缺二字，下一字作「即」；第十一句缺二字之上一字，《金石萃編》存左半邊，作「馬」形，《續古文苑》作「鳴」。", "〗）（按是刻次韋元旦詩後，原署「主簿賈言淑」，書者體會爲尹元凱。", "）。"]'),
('2eb2d4cd-882a-49c7-9be1-42964c6e2928','','尹元凱','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.50000.json','["。"]'),
('2baee7ee-6fee-4aea-8702-ccf2b34f4cad','五言同韋子斿神泉詩（幷序）','尹元凱','唐','唐诗','tang','','[]','桐坂疏抱𦉥，崐丘落縣米。',267,'全唐诗/poet.tang.50000.json','["桐坂疏抱𦉥，崐丘落縣米。", "豈如中輔邑，迸泉毓爲醴。", "氣高靈洮作，潤洽沖務啟。", "月潭信玲瓏，霞溜幾清泚？", "湝湝上善用，的的煩慮洗。", "君子懷淡交，相從澗之底。", "（見《金石萃編》卷六十一。", "序中原缺一字，據《續古文苑》卷四補。", "）（按此詩快乐序在韋元旦、賈言淑詩刻之碑陰，詩前署書者之名曰「大唐裕明子書」，題下署詩序作者之名曰「雲陽主簿明臺子徐彥伯字光」，詩後署詩作者之名曰「裕明子河間尹元凱字戫」。", "望又按史稱徐彦伯名洪，以字顯，據碑，知實名彦伯而字光也。", "彦伯於武后垂拱間爲雲間主簿，屢遷給事中，預修《三教珠英》，歷修文館學士、工部侍郎、太子賓客而卒。", "）。"]'),
('683e6c19-0951-4e06-abc9-2d55a4c4a098','','溫翁念','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.50000.json','["。"]'),
('c57b3077-3cd6-4896-81cf-0c646bbd0369','五言同韋子斿神泉詩','溫翁念','唐','唐诗','tang','','[]','聞君泉壑幽，俯裂頻陽趾。',182,'全唐诗/poet.tang.50000.json','["聞君泉壑幽，俯裂頻陽趾。", "及我性情狎，遥輕武陵涘。", "欿窞明月制，沮𣹤涼風起。", "朋來想辟雝，日去疑濛汜。", "列坐殊滿腹，揚清非洗耳。", "髣髴參石斿，淡焉適真理。", "（見《金石萃編》卷六十一。", "）（〖1〗此詩列尹元凱詩刻之後，署作者之名曰「左司郎中溫翁念字敬祖」，書者亦爲尹元凱。", "據《新唐書》卷七十二中《宰相世系表》載翁念爲彦博之孫，官大僕少卿。", "此碑署銜左司郎中，蓋武后垂拱間仕歷也。", "）。"]'),
('3d058f5d-afe7-4ecf-9ec1-c289c659fc03','五言同韋子斿神泉詩','李鵬','唐','唐诗','tang','','[]','昔日鳴絃地，今聞生澗水。',157,'全唐诗/poet.tang.50000.json','["昔日鳴絃地，今聞生澗水。", "靈潛敝政餘，潤發彫文始。", "滴滴流珠散，渟渟明月止。", "善香懷若人，淡交挹君子。", "鏡澈無纖翳，天清滌煩滓。", "虛忝神僊臺，何由弄風晷？", "（見《金石萃編》卷六十一。", "）（〖1〗詩刻次溫翁念一詩後，署作者之名曰「天官員外郎李鵬字至遠」，亦尹元凱所書。", "碑末紀年曰「垂拱四年龍集戊子四月戊□」，蓋公元六八八年也。", "）。"]'),
('22598cfc-4428-49de-9e31-c574d8c1343f','','光溫古','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.50000.json','["。"]'),
('a130d14d-b078-4490-a783-1366b9fc2af8','句','光溫古','唐','唐诗','tang','','[]','錦色陽川后，絲雨降桐鄉。',235,'全唐诗/poet.tang.50000.json','["錦色陽川后，絲雨降桐鄉。", "（〖1〗句見《金石萃編》卷六十五「唐二十五」。", "按此詩句幷下趙不爲、王鉉、成公簡、李大寶諸人詩句均刻在《衛州共城縣百門陂碑銘》之碑陰，或乞雨，或喜晴，皆摘取兩句，不得見其全爲可惜耳。", "又此詩句前有記事，略謂長安二年〖公元七○二年〗夏五月，州符下縣祈雨。", "六月一日先祈社稷，遍祈山川，其時西北山頂，有雲團團而上，雷起巖突，電發𡓜蕃，須臾之間，降雨一境。", "父老光溫古上詩賀公曰〖句不重錄〗云云。", "望按記事中所稱上詩賀公，公，蓋指靈源公，爲當地民間所祠神名。", "）。"]'),
('6876048a-5d9b-4830-a028-f724d279ce5f','句','趙不爲','唐','唐诗','tang','','[]','調弦敷廣西惠，濟物被深仁。',81,'全唐诗/poet.tang.50000.json','["調弦敷廣西惠，濟物被深仁。", "（〖1〗句列光溫古祈雨詩句後。", "曰「五𠥱〖月〗十〖乙〗〖日〗，前南岳齋郎趙不爲詩曰。", "〖句不重錄〗」望按：《全唐文》爲四○一有趙不爲文。", "）。"]'),
('397d6b7b-d0ca-4cb2-b563-bbc325560ec6','又句','趙不爲','唐','唐诗','tang','','[]','晴暉疑兆夢，甘液類隨車。',50,'全唐诗/poet.tang.50000.json','["晴暉疑兆夢，甘液類隨車。", "（〖1〗句列於此碑碑陰之末，曰：「趙不爲《喜晴》詩曰〖句不重錄〗云云。」", "）。"]'),
('9baadb3f-e119-46d2-986f-983d1849750f','句','王堅','唐','唐诗','tang','','[]','良宰多憂憫，虔誠謁庶神。',62,'全唐诗/poet.tang.50000.json','["良宰多憂憫，虔誠謁庶神。", "（〖1〗句次趙不爲祈雨詩句後，曰「七𠥱〖月〗廿三〖乙〗〖日〗，文林郎王堅詩曰〖句不重錄〗」云云。", "）。"]'),
('97f46ccc-c62a-4af5-8bf3-157a4b8896f2','句','王鉉','唐','唐诗','tang','','[]','雨似隨車至，雲疑逐蓋飛。',82,'全唐诗/poet.tang.50000.json','["雨似隨車至，雲疑逐蓋飛。", "（〖1〗句次王堅詩句後，曰「文林郎王鉉詩曰〖句不重錄〗」云云。", "按唐有兩王鉉，《全唐文》卷七九一收王鉉文二篇，乃大中時處士，此則長安間人。", "）。"]'),
('3ece754f-de76-4987-abf1-f4a70a622b7c','句','成公簡','唐','唐诗','tang','','[]','隨軒感仁惠，應日（原作〖乙〗）灑甘滋。',59,'全唐诗/poet.tang.50000.json','["隨軒感仁惠，應日（原作〖乙〗）灑甘滋。", "（〖1〗句次王鉉詩句後，曰「武聖〖原作●〗縣尉成公簡詩曰〖句不重錄〗云云。」", "）。"]'),
('a462f86f-45d3-4634-af5d-7f006601ccae','句','李大寶','唐','唐诗','tang','','[]','陽耀求便灑，陰霖請復晴。',52,'全唐诗/poet.tang.50000.json','["陽耀求便灑，陰霖請復晴。", "（〖1〗句次成公簡詩句後，曰「成均進士李大寶《賀晴詩》曰〖句不重錄〗云云。」", "）。"]'),
('ea9cef18-11ef-4324-aa73-8fd1e686630c','','馬友鹿','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.50000.json','["。"]'),
('ca01291e-9d6b-492c-be41-f744fc09f9fc','早春陪敕麻先生（慈力）祭岳（久視二年。見《山左金石志》卷十二，亦見《金石萃編》卷五十三。此詩《全唐詩》卷八百八十七補遺卷載之，作者馬令，注曰」失名「。今按《山左金石志》署作者曰「行博城縣令馬友鹿」，則其名固未失也。詩同，不重出，校其異文如下：第三句「鞭撻造神鬼」，「造」《全唐詩》作「走」。五句「忽下元洲使」，「元洲」，《全唐詩》作「袁州」。六句「來赴紫洞前」，「赴」，《全唐詩》作「遊」。八句「白鶴怪時還」，「怪」，《全唐詩》闕；「還」，作「年」。十一句「巖風半山水」，「巖」，《全唐詩》闕。十二句','馬友鹿','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.50000.json','["空。"]'),
('87f9821c-2768-4544-b296-123d746550b4','贈崔十娘','張鷟','唐','唐诗','tang','','[]','自隱多姿則，欺他獨自眠。',48,'全唐诗/poet.tang.50000.json','["自隱多姿則，欺他獨自眠。", "故故將纖手，時時弄小絃。", "耳聞猶氣絕，眼見若爲憐。", "從渠痛不肯，人更別求天。"]'),
('3c4b8756-8e5c-4bdc-b90f-a8b4fcc5fd1a','詩一首','張鷟','唐','唐诗','tang','','[]','歛笑偷殘靨，含羞露半脣。',24,'全唐诗/poet.tang.50000.json','["歛笑偷殘靨，含羞露半脣。", "一眉猶叵耐，雙眼定傷人。"]'),
('7e3f42c0-6165-4212-88a2-f0bca754e1be','又一首','張鷟','唐','唐诗','tang','','[]','夢中疑是實，覺後忽非真。',24,'全唐诗/poet.tang.50000.json','["夢中疑是實，覺後忽非真。", "誠知腸欲繼，窮鬼故調人。"]'),
('5e09e26f-7b2b-4731-94a6-d41f9403b3f2','又一首','張鷟','唐','唐诗','tang','','[]','未必由詩得，將詩故表憐。',25,'全唐诗/poet.tang.50000.json','["未必由詩得，將詩故表憐。", "聞渠擲入火，定是欲相然。", "。"]'),
('67baefa1-b8cb-4691-9280-5cfdad7e951a','又一首','張鷟','唐','唐诗','tang','','[]','心虛不可測，眼細强關情。',24,'全唐诗/poet.tang.50000.json','["心虛不可測，眼細强關情。", "迴身已入抱，不見有嬌聲。"]'),
('2c13df77-886a-4ed9-a1c2-01b61924c9fe','詠𡱈','張鷟','唐','唐诗','tang','','[]','眼似星初轉，眉如月欲渭。',24,'全唐诗/poet.tang.50000.json','["眼似星初轉，眉如月欲渭。", "先須捺後脚，然後勒前腰。"]'),
('32ce7f3d-4314-4899-829e-044ebbed7bba','詩一首','張鷟','唐','唐诗','tang','','[]','忽然心裏愛，不覺眼中憐。',24,'全唐诗/poet.tang.50000.json','["忽然心裏愛，不覺眼中憐。", "未關雙眼曲，直是寸心偏。"]'),
('53e6130a-bb17-41e2-83ef-443a099a79c5','又一首','張鷟','唐','唐诗','tang','','[]','舊來心使眼，心思眼剩（《唐人小說》本作即。',36,'全唐诗/poet.tang.50000.json','["舊來心使眼，心思眼剩（《唐人小說》本作即。", "）傳。", "由心使眼見，眼亦共心憐。"]'),
('16c79884-993e-4671-a9ef-70ad3782cea4','詠刀子','張鷟','唐','唐诗','tang','','[]','自憐膠漆重，相思意不窮。',24,'全唐诗/poet.tang.50000.json','["自憐膠漆重，相思意不窮。", "不惜尖頭物，終日在皮中。"]'),
('a39a3828-ed2b-4fda-bc19-3646b5c53c4c','詩一首','張鷟','唐','唐诗','tang','','[]','向來知道徑，生平不忍欺。',24,'全唐诗/poet.tang.50000.json','["向來知道徑，生平不忍欺。", "但令守行跡，何用數圍碁。"]'),
('5af90233-e556-4a0d-9f96-314df6b978bd','又一首','張鷟','唐','唐诗','tang','','[]','千金此處有，一笑待渠爲。',24,'全唐诗/poet.tang.50000.json','["千金此處有，一笑待渠爲。", "不望全露齒，請爲暫嚬眉。"]'),
('ef313415-5ab5-4c67-8765-f9a58a80aa87','詠破銅熨斗','張鷟','唐','唐诗','tang','','[]','若冷頭面在，生平不熨空。',25,'全唐诗/poet.tang.50000.json','["若冷頭面在，生平不熨空。", "即今雖冷惡，人自覓殘銅。", "。"]'),
('bc0744ac-5717-4451-9199-065c755f5432','舞詞','張鷟','唐','唐诗','tang','','[]','從來巡遶四邊，忽逢兩箇神仙。',56,'全唐诗/poet.tang.50000.json','["從來巡遶四邊，忽逢兩箇神仙。", "眉上冬天出柳，頰中旱地生蓮。", "千看千處嫵媚，萬看萬處㛹妍。", "今宵若其不得，剩命過與黃泉。"]'),
('9d51cce1-03bf-4560-9088-4edbdb978d97','詠筆硯','張鷟','唐','唐诗','tang','','[]','摧毛任便點，愛色轉須磨。',24,'全唐诗/poet.tang.50000.json','["摧毛任便點，愛色轉須磨。", "所以研難竟，良由水太多。"]'),
('5a87a41e-f397-4d8a-9fb8-908e33a55780','詠雙燕子','張鷟','唐','唐诗','tang','','[]','雙燕子，聯聯翩翩幾萬迴。',40,'全唐诗/poet.tang.50000.json','["雙燕子，聯聯翩翩幾萬迴。", "（《唐人小說》本作聯翩幾萬迴。", "）强知人是客，方便惱他來。"]'),
('34c091d6-580c-465e-b56e-629f09c12f3e','詠酒杓子','張鷟','唐','唐诗','tang','','[]','尾動惟須急，頭低則不平。',24,'全唐诗/poet.tang.50000.json','["尾動惟須急，頭低則不平。", "渠今合把爵，深淺任君情。"]'),
('c4e3d658-5ce8-4e5a-a9de-00f5d77dbed4','詠李','張鷟','唐','唐诗','tang','','[]','問李樹，如何意不同？應來主毛裏，翻入客懷中。',22,'全唐诗/poet.tang.50000.json','["問李樹，如何意不同？應來主毛裏，翻入客懷中。"]'),
('c6fad4cc-fc7e-4396-9636-16c04e66338e','答十娘射雉','張鷟','唐','唐诗','tang','','[]','心緒恰相當，誰能護短長。',24,'全唐诗/poet.tang.50000.json','["心緒恰相當，誰能護短長。", "一床無兩好，半醜亦何妨。"]'),
('6bf1b256-d73b-4f68-b9ce-eb7abec1cf00','答十娘詠弓','張鷟','唐','唐诗','tang','','[]','縮幹全不到，抬頭則大過。',25,'全唐诗/poet.tang.50000.json','["縮幹全不到，抬頭則大過。", "若令臍下入，百放故籌多。", "。"]'),
('94ef3f28-cd3b-4cd7-9e66-4e53c0d712ac','詩一首','張鷟','唐','唐诗','tang','','[]','千看千意密，一見一憐深。',24,'全唐诗/poet.tang.50000.json','["千看千意密，一見一憐深。", "但當把手子，寸斬亦甘心。"]'),
('deb80130-92c5-41b6-a595-f1e3a964d2c8','又一首','張鷟','唐','唐诗','tang','','[]','千思千腸熱，一念一心焦。',24,'全唐诗/poet.tang.50000.json','["千思千腸熱，一念一心焦。", "若爲求守得，暫借可憐腰。"]'),
('834d1306-b786-4c8f-aeb8-77c22819aac8','又一首','張鷟','唐','唐诗','tang','','[]','腰支一遇勒，心中百處傷。',24,'全唐诗/poet.tang.50000.json','["腰支一遇勒，心中百處傷。", "但若得口子，餘事不承望。"]'),
('236b624c-139a-4c9b-8e2a-7e369b39aeb5','又一首','張鷟','唐','唐诗','tang','','[]','藥草俱嘗遍，並悉不相宜。',24,'全唐诗/poet.tang.50000.json','["藥草俱嘗遍，並悉不相宜。", "惟須一箇物，不道自應知。"]'),
('263cda28-bb6d-46cb-a91e-c4360f56c247','又一首','張鷟','唐','唐诗','tang','','[]','積愁腸已斵，懸望眼應穿。',24,'全唐诗/poet.tang.50000.json','["積愁腸已斵，懸望眼應穿。", "今宵莫閉戶，夢裏向渠邊。"]'),
('7c3c4216-0f16-4aae-8eff-9384942765cb','別崔瓊英','張鷟','唐','唐诗','tang','','[]','卞和山未斵，羊雍地不耕。',12,'全唐诗/poet.tang.50000.json','["卞和山未斵，羊雍地不耕。"]'),
('a17c525b-d498-4ee1-8a0e-b36e37ef8f24','相思枕留贈十娘','張鷟','唐','唐诗','tang','','[]','南國傳椰子，東家賦石榴。',24,'全唐诗/poet.tang.50000.json','["南國傳椰子，東家賦石榴。", "聊將代左腕，長夜枕渠頭。"]'),
('a74e22c9-ab33-401e-b186-dbffb250e862','益州新樣錦留贈五嫂','張鷟','唐','唐诗','tang','','[]','今留片子信，可以贈佳期。',25,'全唐诗/poet.tang.50000.json','["今留片子信，可以贈佳期。", "裁爲八幅被，時復一相思。", "。"]'),
('c92dba26-eb50-46d1-9a8c-df167168ba33','答張文成','張鷟','唐','唐诗','tang','','[]','（案以下各詩，《遊仙窟》雖謂崔十娘所作，要皆張文成戲墨耳。',54,'全唐诗/poet.tang.50000.json','["（案以下各詩，《遊仙窟》雖謂崔十娘所作，要皆張文成戲墨耳。", "）面非他舍面，心是自家心。", "何處關天事，辛苦漫追尋。"]'),
('890dfc95-2998-4fed-a6a9-33b36cc74ea5','又','張鷟','唐','唐诗','tang','','[]','好是他家好，人非着意人。',24,'全唐诗/poet.tang.50000.json','["好是他家好，人非着意人。", "何須漫相弄，幾許費精神。"]'),
('823af34b-0473-484f-959d-7a73908d8f75','詩一首','張鷟','唐','唐诗','tang','','[]','憐腸忽欲繼，憶眼己先開。',12,'全唐诗/poet.tang.50000.json','["憐腸忽欲繼，憶眼己先開。"]'),
('defef83c-5b14-4e45-8b6c-826e74143c3c','詠尺八','張鷟','唐','唐诗','tang','','[]','眼多本自令渠愛，口少元來每被侵。',32,'全唐诗/poet.tang.50000.json','["眼多本自令渠愛，口少元來每被侵。", "天事風聲徹他耳，教人氣滿自填心。"]'),
('617b8954-16d6-40fb-9373-2608f127af6a','詠𡱈','張鷟','唐','唐诗','tang','','[]','勒腰須巧快，捺脚更風流。',24,'全唐诗/poet.tang.50000.json','["勒腰須巧快，捺脚更風流。", "但令細眼合，人自分輪籌。"]'),
('e840e2fe-07c2-46eb-97d4-3c97728f9e56','詩一首','張鷟','唐','唐诗','tang','','[]','眼心非一處，心眼舊分離。',24,'全唐诗/poet.tang.50000.json','["眼心非一處，心眼舊分離。", "直令渠眼見，誰遣報心知。"]'),
('7694dc89-12d8-4878-8a50-f597c55140fd','又一首','張鷟','唐','唐诗','tang','','[]','眼心俱憶念，心眼共追尋。',25,'全唐诗/poet.tang.50000.json','["眼心俱憶念，心眼共追尋。", "誰家解事眼，副著可憐心。", "。"]'),
('8f5efe34-843b-45db-8e70-7b035c2013b8','詠鞘','張鷟','唐','唐诗','tang','','[]','數捺皮應緩，頻磨快轉多。',24,'全唐诗/poet.tang.50000.json','["數捺皮應緩，頻磨快轉多。", "渠今拔出後，空鞘欲如何。"]'),
('f00122e7-c43e-44df-91cf-bfb805c01365','詩一首','張鷟','唐','唐诗','tang','','[]','雙眉碎客膽，兩眼判君心。',24,'全唐诗/poet.tang.50000.json','["雙眉碎客膽，兩眼判君心。", "誰能用一笑，賤價買千金。"]'),
('d35ea59b-af8f-499d-9e96-425a6b97a25c','詠破銅熨斗','張鷟','唐','唐诗','tang','','[]','舊來心肚熱，無端強熨他。',41,'全唐诗/poet.tang.50000.json','["舊來心肚熱，無端強熨他。", "即今形勢冷，誰肯重（重字原缺，據《唐人小說》本補。", "）相磨。"]'),
('5ad82c7c-4b3e-4517-85cf-28972a821dcf','詩一首','張鷟','唐','唐诗','tang','','[]','得意似鴛鴦，情乖若吳越。',24,'全唐诗/poet.tang.50000.json','["得意似鴛鴦，情乖若吳越。", "不向君邊盡，更知何處歇。"]'),
('619285c7-3ab7-463a-bfaf-670918fb69d6','詠鴨頭鐺子','張鷟','唐','唐诗','tang','','[]','觜長非爲嗍，項曲不由攀。',24,'全唐诗/poet.tang.50000.json','["觜長非爲嗍，項曲不由攀。", "但令脚直上，他自眼雙翻。"]'),
('2a115df3-cd5c-462a-b752-e56072db3cb8','詠雙燕子','張鷟','唐','唐诗','tang','','[]','雙燕子，可可事風流。',22,'全唐诗/poet.tang.50000.json','["雙燕子，可可事風流。", "即令人得伴，更亦不相求。"]'),
('4357e781-0b49-44e1-8613-39b08cb6655d','詠盞','張鷟','唐','唐诗','tang','','[]','發初先向口，欲竟漸伸頭。',36,'全唐诗/poet.tang.50000.json','["發初先向口，欲竟漸伸頭。", "從君中道歇，到底郎（《唐人小說》本作即。", "）須休。"]'),
('d6923d79-bdbc-4580-9836-fea572b5a970','詠蜂子','張鷟','唐','唐诗','tang','','[]','問蜂子，蜂子太無情。',23,'全唐诗/poet.tang.50000.json','["問蜂子，蜂子太無情。", "飛來蹈人面，欲似意相輕。", "。"]'),
('807d47ea-8259-473e-a2b6-8de018e4dfad','詠射雉','張鷟','唐','唐诗','tang','','[]','大夫巡麥隴，處子習桑間。',24,'全唐诗/poet.tang.50000.json','["大夫巡麥隴，處子習桑間。", "若非由一箭，誰能爲解顏。"]'),
('3263485b-bd52-4fe0-869e-030d32d0f5fb','詠弓','張鷟','唐','唐诗','tang','','[]','平生好須弩，得挽則低頭。',24,'全唐诗/poet.tang.50000.json','["平生好須弩，得挽則低頭。", "聞君把提快，再乞五三籌。"]'),
('b42a643d-767d-4286-8f24-96e129374e50','詩一首','張鷟','唐','唐诗','tang','','[]','手子從君把，腰支亦任迴。',24,'全唐诗/poet.tang.50000.json','["手子從君把，腰支亦任迴。", "人家不中物，漸漸逼他來。"]'),
('5544e25a-6fdd-4190-9e3b-e8a9b1f553ca','答文成','張鷟','唐','唐诗','tang','','[]','素手曾經捉，纖腰又被將。',24,'全唐诗/poet.tang.50000.json','["素手曾經捉，纖腰又被將。", "即今輸口子，餘事可平章。"]'),
('9b1e453c-b38c-48d1-8b6e-08e5c0fb0f23','詩一首','張鷟','唐','唐诗','tang','','[]','元來不相識，判自繼知聞。',24,'全唐诗/poet.tang.50000.json','["元來不相識，判自繼知聞。", "天公強多事，今遣若爲分。"]'),
('7aec7ad0-6289-4f01-bf38-fd04a08bebcf','答文成贈別','張鷟','唐','唐诗','tang','','[]','鳯錦行須贈，龍梭久絕互。',12,'全唐诗/poet.tang.50000.json','["鳯錦行須贈，龍梭久絕互。"]'),
('3f80bb68-bc2a-4f2e-bf25-8cf0abe4c73e','報文成雙履','張鷟','唐','唐诗','tang','','[]','雙鳥作失伴，兩燕還相屬。',24,'全唐诗/poet.tang.50000.json','["雙鳥作失伴，兩燕還相屬。", "聊以當兒心，竟日承君足。"]'),
('aabb133b-4f9e-460d-8645-2ef77b6b3c03','報文成','張鷟','唐','唐诗','tang','','[]','他道愁勝死，兒言死勝愁。',25,'全唐诗/poet.tang.50000.json','["他道愁勝死，兒言死勝愁。", "愁來百處痛，死去一時休。", "。"]'),
('1b7fce5f-35ff-4f2c-af35-c310917eb151','報文成','張鷟','唐','唐诗','tang','','[]','他道愁勝死，兒言死勝愁。',24,'全唐诗/poet.tang.50000.json','["他道愁勝死，兒言死勝愁。", "日夜懸心憶，知隔幾年秋。"]'),
('9250e27b-88b6-46ea-9cb3-1c83bb71d690','詠筝','張鷟','唐','唐诗','tang','','[]','（案以下各詩，《遊仙窟》雖謂崔五嫂所作，要亦張文成戲墨而已。',75,'全唐诗/poet.tang.50000.json','["（案以下各詩，《遊仙窟》雖謂崔五嫂所作，要亦張文成戲墨而已。", "）天生素面能留客，發意關情並（《唐人小說》本作併。", "）在渠。", "莫怪向者頻聲戰，良由得伴乍心虛。"]'),
('313e64d8-6711-4045-adbd-a4d5e8673927','詩一首','張鷟','唐','唐诗','tang','','[]','娘子爲性好圍碁，逢人劇戲不尋思。',32,'全唐诗/poet.tang.50000.json','["娘子爲性好圍碁，逢人劇戲不尋思。", "氣欲繼絕先挑眼，既得速罷即須遲。"]'),
('3023a38a-6841-4909-95e2-5f261c1f02e9','詠李','張鷟','唐','唐诗','tang','','[]','李樹子，元來不是偏。',22,'全唐诗/poet.tang.50000.json','["李樹子，元來不是偏。", "巧知娘子意，擲果到渠邊。"]'),
('14d56d1b-64be-4875-a200-e1feba2e1748','詩一首','張鷟','唐','唐诗','tang','','[]','他家解事在，未肯輒相瞋。',24,'全唐诗/poet.tang.50000.json','["他家解事在，未肯輒相瞋。", "徑須剛捉著，遮莫造精神。"]'),
('524d3e10-aae9-47f6-aa02-eaa43e9dabf1','又一首','張鷟','唐','唐诗','tang','','[]','巧將衣障口，能用被遮身。',24,'全唐诗/poet.tang.50000.json','["巧將衣障口，能用被遮身。", "定知心肯在，方便故邀人。"]'),
('04d1c3e6-c831-4f2d-b983-a8d77c34b794','又一首','張鷟','唐','唐诗','tang','','[]','自隱風流到，人前法用多。',24,'全唐诗/poet.tang.50000.json','["自隱風流到，人前法用多。", "計時應拒得，佯作不禁他。"]'),
('9a1d7f89-b3f8-4f6f-920e-4c22ca48f4fa','報文成金釵','張鷟','唐','唐诗','tang','','[]','兒今贈君別，情知復會難。',494,'全唐诗/poet.tang.50000.json','["兒今贈君別，情知復會難。", "莫言釵意小，可以掛渠冠。", "（〖1〗《日本圖經》卷二十二《藝文志》：「《遊仙窟》一卷，唐張文成。", "昌平學舊寫八行本、容安書院舊寫九行本、尾張真福寺舊寫六行本刊本，卷首題《遊仙窟》，寧州襄樂縣尉張文成作，小說家言也。", "寧州，注云屬關內道，在去京三百里西北也。", "日本人言是書作嵯峨天皇時，果爾，則唐元和間也。", "陳氏矩得刊本。", "」〖2〗汪辟疆《唐人小說》：「按張文成《遊仙窟》一卷，唐時流傳日本。", "書凡數刻，中土向無傳本。", "河世寧曾據之駿補《全唐詩》，楊守敬始著錄於，日本訪書志。", "治唐稗者，始稍稍稱焉。", "余舊藏鈔本，卷首有『平等閣』及『忠州李士棻隨身書卷』二印記。", "卷尾有『壬午三月借遵義黎氏影寫本重校』小字一行，乃知此本爲芋仙舊藏。", "芋仙與蒓齋有縞紵之雅。", "黎氏在日本刻《古逸叢書》，嘗以初印本寄李，李累索之，不以爲貪。", "則此本原鈔，或即出諸黎氏，未可知也。", "原鈔卷首題『寧州襄樂縣詩張文成作』。", "世因定爲唐張鷟所撰。", "鷟字文成，深州陸澤人。", "兩《唐書》並附見《張薦傳》。", "鷟兒時夢紫文鸑鷟，其祖謂是兒當以文章瑞朝廷，因以爲名字。", "調露初，登進士第，授岐王府參軍。", "八舉皆登甲科，大有文譽。", "調長安尉，遷鴻臚丞。"]'),
('f3b0ea52-f270-4c9d-b546-2e523536951b','酒名','員半千','唐','唐诗','tang','','[]','帝鄉從事隙，薄暮中山開。',74,'全唐诗/poet.tang.50000.json','["帝鄉從事隙，薄暮中山開。", "地域荆南記，人事豫北□。", "蘭英{身虎}虹上。", "竹葉清風來。", "雲物上可惜，落日顧霞杯。", "（見影印本《新編纂圖增類要事林廣記》卷七。", "）。"]'),
('8d66bf97-bf62-4fb1-bf24-f219a9fb5232','風名','閭丘均','唐','唐诗','tang','','[]','玉階王道泰，金門詞藻多。',74,'全唐诗/poet.tang.50000.json','["玉階王道泰，金門詞藻多。", "文雄自指引，美景相經過。", "野氣連空谷，春色滿長河。", "方從君子會，終宴且當歌。", "（見影印本《新編纂圖增類羣書類要事林廣記》卷七。", "）。"]'),
('1cb2ab25-f434-4c5c-afaf-4424c77fad40','董孝子黯復讎','賀知章','唐','唐诗','tang','','[]','十年心事苦，惟爲復恩仇。',51,'全唐诗/poet.tang.50000.json','["十年心事苦，惟爲復恩仇。", "兩意既已盡，碧山吾白頭。", "（見鄞縣張壽鏞刻《四明叢書》第一集中《賀祕監集》。", "）。"]'),
('ebd1e332-db9d-4471-aeb8-93fc880ce178','石橋詠','崔恂','唐','唐诗','tang','','[]','巨川橫廣路，□涉吟艱危。',501,'全唐诗/poet.tang.50000.json','["巨川橫廣路，□涉吟艱危。", "巧思侔神□，經途變險戲。", "石梁全架□，鐵鏁竟何□。", "昔有黿鼉異，今看結構奇。", "□□□□補，似迫□龍移。", "跨水鼇峯見，凌虛鵬翼垂。", "寧勞浮柱設，詎假造舟爲。", "代久堤維固，年深砌不隳。", "□虹常偃蹇，雲鴈□差池。", "□物三方會，傳名四海□。", "□鐫起花葉，模寫躍蛟螭。", "□矗平踰砥，下穹圓甚規。", "□如丹洞出，窓類白巖窺。", "□鶴臨華表，詞人訪古碑。", "□燕□□□，郢越亘南馳。", "□□無濡足，千秋長□□。", "（見《文物參攷資料》一九五七年第三期俞同奎作《安濟橋補充文獻》所附詩刻拓片。", "）（〖1〗按石刻詩題下原署「趙州長史崔恂」。", "《新唐書》卷七十二下《宰相世系表》鄭州崔氏房有崔恂，杭州刺史清河男。", "其從叔崔元綜，相武后朝，則恂當是中宗、玄宗時人。", "又此詩刻後有魏州司功參軍劉義□《詶崔長史》詩一首，惜已漫漶不可得辨矣。", "〖2〗俞同奎文謂此詩見趙縣安濟橋下所得石刻，同時另出一石，與詩石大小相同，後味殘文尚可辨認，錄如次：「□元八年九月□□□□□□李」於時□□□□□崔恂「任深州□史□□□還此橋過喜其壯麗命」舊詩云□志並七年春俞文考定「□元八年」應爲「經營元八年」，所出詩石爲崔恂開元七年在趙州時作，次年由深州重經此橋，序而刻石。", "）。"]'),
('133c1491-05bc-4e5b-ab72-502771f95dc1','遊石門洞（題擬）','裴士淹','唐','唐诗','tang','','[]','溪竹亂花鳥，是月春將暮。',163,'全唐诗/poet.tang.50000.json','["溪竹亂花鳥，是月春將暮。", "登棧過崖畔，空間瞻瀑布。", "千齡無斷絕，百尺恒奔注。", "高巖迸似珠，半壁灑如霧。", "澹艷水澄澈，欹傾石回護。", "藥房森自閑，苔徑窅誰遇。", "天翠落深沼，雲華生輕樹。", "班輪齊効功，嚴馬何能喻？", "勝蹟蓋爲寡，花錢遊誠可屢。", "謝公鐫舊詞，安得寢章句？", "（見《永樂大典》卷一三○七四「一送」「洞」字「石門洞」條〖十四函一百三十四冊〗。", "）。"]'),
('8e73617b-54b7-45c0-8ba8-6ed995a4852c','','王英','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.50000.json','["。"]'),
('d7cdcdef-7ad2-41c3-9ff3-be8e1b6bd497','感石浮圖','王英','唐','唐诗','tang','','[]','樹福金巖頂，粧巖琢石成。',24,'全唐诗/poet.tang.50000.json','["樹福金巖頂，粧巖琢石成。", "真容繪美素，圖鏤萬年榮。"]'),
('2aeb3eb4-c2a2-4568-83ac-b75664367517','又一首','王英','唐','唐诗','tang','','[]','琉𭸻彫瑩美，圖真琢玉成。',223,'全唐诗/poet.tang.50000.json','["琉𭸻彫瑩美，圖真琢玉成。", "神功呈百福，含聚曰光明。", "輪寶□霄壯，珠瓔鏤石晶。", "感□嚴父志，謁力爲先靈。", "（以上二詩見陸增祥輯《八瓊室金石補正》卷五十八。", "）（〖1〗《八瓊室金石補正》謂「二詩不著撰人名，當是英輩所作。", "」按二詩附於石經山中臺浮圖諸刻之後，是刻先列《王晉造石浮圖記》，標明天寶十二載鶘廿五日建，次列《感怨文》，爲王晉子王英所撰，次刊《感石浮圖》詩二首，末列安禄山題名，曰「御史大夫安禄山供養」，惟「安禄山」三字後人惡其名而鑿之，然尚可辨識。", "）。"]'),
('ffeb988c-1852-43e6-986b-6070c48c8fb4','千秋亭詠（並序）','崔文邕','唐','唐诗','tang','','[]','飲餞憑何地，依巖闢此亭。',489,'全唐诗/poet.tang.50000.json','["飲餞憑何地，依巖闢此亭。", "玉江摽勝託，石壁效題銘。", "秋染藤宜紫，春圖柳愛青。", "樽來是離酌，皆爲送歸情。", "（見石刻拓片。", "亦見《金石苑》。", "）（望按：此詩與《石亭記千秋亭記》合刻一石，記在前，係開元十八年前飛鳥縣主簿趙演撰文，詩居後，題曰「《千秋亭詠》並序」，下署「朝散郎行梓州銅瞐縣詩博陵崔文邕」，詩後有「開元十九年歲次辛未五月五日」一行，當是刻詩年月。", "碑在四川中江縣，友人寧鄉程千帆〖會昌〗以所藏拓片見贈，其末並有近人張巽中跋文一段，畧謂「此碑出吾蜀中江縣{身犬}子店，昔何蝯叟督學來川，曾拓數十紙驗歸，祕而不宣。", "康長素亦手藏一搨，不以示人。", "細玩字裏行間，於晉魏六朝之外，獨具婀娜風致，宜爲道州、南海所寶也」云云。", "今細讀斯記，祇稱「石亭」，不及「千秋」之名，而附詩詩題，則明標「千秋」，以是頗疑崔氏始構此亭。", "原稱「石亭」，其後乃更名其後乃更名「千秋亭」耳。", "然則文題作《石亭記千秋亭記》，其「千秋亭記」四字系開元十九年崔氏刻詩時所後加，不然，安有一文而兼勒二題之理耶。", "又此詩亦見劉喜海《金石苑》，惟「玉江」爲異。", "劉氏曰：「詩內玉誤王，記誤託，未知是否。", "」今按石碑作玉作託，當以拓片爲準。", "）。"]'),
('b9c87c43-3ca4-49c9-bbf4-cbf7c7fb5985','永嘉懷古（題一作《石門山》）','郭密之','唐','唐诗','tang','','[]','永嘉東南盡，□袒《青田志》（作「倚棹」。',426,'全唐诗/poet.tang.50000.json','["永嘉東南盡，□袒《青田志》（作「倚棹」。", "）皆可究。", "帆引滄海風，舟□（《青田志》作「沿」。", "）縉雲溜。", "羣瞐何隱磷，萬□（《青田志》作「物」。", "）更森秀。", "地氣冬轉暄（一作「暝」）瞑（一作暄。", "）氛陰改晝。", "緬懅謝康樂，□（《青田志》作「伊」，一作「夙」。", "）昔兹爲壽（《青田志》作「守」。", "）逸興滿雲林，清詞（一作「詩」。", "）冠宇宙。", "嘗遊石門裏，□□（《青田志》作「勝踐」。", "）宛如舊。", "峭壁苔蘚濃，懸崖（一作「巖」。", "）風雨驟。", "巖隈□（《青田志》作「餘」。", "）灌莽，□□（《青田志》作「壁畔」。", "）空泉甃。", "物是人已非，瑶潭淒□□（《青田志》作「懷獨漱」。", "）（〖1〗案石刻詩前原署「諸暨縣令郭密之」七字。", "〖2〗附《□使永嘉經謝公石門山作》一首〖《全唐詩》題作《永嘉經謝公石門山作》〗：「絕境〖《全唐詩》作「綿境」〗經耳目，未曾〖《全唐詩》、《青田志》並作「嘗」〗曠躋登。", "一窺石門險，載〖《全唐詩》作再〗滌心神懵。", "洞壑閟金澗，𢽽崖{股/皿}〖《全唐詩》、《青田志》並作「盤」〗石楞。"]'),
('aea3e0e4-2daa-4b09-8766-96509bdb9e27','琵琶泓石壁詩刻（按《山西通志》《山右金石記》卷九著錄《》，謂「詩七古一首，見《鳯臺縣志》。」檢《全唐詩》無考卷有權澈五言《題沈黎城》一首。此七古《琵琶泓詩》，蓋未收。）','權澈','唐','唐诗','tang','','[]','咨予白髪年，始佐丹水曲。',544,'全唐诗/poet.tang.50000.json','["咨予白髪年，始佐丹水曲。", "夙願解塵組，幸兹洗煩欲。", "琵琶翠泓湛且清，屏風畫壁勢相迎。", "檉柏颼飀雜風雨，龜龍睗睒游虛明。", "北行七里有靈跡，潭中聖字看歷歷。", "一符君德應明時，一契吾真誓幽適。", "由來此泓□□傳，今夕覩之信可憐。", "夷猶頓使宦積薄，日暮濯纓心浩然。", "（見乾隆四十八年官刊本《鳯臺縣志》卷十七）（此詩又見胡聘之《山右石刻叢編》卷七，詩題作《琵琶泓作幷序》。", "詩前有序，錄如次：「予頃嘗秉憲，負譴而遷，才散數奇，屢移邦國。", "爰初至止，即聞有兹勝，迨今一游，果覯殊絕。", "澄灣納溜，激射成雷，峭壁迴景，周流如畫，嘉木潛鱗，又不可名也。", "北去七里復有石潭焉，潭中有聖字，了了可覩，峰巒相屬，宛似屏障。", "閒行其中，潛洞幽窟，信爲靈異。", "予超然有獨往之意，而賦是詩。", "」詩中有二處稍異。", "第六句「相迎」作「相適」，疑誤。", "第十五句琵琶泓石壁詩刻「宦積」作「宣清」，疑原應作「宦情」。", "）（〖1〗《鳯臺縣志》〖姚學甲等纂修〗卷十九《輯錄部》謂：「唐清九壁詩序石刻在琵琶泓，朝議大夫高平郡別駕權澈詞，錢塘縣尉瑯琊王紓書，天寶五載夏五月二十日。", "從末行逆讀自序，其秉憲被譴，來佐丹曲，訪兹勝遊，詩字俱佳。", "考天寶五載、元宗丙戌。", "權澈名，新舊《唐書》俱不載。", "權氏，《宰相世系表》及姓族諸書並無其人，或非天水一族也。", "郡人王紓，想以瑯琊地望而係之。"]'),
('2303e027-2b90-49cf-93db-7b28999081d6','送張舍人往江東（此詩見韋莊《又玄集》卷上。案《全唐詩》卷一七五作李白詩，題曰《關張舍人之江東》，詩同，不重錄。惟第二句「正在秋風時」，《全唐詩》「在」字作「值」，三句「天晴一雁遠」，「晴」字作「清」爲異耳。〖《文苑英華》卷二六九、《唐文粹》卷十五、影宋本《李太白文集》卷十四皆收此詩爲李白作。〗）','孟浩然','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.50000.json','["空。"]'),
('2eb5f180-8d6c-40cc-a05c-2c45a2dabe24','','韋應物','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.50000.json','["。"]'),
('7f5aec4c-3ce4-4ee9-973b-47e709361fa2','易言','韋應物','唐','唐诗','tang','','[]','長風如刀剪枯葉，大河似箭浮輕舟。',84,'全唐诗/poet.tang.50000.json','["長風如刀剪枯葉，大河似箭浮輕舟。", "投石入水豈有礙，走丸下坂安得留。", "（見影印本《新編纂圖增羣書類要事林廣記》卷七。", "按《全唐詩》卷一九五收韋應物《易言》一首，與此詩全異。", "）。"]'),
('8bc510c5-85d8-4c7f-b20f-69f3bedc1553','句','盧嵩','唐','唐诗','tang','','[]','歲晏以爲期。',69,'全唐诗/poet.tang.50000.json','["歲晏以爲期。", "（《韋江州集》卷五有韋應物作《酬盧嵩秋夜見寄五韻》，詩末原註曰：「盧詩云歲晏以爲期之句。", "」按盧詩不傳，此雖隻句，亦彌足珍。", "）。"]'),
('c4798ce9-c3a2-400f-8c32-7128450b0409','','李揆','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.50000.json','["。"]'),
('db2932d1-8a3f-4693-b68a-99f4dae77969','句','李揆','唐','唐诗','tang','','[]','免相踐蓬閣，臥痾淮海濱。',60,'全唐诗/poet.tang.50000.json','["免相踐蓬閣，臥痾淮海濱。", "偶逢潘川守，宛是洛陽親。", "（「洛陽」，《四部叢刊》影明本、中華上編本《唐詩紀事》皆作「潘陽」。", "）。"]'),
('202c1e80-b368-4fd4-8a57-2069ed80d603','又句','李揆','唐','唐诗','tang','','[]','共仰新侯伯，同瞻舊宰臣。',12,'全唐诗/poet.tang.50000.json','["共仰新侯伯，同瞻舊宰臣。"]'),
('848fd6f2-a99c-4a74-85d2-7b55ef5de88b','又句','李揆','唐','唐诗','tang','','[]','鄉路轅思北，家林巷喜雨。',92,'全唐诗/poet.tang.50000.json','["鄉路轅思北，家林巷喜雨。", "以上各句見《四部叢刊》本《唐詩紀事》卷二十八，注云：「出《江鄰幾雜志》。", "」（《唐詩紀事》卷二十八《李揆》條云：「揆與饒州刺史封漸仲容叔霽連句，揆筆力遒媚。", "」）。"]'),
('05ecf53b-2c7f-46ec-8238-4d9a4a0a1590','夜聽擣衣詩','楊泰師','唐','唐诗','tang','','[]','霜天月照夜河明，客子思歸別有情。',234,'全唐诗/poet.tang.50000.json','["霜天月照夜河明，客子思歸別有情。", "厭坐長宵愁欲死，忽聞鄰女擣衣聲。", "聲來繼續因風至，夜久星低無暫止。", "自從別國不相聞，今在他鄉聽相似。", "不知綵杵重將輕，不悉青砧（一作「碪」）平不平。", "遙憐體弱多香汗，預識更深勞玉腕。", "爲當欲救客衣單，爲復先愁閨閣寒。", "雖忘容儀難可問，不知遙意怨無端。", "寄異土兮無新識，想同心兮長歎傦。", "此時獨自閨中聞，此夜誰知明眸縮。", "憶憶兮心已懸，重聞（一作「閉」）兮不可穿。", "既將因夢尋聲去，只爲愁多不得眠。", "（詩見金毓黻撰集《渤海國志長編》卷十八引《經國集》十三。", "）。"]'),
('ee5ff5a2-f7ca-4863-b345-0ebd351cdf05','奉和紀朝臣公咏雪詩','楊泰師','唐','唐诗','tang','','[]','昨夜龍雲（一作「樓」）上，今朝鶴雪新。',179,'全唐诗/poet.tang.50000.json','["昨夜龍雲（一作「樓」）上，今朝鶴雪新。", "祇（一作「怪」）看花發樹，不聽鳥驚春。", "迴影疑神女，高歌似郢人。", "幽蘭難可繼，更欲效而嚬。", "（同前引《經國集》十三。", "）（按《續日本紀》云：「寶字三年正月，大保藤原惠美朝臣押勝安蕃客於田村第，當代文士賦詩送別，副使揚泰師作詩和之。", "」寶字，系日本淳仁天皇年號，即天平寶字。", "天平寶字三年，當唐肅宗乾元二年，渤海文王大興二十二年。", "）。"]'),
('ccc853c5-2178-4126-a284-c0883f133870','詩一首','獨孤及','唐','唐诗','tang','','[]','簿領日盈機，知君傲煩囂。',167,'全唐诗/poet.tang.50000.json','["簿領日盈機，知君傲煩囂。", "飲和自忘渴，况以初筵招。", "道契跡自親，誰爲列宿遙。", "（誰爲，《文苑英華》卷七一○引此序作「誰謂」。", "）何用結同心，綠琴復長瓢。", "日月若走馬，炎涼催斗杓。", "一年解頤笑，（解頤笑，《文苑英華》作「解大笑」。", "）幾日如今宵。", "奉君千金壽，莫使歲寒凋。", "（案此詩載《全唐文》卷三百八十七獨孤及《冬夜裴員外薛侍御置酒安集序》一文中。", "）。"]'),
('9434ed5e-6e69-4b43-9fe2-175c17d21ad0','又一首','獨孤及','唐','唐诗','tang','','[]','上天垂光兮熙予以青春，今日何日兮共此良辰。',147,'全唐诗/poet.tang.50000.json','["上天垂光兮熙予以青春，今日何日兮共此良辰。", "與君觥濁酒而藉落英兮，（「觥濁酒」，《唐文粹》卷九六引此序作「觵濁醪」。", "）如年華之相親。", "（「如年華之相親」，《唐文粹》作「不知年華之相親」。", "）蹇淹留以醉止。", "孰云含意而未申。", "（案此詩載《全唐文》卷三百八十七獨孤及《仲春裴胄先宅宴集聯句賦詩序》一文中。", "）。"]'),
('4c2abfaf-9963-4284-8ff7-885e2ec5c478','石門歌','馬珦','唐','唐诗','tang','','[]','左一石，右一石，石門中有□□客。',391,'全唐诗/poet.tang.50000.json','["左一石，右一石，石門中有□□客。", "□岫□，懸崖裂，□江□□□劍闕。", "□□□□□□□，石門窊尊□□□。", "外□□□□，□□□□□。", "（見《武昌志》及《湖北金石志》。", "已殘缺不可讀，惜哉。", "）（〖1〗《武昌志》〖《湖北金石志》同〗：「案馬紹基云：是刻濱臨大江，字跡漫漶，前後片存二十八字，幸題與姓名尚完好。", "今又齧去數字矣。", "」〖2〗《明一統志》：「石門山在武昌縣東五里，兩門對峙如門。", "唐武昌令馬珦與元結遊，石刻尚存。", "」〖3〗《輿地碑目》：唐令君馬珦石門石刻在石門。", "郭詳正詩：『雙崖屹然起，劖蘚認題識。", "』〖4〗陳詩《湖北金石存佚考》云：「無年號，在武昌縣北，濱江。", "」〖5〗案清巖觀有《馬珦石門題名詩》曰：「石門開左右，一劍自中分。", "何人施妙法，千載創奇聞。", "良吏多幽思，詩題亦出羣。", "登山尋古蹟，迭石意何殷。", "江上發清嘯，厓前結翠雲。", "至今樊口上，誰不愛清蒼。", "我亦來訪古，心事何紛紛。", "憶到窊尊石，題名定有君。", "」）。"]'),
('adfe0e27-9134-4d3a-b27b-f6b0c845bb88','送薛縣丞還家','常袞','唐','唐诗','tang','','[]','之子一爲別，秋霜萬里心。',48,'全唐诗/poet.tang.50000.json','["之子一爲別，秋霜萬里心。", "野花山路冷，明月柳邊陰。", "聚首情猶淺，垂鞭意更深。", "望君自珍重，幽賞託瑶琴。"]'),
('1f558ee5-d081-4656-82b3-6124886cbbdc','赴京旅次感懷','常袞','唐','唐诗','tang','','[]','萬里雲煙繞畫樓，客居無事轉深愁。',89,'全唐诗/poet.tang.50000.json','["萬里雲煙繞畫樓，客居無事轉深愁。", "秋風翠閣看初動，玉露金莖望欲流。", "廿載承恩誰報主，一生僚屬且封侯。", "明朝努力長安道，不爲晴川戀舊遊。", "（以上二詩見沁泉山館郭柏蒼校刊本《唐制詔集》。", "）。"]'),
('84b0f75f-b06e-4a24-8353-e14687d6b6da','','徐源','唐','唐诗','tang','','[]','徐源字太初，高平人。',26,'全唐诗/poet.tang.50000.json','["徐源字太初，高平人。", "詩一首。", "（《全唐詩》無徐源詩）。"]'),
('a7992a5c-e098-4e29-a5e3-fc469f3a5127','題靈泉寺','徐源','唐','唐诗','tang','','[]','竹園無外事，祕殿夕陰生。',109,'全唐诗/poet.tang.50000.json','["竹園無外事，祕殿夕陰生。", "雲起靈峯隱，風來寶鐸鳴。", "焚香流玉戶，聽鳥度金楹。", "静心歸正法，方此謝塵纓。", "（見武虛谷《安陽縣金石錄》。", "）（詩下原題「高平徐源字太初」七字。", "又紀「皇唐八葉大曆六年歲次辛亥夏四月旬有五日」十九字。", "）。"]'),
('d1b2cfa1-ea5b-438f-88dd-24e62ed9e32e','題靈泉寺','徐淮','唐','唐诗','tang','','["\u9ec4\u6cb3"]','梵宇栖真所，寥寥世事稀。',139,'全唐诗/poet.tang.50000.json','["梵宇栖真所，寥寥世事稀。", "老僧[披]（被）百納，童子學三歸。", "寶剎臨香地，星宮隱翠微。", "誰憐漂泊者，於此遂忘機。", "（亦見《安陽縣金石錄》。", "）（按此詩與徐源詩刻一石，詩下原題「東海徐淮字黃河」七字。", "〖1〗徐淮，原作「徐涵」，從《文物》一九八六年第三期靈泉寺石刻拓片改。", "四詩亦據改數字。", "）。"]'),
('bc267111-b4c6-43cf-8ce0-bedd090054cf','題靈泉寺','程序','唐','唐诗','tang','','[]','煙景[晝]（盡）冥冥，樓臺隱翠屏。',106,'全唐诗/poet.tang.50000.json','["煙景[晝]（盡）冥冥，樓臺隱翠屏。", "猨攀太子樹，鳥聽《法王經》。", "悟理心無著，求緣塔有靈。", "迴車猶未遠，日暮數峯青。", "（亦見《安陽縣金石錄》。", "）（按此詩與徐源、徐淮詩刻一石，詩下原題「廣平程序字[土]〖古〗倫」七字。", "）。"]'),
('a8a53713-7c3e-4042-b2af-01c36ae6f040','題靈泉寺','徐泳','唐','唐诗','tang','','[]','物外經行處，雲峯斷復連。',241,'全唐诗/poet.tang.50000.json','["物外經行處，雲峯斷復連。", "散花飛講席，輕翠澹鑪煙。", "稽首求真偈，觀空[息]（悉）衆緣。", "有時聞法皷，應是會諸天。", "（見《安陽縣金石錄》。", "）（〖1〗按此詩與徐源、徐淮、程序詩刻於一石，詩下原題「高平徐泳字太和」七字。", "又以上四詩皆正書，「皇唐八{葉世=云}大歷六年歲次辛亥夏四月旬有五日」立在善應山。", "〖2〗武虛谷《安陽縣金石錄》卷四：案詩共刻一石音律最詳雅，《全唐詩》未及採錄，宜以此補之。", "前題『皇唐八{葉世=云}』自高祖至代宗數之，刪殤帝不書也。", "葉避太宗諱，作{葉世=云}，易中世字爲云。", "）。"]'),
('656791f5-77dc-4373-9820-560810e60b8c','翻經臺','包佶','唐','唐诗','tang','','["\u5e90\u5c71"]','野蔓高臺下，前朝記不誣。',167,'全唐诗/poet.tang.50000.json','["野蔓高臺下，前朝記不誣。", "金文翻古偈，漢字變胡書。", "綵缐風飄斷，緗縑火燼餘。", "破雲開白日，穿水照芙蕖。", "科斗頻更改，菴園幾遍鋤。", "真門兼逸韻，兩欲慕相如。", "（見《永樂大典》卷二六○三「七皆」「臺」邁「翻經臺」條〖三函三十冊〗。", "復見同書卷六六九九「十八陽」「江」字〖七函六十四冊〗。", "）（見《吉石庵叢書》影印日本存古抄本北宋陳舜俞《廬山記》卷四。", "）。"]'),
('239006e5-0f8f-4e06-94fc-3454403affff','金山','皇甫冉','唐','唐诗','tang','','[]','中江一柱碧崚嶒，壁立千尋我獨登。',104,'全唐诗/poet.tang.50000.json','["中江一柱碧崚嶒，壁立千尋我獨登。", "梵唄波隨招過客，鐘聲船載送歸僧。", "窗前白上浪三尺，嶺上青堆雲幾層。", "六代風流衰歇盡，慿欄感喟意難勝。", "（見丹徒陶紹萊輯《潤州唐人集》卷七，云：「見凈談《金山志》及繆潛《新志》。", "」）。"]'),
('6ed1abf1-bde8-49be-aa66-0c36c8583c93','送韓司直','皇甫冉','唐','唐诗','tang','','[]','（見宋趙師秀《衆妙集》，並見宋周弼《唐三體詩》卷六。',258,'全唐诗/poet.tang.50000.json','["（見宋趙師秀《衆妙集》，並見宋周弼《唐三體詩》卷六。", "按《全唐詩》卷一百八十四作劉長卿詩，詩同，校其異文如下：首句「遊吳還適越」，「適」，《全唐詩》作「入」。", "五句「山明殘雪在」，「山」，《全唐詩》作「岸」。", "七句「季子留遺廟」，《全唐詩》作「季子楊柳廟」。", "又《唐三體詩》本元釋圓至於此句下注曰：「皇覽《冢墓記》：季子冢在毘陵縣暨陽鄉，至今吏唐民祀事。", "」〖唐姚合《極玄集》、宋計有功《唐詩紀事》卷二七均作皇甫冉詩，《文苑英華》卷二七二作皇甫曾詩，《四部叢刊》影明正德本《劉隨州文集》卷三則作劉詩。", "似亦皇甫冉所作爲是。", "〗）。"]'),
('d7ed2189-f1d1-4dd5-98f8-1104b7e8c4ef','送人詩（見《學海類編》唐賈島撰《二南密旨》，題曰皇甫曾《送人詩》，亦見宋周弼《唐三體詩》卷六，題曰《途中送權曙》，皇甫曾作。按唐姚合《極玄集》卷下選此詩，作皇甫冉詩，題曰《途中送權二兄》。《全唐詩》卷二百四十九作皇甫冉詩，題曰《途中送權三兄弟》。又卷二百九十六作張南史詩，題曰《西陵懷靈一上人兼寄朱放》，詩同。校其異文如次：「淮海風濤起，江關幽」〖《極玄集》及《全唐詩》皇甫冉卷張南史卷並作「憂」。〗思長同。悲鵲遶樹，獨作〖《全唐詩》張南史卷作「坐」〗雁隨陽。山晚雲和〖《全唐詩》皇甫冉卷作「初」，張','皇甫曾','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.50000.json','["空。"]'),
('5627f48a-ef9a-4e6e-9148-1aecc0be921d','暇日題草堂','錢起','唐','唐诗','tang','','[]','爲郎過壯歲，晚景對秋天。',65,'全唐诗/poet.tang.50000.json','["爲郎過壯歲，晚景對秋天。", "門掩蒼苔上，池清寒竹前。", "通經未拾紫，煉藥不成仙。", "且醖東臯黍，愁來得醉眠。", "（見宋趙師秀編选《唐衆妙集》。", "）。"]'),
('a1869336-c181-482e-922b-093660e76dcc','雲門山投龍詩刻（並序）','赵居貞','唐','唐诗','tang','','[]','（按《全唐詩》卷二百五十八收此詩，《山左金石志》石刻亦載之，惟異文較多，且序中有二十餘字，詩中有四句爲《全唐詩》所無，故重爲錄出，而以《全唐詩》校之。',77,'全唐诗/poet.tang.50000.json','["（按《全唐詩》卷二百五十八收此詩，《山左金石志》石刻亦載之，惟異文較多，且序中有二十餘字，詩中有四句爲《全唐詩》所無，故重爲錄出，而以《全唐詩》校之。", "）。"]'),
('de1e74bb-31ab-454b-9142-cf5300d7ab02','雲門山投龍詩刻（並序）','赵居貞','唐','唐诗','tang','','[]','□□（《全唐詩》作「曉登」）雲門山，直上壹千尺。',344,'全唐诗/poet.tang.50000.json','["□□（《全唐詩》作「曉登」）雲門山，直上壹千尺。", "絕頂彌□（《全唐詩》作「孤」。", "）聳，盤途幾傾窄。", "前對堅裂峯，□□（《全唐詩》作「下臨」。", "）削成壁。", "陽□（《全唐詩》作「巘」。", "）靈芝秀，陰崖仙乳□。", "（此句《全唐詩》作「陰崖半天赤」。", "）□□□羣山，遠望何所隔。", "太陽未出海，曠晃半天赤。", "（《全唐詩》無以上四句。", "）大壑静不波，渺溟無際碧。", "（「碧」，《全唐詩》作「極」。", "）是時雪初霽，沍寒冰（《全唐詩》作「水」。", "）更積。", "恭（《全唐詩》誤作「披」）展送龍儀，寧安服狐白。", "□□（《全唐詩》作「沛恩」）惟聖主，祈福在方伯。", "三元章醮昇，五域□□（二字《全唐詩》亦闕。", "）覿。", "帟幕翠微亘，機□（《全唐詩》作「茵」。", "）丹洞闢。", "□□（《全唐詩》作「祝起」。", "）鳴天鼓，拜傳端素冊。", "霞間□□□，（《全唐詩》作「朱紱縈」。"]'),
('d38db47d-dba8-4231-b8be-1bad7bc053b7','秋齋（題擬）','韓翃','唐','唐诗','tang','','[]','山月皎如晝，霜風時動竹。',64,'全唐诗/poet.tang.50000.json','["山月皎如晝，霜風時動竹。", "夜半鳥驚栖，窗間人獨宿。", "（見《永樂大典》卷二五三九「七皆」「秋齋」條〖三函三十冊〗《全唐詩所未收》。", "）。"]'),
('f6d3a1b8-6c21-4b79-9a91-f3c4c5ea67ac','河上寄故人','韓翃','唐','唐诗','tang','','[]','河流杳靄曉天，濮水黯澹秋烟。',125,'全唐诗/poet.tang.50000.json','["河流杳靄曉天，濮水黯澹秋烟。", "日暖昆吾臺上，春深顓頊城邊。", "鶯聲亂鳴鴻塞，花片細點龍泉。", "西望情人早至，尤應得醉芳年。", "（按《全唐詩》卷二百四十五有此詩。", "惟前半殘缺不可句讀。", "此見《永樂大典》卷三○○五「九真」「人」字〖五函四十二冊〗。", "完整可讀，故錄存之。", "）。"]'),
('574afca2-f99f-4599-ba03-2c7456f3deeb','訪邱員外丹（題擬）','顧况','唐','唐诗','tang','','[]','五月五日日亭午，獨自騎驢入山隝。',328,'全唐诗/poet.tang.50000.json','["五月五日日亭午，獨自騎驢入山隝。", "來到君家不見君，下驢倚杖叩君戶。", "驚起山童開山扉，黃犬摇尾銜人衣。", "試問先生住何處，云入山中采紫薇，平明一去今未歸。", "引我池中看釣磯，池中數箇白鷗兒，見人慣後癡不飛。", "待君歸來君未歸，卻復騎驢下翠微。", "（見仁和張大昌輯《臨平記補遺》卷四。", "）（《全唐詩續補遺》卷六據《咸淳臨安志》卷九五《紀遺》收此詩，題作《謁丘真人不遇》，今刪彼存此，錄其異文如次：「亭午」作「卓午」，「入山」作「上山」，「歸來」作「君歸」。", "）（〖1〗《臨平記補遺》：「曲園先生曰：『沈〖沈謙〗記於唐人贈邱丹詩悉錄之，而失錄此詩。", "按此詩見宋陳郁《藏一話腴》，云「邱本唐人，棄官學道於此，顧況訪之」云云。", "有詩無題。", "姑據《話腴》題爲《訪邱員外丹》，未知原題云何也。", "』」）。"]'),
('fa5ecf11-5380-49d1-a2a9-0fc1d038ef7e','句（朝天行）','張建封','唐','唐诗','tang','','[]','賴有雙旌在手中，鏌鎁昨夜新磨了。',168,'全唐诗/poet.tang.50000.json','["賴有雙旌在手中，鏌鎁昨夜新磨了。", "（見李肇《國史補》卷上。", "）（〖1〗李肇《國史補·徐州朝天行》：「張建封自徐州入覲，爲《朝天行》。", "末句云：『賴有雙旌在筘，鏌鎁昨夜新磨了。", "』德宗不說。", "」〖2〗《新唐書》卷一百五十八《張報封傳》：「十三年來朝，帝不待日召見延英殿，方會朝赴大夫班，以示殊寵，建封賦《朝天行》以獻。", "帝眷遇異等，賜名馬珍具。", "」）。"]'),
('c8c90034-c629-4fed-ad9d-d9100fc1e130','廳事之西因依墉壑爲山數仞有懸水焉予理戎之暇聊以息讌此相國張公之所作也緬懷高致時濯塵纓即事寄言而賦斯什','裴度','唐','唐诗','tang','','[]','奇峰似天作，半倚增城隅。',141,'全唐诗/poet.tang.50000.json','["奇峰似天作，半倚增城隅。", "何處通泉脉，潺湲竟朝晡。", "挂石懸一帶，灑荷散千珠。", "固宜賞高人，何爲對武夫？", "鼓鼙時鏗{言訇}，吏卒亦喧呼。", "愧爾來我所，顧我非爾徒。", "乃是風流相，昔嘗居此都。", "能移造化力，雅與山水俱。", "多慙受成者，得此聊自娛。", "（見《分門纂類唐歌詩》殘本第三冊《天地山川類》卷三十二。", "）。"]'),
('0d46c47a-b5eb-4ebf-9856-3de1e69552ee','月詩','盧仝','唐','唐诗','tang','','[]','金波絢彩麗初筵，玉冕（友人蔣禮鴻同志謂當作「玉菟」。',104,'全唐诗/poet.tang.50000.json','["金波絢彩麗初筵，玉冕（友人蔣禮鴻同志謂當作「玉菟」。", "菟，同兔。", "）流輝滿大圓。", "鏡裏山川同炯炯，樓前風露共娟娟。", "（清康熙間仁和孫之騄《玉川子詩註》收此詩，云見《萬花谷後集》。", "）（見《錦繡萬花谷後集》卷一《月》）。"]'),
('be609e91-15fb-4ef7-ac6b-f6874e876d15','紀湯泉','賈島','唐','唐诗','tang','','["\u9ec4\u5c71"]','維泉肇何代，開鑿同二儀。',222,'全唐诗/poet.tang.50000.json','["維泉肇何代，開鑿同二儀。", "五行分水火，厥用誰一之。", "在卦得既濟，備象坎與離。", "下有風輪煽，上有雷車馳。", "霞掀祝融井，日爛扶桑池。", "氣殊礐石厲，脉有靈砂滋。", "驪山豈不好，玉環污流脂。", "至今華清樹，空遺後人悲。", "遐哉哲人逝，此水真吾師。", "一濯三沐髪，六鑿還希夷。", "伐毛返骨髓，髪白令人黟。", "十年走塵土，負我汗漫期。", "再來池上遊，觸熱三伏時。", "古寺僧寂寞，但餘壁上詩。", "不見題詩人，令我長嘆咨。", "（見康熙十八年閔麟嗣撰《黃山志定本》卷六，乾隆間刊印。", "此詩承儀徵吳白匋先生見告。", "）。"]'),
('aed8507c-b048-4459-8bbf-e0e1c8923d71','歙郡有黃山樓北瞰黃山山勢中拆若巨門狀因題一絕','于德晦','唐','唐诗','tang','','["\u9ec4\u5c71"]','黟峰翠色自天流，直下青冥豁素秋。',227,'全唐诗/poet.tang.50000.json','["黟峰翠色自天流，直下青冥豁素秋。", "閒倚朱欄頻北望，只宜名作巨門樓。", "（〖1〗詩見康熙十八年閔麟嗣撰《黃山志定本》卷六，乾隆間刊刻。", "此詩承儀徵吳白匋先生見告。", "按原志附注曰：「程弘志云：按《一統志》：刺史有從兄棄官學道，號於方外，刺史爲築室於問政山，山始名問政。", "」望按：《金石萃編》卷八十有于德晦題名，在李虞仲題名之左，曰「監察御史于德晦」，題名後紀「大中六年三月廿四日」云云。", "又《長安志》務本坊有左散騎常侍于德晦宅。", "〖大興徐松撰《唐兩京城坊考》卷二所記同〗）。"]'),
('0cb85a63-9307-437b-aa1d-7b1b00c7769a','寒食下第簡長安故人','武元衡','唐','唐诗','tang','','[]','寒食都人重勝遊，相如獨自閉門愁。',237,'全唐诗/poet.tang.50000.json','["寒食都人重勝遊，相如獨自閉門愁。", "嘗聞婁護因名達，君試將余問五侯。", "（見《永樂大典》卷三○○五「九真」「人」字（五函四十二冊）。", "按詩共二首，其一五言四句，《全唐詩》卷三百十七載之，其二即此詩。", "）（《古今歲時雜詠》卷十一收此詩，前爲五言四句，後爲七言四句，與《大典》同。", "疑原詩應爲雜言體一首。", "《全唐詩》卷三一七錄作五絕，似沿《萬首唐人絕句》卷十四，題作《寒食下第》，錄如次：「柳挂九衢絲，花飄萬家雪。", "如何憔悴人，對此芳菲節。", "」《古今歲時雜詠》「萬家」作「萬里」，「人」作「客」。）"]'),
('9c6ab476-63d8-4647-a94d-59ee3ff8d4ef','臨平湖夜泛','權德輿','唐','唐诗','tang','','[]','素彩皓通津，孤舟入清曠。',150,'全唐诗/poet.tang.50000.json','["素彩皓通津，孤舟入清曠。", "已愛隔簾看，還宜捲簾望。", "隔簾當此時，（《四部叢刊》本《權載之文集》卷六收此詩，此句作「隔簾卷簾時此時」，與《臨平記》同。", "）惆悵思君君不知。", "（此見《永樂大典》卷二二七一「六模」「湖」字《臨平湖》條〖二函二十冊〗。", "此詩亦見沈謙《臨平記》卷四，惟第五句作「隔簾捲簾當此時」爲異。", "）。"]'),
('22c97c99-6a7a-407e-aa92-d15e7cf9098d','題雲居上寺（並序）','吉逾','唐','唐诗','tang','','[]','到此花宮裏，觀身火宅中。',487,'全唐诗/poet.tang.50000.json','["到此花宮裏，觀身火宅中。", "有爲皆是幻，何事不成空？", "晚籟鳴寒谷，秋山響暮鐘。", "欲歸林下路，新月上前峯。", "（見《金石萃編》卷一百五。", "）（〖1〗《金石萃編》王昶按：「雲居上寺，未詳處所。", "據詩前稱范陽縣丞吉逾同躋攀于此云云，則寺當在范陽矣。", "唐時范陽縣屬涿州，今撿《日下舊聞》引《名勝志》云：『涿州有智度寺，石城東北隅，剙自唐時，有舊碑刻。", "其後即雲居寺，俱有石基浮圖。", "』疑即此雲居上寺也。", "謂之上寺者，以在智度寺之後也。", "唐時舊碑刻，或即指此碑。", "吉逾諸人之詩，《全唐詩》無一載者，因錄之，以見唐人詩千餘年來淪於草莽、爲人所未見者，蓋不勝紀云。", "」〖2〗望按：詩題次行原有「范陽縣丞吉逾」六字，詩序辛酉歲云云。", "當是唐德宗建中二年。", "石刻於此詩後出「元和四年四月八是范□□」一行，疑此爲刻石年月，而「范□□」疑本是「范某刻」字樣，當是刻工題名。", "果爾，則自辛酉賦詩以迄元和四年己丑刻石，其間已歷二十九年矣。", "〖吉逾等人詩作於建中二年。", "元和題名，陸增祥《八瓊室金石補正》卷六五錄作「元和四年八月八日范惟清呂〖以下缺〗」幷云此題名雖書於軒轅偉詩首「同前」二字之下，應別標一題，「《萃編》合爲一刻，誤矣」。", "〗）。"]'),
('7898a92e-8c90-4966-afda-063bcc48b18c','題雲居上寺','吉騊駼','唐','唐诗','tang','','[]','石室最高峯，躋攀到此中。',94,'全唐诗/poet.tang.50000.json','["石室最高峯，躋攀到此中。", "白雲連晚翠，清磬度秋風。", "未悟無生理，寧知有想空。", "且歸山下寺，更欲問支公。", "（見《金石萃編》卷一百五。", "）（按詩次軒轅偉詩後，原題曰「同前」，下署「騊駼上」，無官銜。", "）。"]'),
('515b111d-8d03-41cf-b5c9-080f822909fe','題雲居上寺','吉播','唐','唐诗','tang','','[]','石路多奇迹，幽巖鑿寶經。',203,'全唐诗/poet.tang.50000.json','["石路多奇迹，幽巖鑿寶經。", "暮煙千壑裏，新月一山明。", "宿鳥知清梵，樵人慣獨行。", "爲隨歡奉後，豈敢學逃[名]。", "（見《金石萃編》卷一百五。", "）（缺文據吉逾條下所引諸書補。", "）（按詩次吉騊駼詩後，原題曰「同前」，下署「□上」，蓋名已摩滅。", "據吉逾詩序，知爲其猶子吉播所賦。", "詩中「暮煙」，石刻原作「暮煙」，王昶謂是筆誤，今據正。", "〖1〗吉播，原作吉潛，詳前吉逾條附考。", "前引諸書及《八瓊室金石補正》卷六五此詩末署名皆作「播上」。", "）。"]'),
('4e12a790-abd6-46d0-ba84-636f4931ccc2','題雲居上寺','王益','唐','唐诗','tang','','[]','[支]公禪誦處，絕頂共登攀。',190,'全唐诗/poet.tang.50000.json','["[支]公禪誦處，絕頂共登攀。", "日色千峯裏，鐘聲萬壑間。", "[暮]猿吟砌近，沙鳥傍溪閑。", "一逕[堪]藜杖，行行獨下山。", "（見《金石萃編》卷一百五。", "）（缺文據《續古文苑》卷四補。", "《房山石經題記匯編》首字不缺。", "）（〖1〗石刻詩次王潛詩後。", "原題曰「同前」。", "下署「男益上」。", "與吉逾詩序所稱「息益」合。", "〖2〗王益，原作吉益。", "爲王潛之子，詳前吉逾條附考。", "諸書錄石刻。", "此詩收於王潛詩之次，署「男益上」。", "）。"]'),
('1ad24b75-635d-4538-8a15-1b3e5a2ed0ff','','軒轅偉','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.50000.json','["。"]'),
('558f3404-d2ed-497f-84e0-b4919631a102','題雲居上寺','軒轅偉','唐','唐诗','tang','','[]','不著登山屐，捫蘿也上躋。',115,'全唐诗/poet.tang.50000.json','["不著登山屐，捫蘿也上躋。", "石梁分鳥道，苔逕過雲霓。", "梵宇千花裏，秋聲萬籟齊。", "[周]遊興未盡，鐘磬度前溪。", "（見《金石萃編》卷一百五。）", "（缺字據吉逾條下所引諸書補。", "下同。", "）（〖1〗石刻詩次吉逾詩後，原題曰「同作」，下署軒轅偉，無官銜。", "）。"]'),
('47609e76-25d9-46ee-acb2-45397ecb4dfc','題雲居上寺','王潛','唐','唐诗','tang','','[]','萬木千峯空鳥喧，潺潺[溪]水下長川。',131,'全唐诗/poet.tang.50000.json','["萬木千峯空鳥喧，潺潺[溪]水下長川。", "人來石室藏何處。", "一逕歸時帶暮煙。", "（見《金石萃編》卷一百五。", "）（〖1〗石刻詩次吉潛詩後。", "原題曰「同前」。", "下署「節度都巡使太常卿上柱國王潛」。", "第二句第三字原作「氵」，摩其右半，意者或爲「澗」字，或爲「流」字，雖然，未敢擅補也。", "）。"]'),
('d2ed84ca-107c-4d6f-a971-70e692d6e991','汝州北樓晚望少室詩','胡証','唐','唐诗','tang','','[]','峭拔烟雲外，雄居造化工。',194,'全唐诗/poet.tang.50000.json','["峭拔烟雲外，雄居造化工。", "三山慙海上，五嶽讓天中。", "翠積當華甸，騰標占太空。", "周臨萬里暮，猶掛夕陽紅。", "（見《槐廬叢書》《金石錄補》。", "）（〖1〗葉九來《金石錄補》卷十九《唐胡証題少室詩》跋尾：「右唐檢校祠部員外郎胡証《汝州北樓晚望少室詩》，詩云〖不重錄〗。", "永貞元年仲夏記。", "按新舊《書·證傳》皆云貞元中登第，繇渾瑊舉爲從事，自殿中侍御史爲韶州刺史而已。", "據此碑。", "先爲祠部員外郎，可以補史之闕漏。", "」）。"]'),
('538a7b02-b5b7-4c3a-a150-7bfcf2ee3e78','奉敕陪內宴','王孝廉','唐','唐诗','tang','','[]','海國來朝自遠方，百年一醉謁天裳。',62,'全唐诗/poet.tang.50000.json','["海國來朝自遠方，百年一醉謁天裳。", "日宮座外何攸見，五色雲飛萬歲光。", "（見金毓黻撰集《渤海國志長編》卷十八引《文華秀麗集》上。", "）。"]'),
('66c39208-e3a3-4254-9f3a-05305aa66764','春日對雨得情字','王孝廉','唐','唐诗','tang','','[]','主人開宴在邊聽，客醉如泥等上京。',38,'全唐诗/poet.tang.50000.json','["主人開宴在邊聽，客醉如泥等上京。", "疑是雨師知聖意，甘滋芳潤灑羈情。", "（同前。", "）。"]'),
('7ad0f00d-7671-490e-84db-7cc49dd14a9a','在邊亭賦得山花戲寄兩領客使並滋三','王孝廉','唐','唐诗','tang','','[]','芳樹春色（疑應作花）色甚明，初開似笑聽無聲。',44,'全唐诗/poet.tang.50000.json','["芳樹春色（疑應作花）色甚明，初開似笑聽無聲。", "主人每日專攀盡，殘片何時贈客情？", "（同前。", "）。"]'),
('c7faa2e2-6f32-47e4-bb18-717f07b7ccc8','和坂領客對月思鄉之作','王孝廉','唐','唐诗','tang','','[]','寂寂朱明夜，團團白月輪。',54,'全唐诗/poet.tang.50000.json','["寂寂朱明夜，團團白月輪。", "幾山明影徹，萬象水天新。", "棄妾看生悵，羈情對動神。", "誰云千里隔，能照兩鄉人。", "（同前。", "）。"]'),
('7d6020d8-ea72-4db2-bd58-e1dfda677b92','出雲州書情寄兩敕使','王孝廉','唐','唐诗','tang','','[]','南風海路連歸思，北雁長天引旅情。',541,'全唐诗/poet.tang.50000.json','["南風海路連歸思，北雁長天引旅情。", "賴有鏘鏘雙鳯伴，莫愁多日住邊亭。", "（同前。", "）（〖1〗按王孝廉奉渤海國王命使日，日本嵯峨天皇設宴禮之。", "孝廉返國，舟覆溺海而死。", "嵯峨天皇特頒敕書，追贈榮爵，且致悼念。", "嵯峨在位十四年，年號曰弘仁，於唐則爲憲宗元和五年至穆宗長慶三年也。", "敕文附後。", "〖2〗《日本後紀》二十四日本嵯峨天皇《贈渤海使王孝廉正三位敕書》云：「惜往飾終，事茂舊範，褒忠錄績，義存先彝。", "故渤海國使從三位王孝廉，闕庭修聘，滄溟迴艫，復命未申，昊蒼不憖。", "寔雖有命在天，薤露難駐，而銜恨使命，不得更歸。", "朕痛於懷，加贈榮爵，死而有靈，應業泉扃。", "宜可正三位。", "」〖3〗又日僧空海有《傷渤海國大使王孝廉中途物故》詩句，日人阪上今繼有《和渤海大使見寄之作》，可以參閱。", "詩附於次。", "）（〖4〗空海《傷渤海國大使王孝廉中途物故》：一面新交不忍聽，況乎鄉國〖一作「園」〗故園〖一作「國」〗情。", "〖見金毓黻撰《渤海國志長編》卷十八引《高野大師廣傳》下〗〖5〗阪上今繼《和渤海大使見寄之作》：賓亭寂寞對青溪，處處登旅念悽。", "萬里雲邊辭國遠，三春煙裏望卿〖蔣禮鴻及陳九思同志並謂當是「鄉」之形誤。", "〗迷。", "長天去雁催歸思，函谷來鶯助客啼。", "一面相逢如舊識，交情自與古人齊。", "〖見金毓黻撰《渤海國志長編》卷十八引《文華秀麗集》上〗）。"]'),
('4c0d3cd4-7ee8-408d-b70e-6fe4b33fe43e','九銷山','徐凝','唐','唐诗','tang','','[]','人行之字路嶔巇，九銷青山勝九疑。',144,'全唐诗/poet.tang.50000.json','["人行之字路嶔巇，九銷青山勝九疑。", "祇被但白雲生不斷，無端點破碧琉璃。", "（見道士孟宗寶集虛所編《洞霄詩集》卷一。", "）（〖1〗鄧牧《洞霄圖志》卷二《山水門》《九鎖山》條：「自餘杭西郭外，行十有八里，逆溪水上，左右合七峯，皆拔地數百尺。", "其趾犬牙相錯，行路並溪屈折者九，故云九鎖。", "好事者悉命以名。", "」）。"]'),
('ee1b1897-e793-43c7-9c7b-991a418af440','','周匡物','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.50000.json','["。"]'),
('30dd6122-273c-4b28-a6c5-9150496264d2','三橋隱居歌','周匡物','唐','唐诗','tang','','[]','誰家作橋溪水頭，茅堂四月如清秋。',121,'全唐诗/poet.tang.50000.json','["誰家作橋溪水頭，茅堂四月如清秋。", "白雲已過暮山紫，黃鳥不鳴春自幽。", "掀髯背向孤舟立，猶記仙源舊曾入。", "（近人翁國樑《漳州史蹟》亦引此詩「曾」作「會」。", "）雨打疎篷醉不知，桃花一夜新流急。", "（見《漳州府志》。", "末句《漳州史蹟》作「桃花一夜急新流」，誤。", "）。"]'),
('9724a6df-eafd-4fd8-8ef4-f2c348e690fb','湘中紀行','李諒','唐','唐诗','tang','','[]','[湘江]（江水）永州路，水碧山崒兀。',556,'全唐诗/poet.tang.50000.json','["[湘江]（江水）永州路，水碧山崒兀。", "古木暗[漁]（魚）潭，陰雲起龍窟。", "峻屏夾澄[徹]（澈），怪石生[溪渤]（□勒）。", "[巨]艦時邅迴，輕舠已超忽。", "疾如奔羽翼，清可[鑑]（鑒）毛髪。", "寂寞[幾]（榜）漁舟，逶迤逗[啇]（商）[筏]。", "[我]行十月杪，猿嘯中夜發。", "楓葉寒始丹，菊花冬未歇。", "凝流綠可[染]，積[翠]（學）浮堪擷。", "[峭]蒨每驚新，幽奇信誇絕。", "稠[峰]（峯）疊玉嶂，淺[浪]（泿）翻殘雪。", "石[燕]（鷰）雨中飛，[塞]（霜）鴻雲外別。（迴鴈峯）", "泝洄已勞苦，覽[玩]（翫）還愉悅。", "鶴嶺訪胎仙（[祁]陽縣白鶴[嶺]道士屈志静得仙處），𢈪（音吾）亭仰文[喆]（哲）（祁陽𢈪亭，元中丞次山所居。）。", "川間[有]漁釣，山上多薇蕨。", "無[以]（公）佐雍熙，何如養疵拙。", "安人苟有[積]（績），撫己行將[耋]。", "此路好[乘桴]，吾其謝羈紲。", "（見《金石萃編》卷一百八。", "第三句「暗魚」二字原缺，據《輿地紀勝》卷五十六補。", "）（《金石萃編》錄此詩缺誤甚多，而清瞿中溶《古泉山館金石文編殘稿》卷三補錄此詩無缺，今據以校補。", "瞿中溶跋云：李諒《湘中紀行》詩二十行，行三十字，正書左行。", "述葊侍郎《金石萃編》所載闕十五字，又『溪渤』之『渤』誤作『勒』，『積翠』之『翠』誤作『學』，蓋搨本未精之故。", "予遊浯溪，親督搨工椎打，所謂闕泐者一一皆可辨識，乃爲補之。"]'),
('88dfb94e-ecc2-4a28-b281-df6a8057a6c1','杪春再遊廬山（吳汝煜、胡可先云此詩爲涉兄李渤作，見《唐才子傳校箋》卷五。）','李涉','唐','唐诗','tang','','["\u5e90\u5c71"]','二十七年別，煙雲如昨辭。',255,'全唐诗/poet.tang.50000.json','["二十七年別，煙雲如昨辭。", "偶逢行春日，得遂歸山期。", "曉駕出湓城，晚會東林師。", "巡廊閱衆院，遍讀新舊詩。", "蕭魏故已塵，符楊亦川馳。", "拂牀歸塵壁，再覔舊遊詩。", "南訪靜（應作「靖」）節居，石臺有遺基。", "紅葩列澗艷，碧蔦懸林絲。", "迢遞二霄峯，晴雲間出危。", "壇空仙馭遠，谷斷啼猿悲。", "白鹿舊洞門，五老東一枝。", "當時手結茅，聚族長在玆。", "孫姪皆後來，非我昔所知。", "生爲前世翁，安得不涕垂？", "白髪唯兩人，形骸久支離。", "雖同故山會，草草如路歧。", "惆悵塵中身，何由重來斯。", "無令誚余者，更效《北山移》。", "（見《分門纂類唐歌詩》殘本第二冊《天地山川類》卷二十二。", "）。"]'),
('ae0cfb5e-9273-4bac-9afe-2cd2b02e740c','范處士在育王寺書碑因以寄贈','于季友','唐','唐诗','tang','','[]','墨妙復辭雄，扁舟訪遠公。',241,'全唐诗/poet.tang.50000.json','["墨妙復辭雄，扁舟訪遠公。", "□（趙紹祖《金石文鈔》卷七作「雲」）天書梵□（《金石文鈔》作「字」，）霜月步蓮宮。", "跡寄雙林下，名留刼石中。", "遙知松逕望，棠（《金石文鈔》作「栗」）葉滿山紅。", "（見《金石萃編》卷一百八。", "）（又見《兩浙金石志》卷一，第三句不缺，文同《金石文鈔》，末句作「棠葉滿山紅」。", "）（〖1〗石刻於題下原署「明州刺史于季友」。", "按阿育王寺在今浙江鄞縣阿育王山中，此詩及後范的酬和詩附鐫於《阿育王里常住田碑》後。", "碑末有太和七年十二月一日于季友作《碑後記》，則兩詩之作，當亦在同時。）。"]'),
('e6b22a8f-b3f2-4502-b425-e55bfae52c7b','時在育王寺書石字奉酬□丞使君寄贈四韻依次用本韻','范的','唐','唐诗','tang','','[]','（《金石文鈔》題作《時在育王寺書石中丞使君寄目前四韻奉酬本韻》）拙藝荷才雄，新詩起謝公。',377,'全唐诗/poet.tang.50000.json','["（《金石文鈔》題作《時在育王寺書石中丞使君寄目前四韻奉酬本韻》）拙藝荷才雄，新詩起謝公。", "開緘光佛域，望景動星宮。", "風雪文章裏，書鐫琬琰中。", "將誰比佳句？霞綺散成紅。", "（見《金石萃編》卷一百八。）", "（又見《兩浙金石志》卷一，題中「□丞」作「中丞」，「次用本韻」四字爲題注小字。）", "（望按：石刻題下原署曰「處士范的上」。", "于季友《育王寺碑後記》有「剡越間隱逸之士曰范的，業文功書，未遇于時，常萍泊雲水間。", "一日，扁舟到明」等語。", "又《育王寺常住田碑》，原爲萬齊融所撰，徐嶠之書，其後碑隳，大和七年于季友爲明州刺史時，始邀范的重書。", "其碑題下署「順陽范的書並篆額」，是范的爲順陽人。", "范生平可考者僅此。", "又詩中琬下原是「御名」兩字，蓋避武宗諱不書，武宗名炎，則詩中此字原當作琰可知。", "〖此王昶避嘉慶帝諱而注爲「御名」。", "〗然則詩之作在大和間，鐫石則在武宗會昌中，其間相去固將十載矣。）。"]'),
('9077c173-38ae-4ce5-8033-dca418921cef','','盧元輔','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.50000.json','["。"]'),
('18e1e6e1-08a9-4458-95ef-52f097cb235a','遊天竺寺','盧元輔','唐','唐诗','tang','','["\u897f\u6e56"]','水田十里學袈裟，秋殿千金儼釋迦。',419,'全唐诗/poet.tang.50000.json','["水田十里學袈裟，秋殿千金儼釋迦。", "遠客偏求月桂子，老人不記石蓮花。", "武林山價縣隋日，天竺經文隸漢家。", "苔壁媧皇鍊來處，泐中脩竹掃雲霞。", "（見《兩浙金石志》卷二。", "）（〖1〗石刻詩前原題「大唐杭州刺史盧元輔」九字。", "〖2〗阮元《兩浙金石志》：「右刻在下天竺神尼塔下磨崖，文九行，右行，正書，徑二寸。", "此詩《全唐詩》未載。", "按盧元輔於德宗時自河南縣令除杭州刺史，嘗於武林山作見山亭，見《咸淳臨安志》。", "又《胥山碑銘》，元和十年盧元輔文，王遹書，見《輿地碑目》。", "此疑元和時刻。", "又《陜西通志》云：『盧元輔滑州人，曾爲華州刺史。』", "《郎官石柱題名》有金部郎中盧元輔。", "白樂天有《盧元輔除杭州刺史制》，中云：『嘗守商都，再領京縣。』", "皆其歷官也。", "石本『泐中脩竹掃雲霞』，『泐』字係原刻，『脩竹』二字係改鑿。", "『大唐』二字亦添補。", "《西湖志》作『洞中』，蓋據文理，未見石刻也。」", "〖3〗《杭州府志》引《武林石刻記》：「唐盧元輔《遊天竺詩》，縱一尺八寸，橫二尺，正書，字徑二寸。」）。"]'),
('c9f50671-de23-46cc-bf6e-4d21b1afa81b','憶錢塘','李廓','唐','唐诗','tang','','[]','往歲東遊鬢未凋，渡江曾駐木蘭橈。',140,'全唐诗/poet.tang.50000.json','["往歲東遊鬢未凋，渡江曾駐木蘭橈。", "一千里色中秋月，十萬軍聲半夜潮。", "桂倚玉兒吟處雪，蓬遺蘇丞舞時腰。", "仍聞江上春來柳，依舊參差拂寺橋。", "（見韋莊《又玄集》卷中。", "）（〖1〗陶敏云。", "此詩之頸聯「一千里色中秋月，十萬軍聲半夜潮。」", "張爲《詩人主客圖》取爲趙嘏句，《全唐詩》卷五五○亦收趙嘏句。）。"]'),
('c8cd28f3-0c3d-4cc5-96ea-ca24b7350775','遥知（友人陳九思同志疑「知」乃「和」字之訛）元九送王行周遊越','李紳','唐','唐诗','tang','','[]','江湖隨月盈還宿，沙渚依潮斷更連。',78,'全唐诗/poet.tang.50000.json','["江湖隨月盈還宿，沙渚依潮斷更連。", "伍相廟中多白浪，越王臺畔少晴烟。", "低頭綠草羞枚乘，刺眼紅花笑杜鵑。", "莫倚西施舊苔石，由來破國是神仙。", "（見韋莊《又玄集》卷中。", "）。"]'),
('33b2fbcb-28b9-4794-a22d-08b8e7bd4c10','哭微之','白居易','唐','唐诗','tang','','[]','今在豈有相逢日，未死應無暫忘時。',195,'全唐诗/poet.tang.50000.json','["今在豈有相逢日，未死應無暫忘時。", "從此三篇收淚後，終身無復更吟詩。", "（見《文苑英華》。", "）（按《全唐詩》載《哭微之》詩二首，其詩原附於白居易《祭微之文》，畧謂無以寄悲情，作哀詞二首云云。", "《全唐文》卷六百八十一及坊刻《白香山集》均載之。", "惟《文苑英華》卷九百八十九《祭微之文》則謂作哀詞三首，其第三首爲）（諸本所無。", "承友人顧學頡先生函告，爰補錄於此。", "或以其出處不明爲疑，則俟方家之考定於來更可耳。", "）。"]'),
('1f0feffb-b00b-4fd7-a7ad-44494c1b4959','失題','白居易','唐','唐诗','tang','','[]','石榴枝上花千朵，荷葉杯中酒十分。',247,'全唐诗/poet.tang.50000.json','["石榴枝上花千朵，荷葉杯中酒十分。", "滿院弟兄皆痛飲，就中大戶不如君。", "（見《玉照新志》。", "）（〖1〗《玉照新志》〖宋王明清撰，《寶顏堂祕笈》本〗卷三：「王彦國獻臣，招信人，居縣之近郊。", "建炎初，虜人將渡淮，獻臣坐於所居小樓，望見一老士大夫彷徨阡陌間，攜一小僕，負一匣，埋於空迥之所。", "獻臣默識之。", "事定，往掘其地，宛然尚存。", "啟匣，乃白樂天手書詩一紙。", "云〖詩不重錄〗。", "獻臣後南渡，寓居餘姚，嘗出以示余，真奇物也。", "聞後以歸劉綱公舉矣。", "」〖2〗按此亦顧先生所見示，其事可信與否，未敢遽斷，期海內方家有以論定之。", "）。"]'),
('05532703-9c9e-4cb0-9a34-d1be9655a615','春遊（見歷史博物館藏明王氏藏《宋拓四名人法書》冊頁。承顧學頡先生函告，詩爲白居易所作，即未竹垞云後人誤以爲元稹詩者，《全唐詩》亦入元稹卷，今宜還諸樂天。詩不重錄。〖《全唐詩》卷四二三收作元稹詩。顧說見其校點本《白居易集外集》卷上，朱說見《曝書亭集》卷四九。檢南宋洪邁《容齋隨筆五集》卷二云此詩「白樂天書之，題云『元相公《春游》』，錢思公藏其真跡，穆父守越時，摹刻於蓬萊閣下，今不復存。」錢思公指錢惟演，穆父指錢勰，爲北宋前中期執行。其言似比明清人所說更可靠些。此詩是否白作，恐尚難論定。）','白居易','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.50000.json','["空。"]'),
('8c5a8d90-33b9-4317-81ab-41edd6a15d1e','郡治樓望黃山','韋綬','唐','唐诗','tang','','["\u9ec4\u5c71"]','郡齋北望春光好，平楚無雲秋望寬。',216,'全唐诗/poet.tang.50000.json','["郡齋北望春光好，平楚無雲秋望寬。", "清氣爽時塵外見，碧煙飛處静中看。", "争高千仞山皆讓，並秀三峯色也寒。", "莫怪寓名同嶽號，暫圖瞻眺近長安。", "（見康熙十八年閔嗣撰《黃山志定本》卷六，書刻於乾隆間。", "）（〖1〗詩後原附按語：「汪晉穀云：唐有兩韋綬，一德宗朝翰林學士，一穆宗朝吏部尚書。", "以《石門巖志》辨之，當是德宗朝者。", "」〖2〗望按：《金石萃編》卷八十有「華陰縣令韋綬」題名，次「檢校水部員外郎崔熲」題名後。", "韋綬題名下刻「貞元元年二月六日記」九字。", "）。"]'),
('b575640e-ca28-437c-9c5b-dcf660a6a2d9','勸酒行','鮑溶','唐','唐诗','tang','','[]','樂往難重得，老來豈自由。',138,'全唐诗/poet.tang.50000.json','["樂往難重得，老來豈自由。", "嬋娟過三五，珠翠成仇讎。", "君不聞古曲，酒能消人憂。", "何人更年少，君惜秉燭遊。", "莫閑金絲手，月在西南樓。", "羅换歌妾袂，錦纏舞人頭。", "半醉月入懷，仰空笑牽牛。", "那令酒生塵，虛見紅貌秋。", "（見《永樂大典》卷一二○四三「二十有」「酒」字「勸酒」條〖十三函一百二十四冊〗。", "）。"]'),
('e67dff8d-2d70-42c5-bc37-069447d85006','去東林寺詩','曹汾','唐','唐诗','tang','','[]','峯頭不住起孤煙，池上相留有白蓮。',231,'全唐诗/poet.tang.50000.json','["峯頭不住起孤煙，池上相留有白蓮。", "塵網分明知束縛，更須騎馬別林（「林」字，《金石錄補》作「雲」。", "）泉。", "（見《古刻叢鈔》。", "以《槐盧叢書》本《金石錄補》參校之。", "）（〖1〗詩下原署「會昌三年七月十三日祕書省正字曹汾題」十七字。", "〖2〗陶宗儀《古刻叢鈔》：此詩在曇玭碑陰，塵土昏塞，無知之者。", "至和三年春二月，陳國袁陟來遊山，徧抉奇跡，始發其晦。", "東林詩多矣，未有如此篇之意遠而美者，因題以永之。", "汾，開成四年崔蠡下進士，後爲中書舍人，戶部侍郎、忠武軍節度使，實丞相確之弟也。", "）。"]'),
('030398c7-4a81-4de4-8096-d5d66524d7c0','朱槿花','薛濤','唐','唐诗','tang','','[]','紅開露臉誤文君，□□芙蓉草綠雲。',80,'全唐诗/poet.tang.50000.json','["紅開露臉誤文君，□□芙蓉草綠雲。", "（張篷舟《薛濤詩箋》謂北京圖書館藏宋本《分門纂類唐歌詩》，此句無缺文，作「司蒡芙蓉草綠雲」。", "）造化大都排比巧，衣裳色澤總薰薰。", "。"]'),
('9baf7e52-3d34-4ff3-b28d-04e0a1b00d09','浣花亭陪川主王播相公暨寮同賦早菊','薛濤','唐','唐诗','tang','','[]','西陸行終令，東籬始再陽。',80,'全唐诗/poet.tang.50000.json','["西陸行終令，東籬始再陽。", "綠英初濯露，金蘂半含霜。", "自有兼材用，那同衆草芳。", "獻酬樽俎外，寧有懼豺狼。", "（以上二詩見《分門纂類唐歌詩》殘本第六冊《草木蟲魚類》卷五。", "）。"]'),
('a1937a8d-db11-477d-961a-d64f834d0d20','題小華山（原注：「目黃山爲小華」。）','李敬方','唐','唐诗','tang','','["\u9ec4\u5c71"]','峰簇蓮花小，分明似華山。',42,'全唐诗/poet.tang.50000.json','["峰簇蓮花小，分明似華山。", "魚符何日罷，深處掩松關。", "（見閔麟嗣撰《黃山志定本》卷六。", "）。"]'),
('30853ebd-bf9e-4874-bc58-6d36f8cd50e8','送友人罷舉歸東海','雍陶','唐','唐诗','tang','','[]','滄滄天塹外，何島是新羅？',152,'全唐诗/poet.tang.50000.json','["滄滄天塹外，何島是新羅？", "舶主辭蕃遠，碁僧入漢多。", "海風吹白鶻，沙日曬紅螺。", "此去知提筆，須求利劍磨。", "（見韋莊《又玄集》卷下。", "熊飛云《全唐詩》卷五三一收此爲許渾詩。", "今檢《文苑英華》卷二八○收此爲許詩，而許渾自書之烏絲欄詩真蹟及席刻本《丁卯詩集》、《四部叢刊》影宋鈔《下卯集》中皆無此詩。", "應爲誰作，尚難斷定。", "）。"]'),
('344b4e8a-dcf1-4f1f-b52f-8dd21d9eeee0','','張祜','唐','唐诗','tang','','[]','空（按《全唐詩》卷五百十及卷五百十一編張祜詩二卷，又卷八百七十收諧謔詩二首，其中《戲顏郎中騎中騎臘詩》一首已見正卷，蓋複出，又卷八百八十三補遺卷有詩五首。',171,'全唐诗/poet.tang.50000.json','["空（按《全唐詩》卷五百十及卷五百十一編張祜詩二卷，又卷八百七十收諧謔詩二首，其中《戲顏郎中騎中騎臘詩》一首已見正卷，蓋複出，又卷八百八十三補遺卷有詩五首。", "本編所輯四卷，均所未及。", "今從北京圖書館藏南宋蜀刻本《張承吉文集》、《永樂大典》、韋莊《又玄集》、《太平廣記》引唐康駢《劇談錄》、唐馮翊子《桂苑叢談》等書錄出之。", "祜，諸書或有作祐者，誤。", "）。"]'),
('c2ea2f74-0297-4ae6-ae92-c36afd1bae16','慈烏','張祜','唐','唐诗','tang','','[]','慈烏色似漆，孔雀尾如金。',47,'全唐诗/poet.tang.50000.json','["慈烏色似漆，孔雀尾如金。", "內外既相及，聖人空理心。", "（此以下均見南宋蜀刻本《張承吉文集》卷六。", "）。"]'),
('f8af2220-e975-410e-ba37-eaa3512099c5','閑居作五首 其一','張祜','唐','唐诗','tang','','[]','十年狂是酒，一世癖緣詩。',49,'全唐诗/poet.tang.50000.json','["十年狂是酒，一世癖緣詩。", "剩物心長厭，閑書性理不違。", "補窠新鷰子，争食乳鴉兒。", "幸爾隣家竹，春來又許移。"]'),
('6128a8a6-4ea4-47ce-87de-e7c9caaa2da9','閑居作五首 其三','張祜','唐','唐诗','tang','','[]','小院新栽柳，深窗古畫屏。',48,'全唐诗/poet.tang.50000.json','["小院新栽柳，深窗古畫屏。", "屋塼懸蜴蜥，蟲網礙蜻蜓。", "啓軸憐孤進，添盃慮獨醒。", "殷勤東郭外，春麥又苗青。"]'),
('60aa5fb8-0040-4d53-8807-17719f2db621','閑居作五首 其四','張祜','唐','唐诗','tang','','[]','悶看垂簷雨，閑尋小院芳。',48,'全唐诗/poet.tang.50000.json','["悶看垂簷雨，閑尋小院芳。", "壁泥根長麥，籬柱葉生楊。", "旋碾新茶試，生開嫩酒嘗。", "看看花漸老，無復滯春光。"]'),
('0cf0976f-0ece-4670-894d-94596d5b4a32','閑居作五首 其五','張祜','唐','唐诗','tang','','[]','俗人無語詔，病客少經過。',38,'全唐诗/poet.tang.50000.json','["俗人無語詔，病客少經過。", "種竹憐莖少，移花喜日多。", "唯精《左氏傳》，不養右軍鵝。"]'),
('231f5c38-16b9-4f96-acb0-8d813c80ab46','江南雜題三十首 其一','張祜','唐','唐诗','tang','','[]','遠對三茅嶺，踈開一槿籬。',48,'全唐诗/poet.tang.50000.json','["遠對三茅嶺，踈開一槿籬。", "人憐貧好學，自笑老吟詩。", "仰腹獼猴睡，斜身蝘蜒癡。", "殷勤謝莊叟，櫟社更何疑。"]'),
('95234e29-8ed5-48ac-994a-f37065ffb90a','江南雜題三十首 其二','張祜','唐','唐诗','tang','','[]','退居三畝地，聊復謝喧卑。',49,'全唐诗/poet.tang.50000.json','["退居三畝地，聊復謝喧卑。", "盡日題書標，無風下釣絲。", "蚰蜒過竹節，翡翠抱蘆枝。", "惆悵是臨水，星星蓬鬢垂。", "。"]'),
('c17453f5-e2bf-455c-9dae-eaafe575c41f','江南雜題三十首 其三','張祜','唐','唐诗','tang','','[]','鳥逸溪雲静，人行野岸稀。',48,'全唐诗/poet.tang.50000.json','["鳥逸溪雲静，人行野岸稀。", "茅峯三點翠，練水一條輝。", "晚蝶花心少，陰瑩草裏微。", "何妨孟朱舍，夜飲醉歌歸。"]'),
('a0edb3f8-e5ed-41c9-91ee-b0bfc68324bf','江南雜題三十首 其四','張祜','唐','唐诗','tang','','[]','南畝山光對，西郊日影斜。',48,'全唐诗/poet.tang.50000.json','["南畝山光對，西郊日影斜。", "碧抽書帶草，紅節米囊花。", "夜跣嘗琴室，昏岷自酒家。", "何妨人不到，私酌是侯芭。"]'),
('b58dc65d-fb1e-497c-a55f-fefe0d7bafd5','江南雜題三十首 其五','張祜','唐','唐诗','tang','','[]','野岸煙花好，東園自插籬。',50,'全唐诗/poet.tang.50000.json','["野岸煙花好，東園自插籬。", "茈姑交宛葉，喜子抱遊絲。", "盡日人稀到，終年井不窺。", "何當謝貞白，《真誥》是吾師。"]'),
('9e4d77a9-311d-4ce8-accf-a54a1ff648dc','江南雜題三十首 其六','張祜','唐','唐诗','tang','','[]','遠郭浸煙波，村橋入薜蘿。',36,'全唐诗/poet.tang.50000.json','["遠郭浸煙波，村橋入薜蘿。", "水虵驚去疾，山鳥自來多。", "夜月傾壺酒，春風就榜歌。"]'),
('12aa0c9f-a27a-4848-9b5d-a83a97ad6c10','江南雜題三十首 其七','張祜','唐','唐诗','tang','','[]','五里波㳂郭，扁舟棹到門。',48,'全唐诗/poet.tang.50000.json','["五里波㳂郭，扁舟棹到門。", "水經春雨漲，山近夕陽溫。", "鸂鶆穿蘆葉，蟛蟖上竹根。", "憂來欲誰話，猶賴酒盈罇。"]'),
('7f4564e4-ccb7-47b0-9bf9-d87dc5c022f8','江南雜題三十首 其八','張祜','唐','唐诗','tang','','[]','村橋路不端，數里就迴湍。',75,'全唐诗/poet.tang.50000.json','["村橋路不端，數里就迴湍。", "積壤連涇脉，高林上笋竿。", "早嘗甘蔗淡，生摘琵琶酸。", "（「琵琶」，嚴壽澄校《張祜詩集》云：疑「枇杷」之誤。", "）好是去塵俗，煙花長一欄。"]'),
('9a275436-ae1f-463d-ae10-2842ad4245e4','江南雜題三十首 其九','張祜','唐','唐诗','tang','','[]','曉日明高柳，春池合細萍。',36,'全唐诗/poet.tang.50000.json','["曉日明高柳，春池合細萍。", "鷰巢通蜴蜥，魚網漏蜻蜒。", "汩沒非兼濟，終窮是獨醒。"]'),
('d9756b80-829c-4b5d-b2f9-884aa75ff9c5','江南雜題三十首 其十','張祜','唐','唐诗','tang','','[]','三峯前望峻，一派上遊斜。',62,'全唐诗/poet.tang.50000.json','["三峯前望峻，一派上遊斜。", "雨過離披草，風吹顛倒查。", "拂林山鵲翅，叢岸野裳（望疑「裳」爲「棠」之誤。", "）花。", "好是醉中舞，村橋行數家。"]'),
('e36c636d-eb74-4819-8e0c-038ac267c194','江南雜題三十首 其十一','張祜','唐','唐诗','tang','','[]','碧草分遥岸，清池入細流。',86,'全唐诗/poet.tang.50000.json','["碧草分遥岸，清池入細流。", "投鋪虛飲馬，自物且垂鈎。", "小鳥聞批頰，徵蟲弄印頭。", "（「徵」，嚴云：疑當作「徵」。", "《海錄碎事》卷二十二引此二句，正作「微」字。", "）何妨一壺酒，遠遠棹扁舟。"]'),
('179a456b-eeb1-45c3-8ff8-f62c2ca32b29','江南雜題三十首 其十二','張祜','唐','唐诗','tang','','[]','端居無外事，長日臥煙嵐。',49,'全唐诗/poet.tang.50000.json','["端居無外事，長日臥煙嵐。", "樹影侵籬北，花香自水南。", "酒腸嬰女笑，碁路老僧諳。", "似此成乖嬾，嵇康七不堪。", "。"]'),
('683e75a5-3a53-46f8-94f5-06b0bc20f296','江南雜題三十首 其十三','張祜','唐','唐诗','tang','','[]','一逕遶荒陂，渟洿是小池。',48,'全唐诗/poet.tang.50000.json','["一逕遶荒陂，渟洿是小池。", "紅蕉心半卷，白練尾長垂。", "倒篋纏書帶，尋竿解釣絲。", "聊當事山履，遠與白雲期。"]'),
('06b4dbde-d47b-40c1-924b-08d9fd236216','江南雜題三十首 其十四','張祜','唐','唐诗','tang','','[]','久病無行意，溪亭益到稀。',48,'全唐诗/poet.tang.50000.json','["久病無行意，溪亭益到稀。", "月迴秋扇影，螢落夜琴微。", "滄海尚凝棹，木山誰採薇？", "佳期不可俟，空羡鷰西歸。"]'),
('ba4419d8-17b9-43a9-bf31-791ed80d859c','江南雜題三十首 其十五','張祜','唐','唐诗','tang','','[]','碧溪窮欲盡，迴棹喜山家。',48,'全唐诗/poet.tang.50000.json','["碧溪窮欲盡，迴棹喜山家。", "曲岸深迷竹，平灘下見沙。", "懸窠巧婦子，拂水剪刀花。", "好是棲心地，人間路不遐。"]'),
('97b42d80-f46b-4f3e-8a72-6c7ed501f0af','江南雜題三十首 其十六','張祜','唐','唐诗','tang','','[]','僻居成嬾病，春至強耕蠶。',48,'全唐诗/poet.tang.50000.json','["僻居成嬾病，春至強耕蠶。", "後港通圍竹，前溪下檐柑。", "舊巢飛巧婦，新葉長宜男。", "且賴身無事，窮愁亦自甘。"]'),
('01e69b6f-6246-4adc-9c26-f2b72f690d76','江南雜題三十首 其十七','張祜','唐','唐诗','tang','','[]','小檻雲低處，高廊雨過時。',65,'全唐诗/poet.tang.50000.json','["小檻雲低處，高廊雨過時。", "鹿胎含笋籜，猿臂長松枝。", "舊匣藏鈎軫，沉查骨釣絲。", "（「骨」，嚴云：疑當作「罥」。", "）平生心未遠，徒欲效鴟夷。", "。"]'),
('7c0c3c3e-2d92-4fd9-97c5-eabf1e0267dd','江南雜題三十首 其十八','張祜','唐','唐诗','tang','','[]','春醪盡數盃，竹逕坐深苔。',48,'全唐诗/poet.tang.50000.json','["春醪盡數盃，竹逕坐深苔。", "鳥道思歸樂，人呼隱去來。", "溪花流作片，雨葉爛成堆。", "訪戴值兹夕，何妨乘興迴。"]'),
('0ef108fd-3581-41e0-9b87-fe60d33fd0cd','江南雜題三十首 其十九','張祜','唐','唐诗','tang','','[]','洛下無名客，江南不繫舟。',48,'全唐诗/poet.tang.50000.json','["洛下無名客，江南不繫舟。", "病身黃葉晚，詩思碧雲秋。", "雀語嘉賓笑，蛩鳴嬾婦愁。", "幸因重醖熱，聊作醉鄉遊。"]'),
('ccaf5bb1-f4ef-41d7-908e-ece6b228524f','江南雜題三十首 其二十','張祜','唐','唐诗','tang','','[]','余生唯愛酒，師長是山翁。',48,'全唐诗/poet.tang.50000.json','["余生唯愛酒，師長是山翁。", "定葬槽丘下，須沉釀瓮中。", "鵜鴣春作鳥，舂黍夏爲蟲。", "會入醉鄉去，爲君成醉風。"]'),
('c5c4befd-47c5-4ffd-a9fe-21ae799a733f','江南雜題三十首 其二十一','張祜','唐','唐诗','tang','','[]','翠竹千竿聳，青池一面臨。',50,'全唐诗/poet.tang.50000.json','["翠竹千竿聳，青池一面臨。", "白煙生草末，黃粉露花心。", "簇脚蠨蛸桂，（望疑「桂」爲「挂」之誤。", "）拋身翡翠沉。"]'),
('685f5d38-8324-48d5-90e6-7dd07e675eb9','江南雜題三十首 其二十二','張祜','唐','唐诗','tang','','[]','滄海一遺民，詩書盡老身。',49,'全唐诗/poet.tang.50000.json','["滄海一遺民，詩書盡老身。", "不逢青眼舊，争奈白頭新。", "小小調茶鼎，銖銖定藥斤。", "空疎更誰問，賴與酒家隣。", "。"]'),
('f6f235f9-a246-4e2e-9e2f-6b47326ff853','江南雜題三十首 其二十三','張祜','唐','唐诗','tang','','[]','南國久無悰，東郊自養蒙。',48,'全唐诗/poet.tang.50000.json','["南國久無悰，東郊自養蒙。", "老年孤枕在，愁夜一樽空。", "澇水聞歌女，枯枝見宛童。", "秋來因攬鏡，強欲理衰蓬。"]'),
('c246a45e-416b-4a39-bf58-ba9f85cb04ab','江南雜題三十首 其二十五','張祜','唐','唐诗','tang','','[]','郊園日牢落，無意及壺飱。',48,'全唐诗/poet.tang.50000.json','["郊園日牢落，無意及壺飱。", "大笑俯塵甑，高歌敲酒盆。", "汲池澆韮壟，占石坐松根。", "未免猶隨俗，長竿掛一褌。"]'),
('a601aafc-8e20-4b39-b70f-4c211f96b66e','江南雜題三十首 其二十六','張祜','唐','唐诗','tang','','[]','三年江海客，長日犯埃氛。',48,'全唐诗/poet.tang.50000.json','["三年江海客，長日犯埃氛。", "失脚遠行地，無心空羡雲。", "愚非甯武子，蔽是卓文君。", "以此圖終計，深棲麋鹿羣。"]'),
('349eac6a-d40e-4177-b862-4c9701c19648','江南雜題三十首 其二十七','張祜','唐','唐诗','tang','','[]','卜築寄雲陽，穿池面草堂。',36,'全唐诗/poet.tang.50000.json','["卜築寄雲陽，穿池面草堂。", "尋常登峻嶺，丈六得奇彊。", "井鮒依頹甃，隣花出敗墻。"]'),
('a912b789-7543-4373-afd3-f78dba057acd','江南雜題三十首 其二十八','張祜','唐','唐诗','tang','','[]','美人殊不見，惆悵望行雲。',48,'全唐诗/poet.tang.50000.json','["美人殊不見，惆悵望行雲。", "竹翠静含粉，榴花輕曳裙。", "嬋娟非月色，散漫是蘭薫。", "無復荆王夢，子規空夜聞。"]'),
('61b71081-ea1d-47d2-8263-f5e4e14473e3','江南雜題三十首 其二十九','張祜','唐','唐诗','tang','','[]','佳期楚雲外，寂寞是春華。',48,'全唐诗/poet.tang.50000.json','["佳期楚雲外，寂寞是春華。", "昔去軒車遠，今來衣帶賒。", "生風貝母葉，活艷鼠姑花。", "惆望碧江阻，夢𩲑雲陟遐。"]'),
('62d6c3ae-c835-43d9-baa8-89e7321e12be','寓居臨平山下三首','張祜','唐','唐诗','tang','','[]','（按此第一首亦見《永樂大典》卷二二七一、七模、湖字臨平湖條〖二函二十冊〗。',75,'全唐诗/poet.tang.50000.json','["（按此第一首亦見《永樂大典》卷二二七一、七模、湖字臨平湖條〖二函二十冊〗。", "又清初沈謙《臨平記》卷四亦載之。", "題曰《過臨平湖》，即將兩書異字校注於下。", "）。"]'),
('28e5fe53-7997-4d0c-b998-4d908628d46d','寓居臨平山下三首 其一','張祜','唐','唐诗','tang','','[]','三月平湖浪（《大典》及《臨平記》作「草」。',186,'全唐诗/poet.tang.50000.json','["三月平湖浪（《大典》及《臨平記》作「草」。", "）欲齊，綠楊分映（《臨平記》作「影」。", "）入長堤。", "田家起處烏龍（《臨平記》作「猶」。", "）静，（《大典》及《臨平記》作「吠」。", "）酒客醒時謝豹啼。", "溪（《大典》及《臨平記》作「山」）檻正當蓮葉渚，水涇新麥稻苗畦。", "（《大典》作「水堘新擘稻秧畦」，《臨平記》作「水塍新築稻秧畦」。", "）人間謾說多歧路，咫尺神仙洞却迷。", "（《臨平記》作「路欲迷」。", "）。"]'),
('8150ee7e-61e3-4b9b-82b5-6b46385af482','寓居臨平山下三首 其二','張祜','唐','唐诗','tang','','[]','一角橫查礙小灘，漁舟稍稍避迴湍。',66,'全唐诗/poet.tang.50000.json','["一角橫查礙小灘，漁舟稍稍避迴湍。", "鹿蹄踏葉暮山響，龜殻曝沙春水寒。", "詩句近吟知律變，《易》書窮討覺才難。", "風光好處自擕酌，歸去醉扶花藥欄。"]'),
('afdf02f9-0d3e-4bd2-8eb1-9c2cb8694c10','寓居臨平山下三首 其三','張祜','唐','唐诗','tang','','[]','散髪垂肩久不簪，竹床推椀就藤陰。',64,'全唐诗/poet.tang.50000.json','["散髪垂肩久不簪，竹床推椀就藤陰。", "澗傍春渡水流急，山半夜歸雲色深。", "拂檻數竿爲去處，隨波一葉是浮沉。", "世間年少正行樂，應笑老人無事心。"]'),
('196d2422-4423-4390-b9b8-aecac59b9723','到廣陵','張祜','唐','唐诗','tang','','[]','一年江海恣狂遊，夜宿倡家曉上樓。',87,'全唐诗/poet.tang.50000.json','["一年江海恣狂遊，夜宿倡家曉上樓。", "嗜酒幾曾羣從小，爲文多是諷諸侯。", "逢人說劒三攘臂，對鏡吟詩一掉頭。", "今日更來憔悴意，不堪風月滿揚州。", "（此以下均見南宋蜀刻本《張承吉文集》卷七。", "）。"]'),
('be97408b-ceec-4a1c-aa25-d0e61d4881f3','謝高燕公惠生衣','張祜','唐','唐诗','tang','','[]','高公寵歲賜白衣裳，驚訝災天雪滿箱。',65,'全唐诗/poet.tang.50000.json','["高公寵歲賜白衣裳，驚訝災天雪滿箱。", "乍展輕煙總手滑，如披薄霧覺身凉。", "誰家纖素秋蟾色，何處絲抽嫩異香？", "珍重六銖無可贈，空憑七字當瓊漿。"]'),
('64eb21d4-e493-460c-81e8-cf0994ed3401','戲贈村婦','張祜','唐','唐诗','tang','','[]','二升酸醋瓦瓶盛，請得姑嫜十日程。',64,'全唐诗/poet.tang.50000.json','["二升酸醋瓦瓶盛，請得姑嫜十日程。", "赤黑畫眉臨水笑，草鞋苞脚逐風行。", "黃絲髪亂梳橑緊，青䘢裙高種掠輕。", "想得到家相見後，父孃由唤小時名。"]'),
('cca1a5fb-0c2c-4d93-807d-94bfc7ef1383','偶登蘇州重玄閣','張祜','唐','唐诗','tang','','[]','飛閣層層茂苑間，夏凉秋晚屙登攀。',64,'全唐诗/poet.tang.50000.json','["飛閣層層茂苑間，夏凉秋晚屙登攀。", "萬家前後皆臨水，四檻高低盡見山。", "何事越王侵敵國，不妨遼鶴唁人寰。", "五湖直下須歸去，自笑身閑迹未閑。"]'),
('64313420-1f91-405d-a4a2-1c095a0e5496','投蘇州盧中丞','張祜','唐','唐诗','tang','','[]','金紫清門美丈夫，聖人憂地詔分符。',64,'全唐诗/poet.tang.50000.json','["金紫清門美丈夫，聖人憂地詔分符。", "猶將儉德同朝客，不着尊官傲世儒。", "經術在心長說體，吏材臨事必開模。", "西來郡界逢鄉老，盡說而今是坦途。"]'),
('7d3c571e-4fd7-4430-86f1-84498af12518','投滑州上盧尚書','張祜','唐','唐诗','tang','','[]','雨露恩重棣萼繁，一時旌旆刊雄藩。',65,'全唐诗/poet.tang.50000.json','["雨露恩重棣萼繁，一時旌旆刊雄藩。", "權經兩使材尤重，位近三台道益尊。", "江海豁開爲氣岸，河隍堅畫在心源。", "門闌盡是雲霄客，應念於陵獨灌園。", "。"]'),
('f318ed52-7c91-4458-8c52-c5a264969731','投蘇州盧郎中','張祜','唐','唐诗','tang','','[]','三地分符寵更深，兩方旌斾日駸駸。',64,'全唐诗/poet.tang.50000.json','["三地分符寵更深，兩方旌斾日駸駸。", "蛟龍可是池中物，鳯鳥無非閣上音。", "世重才人皆立績，客依公子盡推心。", "猶思謝尚經牛渚，曾聽袁宏一夜吟。"]'),
('becc1d63-2739-4007-8d3d-2e0fadef9ba4','送劉軺秀才江陵歸寧','張祜','唐','唐诗','tang','','[]','出告遊方是素辭，喜君迴棹不逾時。',93,'全唐诗/poet.tang.50000.json','["出告遊方是素辭，喜君迴棹不逾時。", "荆門暮指連山遠，郢國春歸上水遲。", "罇酒惜離文舉坐，郡齋誰覆中宣碁。", "（《輿地紀勝》卷六五引以上四句，「中宣」作「仲宣」，是。", "）殷勤莫忘趨庭日，學禮三餘已學詩。"]'),
('03348032-d1f9-40cf-b35a-29e297a52709','奉和池州杜員外南亭惜春','張祜','唐','唐诗','tang','','[]','草霧輝輝柳色新，前山差掩黛眉頻。',64,'全唐诗/poet.tang.50000.json','["草霧輝輝柳色新，前山差掩黛眉頻。", "碧溪潮漲碁侵夜，紅樹花深醉度春。", "幾恨今年提已過，翻悲昨日事成塵。", "可知屈轉江南郡，還就封州詠白蘋。"]'),
('58fdb972-9268-4d5c-8449-b1b0051d3dc0','題河陽新鼓角樓','張祜','唐','唐诗','tang','','[]','重樓高桍兩簷開，曉夕風雲會振雷。',64,'全唐诗/poet.tang.50000.json','["重樓高桍兩簷開，曉夕風雲會振雷。", "中國最推鼙鼓地，大臣先選陳樑材。", "馬悲塞北千羣牧，鴈到城南一半迴。", "從此聖朝思將帥，上衣須脫食須推。"]'),
('46754f32-a6ab-4a3c-91d2-e7cb59511aac','觀楚州韋舍人新築河堤怺建兩閶門（按此詩亦見《永樂大典》卷三五二七「九真」「門」字「北閶門」條〖五函四十九冊〗。《大典》引《元一統志》曰：「淮安路有北閶門，唐〖張，原脫〗祐〖應作祜〗有《陪楚州韋舍人北閶門遊燕詩》。」）','張祜','唐','唐诗','tang','','[]','宴賓容易小筵成，隼擊秋原助放情。',64,'全唐诗/poet.tang.50000.json','["宴賓容易小筵成，隼擊秋原助放情。", "紅袖退行鞍上語，白眉迂步馬前迎。", "一冬霜意先黃葉，兩路風威動翠旌。", "須道孔融罇已滿，不勞臺下說餘酲。"]'),
('82a0d26d-71d4-455f-87ad-428a7073af52','題潤州李尚書北固新樓','張祜','唐','唐诗','tang','','[]','躡石攀雲一逕危，粉廊朱檻眺江湄。',64,'全唐诗/poet.tang.50000.json','["躡石攀雲一逕危，粉廊朱檻眺江湄。", "青山半在潮來處，碧海先看月滿時。", "樹色轉煙城斗峻，水光浮草岸遥卑。", "西樓又起公羊意，坐對寒潮向渺瀰。"]'),
('fb47b8e6-e6b0-4b84-b834-b43bdfdf3857','酬張權宣州新橋秋夜對月見寄','張祜','唐','唐诗','tang','','[]','謝亭煙月泛清流，千載溪山一造舟。',66,'全唐诗/poet.tang.50000.json','["謝亭煙月泛清流，千載溪山一造舟。", "風定遠帆依郡郭，夜深寒笛起江樓。", "張憑逆旅逢新唱，王粲從軍值勝游。", "長愛征南杜公意，不將餘力礙《春秋》。"]'),
('e22b1cfe-f30d-4820-9053-1dd4e2acdb61','題宛陵新橋兼獻裴尚書','張祜','唐','唐诗','tang','','[]','富平津路遠陵開，武庫森森又姓裴。',64,'全唐诗/poet.tang.50000.json','["富平津路遠陵開，武庫森森又姓裴。", "高步已吟携手句，上聞初喜造舟才。", "霜明華表塵初静，月正欄干斗乍回。", "猶憶醉歌南浦夜，五更人過萬聲雷。"]'),
('fbf4e269-503d-4bf9-8e21-a0958f3aa92a','所居即事六首（原注：丹陽閑居寄鄭明府如範上人。） 其一','張祜','唐','唐诗','tang','','[]','南下丹陽一水灣，陋居瓢飲是希顏。',64,'全唐诗/poet.tang.50000.json','["南下丹陽一水灣，陋居瓢飲是希顏。", "來爲野鳥入春郭，去作溪雲歸夜山。", "蓬鬢已衰言必賤，竹門雖立意無關。", "陶潛惠遠如相愛，朝訪遺民暮却還。"]'),
('ef179582-6040-4a1b-b5f0-0647986ad061','所居即事六首（原注：丹陽閑居寄鄭明府如範上人。） 其二（原注：溪上小齋。）','張祜','唐','唐诗','tang','','[]','日暮空齋對小溪，遠村歸岸醉如泥。',137,'全唐诗/poet.tang.50000.json','["日暮空齋對小溪，遠村歸岸醉如泥。", "杜鵑花茫然杜鵑叫，烏臼葉生烏臼啼。", "（嚴云：「頷聯二句見《唐詩紀事》，『花落』作『花前。", "』」又見《海錄碎事》卷二十二、《全唐詩》卷五一一，「花落」作「花發」，「葉生」作「花生」。", "）野食不妨菰作飯，園蔬何必稻爲虀。", "辛勤最愛孟光意，除却梁鴻無急妻。"]'),
('b9a6f1c3-4395-484d-b09e-693f1ab2f3b1','所居即事六首（原注：丹陽閑居寄鄭明府如範上人。） 其三','張祜','唐','唐诗','tang','','[]','牢落東溪滿鬢絲，一身扶杖二男隨。',86,'全唐诗/poet.tang.50000.json','["牢落東溪滿鬢絲，一身扶杖二男隨。", "（《全唐詩》卷五一一據《野客叢書》收此句。", "）鳴鳩在處携書卷，科斗生時想墨池。", "日夕愛琴憐犬子，春風詠雪喜胡兒。", "我家命駕還千里，別與鱸魚爲後期。"]'),
('eca96d99-534b-4d9f-865a-944e3e79e8ea','所居即事六首（原注：丹陽閑居寄鄭明府如範上人。） 其四（原注：春日寓言。）','張祜','唐','唐诗','tang','','[]','寂寞春風意未降，酒狂詩癖舊無雙。',64,'全唐诗/poet.tang.50000.json','["寂寞春風意未降，酒狂詩癖舊無雙。", "柳花飛處曾逢雪，桃葉開提憶渡江。", "自古不堪居陋巷，從今休更犯危邦。", "聖朝何用詢名姓，從放書生老北窗。"]'),
('0b4d1ce7-dfc8-42b1-a3f0-b5d96d7b2db1','所居即事六首（原注：丹陽閑居寄鄭明府如範上人。） 其五（原注：偶作。）','張祜','唐','唐诗','tang','','["\u5e90\u5c71"]','南窮海徼北天涯，惆悵亡羊是路歧。',64,'全唐诗/poet.tang.50000.json','["南窮海徼北天涯，惆悵亡羊是路歧。", "眼下已隳梁武佛，耳中猶聽魏文詩。", "三茅道士朝携手，五柳先生夜對棊。", "自向廬山爲一社，百年生計任嬰兒。"]'),
('78083627-3f1d-4dfb-9853-9aaa0ce0c889','所居即事六首（原注：丹陽閑居寄鄭明府如範上人。） 其六','張祜','唐','唐诗','tang','','[]','晨起常掻兩鬢絲，小亭深坐一洿池。',65,'全唐诗/poet.tang.50000.json','["晨起常掻兩鬢絲，小亭深坐一洿池。", "墻頭鸜鵒隈花葉，水面蜻蜓寄草枝。", "賴得木奴些子力，生憎魚婢苦頑癡。", "扁舟遠棹尋春處，竹榼新醪喜自隨。", "。"]'),
('5e2e1eb0-f67c-4cdf-b7de-cd64d19dc951','贈薛鼎臣侍御','張祜','唐','唐诗','tang','','[]','君子清明致自強，大寮僉語美公方。',64,'全唐诗/poet.tang.50000.json','["君子清明致自強，大寮僉語美公方。", "長才上拔孤摽日，利劒新磨一匣霜。", "千里早時知逸足，片言中夜許剛腸。", "已知金石終無變，應蓄歸休在智囊。"]'),
('af7ca7f8-2c4d-40f3-8841-0a232c8228d2','偶信','張祜','唐','唐诗','tang','','[]','浮生擾擾務華虛，未勝東歸重結廬。',64,'全唐诗/poet.tang.50000.json','["浮生擾擾務華虛，未勝東歸重結廬。", "自已忘言師靖節，聘関真隱慕玄居。", "無機坐上休捫虱，失脚溪頭便釣魚。", "唯恨世間些子事，兩莖衰髪爲人梳。"]'),
('761ab788-511b-4278-98af-64f34b209482','贈季峯上人','張祜','唐','唐诗','tang','','[]','時賢近喪若山崖，却賴青雲望素乖。',64,'全唐诗/poet.tang.50000.json','["時賢近喪若山崖，却賴青雲望素乖。", "強似鵷鸞趍宦達，可勝藜藿伴僧齋。", "一壺酒外終無事，萬卷書中死便埋。", "唯是江東道門子，許詢長說是吾儕。"]'),
('0cf0328d-fc5c-4b83-98a2-00baca29b3bb','送法鏡上人歸上元','張祜','唐','唐诗','tang','','[]','南國僧遊二十年，却因無任訪生緣。',64,'全唐诗/poet.tang.50000.json','["南國僧遊二十年，却因無任訪生緣。", "風迴建業秋歸寺，月滿秦淮夜到舡。", "故老盡成雙鬢雪，舊房深鏁一林煙。", "莫言了悟爲真理，不歎興亡在眼前。"]'),
('3853c0c3-3b28-4c83-bfb3-f1720ece3b87','鷹（按《全唐詩》卷三百六十一作劉禹錫詩，題曰《白鷹》。詩同，不重錄。校其異字如下：第一句「手羽斒斕白野裁」，「野」，《全唐詩》作「紵」，是。二句「馬前擎出不擎猜」，「不擎」，《全唐詩》作「不驚」，是。五句「綠玉觜啗雞腦破」，「啗」，《全唐詩》作「攅」。末句「所以人人道俊裁」，「裁」，《全唐詩》作「哉」，是。〖《劉賓客文集》不收此詩，應爲張祜作。〗）','張祜','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.50000.json','["空。"]'),
('807b9361-acce-4685-954a-e7b17fe599c3','題李戡山居','張祜','唐','唐诗','tang','','[]','三畝溪田竹逕通，道情交態只漁翁。',64,'全唐诗/poet.tang.50000.json','["三畝溪田竹逕通，道情交態只漁翁。", "青山夜入孤帆遠，碧水秋澄一檻空。", "自以蛙聲爲皷樂，聊將早色當屏風。", "莫言酷學無知己，未必王音不薦雄。"]'),
('f7c19297-1d3e-4b55-a2c9-4b5af225e82b','題李山人園林','張祜','唐','唐诗','tang','','[]','幾年垂釣碧江潯，長愛嚴陵是此心。',65,'全唐诗/poet.tang.50000.json','["幾年垂釣碧江潯，長愛嚴陵是此心。", "萬壑深秋聞伐木，一溪長日看淘金。", "桑生壠上螟蛉挂，竹在沙頭翡翠沉。", "唯道石田堪種黍，不將衰髪羡華簪。", "。"]'),
('42937589-4430-4059-a308-3d7a6727ec83','投河陽右僕射','張祜','唐','唐诗','tang','','[]','黠虜搆攙搶，（應作「欃槍」或「攙槍」。',132,'全唐诗/poet.tang.50000.json','["黠虜搆攙搶，（應作「欃槍」或「攙槍」。", "）將軍首出征。", "萬人旗下泣，一馬陳前行。", "對敵梟心死，衝圍虎力生。", "雪霜齊擐甲，風雨驟揚兵。", "指點看鞭勢，喧呼認前聲。", "狂胡追過磧，貴主奪還京。", "黑夜星華朗，黃昏火號明。", "無非刀筆吏，獨傳說時英。", "（本卷均見南宋蜀刻本《張承吉文集》卷八。", "）。"]'),
('e5083d11-7f30-4681-9c30-f98524b56778','宋城道中逢王直方八韻','張祜','唐','唐诗','tang','','[]','二年離子載，發跡自江南。',96,'全唐诗/poet.tang.50000.json','["二年離子載，發跡自江南。", "馬上行尋度，途中語再三。", "始因窮去魏，河北戰方酣。", "後以文投許，淮西難未戡。", "謫官逢李涉，狂客見劉弇。", "失意憐初話，多端耻舊諳。", "茶風無奈筆，酒禿不勝簪。", "幾鬱胸中恨，聊當遂劇談。"]'),
('8b1b22a4-37a9-4916-a724-9cf313cda916','題重玄寺閣八韻','張祜','唐','唐诗','tang','','[]','朱閣鱗虛搆，環瞻極水鄉。',97,'全唐诗/poet.tang.50000.json','["朱閣鱗虛搆，環瞻極水鄉。", "青螺蔟山色，白練展湖光。", "矗戶浮雲過，斜軒早鴈翔。", "萬簷攢肆邸，千葉溢津航。", "疊供儳寒碧，飛窗漏夕陽。", "月輪霄輾棟，風鐸曙鏗廊。", "塔聳尖層出，河縈小派長。", "因還九霄上，凝步獨成章。", "。"]'),
('6e1b8a95-ee7c-465b-b0c0-d2e16a9242eb','投韓員外六韻','張祜','唐','唐诗','tang','','[]','見說韓員外，聲華溢九垓。',87,'全唐诗/poet.tang.50000.json','["見說韓員外，聲華溢九垓。", "大川舟欲濟，荒草路初開。", "聳地千潯壁，（「千潯」，疑應作「千尋」。", "）森雲百丈材。", "狂波心上湧，驟雨筆前來。", "後學無人譽，先賢亦自媒。", "還聞孔融表，曾薦禰衡才。"]'),
('94686acf-6110-49f2-bb09-bd49f4df32ca','登杭州龍興寺三門樓','張祜','唐','唐诗','tang','','[]','十里江城下渺漫，兩層門上倚欄干。',66,'全唐诗/poet.tang.50000.json','["十里江城下渺漫，兩層門上倚欄干。", "偏宜竹翠山長潤，早見梅花地少寒。", "沙觜漸平人改路，潮痕初静鳥移灘。", "高樓酒夜誰家笛，一曲《凉州》夢裏殘。"]'),
('8bc20a00-130e-4ddd-b022-ba38fc772b5e','江上旅伯呈池州杜員外','張祜','唐','唐诗','tang','','[]','（按《全唐詩》卷五一一收此詩之前四句，缺其後半。',107,'全唐诗/poet.tang.50000.json','["（按《全唐詩》卷五一一收此詩之前四句，缺其後半。", "題作《江上旅伯呈杜員外》，今全錄之。", "）牛渚南來沙岸長，遠吟佳句望池陽。", "野人未必非毛遂，太守還須是孟嘗。", "江郡風流今絶世，杜陵才子舊爲郎。", "不妨酒夜因閑語，別指東山是醉鄉。"]'),
('31b4bec5-ec7e-43fe-910e-5820353a6e0e','題臨平驛亭','張祜','唐','唐诗','tang','','[]','津亭一望海西壖，舊說湖開是幾年。',64,'全唐诗/poet.tang.50000.json','["津亭一望海西壖，舊說湖開是幾年。", "風起半山雲出寺，雨餘深岸水平舡。", "竹林上拔高高笋，荷葉中藏小小蓮。", "長愛向南些子地，兩三家近野唐邊。"]'),
('33869a36-d15c-4cca-b242-129657d2eb8d','窮居','張祜','唐','唐诗','tang','','[]','陋巷長聞君子窮，我生寧免因儒宮。',80,'全唐诗/poet.tang.50000.json','["陋巷長聞君子窮，我生寧免因儒宮。", "辛勤自灌一畦韮，鹵莽還開三徑蓬。", "竹下喜逢青眼士，草中甘作白頭翁。", "佳期日暮不知處，把鈎（陳九思同志謂是「釣」字之訛。", "）徒吟江上風。"]'),
('668b42f8-4cf1-4af6-985b-e8381bcc4fa5','題贈崔權處士','張祜','唐','唐诗','tang','','[]','（按此詩亦見《永樂大典》卷一三四五○「二寘」「士」字「處士」條。',119,'全唐诗/poet.tang.50000.json','["（按此詩亦見《永樂大典》卷一三四五○「二寘」「士」字「處士」條。", "〖十四函一百三十七冊〗。", "）讀盡儒書鬢皓然，身遊城市（《大典》作「下」）意林泉。", "已因駿馬成三逕，猶恨胡麻欠一廛。", "真玉比來曾不磷，直鈎從此更誰憐？", "遺民莫恨無高躅，陶令而今亦甚賢。"]'),
('e2142c37-e2fc-4ed6-8f98-c790c2388fca','酬餘姚鄭摸（《大典》作「模」）明府見贈長句四韻','張祜','唐','唐诗','tang','','[]','（按此詩亦見《永樂大典》卷一一○○○「六姥」「府」字「明府」條。',106,'全唐诗/poet.tang.50000.json','["（按此詩亦見《永樂大典》卷一一○○○「六姥」「府」字「明府」條。", "〖十一函一百十冊〗）仙令東來值勝遊，人間稀遇一扁舟。", "萬重山色軍江徼，十里溪聲到縣樓。", "吏隱不妨彭澤遠，公才多謝武城優。", "生疎莫笑滄浪叟，白首直竿是直鈎。"]'),
('5e16814d-afb7-4b70-9a43-630e9b6be592','早秋貴溪南亭晚眺','張祜','唐','唐诗','tang','','[]','溪流照檻肅埃氛，百里秋光草樹分。',64,'全唐诗/poet.tang.50000.json','["溪流照檻肅埃氛，百里秋光草樹分。", "青壁峻時山背日，碧潭空處水銷雲。", "千尋下徹魚無隱，一點高飛鷺出羣。", "迴首故鄉人未去，亂蟬聲噪不堪聞。"]'),
('d799a1de-5f30-47a3-8090-d735ccc9b90d','壽州裴中丞出柘枝','張祜','唐','唐诗','tang','','[]','青娥十五柘枝人，玉鳯雙翹翠帽新。',64,'全唐诗/poet.tang.50000.json','["青娥十五柘枝人，玉鳯雙翹翠帽新。", "羅帶却翻柔紫袖，錦靴前踏沒紅茵。", "深情記處常低眼，急拍來時旋折身。", "愁見曲終如夢覺，又迷煙水漢江濱。"]'),
('19bf83aa-e89d-47f8-af3d-dad942523a0f','池州周員外出柘枝','張祜','唐','唐诗','tang','','[]','紅筵高設畫堂開，小妓粧成爲舞催。',64,'全唐诗/poet.tang.50000.json','["紅筵高設畫堂開，小妓粧成爲舞催。", "珠帽著聽歌遍匝，錦靴行踏鼓聲來。", "纖纖玉笋羅衫撮，戢戢金星鈿帶迴。", "長恐周瑜一私顧，不教閑客望瑤臺。"]'),
('8b53132b-2813-4285-9929-df9c447d4d75','贈柘枝','張祜','唐','唐诗','tang','','[]','鴛帶排方鏤綠牙，紫羅衫卷合懽花。',64,'全唐诗/poet.tang.50000.json','["鴛帶排方鏤綠牙，紫羅衫卷合懽花。", "當筵舞汗銷胸雪，入破凝姿動臉霞。", "帽側蹙腰鈴數轉，亞身招拍腕頻斜。", "須臾曲罷歸何處？稱道巫山是我家。"]'),
('2dee316a-0c0d-42f8-93e9-3d7bc23307d4','觀濠州田中丞出臘','張祜','唐','唐诗','tang','','[]','東城曉出静塵埃，紫畫神旗向日開。',64,'全唐诗/poet.tang.50000.json','["東城曉出静塵埃，紫畫神旗向日開。", "錦袖半攘争捧轡，銀鞍不下小傳盃。", "馬盤草上朱弓滿，鴈落雲中白羽迴。", "晚向三通殘皷盡，北原千騎卷行來。"]'),
('cefa5eaa-afb2-4668-a894-1ca3484bd33d','鍾陵旅泊','張祜','唐','唐诗','tang','','["\u957f\u6c5f"]','城衘西面驛堤連，十里長江夜看舡。',64,'全唐诗/poet.tang.50000.json','["城衘西面驛堤連，十里長江夜看舡。", "漁市月中人静過，酒家燈下犬長眠。", "龍笻迥泊灘聲下，略彴深行樹影邊。", "唯是南風還小瘴，與他歸去避衰年。"]'),
('ed120ae4-0e8b-454e-8a9b-50d79e05c5ec','湘中行','張祜','唐','唐诗','tang','','[]','南去長沙又幾程，二妃來死我來行。',64,'全唐诗/poet.tang.50000.json','["南去長沙又幾程，二妃來死我來行。", "人歸五嶺暮天碧，日下三湘寒水清。", "遠地毒虵冬不蟄，深山古木夜爲精。", "傷心靈跡在何處？斑竹廟前風雨聲。"]'),
('2e9d7727-8434-42c3-9122-978eb79cf2b4','秋日宿簡寂觀陸先生草堂','張祜','唐','唐诗','tang','','["\u5e90\u5c71"]','紫霄峯下草堂仙，千載空梁石磬懸。',145,'全唐诗/poet.tang.50000.json','["紫霄峯下草堂仙，千載空梁石磬懸。", "白氣夜生龍在水，碧雲秋斷鶴歸天。", "竹廊影過中庭月，松檻聲來半壁泉。", "明日又爲浮世恨，滿山行路夢依然。", "（見《吉石庵叢書》本陳舜俞《廬山記》卷四，題作《簡寂觀》，「空梁」作「空遺」，「竹廊」作「空遺」，「竹廊」作「竹房」，「鑾過」作「影占」，「行路」作「徒積」。", "）。"]'),
('032ad1bb-1476-4794-ade1-952b3e4d8295','投滑州盧尚書','張祜','唐','唐诗','tang','','[]','海內諸侯最屈名，不妨中立自經營。',64,'全唐诗/poet.tang.50000.json','["海內諸侯最屈名，不妨中立自經營。", "文翁莫猒分符久，韓信終須仗鉞行。", "静以軍威齊虎士，別將才力誚儒生。", "親筆幾話南遷客，未必無憂是早榮。"]'),
('978ebcc5-8f6e-4140-b55e-e6b4527779ee','送鄭灊判官歸冬寧','張祜','唐','唐诗','tang','','[]','結束翩翩肯寡悰，早時强學已三冬。',64,'全唐诗/poet.tang.50000.json','["結束翩翩肯寡悰，早時强學已三冬。", "鯉庭趍日通明訓，鄭曲歸時美盛宗。", "摘句競推梁記室，談經今紹漢司農。", "異聞不暇陳亢問，爾德無非是孝恭。"]'),
('3ea049dd-1b91-44d0-bb6f-19dc44d80cf5','經咸陽城','張祜','唐','唐诗','tang','','[]','阿房宮盡客誰來，可惜連雲萬戶開。',64,'全唐诗/poet.tang.50000.json','["阿房宮盡客誰來，可惜連雲萬戶開。", "秦地起爲千載業，楚兵焚作一場灰。", "應知長者名終在，祇是生人意不迴。", "何事暴成還暴廢，祖龍須死項須摧。"]'),
('34231cba-faf4-4f7a-b513-dfee49d77392','惠尼童子','張祜','唐','唐诗','tang','','[]','慢眉童子語惺惺，實爲天主自有靈。',79,'全唐诗/poet.tang.50000.json','["慢眉童子語惺惺，實爲天主自有靈。", "（「主」，嚴疑「生」之誤。", "）可惜綠絲梳黛髻，枉將纖手把銅瓶。", "低迴綩態傳師教，更學吳音誦梵經。", "不似俗家諸姊妹，朝朝畫得兩蛾青。", "。"]'),
('93dcad5c-2441-4a22-a374-acda014cfede','將之會稽先寄越中知友','張祜','唐','唐诗','tang','','[]','三年此路卻迴頭，認得湖山是舊遊。',48,'全唐诗/poet.tang.50000.json','["三年此路卻迴頭，認得湖山是舊遊。", "百里鏡中明月夜，萬重屏外碧雲秋。", "竹林雨過誰家宅，楊葉風生河處樓。"]'),
('8a439117-3395-4903-b072-f374ad69293b','陪杭州郡使讌西湖亭','張祜','唐','唐诗','tang','','["\u897f\u6e56"]','小亭移宴近雲端，十里山圖馬上看。',64,'全唐诗/poet.tang.50000.json','["小亭移宴近雲端，十里山圖馬上看。", "青壁遠光凌鳥峻，碧湖深影鍳人寒。", "詩成病愈生犀角，酒引嬌娃活牡丹。", "歸去不須愁暮雨，高唐神女屬仙壇。"]'),
('823d933f-f5c4-40e0-9ee0-a00b5d01a8de','杭州晚眺','張祜','唐','唐诗','tang','','[]','萬仞危峯厭渺漫，碧雲梢上倚欄干。',66,'全唐诗/poet.tang.50000.json','["萬仞危峯厭渺漫，碧雲梢上倚欄干。", "雲橫海鴈天風夕，月照城鵶水霧寒。", "行客待潮來遠渡，居人瞻火去平灘。", "蕭條醉臥誰家笛，一曲《梁州》夢裏殘。"]'),
('b7f728a4-49e4-4bdd-8bfc-f458f801caea','彈琴謌','張祜','唐','唐诗','tang','','[]','楚人玉琴怨聲苦，客欲聽時盡懷土。',64,'全唐诗/poet.tang.50000.json','["楚人玉琴怨聲苦，客欲聽時盡懷土。", "別鶴朝辭滄海雲，悲風夜入瀟湘雨。", "弄之不難聽者難，金徽冷冷流水寒。", "一曲自然堪下淚，三山不忍向君彈。"]'),
('ee111042-3c23-4324-9f94-200db76cf5cc','射虎詞','張祜','唐','唐诗','tang','','[]','高山路傍射虎兒，執弓走箭如星馳。',64,'全唐诗/poet.tang.50000.json','["高山路傍射虎兒，執弓走箭如星馳。", "一夫中虎人所異，萬夫圍虎人不知。", "崗頭少年羞弓箭，從此誓心休射虎。", "更使山頭白額來，萬金懸賞如泥土。"]'),
('eeafd616-062e-4e3f-9242-cba2f69a10ba','古鏡謌','張祜','唐','唐诗','tang','','[]','小兒行把街中劇，千年𥘴斗銅衣碧。',81,'全唐诗/poet.tang.50000.json','["小兒行把街中劇，千年𥘴斗銅衣碧。", "將金换得試磨看，俄見洞門深一尺。", "夜深時出仰照天，二十八宿中相連。", "青龍耀躍麟眼動，神鬼不敢當庭總之。", "明朝擎出遊都市，一半狐狸落城死。"]'),
('0d3d1cb6-94b8-401c-b450-182b2b5991b3','開聖寺','張祜','唐','唐诗','tang','','[]','西去山門五里程，粉牌書字甚分明。',64,'全唐诗/poet.tang.50000.json','["西去山門五里程，粉牌書字甚分明。", "蕭帝壞陵深虎跡，廣師遺院閉松聲。", "長廊畫剥僧形影，古壁塵昏客姓名。", "何必更將空理遣，眼前人事已浮生。"]'),
('ec876eb3-cb16-4e3e-8aee-053f3ebf1197','偶題','張祜','唐','唐诗','tang','','[]','微風和暖日鮮明，草色迷人向渭城。',78,'全唐诗/poet.tang.50000.json','["微風和暖日鮮明，草色迷人向渭城。", "越客捲簾閑不語，楚娥攀樹獨含情。", "紅垂菓蔕櫻珠重，黃點花鬢粉蝶輕。", "（「鬢」，嚴疑「鬚」之誤。", "）自是青樓無近信，莫將心事問卿卿。"]'),
('86b72a41-0eff-4077-a4f6-8d308c5e339d','曉別','張祜','唐','唐诗','tang','','[]','翠羽朱冠碧樹雞，未鳴先下短墻啼。',114,'全唐诗/poet.tang.50000.json','["翠羽朱冠碧樹雞，未鳴先下短墻啼。", "窗間謝女青蛾斂，門外蕭郎白馬嘶。", "斜漢繁星當燭盡，淡煙殘月映花迷。", "景陽宮裏晨鍾動，不語垂鞭上柳堤。", "（《全唐詩》卷五七八作溫庭筠詩，題作《贈知音》。", "別《才調集》卷二、《文苑英華》卷二八八亦作溫詩。", "）。"]'),
('7a94c00e-0a0e-4b8a-86de-93ecc4e572e3','上元懷古','張祜','唐','唐诗','tang','','[]','倚雲宮闕已平蕪，東望連天到海隅。',65,'全唐诗/poet.tang.50000.json','["倚雲宮闕已平蕪，東望連天到海隅。", "文物六朝興廢地，江山萬里帝王都。", "只聞丞相夷三族，不見扁舟泛五湖。", "遥想永嘉南過日，洛陽風景盡歸吳。", "。"]'),
('9060e332-b72c-421c-879d-90a710e40076','隋堤懷古','張祜','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u6000\u53e4"]','隋季窮兵復濬川，自爲猛虎可周旋。',64,'全唐诗/poet.tang.50000.json','["隋季窮兵復濬川，自爲猛虎可周旋。", "錦帆東去不歸日，汴水西來無盡年。", "本欲山河傳百二，誰知鍾鼎已三千。", "那堪重問江都事，迴望空悲綠樹煙。"]'),
('4351b470-b3b7-46a2-8329-1e450bac14bb','洛陽春望','張祜','唐','唐诗','tang','','[]','世事空悲衰復榮，慿音一望更添情。',79,'全唐诗/poet.tang.50000.json','["世事空悲衰復榮，慿音一望更添情。", "紅顏只向愛中盡，芳草先從愁處生。", "佳氣藹空迷鳯闕，綠楊抵水撓宮城。", "（「撓」，嚴疑當作「繞」。", "）遊執行駐馬煙花外，玉笛不利何處聲。"]'),
('db0a20c7-7a54-40c6-b0b7-4a6e8987bf97','灞上送客','張祜','唐','唐诗','tang','','[]','自省論心意不疑，五年風水因追隨。',64,'全唐诗/poet.tang.50000.json','["自省論心意不疑，五年風水因追隨。", "憐君有玉曾三獻，顧我無才忝一枝。", "煙隔灞亭人去日，雨迷秦樹鴈歸時。", "那知此夏罇前別，卻遣相如歎路歧。"]'),
('69e15ebb-d824-4be9-a191-1a2d58d6240f','經西溩偶題（按《全唐詩》卷五百七十七作溫庭筠詩，詩同，不重錄，校其異字如下：第二句「芳草無人情自迷」，《全唐詩》作「芳草無情人自迷」，是。四句「荇花唼喋青頭雞」，「荇」，「全唐詩」作「杏」，非。五句「微紅杏蔕惹蜂粉」，「杏」，《全唐詩》作「柰」。七句「借問含嚬向何許」，「許」，《全唐詩》作「事」，非。〖《文苑英華》卷一六一作溫詩。〗）','張祜','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.50000.json','["空。"]'),
('73d9da07-8db0-416e-a855-300d77d61ac6','喜聞收復河隴','張祜','唐','唐诗','tang','','[]','詔書頻降盡論邊，將擇英雄相卜賢。',78,'全唐诗/poet.tang.50000.json','["詔書頻降盡論邊，將擇英雄相卜賢。", "河隴已耕曾歿（陳九思同志疑當作「沒」。", "）地，犬羊誰辯却朝天。", "高懸日月胡沙外，遥拜旌旗漢壘前。", "共感垂衣匡濟力，華夷同見太平年。"]'),
('d456ab8d-32f2-4264-af12-6d2179ffc822','冬日幷州道中寄荆門舍','張祜','唐','唐诗','tang','','[]','聖明神武尚營邊，我是何人不控弦。',64,'全唐诗/poet.tang.50000.json','["聖明神武尚營邊，我是何人不控弦。", "身着貂裘隨十萬，心思白社隔三千。", "雲沉古戍初寒日，鴈下平陂欲雪天。", "却爲恩深歸未得，許隨車騎勒燕然。"]'),
('9d1e7af7-f861-47f8-aa63-0d8417c818fe','和李子智魯中使院前鑿池種蘆之什','張祜','唐','唐诗','tang','','[]','鑒地栽蘆貯碧流，臨軒一望似汀洲。',86,'全唐诗/poet.tang.50000.json','["鑒地栽蘆貯碧流，臨軒一望似汀洲。", "䓗籠好映淮南樹，疎野偏直海上鷗。", "歷歷迎風欹枕曉，蕭蕭和雨捲簾秋。", "君看范蠡功成公然上道煙波無去舟。", "（見《全芳備祖後集》卷十二《蘆》，缺題。", "）。"]'),
('6c83e8a1-2ad0-4df4-8dd0-59ddea35f906','長安感懷','張祜','唐','唐诗','tang','','[]','家寄東吳西入秦，三年虛度帝城春。',64,'全唐诗/poet.tang.50000.json','["家寄東吳西入秦，三年虛度帝城春。", "流光漸漸到華髪，離恨蕭蕭生白蘋。", "楚夢覺來愁翠被，越吟聲盡怨芳塵。", "更聞玉笛吹明月，一曲風前淚滿巾。"]'),
('d335d30c-c543-4399-96b4-78eac60a598f','題徐州流溝寺','張祜','唐','唐诗','tang','','[]','古寺層層結構勞，土岡前面峻如濠。',65,'全唐诗/poet.tang.50000.json','["古寺層層結構勞，土岡前面峻如濠。", "露雲竹翠石橋冷，風起松聲山殿高。", "日色動廊開木槿，夜陰生院結蒲桃。", "西龕禪客不相得，一片舊階行幾遭。", "。"]'),
('642342b4-871b-441e-92eb-d34c02ae3483','貧居遣憤','張祜','唐','唐诗','tang','','[]','築室枕隋流，貧居喜自由。',96,'全唐诗/poet.tang.50000.json','["築室枕隋流，貧居喜自由。", "未爲齊國悲，争免魯人丘。", "不畏長堪恥，無成久更羞。", "家須男子繼，國合丈夫憂。", "苟利他相與，誅當我自求。", "輪迴飜礙直，劒折却思柔。", "老虎終開眼，微蟲會叩頭。", "但令吾舌在，何畏不封侯。"]'),
('852966ee-e24a-40e8-be08-f9b7987aec6d','題弋陽徐明府水亭','張祜','唐','唐诗','tang','','[]','小邑不勞賢，心期勝地偏。',72,'全唐诗/poet.tang.50000.json','["小邑不勞賢，心期勝地偏。", "樹微青嶂聳，沙淺碧波旋。", "盪槳投昏岸，燒燔指濕煙。", "板簷傍眺寺，石路上登舡。", "水檻推衣浴，風軒側枕眠。", "無因長寄此，吟和酒中仙。"]'),
('d7d635b2-178e-4e6a-8bce-8a4cab75e2fa','題靈巖寺','張祜','唐','唐诗','tang','','["\u897f\u6e56"]','北寺三年別，西湖十里程。',96,'全唐诗/poet.tang.50000.json','["北寺三年別，西湖十里程。", "山門橋上轉，石路閣中行。", "地入千重險，江分一面平。", "引藤聞鼠亂，窺洞見龍驚。", "嶂月排簷出，屏風倚檻成。", "猿尋青壁過，樹遶碧崖生。", "小殿靈雲影，高廊下水聲。", "何當還夢謝，盡我一詩情。"]'),
('58c8a928-d5a2-47b1-a798-ab2dfae569f2','題天竺寺','張祜','唐','唐诗','tang','','[]','臺殿聳高摽，鐘聲下小子遥。',137,'全唐诗/poet.tang.50000.json','["臺殿聳高摽，鐘聲下小子遥。", "路分松到寺，山斷石爲橋。", "引水穿廊去，呼猿繞檻眺。", "海明初上月，法白正來潮。", "夏雨蓮苞破，秋風桂子彫。", "（「夏雨」二句，《嘉泰會稽志》卷九引。", "《全唐詩》卷五一一據《海錄碎事》收入。", "）亂雲行沒脚，欹樹過低腰。", "嫩綠茶新焙，乾黃竹旋燒。", "唯思閑事了，長此臥煙霄。", "。"]'),
('2c222379-ec1f-4db6-8139-3beacfee795c','讀韓文公集十韻','張祜','唐','唐诗','tang','','[]','天縱韓公愈，才爲出世英。',122,'全唐诗/poet.tang.50000.json','["天縱韓公愈，才爲出世英。", "言前風自正，筆下意先萌。", "塵土曾無跡，波瀾不可名。", "詞高碑益顯，疏直事終明。", "片段隨冰釋，絲毫入鏡清。", "文彫玉璽重，詩織錦梭輕。", "別得春王旨，深㳂《大雅》情。", "窮奇開蜀道，詭恠哭秦坑。", "驥逸終難襲，鵰蹲力更生。", "誰當死後者，別爲破規程。"]'),
('3c553821-94d7-4c7e-84b8-10cc3d8c9c2d','題岳州徐員外雲夢新亭十韻','張祜','唐','唐诗','tang','','[]','古地摽圖籍，新亭建梓材。',122,'全唐诗/poet.tang.50000.json','["古地摽圖籍，新亭建梓材。", "水從三峽漲，人自九江來。", "宿涵曹推遠，停驂謝喜陪。", "山形連岳去，草色盡天迴。", "晚檻高牆出，晴郊古戍開。", "陽精動金礦，暗魄孕珠胎。", "竹换經冬葉，松移帶雨栽。", "夜深南浦鴈，春老北枝梅。", "山峴嶺功初畢，汀洲詠幾裁。", "仙遊秪斯在，何用便蓬萊。", "。"]'),
('0e25d279-b3ea-4c2e-a34d-714a42830450','吳中懷古十六韻','張祜','唐','唐诗','tang','','[]','萬里江連蜀，千山水占吳。',214,'全唐诗/poet.tang.50000.json','["萬里江連蜀，千山水占吳。", "地形分楚塞，舟路控閩隅。", "西北京華遠，東南王氣無。", "未爲勾踐入，先是子胥殂。", "國破重泉恨，天迷兆庶乎。", "黑煙宗廟廢，紅艷美人駈。", "舊戰儲宮盡，新加太宰誅。", "拆言江北死，羞面角東途。", "假僨屍猶泊，教懸骨未枯。", "墮釵殘玉鷰，穿墓得金鳧。", "苑樹深行鹿，閶門逈噪烏。", "夜陰生越絕，秋色遍姑蘇。", "羣邑空遺跡，山川是廢圖。", "六朝人已去，三國事應殊。", "欲下金陵泣，還爲建業吁。", "傷心此時意，狂乞賴麻襦。", "（本卷均見南宋蜀刻本《張承吉文集》卷九。", "）。"]'),
('ad67dcea-a2e9-4f1b-86d8-37197b2522b3','和岳州徐員外雲夢新亭二十韻','張祜','唐','唐诗','tang','','[]','澤國連荒徼，津亭揭上游。',256,'全唐诗/poet.tang.50000.json','["澤國連荒徼，津亭揭上游。", "飛欄控乾馬，却住壓坤牛。", "（「却住」，嚴疑應作「却柱」。", "）滉漭吞何處，青蒼別幾州。", "黑天三伏裏，紅日五更頭。", "樹失湘潭髪，山明楚塞漚。", "舜巡初此去，禹鑿向南休。", "白氣都爲曉，清光別是秋。", "雨行神女過，雲降帝妃遊。", "接鑑凌星斗，褰簾就月鈎。", "草煙凝夜思，花露滴春愁。", "近渚延沙濕，中壖小島浮。", "竹尋諸洞遍，石占一泉幽。", "日復上山頂，波連歸客舟。", "招𩲑宋餘恨，吊死屈何投。", "臣子悲遷斥，王孫念去留。", "林當藏漢道，兵昔益巴丘。", "縛將高皇策，燒舡太祖羞。", "星霜人自變，江漢事長流。", "勝景離方絕，功符坎德優。", "還因望京意，歌詠爲皇猷。"]'),
('bc87d881-d4b2-46a4-baa6-923814fddd96','投陳許崔尚書二十韻','張祜','唐','唐诗','tang','','["\u6cf0\u5c71"]','重鎮壓華戎，恩威達聖聰。',240,'全唐诗/poet.tang.50000.json','["重鎮壓華戎，恩威達聖聰。", "泰山高不讓，滄海闊難窮。", "接物懽盈貌，安民術在衷。", "旱天雲出水，霜野鶚摶風。", "東土承殊渥，南方著顯功。", "瑞呈須是鳯，畋獲必非熊。", "令下齊軍仵，詩傳入帝宮。", "春行膏雨降，夜仰德星藂。", "翰苑推詞敏，台庭揖道崇。", "才周儒學外，禮厚笑譚中。", "吏理今廉度，文章昔馬融。", "行慿孤竹立，諾爲一言終。", "揭檻樓臺聳，加籩海陸豐。", "俯移青玉案，高掛綠沉弓。", "大幕賓名瑀，長裾客姓馮。", "耻爲狂狷者，強廁滑稽雄。", "馬足虛行地，鞭頭漫畫空。", "無能甘畫虎，失趣奈雕蟲。", "死歎身何處，生嗟命不通。", "聊當問詹尹，猶許訴明公。"]'),
('26d4f7cb-40e0-4523-96ff-6849a1572887','酬房子客郊居六韻','張祜','唐','唐诗','tang','','[]','三畝田東竹一墟，習家深處自安居。',96,'全唐诗/poet.tang.50000.json','["三畝田東竹一墟，習家深處自安居。", "每逢山簡能騎馬，長羨王弘不賣魚。", "南國煙帆低晚岸，北林霜葉墮寒蔬。", "郡中舊指賢哉巷，門外多來長者車。", "近日稍聞池盡墨，他時誰見壁藏書。", "已知每提能携酒，同倚閶門四檻虛。"]'),
('1b7490fe-c3d2-4907-837a-0c8b5e83befd','觀潮十韻','張祜','唐','唐诗','tang','','["\u94b1\u5858\u6c5f"]','泯泯順爲迴，泙泙逆是來。',120,'全唐诗/poet.tang.50000.json','["泯泯順爲迴，泙泙逆是來。", "草微淹澤莽，沙漲積雲堆。", "不止靈威怒，當慿恠力推。", "夏天江疊雪，晴日海奔雷。", "近落痕猶淺，初平勢漸開。", "舟驚浮浩渺，石看打崔嵬。", "鳥下愁灘沒，人行畏岸頹。", "鼓風連涵澹，值洑更旋迴。", "進退隨蟾魄，虛盈合蚌胎。", "何妨俾巨浸，爲爾濟川才。"]'),
('886e5d0d-ae10-431e-adf8-d66636854b43','觀《山海圖》二首 其一','張祜','唐','唐诗','tang','','[]','古色辨微茫，華夷在一堂。',96,'全唐诗/poet.tang.50000.json','["古色辨微茫，華夷在一堂。", "雲霞開藻井，天地出雕梁。", "細草生毫末，輕風拂黛光。", "夜山猶帶景，秋樹不凋霜。", "隱竹纔分翠，穠華欲墮香。", "無風帆自起，度日鳥空翔。", "舟勢鯨吞久，樓形蜃吐長。", "更看臺上鏡，造化落中央。"]'),
('424f9a6e-8057-408b-91be-4942133d6609','觀《山海圖》二首 其二','張祜','唐','唐诗','tang','','[]','何人筆思狂，一壁盡滄浪。',72,'全唐诗/poet.tang.50000.json','["何人筆思狂，一壁盡滄浪。", "日月明丹拱，煙雲起畫梁。", "山嵐開曉色，海氣動秋光。", "島踞鰲睛大，沙行鰐齒長。", "粉波明百越，黛點簇三湘。", "詎作無圖意，空迷造化鄉。"]'),
('c15a3482-9915-40be-a533-ea5ad8d4381c','題海陵監李端公後亭十韻','張祜','唐','唐诗','tang','','[]','古城連廢地，規畫自初心。',120,'全唐诗/poet.tang.50000.json','["古城連廢地，規畫自初心。", "眺出紅亭址，裁成綠樹林。", "竹欹叢岸勢，池滿到簷陰。", "暗草通溪遠，閑花落院深。", "上簾新鷰入，拋葉小魚沉。", "晚影移罇惜，殘芳秉燭尋。", "風蘭曳衣繡，露柳柫頭簪。", "屬詠聊題極，垂竿旋屈針。", "短橋多凭看，高堞幾登臨。", "漫廁賓階末，無因和至音。"]'),
('3ae06bee-e8ad-4a7d-abbd-f22b890d2f4b','題江陵崔兵曹林亭','張祜','唐','唐诗','tang','','[]','小隱蜀江邊，重巒盡一川。',97,'全唐诗/poet.tang.50000.json','["小隱蜀江邊，重巒盡一川。", "山形分斷岸，水勢盡平田。", "嫩碧生欄淺，輕紅落砌蔫。", "短橋扶竹過，欹路把藤緣。", "南巷纖埃隔，東郊遠思延。", "月庭潛潤石，風渚自移舡。", "滴露蒲光冷，摇波柳翠鮮。", "關心每來勝，幸爾必相然。", "。"]'),
('9d140e14-2712-48ed-86ba-33f5abb15921','題宿州城西宋徵君林亭','張祜','唐','唐诗','tang','','[]','數畝四郊地，紐帶勝漸偏。',72,'全唐诗/poet.tang.50000.json','["數畝四郊地，紐帶勝漸偏。", "磴崖欹入竹，筒水下澆田。", "黑壤霑河潤，紅葩寄樹鮮。", "驛明昏岸火，檣插曉林煙。", "嫩笋撑簷曲，新荷帖沼圓。", "不妨成隱顯，長日步通阡。"]'),
('c98078a0-ace6-4b84-aaf9-d25914d4accd','題泗州劉中丞郡中新樓。','張祜','唐','唐诗','tang','','[]','一檻構庭上，臨川望益崇。',96,'全唐诗/poet.tang.50000.json','["一檻構庭上，臨川望益崇。", "朗懷披夏日，高嘯得清風。", "紫府須黃霸，青山屬謝公。", "夜聲聞動草，春意覺抽叢。", "野迥雲初白，天寒樹間紅。", "月華深委素，淮色逈流空。", "暮雨佳人到，良辰樂事同。", "更憐初渡水，先詠子來工。"]'),
('afa2c29f-abc4-49f1-b054-954ce8ad73c2','奉和湖州蘇員外題游柸池','張祜','唐','唐诗','tang','','[]','舊勝因金剎，新遷就水堂。',72,'全唐诗/poet.tang.50000.json','["舊勝因金剎，新遷就水堂。", "何勞數爵筭，不止一龜航。", "忝座非珎席，窮源喜濫觴。", "酒醲開若醖，詩妙掇蘋芳。", "廣檻餘清景，連山疊霽光。", "徒思繼高韻，益歎謬成章。"]'),
('05f9c1ae-7fb1-4d58-b558-0211feb466bb','奉和浙西盧大夫題假山','張祜','唐','唐诗','tang','','[]','入門驚秀崪，規畫自奇人。',72,'全唐诗/poet.tang.50000.json','["入門驚秀崪，規畫自奇人。", "遠不離堦砌，高寧讓隙塵。", "巖成須夢說，岳就合生申。", "掩映深尤妙，踈通久更新。", "聊思峴嶺日，小認會稽春。", "好是怡情處，西樓長景真。"]'),
('7c477b22-0ef3-48ee-86d4-b9403d805cb6','越州懷古','張祜','唐','唐诗','tang','','[]','振檝大江東，前林波萬頃。',73,'全唐诗/poet.tang.50000.json','["振檝大江東，前林波萬頃。", "高秋海天闊，色落湖山影。", "行尋王謝迹，望望登絕嶺。", "荒林草木瘦，古樹泉石冷。", "昔游不可見，牢落餘風景。", "窮愁心未死，一筆聊復秉。", "。"]'),
('d6a68d36-0253-4ad1-b072-188bac2f1ca6','晚下彭澤','張祜','唐','唐诗','tang','','[]','斜日照鳥當，（「鳥當」，嚴疑當作「馬當」。',89,'全唐诗/poet.tang.50000.json','["斜日照鳥當，（「鳥當」，嚴疑當作「馬當」。", "）孤舟下彭澤。", "平分江九派，斂度山一壁。", "淺浦橫黑查，高林間白石。", "帆收天益暝，鳥沒嵐更碧。", "依依戍前鼓，稍稍村外笛。", "何處上面眠人，月明西楚客。"]'),
('20048999-ed26-4905-aed8-8eaacb0f0bac','游仙','張祜','唐','唐诗','tang','','[]','赤足一仙翁，耳毫垂兩頸。',108,'全唐诗/poet.tang.50000.json','["赤足一仙翁，耳毫垂兩頸。", "摩娑雪毛項，騎上崑崙頂。", "顧我踨鹿蹄，去遊遐寂境。", "洞門出昏黑，却望如側井。", "行折青桂枝，隔雲敲石屏。", "空巖響深徹，臺觀凝碧冷。", "風觸瓊樹花，動摇天水影。", "端衣禮真貌，心目明耿耿。", "願侶牧羊兒，休休在崖嶺。"]'),
('105e186b-9ce9-46a8-a184-7412aa966c3b','寓言','張祜','唐','唐诗','tang','','[]','江海一遺叟，塊然窮巷居。',210,'全唐诗/poet.tang.50000.json','["江海一遺叟，塊然窮巷居。", "門前是川陸，反背臥枕袪。", "興來座援琴，忽忽味《關雎》。", "但願致樽酒，豈憂無斗儲。", "野牧亦乘馬，家池還釣魚。", "偶思榮啓期，益喜鬢白初。", "日夕粗充飢，呼兒掇園蔬。", "行登逸民舟，坐愧長者車。", "倐值體中佳，未嘗廢三餘。", "理生且自昧，安忍限衆徂。", "屏迹豈無素，立誠非甚踈。", "杜門草《太玄》，落草賦《子虛》。", "大賈傾十萬，一名終不書。", "小人苟片善，言下輙紀渠。", "不然少年長，百萬看一樗。", "過此任老圃，笑歌立倚鋤。", "道門演空言，未必死錄除。"]'),
('119155b5-27ae-4d3a-9123-a9697b04bf06','題池州杜員外弄水新亭','張祜','唐','唐诗','tang','','[]','廣廈光奇輩，恢材卓不羣。',98,'全唐诗/poet.tang.50000.json','["廣廈光奇輩，恢材卓不羣。", "夏天平岸水，春雨近山雲。", "婉衍榱甍揭，端完柱石分。", "孤帆驚乍駐，一葉動初聞。", "晚檻餘清景，涼軒啓碧氛。", "賓筵習主簿，詩版鮑參軍。", "露灑新篁滴，風含秀落葉松薰。", "何勞思峴嶺，虛望漢江濱。"]'),
('a7977676-d92c-4ff9-a9c6-254090d87cb7','戊午年寓興二十韻','張祜','唐','唐诗','tang','','[]','大道開王室，辛勤自賈生。',257,'全唐诗/poet.tang.50000.json','["大道開王室，辛勤自賈生。", "白衣逢聖主，青眼賴時英。", "一路來邊海，三年別上京。", "淚因南國盡，心向北辰傾。", "咄咄中途事，栖栖此日行。", "登封期未卜，弔汩恨空盈。", "謫見天何再，勤憂詔未幷。", "漢胡當重理，魏相昔權兵。", "《葛藟》機尤巧，《鴟鶚》義可精。", "（「鴟鶚」當作「鴟鴞」。", "）舊恩移保傳，初論激公卿。", "後學稽前古，先儒制未萌。", "朱雲曾痛憤，劉向幾吞聲。", "日月今纔朗，煙塵久未清。", "詎聞高鳥盡，終俟小鮮烹。", "坦坦前王道，雄雄近世名。", "帝圖殷太甲，人鏡魏文貞。", "逸足期千里，窮鱗渴一泓。", "徵賢寧乏詔，進善豈無旌。", "狡兔當寒伏，荒雞半夜鳴。", "殷勤在伊呂，爲我致昇平。"]'),
('fee1d418-d1c1-44c1-9707-d89ab86bc120','投陳許李司空二十韻','張祜','唐','唐诗','tang','','[]','上將出東征，驊騮得路行。',240,'全唐诗/poet.tang.50000.json','["上將出東征，驊騮得路行。", "青雲仰高步，白日見精誠。", "朗抱韜羣物，沉思活庶氓，田文今得士，孫武舊能兵。", "曉月當樓色，秋鞞入地聲。", "鬼神愁運思，姦猾恐迴情。", "破敵連收柵，屯師立下城。", "龍觀淮甸虎，鱣視海湄鯨。", "勇冠臨危貌，勳崇定遠名。", "突圍親斬首，開道看擒生。", "陳變虵頭出，槍迴豹尾橫。", "束衣金甲冷，揮箭鐵鞭鳴。", "歷戰長諸葛，封侯小富平。", "去淮初五馬，遷滑再雙旌。", "道秪蕭何直。", "功惟范蠡成。", "感恩懷敢炙，知味渴和羹。", "曙閤銅牌入，昏堂蠟燭明。", "玉鈎紅袖把，銀注紫衣擎。", "接坐羞人識，還家畏嫂輕。", "猶希匹夫膽，一向信陵傾。"]'),
('458bc439-8f42-428b-8160-d9898d764176','投魏博田司空二十韻','張祜','唐','唐诗','tang','','[]','聖代倚龍驤，青油鎮北方。',240,'全唐诗/poet.tang.50000.json','["聖代倚龍驤，青油鎮北方。", "國除心腹病，時詠股肱良。", "兆栛周畋吉，言應禹拜昌。", "中台初復位，太白定揚光。", "傳癖深元凱，籌謀奧子房。", "率先供帝命，特地舉朝綱。", "吏改新曹局，民耕舊戰場。", "節旌窮海島，詩句起河梁。", "幕府推賢佐，杯盤任客狂。", "峯巒資秀崪，鵰鶚避軒昂。", "列座花茵展，鳴鼉錦臂攘。", "小旗鞍馬令，尖帽柘枝娘。", "掃路麾幢出，開衙斧鉞行。", "旌旗垂玳瑁，黃帕結鴛鴦。", "報主親臨敵，屯師首犯彊。", "裂紅偷賊號，纏褐眩戎裝。", "夜柵迴千馬，昏鼙亞萬鎗。", "桉聲鋪陣血。", "垂淚撫刀瘡。", "豹望因文變，鯤期假翅翔。", "空勞千里役，何策利梁王。"]'),
('bb69e2a6-91d2-4816-bab1-40c9fab7fa5b','投魏博李相國三十二韻','張祜','唐','唐诗','tang','','[]','天意兆昇平，忠良自間生。',289,'全唐诗/poet.tang.50000.json','["天意兆昇平，忠良自間生。", "二年移四鎮，一夜破重城。", "白刃來臨敵，青油引出京。", "指途諳老馬，望海哂長鯨。", "國用鞭頭筭，軍機帳下萌。", "王師初戮力，賊將首推誠。", "鼎鼐傳家世，藩隅易弟兄。", "風雲將氣合，才命與時幷。", "咳唾收齊土，瘡痍肓蔡甿。", "指撝從上策，談笑賴高情。", "發號方迴踵，歸農務散兵。", "紫微纔近侍，彤矢又專征。", "曲直須繩準，幽深藉鏡明。", "曉江流汗漫，秋華聳崢嶸。", "士勇思陳力，兒啼畏道名。", "文王開卦兆，武帝下星精。", "遠寄恩彌厚，深欺敵不勍。", "儉風敦制度，和氣茂逢迎。", "畫障朱軒設，蠻刀粉壁橫。", "木魚連錀動，金獸齒環獰。", "舞席宮鬃出，賓盤海饌盈。", "繡蹄紅毬臥，花領紫絛縈。", "鵷鷺初移府，熊羆夜烈營。", "（「烈」，嚴疑當作「列」。"]'),
('0664d216-e289-4807-b27b-c5f15fbc5c19','讀《西漢書》十四韻','張祜','唐','唐诗','tang','','[]','日月中華正，星辰上國偏，經綸今四海，討伐舊三邊。',168,'全唐诗/poet.tang.50000.json','["日月中華正，星辰上國偏，經綸今四海，討伐舊三邊。", "失道非無素，乘時不偶然。", "安劉機在早，誅呂計須權。", "禮樂勝殘後，干戈止殺前。", "未聞晁氏戮，初幸賈生緣。", "善馬來何利，窮兵去甚堅。", "國讎因破虜。", "民耗是求仙。", "忍憤中郎節，殘形太史編。", "冲融當魏邴，靦衍自昭宣。", "故老心徒切，先皇道益懸。", "元成真漸地，哀少卒崩天。", "七廟傾王莽，三公敗董賢。", "興亡豈無誡，爲看借秦篇。"]'),
('8e8c7362-fba6-4e37-ae1a-7fd2ddc72799','苦旱','張祜','唐','唐诗','tang','','[]','河上勞兵地，江南酷旱天。',240,'全唐诗/poet.tang.50000.json','["河上勞兵地，江南酷旱天。", "那知討邢日，不是尅殷年。", "忽忽嗟時難，矜矜畏序愆。", "雲徒蔽日月，雨合降山川。", "造化爐思火，陰陽炭鼓煙。", "披懷遭赤晝，濯足想清漣。", "獄俟于公決，心期戴令虔。", "敢忘霑霈澤，俁幸及私田。", "請禱誠明矣，焚巫策昧然。", "靈山罷齊景，美玉罄周宣。", "石鷰曾誰舞，泥龍愈自堅。", "魚窮悲涸轍，井漆奈枯泉。", "五畝憂還軫，三時望益懸。", "蹔欣垂滴瀝，終訝阻纏綿。", "貶損心應懇，踈通稅必蠲。", "乘軒嘗拯物，飲馬昔投錢。", "火宅逢僧話，炎荒想客遷。", "泥蟠尺蠖久，草長蒺藜先。", "病體長兼慮，窮愁益自煎。", "猶希畏途上，一詠凱歌旋。"]'),
('f576969d-9fb6-4fc0-9ad4-b2149b127bd4','苦雨二十韻','張祜','唐','唐诗','tang','','[]','積雨江城久，騰雲海嶠來。',240,'全唐诗/poet.tang.50000.json','["積雨江城久，騰雲海嶠來。", "暑當初縝絺，寒亦重然灰。", "曖昧連中夏，調和仰上台。", "地平天沒塹，舟利木兼材。", "電影窗遙入，雷聲轍乍迴。", "邊除深溢潦，枕簟去浮埃。", "太陸青蘋泛，曾崖白浪豗。", "初跳倒蛙黽，疾長半蒿萊。", "壞壤虛爲穴，淙沙逈作堆。", "未如歸結網，何憚渴操杯。", "漏屋誠難葺，崩牆不易坯。", "遠愁超滉瀁，高羨陟崔嵬。", "俯祝陰靈遍，聊飡水物該。", "病非宜長老，憂是主嬰孩。", "淺淺斟茶鼎，環環盪酒罍。", "濯枝憐鳥噤，流麥分人咍。", "日色疑羞出，天心似惜開。", "巨鱗承水使，纖介幸時災。", "折角巾全委，低頭柱頓摧。", "神龍曾未失，螻蟻莫相裁。"]'),
('31cba378-c223-40d2-b9cf-811018999cf3','陪楚州韋舍人北閶門遊宴','張祜','唐','唐诗','tang','','[]','柘岸齊空遠，通波跨檻牢。',240,'全唐诗/poet.tang.50000.json','["柘岸齊空遠，通波跨檻牢。", "四方人意便，兩路馬行高。", "霧柳蒙疎葉，風帆掛並艘。", "碧雲秋水靜，紅日暮霞韜。", "苟藉公心度，稀逢敏手操。", "舊恩重雨露，新命壓波濤。", "挹海驚涯涘，冲霄訝羽毛。", "絲綸初變體，錦袖旋揮毫。", "美景尤難卜，良辰不易遭。", "名華應獨步，語韻洽朋曹。", "異日知司衮，閑時解夢刀。", "卿材尊宦達，侯業重人豪。", "拽盞憐稀飲，扶鞍哂遽逃。", "香鳧深促坐，畫鷁遠迴篙。", "賭氣連呼采，縻心乍漱醪。", "俁妨孤憤激，肯忘一言褒。", "北闕承優話，南方續廣騷。", "不嘗書咄咄，誰話酒陶陶。", "末路猶提筆，雄藩佇擁旄。", "只愁迂蹇步，歸去又蓬蒿。"]'),
('e078d89c-442a-496c-b12f-b69b15c815c2','又陪楚州韋舍人閶門遊讌次韻北閶門','張祜','唐','唐诗','tang','','[]','遠派通催急，層欄架柱牢。',240,'全唐诗/poet.tang.50000.json','["遠派通催急，層欄架柱牢。", "中開一閤靜，外拔兩簷高。", "㼘崪基崇岸，灣環隘近艘。", "勁竿紅旆展，長鐙紫囊韜。", "舊好千金諾，新題一筆操。", "開懷侵月露，惜別話風濤。", "盡納黃泥水，平分沼沚毛。", "詩能拘咫寸，酒妙乏絲毫。", "不止才無敵，非論運合遭。", "宦情周上智，美論逸諸曹。", "擬義臨戎鉞，從容宰社刀。", "三千藂秀彦。", "百萬舉名豪。", "死士曾無悔，生民肯更逃。", "下簾欣繼燭，歸路止排篙。", "綵柚撩青鬢，金舡泛白醪。", "韻慙高手壓。", "文豈拙詞褒。", "賈誼猶興歎，楊雄重返騷。", "不當離急引，應獲在甄陶。", "強逐騑騑駟，徒瞻孑孑旄。", "何堪縱高祖，生意任庭蒿。"]'),
('d3b41f79-cf5e-478d-8d4b-93bbbe994acb','投太原李司空','張祜','唐','唐诗','tang','','[]','煙塵繞北京，千里動人情。',241,'全唐诗/poet.tang.50000.json','["煙塵繞北京，千里動人情。", "位壓中華險，功排上將榮。", "四方分萬石，三鎮擁雙旌。", "大郡爲深寄，河湟仗素城。", "雄才身挺拔，柱石勢映傾。", "霍氏勳元重，胡家正本清。", "殊恩酬義勇，積慶自忠貞。", "海岱乘時出，風雲得氣生。", "虎頭膺將號，龍額擅侯名。", "麴蘗功歸酒，塩梅味到羹。", "碧霄長日路，黃犬少年行。", "號令誅旡軌，觀風審未萌。", "物情周智用，賓禮盡逢迎。", "促座杯心亞，開場鏡面平。", "神隈旗幹動，虎占地衣獰。", "紫綬分排馬，青娥亂替觥。", "魚金垂重獺，羅袖拂毬輕。", "暖閤朝呈簡，深簾夜按笙。", "栖遑窮蔡澤，孱弱病劉楨。", "試暗秦臺下，應迴照膽明。", "。"]'),
('aff8eba5-568b-4bf3-acbe-d46e99b7a77c','獻太原裴相公三十韻','張祜','唐','唐诗','tang','','["\u9ec4\u6cb3"]','萬古元和史，功名將相殊。',263,'全唐诗/poet.tang.50000.json','["萬古元和史，功名將相殊。", "英明逢主斷，直道與天符。", "一鏡辭西闕，雙旌鎮北都。", "輪轅歸大匠，劒戟盡洪爐。", "物望朝端洽，人情海內輸。", "重輕毫在手，斟酌斗迴樞。", "邴吉真丞相，陳蕃實丈夫。", "禮賓青眼色，憂國白髭鬚。", "幾賴平中土，長愁入五湖。", "旱苗今雨活，妖沴共風驅。", "料敵窮天象，開邊過地圖。", "黃河歸博望，青塚破兇奴。", "虎豹皆親射，豺狼例手誅。", "坐籌千不失，持鉞四無虛。", "勇義精誠感，溫良美價沽。", "夔龍甘道劣，賈馬分材枯。", "曙色開營柳，秋聲動塞榆。", "縱橫追穴兔，直下灌城狐。", "舉論當前古，推心及後儒。", "風雲如借便，開眼即天衢。", "（本卷均見南宋蜀刻本《張承吉文集》卷第十。", "）。"]'),
('9da5d218-0cb7-47d1-bb56-77a5ec129165','途次楊州贈崔荆二十韻','張祜','唐','唐诗','tang','','[]','逆旅楊州郭，音容幸此遭。',240,'全唐诗/poet.tang.50000.json','["逆旅楊州郭，音容幸此遭。", "酒漿曾不罷，風月更何逃。", "寺塔排雲直，閭門架水牢。", "煙籠春樹薄，日映曙樓高。", "碧草連除卷，青旗指濁醪。", "粉胸斜露玉，檀臉慢迴刀。", "躍馬君心勁，嗔奴我氣亭。", "尾生從抱柱，顏子也酺糟。", "赤柏看眉睫，生憎惜羽手。", "北邙終寂寞，南國且遊𢕟。", "觱篥行移束，箜篌旋轉絛。", "袖因迎顐破，肩爲請挼勞。", "未省求媒氏，焉能泥賊曹。", "揀花偷芍藥，和葉窠櫻桃。", "悶口無端語，窮頭盡興搔。", "覆身唯綠葛，醫病只青蒿。", "事過宜他哂，詩成苟自褒。", "醉時心爛漫，別夜眼號咷。", "接席觀誠忝，升堂跡貴叨。", "殷勤欲離抱，爲爾一揮毫。"]'),
('2e9f74cf-3810-476d-8da7-30393b80e83a','投宛陵裴尚書二十韻','張祜','唐','唐诗','tang','','[]','憶拜明公日，青雲料果符。',240,'全唐诗/poet.tang.50000.json','["憶拜明公日，青雲料果符。", "徵賢披顯詔，射策冠英儒。", "物論推前哲，朝綱揖大巫。", "德門深茂秀，義土闢膏腴。", "簡翰垂師法，文章述帝謨。", "民歡車轍至，士畏履聲趨。", "省闥名尤美，藩方政歷殊。", "五兵森武庫，百氏祕文樞。", "小謝才難比，諸荀道亦具。", "幾年思樂土，長日詠生蒭，潔儉遵明訓，清通軌令圖。", "馬奔爲信竹，鞭舉示刑蒲。", "促座嘉賓滿，分題健筆濡。", "碧江秋鳥聚，青漳瞑猿孤。", "月上連城璧，星環合浦珠。", "早涼生玉樹，盛暑退冰壺。", "豹變真君子，龍鍾淺丈夫。", "新知多巂彥，舊態只狂奴。", "敢望憐哀鳥，何煩敬朽株。", "已愁沾洒淚，還去海西隅。"]'),
('90a2e6bf-b0fe-44ff-bf43-be4843fd9914','庚子歲寓遊楊州贈崔荆四十韻','張祜','唐','唐诗','tang','','[]','窮賤正相仍，逢君又廣陵。',288,'全唐诗/poet.tang.50000.json','["窮賤正相仍，逢君又廣陵。", "坐愁身兀兀，行信脚騰騰。", "小巷朝歌滿，高樓夜吹凝。", "月明街廓路，星散市橋燈。", "鈍僕常羞使，贏驂半醉乘。", "酷遭狂客引，剛被俗人憎。", "睚眦寧宜慣，趦趄苟未能。", "坊期瑞芝宿，閣詢慶雲登。", "逈眺江千里，高臨塔九層。", "山嵐開碧罅，海日上紅稜。", "曲岸盤回出，飛欄斗峻凭。", "鷺鷥行淺草，龜殻上新菱。", "野霽崗形兀，林昏地氣蒸。", "春天聊共賞，夏日幾同瞢。", "自給勞方寸，官沽厭窄升。", "堅强心似石，險峭志如陵。", "悶極行挑耳，狂來起扼肱。", "腸風終作疹，肺病不爲徵。", "玉樹當巡打，香毬帶柏承。", "暗歸逃酒席，私語結鈎朋。", "僻性從他論，幽情且自矜。", "砌開紅艷槿，庭架綠陰藤。", "冷滑連心簟，輕疎着體繒。", "被裁新蜀錦，光砑小吳綾。"]'),
('8b37264a-d203-4cc3-b147-971b7966ffab','遊蔚過昭陵十六韻','張祜','唐','唐诗','tang','','[]','天意亡隋日，人心啓聖年。',248,'全唐诗/poet.tang.50000.json','["天意亡隋日，人心啓聖年。", "順時興義卒，撥亂起戎旃。", "羣盗猶蜂蟻，妖星尚屬聯。", "既教龍戰野，須見血成川。", "睿筭無遺策，神功亦有權。", "王尋徒百萬，光武只三千。", "（原注：太宗嘗以騎兵三千破僞夏十萬於虎牢。", "）海静鯨鯢死，雲開日月懸。", "講兵將耀德，獵渭本搜賢。", "向闕皆鏘玉，臨關罷控弦。", "大鑪銷劒戟，鴻澤盪腥膻。", "太祖恩堯禪，（原注：武德末，天下既平，高祖致政。", "）神孫受禹傳。", "（原注：貞觀既終，高宗嗣位。", "）宮車悲未已，陵樹藹蒼然。", "岳立青冥外，虬蟠白水邊。", "乾坤資王氣，巖壑擁晴煙。", "虞爮曾南狩，軒轅亦上仙。", "斷髯無復見，空拜鼎湖前。"]'),
('4ab4bfb6-37db-4014-8487-53bfe55e15e1','敍詩','張祜','唐','唐诗','tang','','[]','二雅泄詩源，滂滂接漣漪。',300,'全唐诗/poet.tang.50000.json','["二雅泄詩源，滂滂接漣漪。", "宣尼昔道{卄/氵史}，豁豁無阻疑。", "小開作涇港，大漲爲塘陂。", "可令萬頃澄，可使百派支。", "生民苟灌溉，九穀長蕃滋。", "何意束晳徒，《補亡》輒繼之。", "安知去聖遠，立旨無乖隳。", "五言起李陵，其什傷遠離。", "雄材耻小用，屬詠隅成規。", "後時班婕妤，團扇託憂悲。", "枚情既云妙，蔡韻肯容卑。", "建安陳思王，龍變五不知。", "劉楨骨氣真，王粲文質奇。", "阮公先興亡，陸氏以才推。", "雅怨止潘子，高摽存左思。", "延年得殊致，靈運拔英姿。", "沈侯美玉蘊，謝守文錦摛。", "江詞騁奇妙，鮑趣出孤危。", "飄飄喜澤翁，於在務脫遺。", "陳隋後諸子，往往沙可披。", "拾遺昔陳公，强立制頹萎。", "英華自沈宋，律唱{牙丿=丶}相維。", "其間豈無長，聲病爲深宜。", "江寧王昌齢，名貴人可垂。"]'),
('08978ad6-2097-4f42-a579-fc71623735b2','大唐聖功詩','張祜','唐','唐诗','tang','','[]','祜聞昔隋末。',293,'全唐诗/poet.tang.50000.json','["祜聞昔隋末。", "煬帝厄圍兵。", "太宗初應募，杖劎起邊征。", "揚師列虛旗，首激將軍誠。", "神略在一斷，解圍當未萌。", "高祖守河東，權力已兼幷。", "猖狂蟻結徒，舉踵乃擊平。", "隋德日已衰，俯折士尊名。", "羣才{牙丿=丶}相枤，諾以義爲盟。", "屯軍起邊州，李密馳傳迎。", "楊眉愛姿度，失口真王英。", "由是太河南，千里響應聲。", "降王與拘竇，親待入宮城。", "乃命臣蕭瑀，府庫掌虛盈。", "次命臣玄齡，圖書收付卿。", "開牢釋姧枉，各更重從輕。", "迴戈略僞主，太廟告明明。", "殊功苟未已，徽號爲重旌。", "文物一以興，賢良俱間生。", "聲詩日盈聽，智論益縱橫。", "何意蕭牆內，陰謀中構傾。", "直詞雖可進，王法詎該情。", "甲子上即位，南郊赦憲灜。", "八蠻與四夷，朝貢路交争，三月后親蠶，癸亥上親耕。"]'),
('9f48917a-e5a1-4013-b538-0e6995727431','元和直言詩','張祜','唐','唐诗','tang','','["\u9ec4\u6cb3"]','東野小臣祜，聖朝垂淚言。',264,'全唐诗/poet.tang.50000.json','["東野小臣祜，聖朝垂淚言。", "微塵豈裨助，永負丘山恩。", "箕子昔爲奴，所悲逢世昏。", "明時便鉗舌，切恐負乾坤。", "臣當涉黃河，心目日且煩。", "分明在人世，不喻波渾渾。", "願以所支流，却尋到崑崙。", "但窮此生感，沒齒寧爲寃。", "臣讀帝王書，粗知治亂源。", "文思苟未安，詎得賓四門。", "陛下欲垂衣，一與夔契論。", "成湯事不盡，勿更隨波翻。", "直者舉其材，曲者尋其根。", "直固不可遺，曲亦不可焚。", "用材苟端審，帝道即羲軒。", "陛下復土階，四方敢高垣。", "陛下喜雕牆，四方必重藩。", "畋獵豈無娛，湯泉豈無溫。", "始知堯爲心，清淨自成尊。", "比干不憚死，諫道久而存。", "許由不務策，志士亦所敦。", "兢兢小臣祜，萬死甘詞繁。"]'),
('55f15946-e21f-4ea8-ba0a-76a6e229f393','旅次岳州呈徐員外','張祜','唐','唐诗','tang','','[]','襄漢止薄遊，登舟捨羸策。',281,'全唐诗/poet.tang.50000.json','["襄漢止薄遊，登舟捨羸策。", "浮名乃閑事，且作山水客。", "遠持屠龍伎，南訪賈誼跡。", "連崗黯雲樹，斜日半赤壁。", "青水去悠悠，青山來歷歷。", "囊無一金備，不省爲計畫。", "村旗{牙丿=丶}誇酒，咺薄升斗窄。", "提筆猒班超，把詩憐阮籍。", "徐公岳陽守，遇我心的的。", "湖鮮爲我鱠，湖藻爲我摘。", "得吟多高樓，得語多末席。", "平生負微志，不獨詩酒溺。", "終懷咸谷泥，定刻燕然石。", "會公饒迎餞，微懇私已識。", "逢時魯連輩，一局如博奕。", "憂來獨求醉，兀兀臨大澤。", "屈原誠褊人，自死終何益。", "南湖雪晴夜，星月林摵摵。", "君山洞門叟，相語鶴兩隻。", "風松座翹𣍿，向月吹玉笛。", "笑命詩思苦，莫信狂李白。", "於狂是空疎，於仙是遐謫。", "寄言徐太守，人在無金液。"]'),
('d9e79943-6773-45dc-9ad0-a9754b7821f2','登香爐峯寄遠人','張祜','唐','唐诗','tang','','[]','前登香爐峯，却指湓城郡。',121,'全唐诗/poet.tang.50000.json','["前登香爐峯，却指湓城郡。", "大江北潮海，崇岳南作鎮。", "相逢虎溪子，輕策聊一振。", "水石動寒光，風松洒高韻。", "憂來月成語，忽忽千里憤。", "六朝空遺文，三國無尺燼。", "孤禽下雲久，遠樹入煙盡。", "客恨猒山重，歸心喜流順。", "故執行瀟湘別，即此無音信。", "憔悴十年心，誰人不緇磷。"]'),
('4798de2e-7340-47dc-8ad0-fe123a8e39ef','丹陽新居四十韻','張祜','唐','唐诗','tang','','[]','不出丹陽郭，茅簷寄北偏。',288,'全唐诗/poet.tang.50000.json','["不出丹陽郭，茅簷寄北偏。", "四隅疎積潦，萬頃控平田。", "地勢金陵豁，灣形珥瀆連。", "路分南畝上，山映後湖邊。", "故國心殊阻，新池手強穿。", "閑吟招隱詠，靜賦篤終篇。", "大樹應徒爾，高門亦偶然。", "孤雲出小嶼，侶鶴下遼天。", "早巿歸人語，昏亭醉客眠。", "五更衘月岸，一宿渡江舡。", "雪旦飛瓊圃，花時麗錦川。", "茅峯遙自對，練水曲相㳂。", "夜出澤頭火，晴昏巷裏煙。", "人情嗤散漫，鳥性樂暄妍。", "夏菓垂簪上，春農起面前。", "竹欄隈杳嫋，藤杖決潺湲。", "不忝端居勝，何妨病者便。", "水軒斜浸柳，風檻散披蓮。", "接壤重崗抱，坯沙淺洞延。", "外瞻羣嶺拔，中坐兩崖顛。", "峻面嶙岣甃，崇臺碨礧填。", "小橋深宛宛，新瀑下涓涓。", "架俯薔薇立，籬因枳殻編。", "何當把牙筭，祇是躡苔錢。"]'),
('d771c4a5-677d-4739-a2d3-fe315101b73d','憶江東舊遊四十韻寄宣武李尚書','張祜','唐','唐诗','tang','','[]','憶作江東客，猖狂事頗曾。',290,'全唐诗/poet.tang.50000.json','["憶作江東客，猖狂事頗曾。", "海隅思變化，雲路折飛騰。", "小子今何述，高賢昔謬稱。", "瘦體休問馬，病爪莫論鷹。", "海棹扁舟泛，江開一檻憑。", "岸環青莽蒼，峰峭碧崚嶒。", "水國程無盡，煙郊思不勝。", "金絲援嫩柳，玉片犯殘冰。", "夜伯度操檝，朝行看下罾。", "沙明春雨霽，野白暮雲蒸。", "蒲晚帆山葉，花開鏡水菱。", "亂芳叢沼沚，餘溜泄溝塍。", "鷲嶺因支訪，龍門詣李登。", "黃鸎春惱客，白鶴夜依僧。", "粗得狂歌趣，深疑笑病癥。", "地窮屯健馬，天盡抑飛鵬。", "桂彩分城堞，松香在閣層。", "酒徒窮不破，詩債老相仍。", "伯玉年將近，宣尼《易》未弘。", "歲儲雖自乏，社肉必均秤。", "造化三光借，乾坤一塊凝。", "才當論曲直，命可繫衰興。", "鳳鳥非無歎，驊騮靡不乘。", "豹文須蔚蔚，羊目漫睖睖。"]'),
('966e155e-8eae-430f-abcc-337bcd0c9a42','戊午年感事書懷二百韻謹寄獻太原裴令公淮南李相公漢南李僕射宣武李尚書','張祜','唐','唐诗','tang','','[]','塞色深河曲，江聲接海壖。',293,'全唐诗/poet.tang.50000.json','["塞色深河曲，江聲接海壖。", "一生勞遠地，萬事誡中年。", "失路爲閑物，無官入長錢。", "高蹤非隱遁，下界即狂顛。", "漸老稀時輩，歸休著近篇。", "星明知帝座，琴妙覺商絃。", "闕下非才入，江南是性牽。", "山猿拾蟲豸，野鳥避鷹鸇。", "戲傲東方朔，文輕司馬遷。", "萬言成弃置，五字失雕鐫。", "去外尋莊叟，生涯挈道詮。", "新秋唯白髪，舊欠祇青氊。", "志業寧常墮，窮耕豈素便。", "高低徇雞日，得失付魚筌。", "醉臥捫雲扃，狂歌上釣舡。", "古桐收取好，壞屋薦來偏。", "（原注：祜累蒙方鎮論薦。", "）却猒長裙曳，寧辭短褐穿。", "憤窮多自樂，不佞少人憐。", "靜祝旄頭矢，閑看馬腹鞭。", "長途思逐日，高閣夢凌煙。", "讀《易》刪王註，通《詩》斷鄭箋。", "灰心志射鵠，火性急韋編。", "昔命公稱許，嘗封國是燕。"]'),
('277abb5e-74fb-48f6-9014-cb86a25e44ce','夢李白','張祜','唐','唐诗','tang','','["\u5e90\u5c71"]','我愛李峨嵋，夢尋尋不見。',334,'全唐诗/poet.tang.50000.json','["我愛李峨嵋，夢尋尋不見。", "忽聞海上騎鶴人，云白正陪王母宴。", "須臾不（陳九思同志疑「大」字之訛。", "）醉下碧虛，搖頭逆浪鞭赤魚。", "迴眸四顧飛走類，若嗔老氣多終諸。", "問余曰張祜，爾則狂者否？", "朝來王母安瑤池，茅君道爾還愛酒。", "祜當聽我言，我昔開元中，生時值明聖，發迹恃文雄。", "一言可否由賀老，即知此老心還公。", "朝廷大稱我，我亦自超羣。", "嚴陵死後到李白，布衣長揖萬乘君。", "玄宗開懷死（陳九思同志疑當作「樂」。", "）其說，滿朝呼吸生氣雲。", "中人高力士，脫驊（疑是「鞾」之誤。", "「鞾」，同「靴」。", "）羞欲樂。", "（陳九思同志疑當作「死」。", "）讒言密相構，送年千萬里。", "辛苦夜夜歸，知音聊復稀。", "青雲舊李白，憔悴爲酒客。", "自此到人間，大蟲無肉喫。", "男兒重意氣，百萬呵一擲。", "董賢在前官亦崇，梁冀破家金謾積。", "匡山夜醉時，吟爾古風詩。"]'),
('ebfe4c22-dd0c-43b0-8e74-feb29fecddcf','句','楊洵美','唐','唐诗','tang','','[]','暮鵶不噪禁城樹，衙鼓未殘賓衛秋。',51,'全唐诗/poet.tang.50000.json','["暮鵶不噪禁城樹，衙鼓未殘賓衛秋。", "（賓衛，《唐詩紀事》卷五一作「兵衛」。", "）（見唐張爲《詩人主客圖》。", "）。"]'),
('baa5bd9c-026e-4595-97a5-e1f22562c80f','七絕一首','杜牧','唐','唐诗','tang','','[]','嵓□□□萬木中，□□特地一枝紅。',271,'全唐诗/poet.tang.50000.json','["嵓□□□萬木中，□□特地一枝紅。", "擬攀叢棘□寥寂，□□□香感細風。", "（見陸心源《吳興金石記》卷四。", "《吳興金石記》云此詩在顧渚山，詩前有序，已殘泐，錄如次：「□於□□□□爲大中五年刺史樊川杜牧奉貢訖事季春□休來□□□七言。", "」詩及序又見《兩浙金石志》卷三，但殘泐更甚，詩中第二句「特地」作「時池」，似誤。", "）（《吳興金石記》陸心源案畧云：「拓本高一尺三寸，廣二尺三寸，字徑二寸，……談錀《吳興志》：牧於大中四年十一月授湖州刺史。", "逾年，以考功郎中知制誥，遺愛塞路。", "公退之餘，登臨賦詠，碧瀾消暑，俱有留題。", "蓋亦不知顧渚之有詩刻石也。", "《樊川集》亦未收。", "」）。"]'),
('c7674015-09cf-4d61-9143-16d4442637c2','宣州開元寺贈惟直上人','許渾','唐','唐诗','tang','','[]','曾與徑山爲小師，十年僧行衆人知。',109,'全唐诗/poet.tang.50000.json','["曾與徑山爲小師，十年僧行衆人知。", "夜深月色當禪處，齋後鐘聲到講時。", "經雨綠苔侵古畫，過秋紅葉落新詩。", "勸君莫厭江城客，雖在風塵別有期。", "（見丹徒陳慶年刊《橫山草堂叢書》本《許渾詩真蹟錄》。", "）（《全唐詩》卷五二六誤作杜牧詩。", "）。"]'),
('6c4945f9-696c-41c3-90ca-b55b864c2e72','茅山題徐校書隱居','許渾','唐','唐诗','tang','','[]','深居四十年，語舊淚潺潺。',259,'全唐诗/poet.tang.50000.json','["深居四十年，語舊淚潺潺。", "官滿春辭省，兵來夜出關。", "思隨江鶴遠，心寄海鷗閒。", "莫訝頻相訪，前峯似故山。", "（同前。", "）（案唐許渾烏絲欄真蹟，宋岳珂《寶真齋法書贊》著錄之，其跋畧謂「右唐郢州刺史許渾所書烏絲欄詩一百七十一篇真蹟，分上下凡二卷。", "纖組閒錯，辭格華古，筆妙爛然，見爲三絕」云云。", "《橫山草堂叢書》陳慶年跋謂：「用晦真蹟自敍云：『編集新舊五百篇』。", "《全唐詩》編丁卯詩至五百三十餘著，逾於郢州自紀之數，丁卯之詩，宜若一無所遺。", "乃《宣州開元寺贈惟直上人一首》與《茅山題徐校書隱居一首》明載於真蹟中者，即爲《全唐》摭拾所不及。", "」）。"]'),
('b34f1e29-1c24-41c6-a372-bc2d5b6cb1de','訪白雲山人','李商隱','唐','唐诗','tang','','[]','瀑近懸崖屋，陰陰草木青。',106,'全唐诗/poet.tang.50000.json','["瀑近懸崖屋，陰陰草木青。", "自言山底住，長向月中畊。", "晚雨無多點，初蟬第一聲。", "煮茶歸未去，刻竹爲題名。", "（見《永樂大典》卷三○○四「九真」「人」字〖五函四十一冊〗。", "）（周建國云此詩可信，義山另有《白雲夫舊居》詩可參。", "）。"]'),
('6a12a7c2-34e1-4f43-8804-8b629c306494','謁華嶽廟','賈竦','唐','唐诗','tang','','["\u534e\u5c71"]','老柏寒颼颼，清祠晝寂寂。',398,'全唐诗/poet.tang.50000.json','["老柏寒颼颼，清祠晝寂寂。", "開門華山北，嵐氣沉日夕。", "國家崇明祀，五岳盡封冊。", "福我西土民，報君金天籍。", "惟神本貞信，以道徵損益。", "無力惑聰明，訛言縱巫覡（原作「●●」）。", "因循作風俗，相與成（《雍州金石記》作「舊」）溺。", "疲病閭里甿，錐刀往來客。", "（《雍州金石記》作「役」。", "）我行歲云暮，登殿拜瑤席。", "奠酒徹明靈，緒言多感激。", "欝然展冠冕，凜若生矛戟。", "斑駮石色重，陰深香煙碧。", "虹梁無燕雀，玉座鎮虺蜴。", "肸（原作「{肹八=丷}」）蠁似有聞，依俙（《雍州金石記》作「稀」，通。", "）疑所覿。", "髫年業文翰，弱冠薦屯厄。", "天命幾微茫，神逵徒悚惕。", "今來遊上國，幸遇陶唐曆。", "正直不吾欺，願言從所適。", "（見《金石萃編》卷一百五，以《惜陰軒叢書》《雍州金石記》校其異。", "）（〖1〗石刻詩後原題《唐元和元年十月二十八日。", "姪男宣義郎行華州參軍琡太和六年四月廿六日重修》。", "〖2〗朱彝尊《曝書亭集》：元和元年十月，著作郎河南賈竦《謁華岳廟》賦五言詩題名。"]'),
('ca84ad38-8755-4f1e-b380-bccc999b83b7','涇川野居晚望','劉得仁','唐','唐诗','tang','','[]','地極接穹蒼，西維落太陽。',74,'全唐诗/poet.tang.50000.json','["地極接穹蒼，西維落太陽。", "泉聲入深稻，山色出南崗。", "風起蘆兼荻。", "煙生柘與桑，歸來坐幽石，半壁冷蟾光。", "（見《分門纂類唐歌詩》殘本第一冊《天地山川類》。", "）。"]'),
('f484ee42-1e04-4497-9b2c-17cee3fc3439','白龍潭','繆島雲','唐','唐诗','tang','','[]','中有白龍盤，偷湫見說難。',48,'全唐诗/poet.tang.50000.json','["中有白龍盤，偷湫見說難。", "風雲隨步起，雨雹出山寒。", "鳥道懸青壁，天河瀉碧湍。", "軒皇曾向此，金鼎煉還丹。"]'),
('40fd3cb1-3658-4e7e-9a03-f57af83ab8aa','遊黃山懷古','繆島雲','唐','唐诗','tang','','["\u9ec4\u5c71"]','浮丘與軒后，鶴馭杳難思。',48,'全唐诗/poet.tang.50000.json','["浮丘與軒后，鶴馭杳難思。", "三十六峯頂，不知何處奇。", "枯杉龍腦溢，陰洞石膏垂。", "莫問當時事，蒼苔鎖斷碑。"]'),
('02fc2f92-eb29-46cd-be7b-f57d14ab1fa1','登天都峯','繆島雲','唐','唐诗','tang','','[]','盤空千萬仞，險若上丹梯。',48,'全唐诗/poet.tang.50000.json','["盤空千萬仞，險若上丹梯。", "迥入天都裏，回看鳥道低。", "他山青點點，遠水白凄凄。", "欲下前峯暝，巖間宿錦雞。"]'),
('aed89c3c-defe-4b66-a44a-5f65ae8c1271','馬跡石','繆島雲','唐','唐诗','tang','','[]','堪信曾鸞駕，尋僊道已成。',49,'全唐诗/poet.tang.50000.json','["堪信曾鸞駕，尋僊道已成。", "因過盤石上，如印玉沙行。", "苔逐方圓匝，泉隨深淺生。", "臨迴山色暮，拂拂翠雲平。", "。"]'),
('50eb7566-0bb3-4a8f-a58f-7b0a69c1a882','望黃山諸峯','繆島雲','唐','唐诗','tang','','["\u9ec4\u5c71"]','峰峰寒列簇芙蕖，靜想嵩陽秀不如。',64,'全唐诗/poet.tang.50000.json','["峰峰寒列簇芙蕖，靜想嵩陽秀不如。", "峭拔雖傳三十六，參差何啻一千餘。", "浮丘處處留丹竃，黃帝層層隱玉書。", "終待登臨最高頂，便隨鸞鶴五雲車。"]'),
('769bab0d-5322-431b-85ae-2a14be2c73c5','湯泉','繆島雲','唐','唐诗','tang','','[]','暖泛朱砂石壁幽，軒皇曾浴上丹丘。',64,'全唐诗/poet.tang.50000.json','["暖泛朱砂石壁幽，軒皇曾浴上丹丘。", "陰陽相煮連珠浦，今古長煎瀉鏡流。", "紫氣曉籠煙色澹，錦霞明照火光浮。", "何方爲洗身輕後，便跨飛龍到十洲。"]'),
('f66e71ab-1ac5-4b7a-bd8b-6aead6cc415e','朱砂石','繆島雲','唐','唐诗','tang','','[]','寒巖萬丈陟崔嵬，只恐朱砂勢便頹。',64,'全唐诗/poet.tang.50000.json','["寒巖萬丈陟崔嵬，只恐朱砂勢便頹。", "採蘩客聞雷擘去，臥雲僧見鳥銜來。", "丹霞迥爍嵌空片，紅日斜分突兀堆。", "儻得神僊惠纖粟，便能輕舉向瑤臺。"]'),
('2826f893-d4af-4160-8cf8-86b09e3660f2','石人峯','繆島雲','唐','唐诗','tang','','[]','雙峯何代列巍巍，忽化僊人世所稀。',64,'全唐诗/poet.tang.50000.json','["雙峯何代列巍巍，忽化僊人世所稀。", "絕頂長年相對坐，九天何日却同歸。", "風生松柏喧天樂，山隱雲霞挂道衣。", "終願捫蘿一相訪，共君齊跨鳯鸞飛。"]'),
('1e1263bf-14bd-4de4-941e-9d129214e49e','僊僧洞','繆島雲','唐','唐诗','tang','','[]','先朝曾有日東僧，向此乘龍忽上昇。',65,'全唐诗/poet.tang.50000.json','["先朝曾有日東僧，向此乘龍忽上昇。", "石徑已迷紅樹密，蘿龕猶在紫雲凝。", "鉢盂峯下留丹竃，錫杖前邊隱聖燈。", "從此舊庵遺跡畔，月樓霜殿一層層。", "。"]'),
('188acf91-fb17-49d8-8d83-199775bae8f7','僊橋','繆島雲','唐','唐诗','tang','','["\u9ec4\u5c71"]','千丈側懸飛鳥外，雙峯橫架碧天心。',113,'全唐诗/poet.tang.50000.json','["千丈側懸飛鳥外，雙峯橫架碧天心。", "月中纔有僊人過，山下應聞笙磬音。", "丹竃路穿瑤草濕，朱砂泉迸錦霞深。", "軒轅去後雖然在，爭奈凡流無處尋。", "（以上十首均見康熙十八年閔麟嗣撰《黃山志定本》卷六。", "）（〖1〗繆島雲逸詩承儀徵吳白匋先生見告。", "）。"]'),
('e16e960d-f066-45e2-8772-a88b5fa09c2d','覽卷贈張山人','趙嘏','唐','唐诗','tang','','[]','五字誰能摘？一枝猶未攀。',80,'全唐诗/poet.tang.50000.json','["五字誰能摘？一枝猶未攀。", "始知無價玉，出自有名山。", "春靜烟花秀，夜深風月閑。", "如何恃高節，垂老住雲間。", "（見《永樂大典》卷三○○四「九真」「人」字〖五函四十一冊〗。", "）。"]'),
('d68b75ec-b677-4283-9ef5-35294e4f7316','惠泉','宇文鼎','唐','唐诗','tang','','[]','璞玉耀荆山，山根竇玉泉。',289,'全唐诗/poet.tang.50000.json','["璞玉耀荆山，山根竇玉泉。", "有聲清出籟，凝色碧於天。", "曉靜微涵日，春晴淺浸煙。", "巖花紅影密，啼鳥下沙壖。", "（見《湖北金石志》。", "）（〖1〗詩末原題「寶曆□年二月廿一日」九字。", "〖2〗《湖北金石志》：「案石碑高二尺四寸，寬三尺一寸，首行書『惠泉』二字，次行漫漶莫辨，當是作詩人姓名。", "中六行行書五律一首云〖詩不重錄〗。", "末行書『寶曆□年二月廿一日』，字徑二寸許。", "案鄭漁仲《金石畧》載荆門軍有宇文鼎《惠泉詩》。", "新舊《唐書》無鼎傳，《全唐詩》亦未之及。", "是刻雖闕其名，然以年號與鄭氏所載證之，詩爲文鼎作無疑。", "唐代詩人湮沒無聞者，正復不少，今荆門象山石壁留此《惠泉》詩刻，以傳文鼎之名，不可謂非幸矣。", "」）。"]'),
('16598afb-e829-460d-8f4d-4cb6298e9a7d','聳翠峰題石（原注：峯在袁州府城西三十里。）','盧肇','唐','唐诗','tang','','[]','聳翠峰高千百尺，四時常似莓藍色。',135,'全唐诗/poet.tang.50000.json','["聳翠峰高千百尺，四時常似莓藍色。", "卓然萬古鎮祗園，世代鬼工驅不得。", "巍巍直上插青天，遠疑似與天相連。", "韎臨下視羣山小，千里平鋪在眼（一作「目」）前。", "藤蔓交加生薜荔，土毛蒼蘚相蒙蔽。", "風翦雲開雨歇時，飛出一山新翡翠。", "日迴影倒落前溪，煙波湛湛浸琉璃。", "更將何物可比類，分明一隻擎天柱。"]'),
('576d0850-5a8b-4275-ab24-45f723a7330a','綠陰亭','盧肇','唐','唐诗','tang','','[]','亭邊古木晝陰陰，亭下寒潭百丈深。',198,'全唐诗/poet.tang.50000.json','["亭邊古木晝陰陰，亭下寒潭百丈深。", "黃菊近連陶令宅，青山遙負（一作「償」）向平心。", "人歸別浦村煙斂，魚躍澄波檻水沈。", "更愛玉琴調惠政，爲君登此一開襟。", "（按《全唐詩》止有前四句，今從《臨江府志》錄全。", "）（《全唐詩續補遺》卷十據《隆慶臨江府志》卷十三收此詩，題下注：「在新喻縣右，俯臨袁江。", "」「亭邊」作「亭間」，「百丈」作「百尺」，「近連」作「舊連」，「向平」作「子平」，「檻水」作「檻影」。", "今刪彼存此。", "）。"]'),
('cc0d859d-e13c-4ea7-88e8-b7735d131dc9','弔進士楊鄴','盧肇','唐','唐诗','tang','','[]','名未榮身親在堂，九重泉路去何忙。',64,'全唐诗/poet.tang.50000.json','["名未榮身親在堂，九重泉路去何忙。", "夫妻鏡裏鸞分影，兄弟雲中雁斷行。", "林木蕭疏花失色，池亭牢落月無光。", "思君欲向靈山哭，又恐猿聞更斷腸。"]'),
('4acbee46-fbf2-4b4e-b740-f98ed3ae0a1f','戲宜春李令求廳前杜鵑','盧肇','唐','唐诗','tang','','[]','杜家有女小名鵑，生在陶公吏案前。',103,'全唐诗/poet.tang.50000.json','["杜家有女小名鵑，生在陶公吏案前。", "百里望風驚調態，千金買笑愜當筵。", "預防戶外鋤蘭地，莫把籬東種菊田。", "爲問河陽妖艷主，聘財卻（一作「都」）要幾多錢？", "（以上四詩均見《豫章叢書》《袁州二唐人集》中《文標集》卷下。", "）。"]'),
('0cf02b7f-f3b8-44b5-8ea0-8574d7f14b6a','句','李貽孫','唐','唐诗','tang','','[]','羣烏幸胙餘。',304,'全唐诗/poet.tang.50000.json','["羣烏幸胙餘。", "（見宋陸游《入蜀記》卷六。", "）（〖1〗《入蜀記》卷六頁十一〖《知不足齋叢書》本〗：「祠舊有烏數百，送迎客舟。", "自唐夔州刺史李貽孫詩已云羣烏幸胙餘矣。", "」〖2〗李貽孫，原作李貽。", "李貽孫曾官夔州刺史，《全唐文》卷五四四收其會昌五年撰《夔州都督府記》，《金石錄》卷九著錄會昌五年九月「唐李貽孫《神女廟詩》」。", "陸游在述巫山神女祠中景物時引及此句，應即《神女廟詩》之殘句。", "）（兩《唐書》無李貽孫傳，今參張忱石所考，補傳如次：李貽孫，字里不詳。", "大和初任福建團練副使，會昌五年爲夔州刺史，大中三年任左諫議大夫充宏文館學士，大中五年任福建觀察使。", "又曾任金部、司勳員外郎。", "約卒于大中六年後。", "原列「無考」作者，今移此。", "）。"]'),
('0d338455-830f-4a45-bfc6-0a62d26da8e0','新安郡北百餘里即黃山西北有山峯高出頗類大華因目爲小華山前郡守才客題詠至多偶登斯樓因成一絕','任宇','唐','唐诗','tang','','["\u9ec4\u5c71"]','雪晴雨霽潼關道，僊掌分明幾度逢。',55,'全唐诗/poet.tang.50000.json','["雪晴雨霽潼關道，僊掌分明幾度逢。", "可料新安郡樓上，黃山深處見三峯。", "（見康熙十八年閔麟嗣撰《黃山志定本》卷六。", "）。"]'),
('da97fe48-3ea1-42bd-b08f-9b7f5efe5c26','','裴休','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.50000.json','["。"]'),
('d326c8d9-75d5-4000-8888-9f0e2f222838','太平興龍寺詩（題擬）','裴休','唐','唐诗','tang','','["\u5e90\u5c71"]','麟臺朝士辭書府，鳯闕禪宗出帝京。',172,'全唐诗/poet.tang.50000.json','["麟臺朝士辭書府，鳯闕禪宗出帝京。", "當堰雙林親惠遠，行過五老訪淵明。", "白衣居士輕班爵，敗衲高僧薄世情。", "引得病夫無外想，一身師事竺先生。", "（見《永樂大典》卷六六九九。", "十八陽。", "江字（七函六十四冊）。", "餘參閱本書卷三崔融詩附注。", "此詩又見《吉石庵叢書》本陳舜俞《廬山記》卷四，原題甚長。", "岑仲勉《唐方鎮年表正補》考證應爲裴坦作，是。", "另詳《全唐詩續拾》卷三十二。", "）。"]'),
('7c0f46bb-10f5-4850-9b20-91e24f1dff9f','白鶴觀水閣題詩（題擬）','鄭畋','唐','唐诗','tang','','[]','松陰如幄水如羅，秋盡山青白鳥過。',122,'全唐诗/poet.tang.50000.json','["松陰如幄水如羅，秋盡山青白鳥過。", "獨坐一庵心正寂，數聲何處竹枝歌。", "（見《永樂大典》卷二三四三「六模」「梧」字「梧州府」引《輿地紀勝》云「白鶴觀在州西。", "咸通末，鄭畋守蒼梧，建水閣，題詩」。", "）（此詩見《太平寰宇記》卷一六四、《輿地紀勝》卷一○八。", "）。"]'),
('6dd09de2-74fb-404a-885b-4e9cd16af659','','張濬','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.50000.json','["。"]'),
('3d34f75a-2bc1-44b2-8177-82c898b3b14a','山居洞前得杜鵑花走筆偶成以□（八瓊室本作「簡」）桂帥僕射兼寄呈廣州僕射劉公','張濬','唐','唐诗','tang','','[]','桂（八瓊室本作「幄」）中籌策知無暇，洞裏□花別有珍（八瓊室本作「春」。',287,'全唐诗/poet.tang.50000.json','["桂（八瓊室本作「幄」）中籌策知無暇，洞裏□花別有珍（八瓊室本作「春」。", "）獨酌高吟問山水，到頭山景屬何（八瓊室本作「閑」）人。", "（見《金石續編》卷十二，又見《八瓊室金石補正》卷七十七。", "）（桂林市文管會近年普查石刻，編爲《桂林石刻》三冊，第一冊收此詩較完整。", "題中「以□」二字作「用別」，前二句異文均同《八瓊室金石補正》，「□花」作「觀花」，末句「何人」作「詩人」。", "）（按石刻於詩題下原署曰「河間張濬」。", "又此詩之後有嶺南節度使劉崇龜和詩一首，《全唐詩》卷七百十五收之。", "石刻於劉詩之後有「韓寧元年三月廿七日將仕郎前守監察御史張巖書」一行。", "《廣西通志·金石略》謂石刻在臨桂龍隱巖下。", "）。"]'),
('d0c0f19e-3d90-4701-beb6-075b8b397074','送凌處士赴連州邀','李濤','唐','唐诗','tang','','[]','連山羣書至，策馬出長安。',229,'全唐诗/poet.tang.50000.json','["連山羣書至，策馬出長安。", "落日對酒別，晚關衝雪寒。", "霜飛湖草綠，春近嶺梅殘。", "知己雲霄在，那言欲掛冠。", "（見北京圖書館藏《永樂大典》卷一三四五○「二寘」「處士」條。", "）（按唐有兩李濤，其一長沙人，與溫庭筠同時，《全唐詩》卷七百九十五收詩句六句。", "其一字信臣，避地湖南，事馬殷，後唐天成中進士，歷仕晉、漢，至宰輔，入周，封莒國公，後歸宋，《全唐詩》卷七百三十七收詩一首，又卷八百七十《諧謔二》收詩一自，卷八百七十一《諧謔三》收歇後語兩句。", "此李濤頗疑係溫庭筠同時之李濤。", "）。"]'),
('2c23eb99-403d-4bea-bf4d-f72a14dd9ef4','奉和元孚大德（亦依本韵）','王謩','唐','唐诗','tang','','[]','華頂高峯接太虛，承攀琪樹賦垂珠。',120,'全唐诗/poet.tang.50000.json','["華頂高峯接太虛，承攀琪樹賦垂珠。", "當時惟有建公在，老宿如今一半無。", "（見明陶宗儀《古刻叢鈔》，與元孚詩同刻一石。", "）（案詩原署「中散大夫行台州司馬賜魚袋王謩幷書」。", "又刻後紀「唐大中九年歲次乙亥八月丁丑朔六日壬午重題，以紀他年之事」，共廿六字。", "）。"]'),
('5321fbf7-e8e5-4458-a12d-8627f8a94d53','句','高駢','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.50000.json','["。"]'),
('54f295e5-7eed-4deb-8f79-e3b77d9f4795','句 一','高駢','唐','唐诗','tang','','[]','手栽桃李十餘春，今日經過重建勳。',51,'全唐诗/poet.tang.50000.json','["手栽桃李十餘春，今日經過重建勳。", "（《經虢縣》。", "見崔致遠《桂苑筆耕集》卷十七《磻溪》詩自注引高駢句。", "）。"]'),
('233a42cf-c75c-4583-bbfe-f70e8dab9f70','句 二','高駢','唐','唐诗','tang','','[]','水急魚難釣，風吹柳易低。',62,'全唐诗/poet.tang.50000.json','["水急魚難釣，風吹柳易低。", "（《釣魚亭》。", "見《桂苑筆耕集》卷十七崔致遠《釣魚亭》詩自注引高駢句。", "參閱本書第十九卷崔致遠詩集。", "）。"]'),
('35d3759d-8cb2-41e5-bebb-012b7ada9569','題朝陽洞','李當','唐','唐诗','tang','','[]','江上朝陽洞，無人肯暫過。',69,'全唐诗/poet.tang.50000.json','["江上朝陽洞，無人肯暫過。", "今來愜心賞，迴首戀煙蘿。", "（見《八瓊室金石補正》。", "）（〖1〗石刻於詩題下署「義陽守李當」五字。", "餘說詳魏深詩按語。", "）。"]'),
('571cb80c-5084-475c-8054-291ff776c4ea','奉和左丞八舅題朝陽洞','魏深','唐','唐诗','tang','','[]','北闕飛新詔，東山喜更過。',458,'全唐诗/poet.tang.50000.json','["北闕飛新詔，東山喜更過。", "文星動巖夢，章句別杉蘿。", "（見《八瓊室金石補正》。", "）（〖1〗望按：碑刻幷有魏深《書事》，畧敍李當嘗自中書舍人問俗湖南，後除戶部侍郎，尋出尹河南。", "移宣□，鎮褒斜，旋拜天官氏，歲餘，除尚書左丞。", "於時奸臣竊柄，凡不附者悉遭摒斥，由是出牧道州。", "道州山民起事，當以書招諭之，）（不勞尺刃而山民順之云云。", "又按《書事》中謂奸臣竊柄，蓋指路巖及韋保衡諸人。", "路，《新唐書》有傳，與韋皆懿宗、僖宗時人。", "又石刻于詩題下署曰「從甥前□州軍事判官鄉貢進士魏深」。", "〖光緒《湖南通志·金石六》云此句缺字「似高字」。", "《唐文續拾》卷六小傳作「道州軍事判官」，似據文意推測。", "〗〖2〗陸增祥《八瓊室金石補正》卷六十：案《金石錄目》：「李舟《朝陽岩詩》，大曆十三年九月，李當、牛嵸詩附。", "」自大曆十三年至咸通十四年，相距九十餘載，此題之李當，蓋別一人也。", "《唐書·宰相世系表》姑臧大房有李當，官至刑部尚書，時代亦相近，當即此題詩之人。", "〖3〗望又按：牛嵸，《全唐詩》作牛叢，其題朝陽岩詩，見《全唐詩》卷五百四十二。", "李舟《朝陽岩詩》未見。", "）。"]'),
('180b0f3c-58bf-47b2-8eeb-1adf2055ef18','省題詩二十一首 天驥呈才','王棨','唐','唐诗','tang','','[]','馬知因聖出，才本自天生。',72,'全唐诗/poet.tang.50000.json','["馬知因聖出，才本自天生。", "駔駿何煩隱，權奇願盡呈。", "電從雙眼落，雲向四蹄輕。", "過去王良喜，嘶來伯樂驚。", "絕塵慚逸步，曳練議能名。", "唯待金鞭下，春風紫陌情。"]'),
('ec340e6a-bf9d-45da-b657-23bc4c773464','省題詩二十一首 上德不德','王棨','唐','唐诗','tang','','[]','何從稱上德，捨德德方全。',74,'全唐诗/poet.tang.50000.json','["何從稱上德，捨德德方全。", "聖者如非聖，賢者不自賢。", "海甯言我廣，神豈謂予玄。", "伐善功難立，無爲化易宣。", "[道]惟聞邃古，理亦愧先天。", "欲述猶龍旨，應忘得意筌。"]'),
('4f551b6d-17d6-4de8-8854-af24a4b24e00','省題詩二十一首 農祥晨正','王棨','唐','唐诗','tang','','[]','玉律方移候，農祥已向晨。',60,'全唐诗/poet.tang.50000.json','["玉律方移候，農祥已向晨。", "昭回當午地，皎潔向天津。", "北陸收殘凍，東臯見早春。", "影浮佳氣動，光射曙雲新。", "千畝功將起，三推禮欲申。"]'),
('569c3ddd-64e4-4e8d-8848-e65dd8c24078','省題詩二十一首 詠白','王棨','唐','唐诗','tang','','[]','非青玄赤黃，正色配金方。',72,'全唐诗/poet.tang.50000.json','["非青玄赤黃，正色配金方。", "魚表周王德，麟呈漢帝祥。", "寒來邊草遠，春至嶺梅芳。", "曳練聞良馬，銜鉤見瑞狼。", "張蒼肥似瓠，潘岳鬢如霜。", "虛室能生後，方知守黑長。"]'),
('b659cc66-8238-432b-b46c-0616e66d342d','省題詩二十一首 詠菊','王棨','唐','唐诗','tang','','[]','秋來多野菊，節應[有]黃花。',76,'全唐诗/poet.tang.50000.json','["秋來多野菊，節應[有]黃花。", "閒葉玉如栗，滿藂金出沙。", "池邊迷瑞鵠，洞裏悟仙牙。", "蘂散非紅豓，香飄異[綺]葩。", "贈詩宜魏帝，泛酒稱陶家。", "明日登高處，期君手不賒。"]'),
('9021ba83-ce75-469e-993a-e16b7bfefc4a','省題詩二十一首 詠清','王棨','唐','唐诗','tang','','[]','潔澈浮天色，鏘洋入樂聲。',73,'全唐诗/poet.tang.50000.json','["潔澈浮天色，鏘洋入樂聲。", "露零金掌滿，冰結玉壼盈。", "屏障排雲母，簾櫳動水精。", "南山秋雨霽，北牖晚風生。", "裴楷當年意，胡威近日名。", "未知堯舜化，寰宇一時清。", "。"]'),
('abac1e3c-0a22-469d-9ab3-e3fd1ccc2134','省題詩二十一首 月前菊','王棨','唐','唐诗','tang','','[]','秋菊近重陽，原頭復道旁。',72,'全唐诗/poet.tang.50000.json','["秋菊近重陽，原頭復道旁。", "藂滋寒露綠，花綻晚風黃。", "蘗染枝枝豔，星分處處芳。", "乍疑金散野，遙誤葉經霜。", "籬下何人採，罇中滿座香。", "唯應未歸客，對此欲沾裳。"]'),
('cf693e4c-b030-4dcf-9db6-ccc146886660','省題詩二十一首 上巳日曲江錫宴羣臣','王棨','唐','唐诗','tang','','[]','池散暮春景，君垂晞露恩。',72,'全唐诗/poet.tang.50000.json','["池散暮春景，君垂晞露恩。", "妙音迴舜樂，濃味降堯罇。", "詔出傾蘭省，筵開對杏園。", "輕漣搖彩艦，芳草映華軒。", "禊事輝朝曲，歡聲徹帝門。", "常陪觀者列，低首望餘暄。"]'),
('255a7cbd-21a0-4702-85d2-606982dc99b5','省題詩二十一首 甸服耆舊望籍千畝','王棨','唐','唐诗','tang','','[]','不展三推禮，如今已幾年。',74,'全唐诗/poet.tang.50000.json','["不展三推禮，如今已幾年。", "郊畿春又至，父老頸空延。", "扶杖溝塍側，傾心日月邊。", "[望恩]情倍百，流目地方千。", "未覩公卿從，長愁犬馬先。", "幸同黃耇意，因此願聞天。"]'),
('4d724b13-091d-4c81-baeb-caeac0182cca','省題詩二十一首 曉日禁林聞清漏','王棨','唐','唐诗','tang','','[]','曉過宮垣側，猶聞漏水頻。',72,'全唐诗/poet.tang.50000.json','["曉過宮垣側，猶聞漏水頻。", "清音傳五夜，山影值三春。", "露碎金壺滴，風和玉佩振。", "依稀連鳯沼，髣髴辨雞人。", "溫樹初凝霧，彤闈漸向晨。", "若非鴛鷺伴，誰此繼香塵。"]'),
('411d292d-e202-49ff-9167-5e4946faf555','省題詩二十一首 未明求衣','王棨','唐','唐诗','tang','','[]','夙夜甯無準，憂勤事萬機。',80,'全唐诗/poet.tang.50000.json','["夙夜甯無準，憂勤事萬機。", "良宵猶未曙，深殿早求衣。", "長樂鐘纔動，華胥夢已歸。", "絲綸傳紫禁，黼黻進彤闈。", "被處燭仍在，垂時星始稀。", "豈（一作「恭」）惟漢文帝，因此致巍巍。", "。"]'),
('9b924327-8d39-4fe3-a3d2-ed0ec225571c','省題詩二十一首 寒雨滴空階','王棨','唐','唐诗','tang','','[]','霏霏飄永夜，滴滴落空階。',72,'全唐诗/poet.tang.50000.json','["霏霏飄永夜，滴滴落空階。", "自有路歧恨，那堪離別懷。", "簷前聲乍碎，枕畔夢全乖。", "遠與巖泉雜，微將漏水諧。", "天涯思舊友，法上憶閒齋。", "坐到空庭曉，殘雲帶石崖。"]'),
('25385a44-05e5-476c-a05d-99d711de639c','省題詩二十一首 山明松雪','王棨','唐','唐诗','tang','','[]','高樹錄軒曉，長松帶雪明。',72,'全唐诗/poet.tang.50000.json','["高樹錄軒曉，長松帶雪明。", "景疑殘月在，林似野雲橫。", "密葉緣多亞，脩條被壓傾。", "曙空連嶂白，寒氣到簷清。", "影雜青牛重，光迷皓鶴驚。", "披衣凝望久，無限剡溪情。"]'),
('8839db68-623b-4b0d-ad1b-91bd362fca91','省題詩二十一首 元日端門肆赦','王棨','唐','唐诗','tang','','[]','史官開聖曆，天子御層樓。',77,'全唐诗/poet.tang.50000.json','["史官開聖曆，天子御層樓。", "壽[域]（城）南山色，恩波東海流。", "繞欄生杞梓，當檻簇貔貅。", "日月祥光近，山河喜氣浮。", "兆人瞻鳯扆，萬里御皇猷。", "欲識春生處，雞竿最上頭。"]'),
('6e51e6cd-9e51-475b-ae10-79b359446890','省題詩二十一首 原隰荑綠柳','王棨','唐','唐诗','tang','','[]','晴郊浮淑氣，疎柳發柔荑。',72,'全唐诗/poet.tang.50000.json','["晴郊浮淑氣，疎柳發柔荑。", "嫩翠原頭徧，巨絲隰畔低。", "和煙方鬱鬱，伴草欲萋萋。", "葉少眉難短，條新帶未齊。", "離人心已醉，游客步初迷。", "無限遷喬意，芳菲正好棲。"]'),
('b5974bad-6e41-46b1-a46c-0be2ce8c71f3','省題詩二十一首 風中琴','王棨','唐','唐诗','tang','','[]','虛簷來曉吹，橫榻有瑤琴。',72,'全唐诗/poet.tang.50000.json','["虛簷來曉吹，橫榻有瑤琴。", "暗報青蘋葉，潛生綠綺音。", "數聲隨籟去，餘響人堂深。", "徽假大王按，弦因少女吟。", "如箏飄閣上，似瑟鼓江潯。", "若與鐘期會，還知天地心。"]'),
('8cbf2238-b598-482c-a83d-a6189e26622c','省題詩二十一首 文不加點','王棨','唐','唐诗','tang','','[]','娛賓初命賦，摛翰已堪誇。',72,'全唐诗/poet.tang.50000.json','["娛賓初命賦，摛翰已堪誇。", "思發才無滯，文成點不加。", "筆端舒錦繡，手下走龍蛇。", "罷益銀鉤勢，休添麗澤華。", "誤蠅寧復見，倚馬未爲嘉。", "有愧當明試，含毫到日斜。"]'),
('de073a36-758e-4df5-b054-8c202ec397eb','省題詩二十一首 曲江春望','王棨','唐','唐诗','tang','','[]','暇日來南陌，春晴望曲江。',72,'全唐诗/poet.tang.50000.json','["暇日來南陌，春晴望曲江。", "地方駢綺席，城過拂霓幢。", "寶塔搖鈴鐸，雲樓闢璅窗。", "落風花片片，掠水燕雙雙。", "游女紅銀䡝，王孫白玉缸。", "莫論仙禁裏，祗此見雄邦。"]'),
('75806ff4-71e6-4ebb-bb38-e91d2544a809','省題詩二十一首 邊城曉角','王棨','唐','唐诗','tang','','[]','十年拋故國，五夜在邊城。',76,'全唐诗/poet.tang.50000.json','["十年拋故國，五夜在邊城。", "月照沙千里，風吹角一聲。", "清音飄遠戍，殘韻落荒營。", "背雪征鴻報，眠霜[老鶴驚]。", "李陵應下淚，蔡琰豈勝情。", "直是吳兒聽，[鄉關夢不成]。"]'),
('9186bfac-9ad4-404e-9dc0-f93af34ee4b6','省題詩二十一首 三峽聞猿','王棨','唐','唐诗','tang','','[]','扁舟韎楚峽，孤櫂下巫雲。',72,'全唐诗/poet.tang.50000.json','["扁舟韎楚峽，孤櫂下巫雲。", "正值三聲斷，仍教五夜聞。", "淒淒流洞壑，杳杳透烟氛。", "灩澦秋歸盡，陽臺曙欲分。", "何人悲失計，幾度恨離羣。", "聽後盈巾淚，家山接海濆。"]'),
('deb4fb3d-b94c-479f-9bce-0cb395ccf890','省題詩二十一首 寒梧鳯棲','王棨','唐','唐诗','tang','','[]','本向高岡植，甯將衆木齊。',197,'全唐诗/poet.tang.50000.json','["本向高岡植，甯將衆木齊。", "雖隨楊柳落，長待鳯凰棲。", "井上枝微亞，窗前影乍低。", "九苞和月立，六律帶霜飛。", "秦女含吹管，周王罷翦珪。", "既同丹穴樹，那肯宿羣雞。", "（以上各詩均見《麟角集》。", "）（此組長詩原有缺誤，據《天壤閣叢書》本《麟角集》校補。", "）（〖1〗《麟角集》原署「唐水部郎中福唐王棨輔之著」，《省題詩》二十一首爲該集附錄。", "原書云：「宋紹興乙卯，八代孫蘋任著作左郎，於館閣校讎，見先郎中省題詩，錄附之。", "」）。"]'),
('c4b89bd7-3c42-432c-9b3c-f203f18d326a','贈王郎中棨（題擬，參閱前王棨小傳）','李顏','唐','唐诗','tang','','[]','蓬灜上客顏如玉，手探月窟如夜燭。',46,'全唐诗/poet.tang.50000.json','["蓬灜上客顏如玉，手探月窟如夜燭。", "笑顧姮娥玉兔言，謂折一枝情未足。", "（見黃璞撰《王郎中傳》。", "）。"]'),
('958461ca-1d08-4483-b6ee-53e7db173359','題包山','皮日休','唐','唐诗','tang','','[]','一片煙村勝畫圖，四邊波浪送清虛。',58,'全唐诗/poet.tang.50000.json','["一片煙村勝畫圖，四邊波浪送清虛。", "此中人若無租稅，直是蓬瀛也不如。", "（見《分門籔類唐歌詩》殘本第四冊《天地山川類》。", "）。"]'),
('961972d9-99b3-4c7f-b4e7-b5c255f15664','','魏璞','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.50000.json','["。"]'),
('3e3d34d3-16a4-4171-a722-ae8c7e3fb406','尋鳥窠蹟','魏璞','唐','唐诗','tang','','[]','（原注：唐道林禪師入秦望山，見長松蟠曲如蓋，送棲止其上，故稱鳥窠禪師。',127,'全唐诗/poet.tang.50000.json','["（原注：唐道林禪師入秦望山，見長松蟠曲如蓋，送棲止其上，故稱鳥窠禪師。", "）爲訪名僧蹟，言尋小曲阿。", "松林春日靜，石逕晚雲多。", "道法傳馴鵲，（原注：有鵲巢側，自然馴狎。", "）禪機顯化螺。", "（原注：嘗入市，見食螺已截尾，乞放之池。", "至今螺螄繁生。）", "悉無尾如截，遺蹟在蘆院。"]'),
('27afecd5-6b24-464d-8cc6-889810c6b0e4','陪皮襲美陸魯望重過鳥窠蹟','魏璞','唐','唐诗','tang','','[]','重探靈蹟到空山，山下茅庵幾叩關。',64,'全唐诗/poet.tang.50000.json','["重探靈蹟到空山，山下茅庵幾叩關。", "不爲白雲招客屐，那教清境接人寰。", "螺池水色經年靜，仙嶺松聲鎮日閒。", "擬約高賢同結社，好移竹室住前灣。"]'),
('008e5ae1-9900-4a4d-8736-718cad511ede','題舜山後牛跡石','魏璞','唐','唐诗','tang','','[]','耕鑿連雲磴，蹄痕見福衡。',286,'全唐诗/poet.tang.50000.json','["耕鑿連雲磴，蹄痕見福衡。", "泣天伸養志，喘月藉留名。", "紀鳯儀同美，歌麟趾歧榮。", "勝遺方寸地，風動後人耕。", "（以上三詩均見《江上詩鈔》卷一。", "）（望按：顧季慈心求輯《江上詩鈔》卷一收魏璞詩五首，其一《奉和皮襲美悼鶴》，其二《又奉和襲美一首》。", "二詩《全唐詩》收之，惟「璞」作「朴」。", "小傳云：「魏朴字不琢，毘陵人。", "詩二首。", "」又按《全唐詩》皮日休卷有《五貺詩》幷序。", "序云：「毘陵處士魏不琢，氣真而志放，居毘陵凡二紀，閉門窮學」云云。", "又有《寄毘陵魏處士朴》一首，他詩詩題又有「毘陵魏不琢處士」之語。", "又《全唐詩》陸龜蒙卷有《奉和襲美目前魏處士五貺詩》及《和襲美寄毘陵魏處士朴》等詩，可相參閱。", "）。"]'),
('662612f8-e699-44e1-83dd-4e82fc38f973','晚思','司空圖','唐','唐诗','tang','','[]','蛩餘窗下月，草濕堦前露。',51,'全唐诗/poet.tang.50000.json','["蛩餘窗下月，草濕堦前露。", "晚景淒我衣，秋風入何樹？", "（此見《分門纂類唐歌詩》殘本第一冊《天地山川類》。", "）。"]'),
('efb2909c-4cec-4dab-adab-9376d72a8e51','牡丹','來鵬','唐','唐诗','tang','','[]','中國名花異國香，花開得地更芬芳。',89,'全唐诗/poet.tang.50000.json','["中國名花異國香，花開得地更芬芳。", "纔呈冶態當春晝，却歛妖姿向夕陽。", "雨過阿嬌慵粉黛，風□□□□□□。", "□□□□□□□，□□□□□□□。", "（見《分門纂類唐歌詩》殘本《草木蟲魚類》卷三。", "）。"]'),
('f9b6c7ee-ca67-4998-baab-4dd1d5ccf50f','','劉蛻','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.50000.json','["。"]'),
('68d6bce0-c0bc-40b1-999b-a25870e2d380','覽陳拾遺文集（按題下原署名曰「東川觀察判官長沙劉蛻」。）','劉蛻','唐','唐诗','tang','','[]','郪中好事人，家藏君十軸。',262,'全唐诗/poet.tang.50000.json','["郪中好事人，家藏君十軸。", "余來多暇日，借得晝夜讀。", "意氣高於頭，冰霜冷人腹。", "就中《大雅》篇，日日吟不足。", "生遇明皇帝，君臣竟不識。", "沉湮死下位，我輩更莫卜。", "射洪客來說，露碑今已踣。", "剜刓存滅半，勢欲入溝瀆。", "寓書託宰君，請爲試摩挃。", "樹之四達地，覆碑高作屋。", "憤君死後名，再依泥沙辱。", "世路重富貴，婉娩好眉目。", "文學如君輩，安得足衣食。", "不死橫路渠，爲幸已多福。", "我有平生心，推殘不局促。", "揖君盛年名，萬鐘何足祿。", "量長復校短，鳧脛不願續。", "悲君淚垂頤，雲山空蜀國。", "（見《永樂大典》卷三一三四「九真」「陳」字「陽子昂」條引《潼川志》〖五函四十四冊〗。", "）。"]'),
('f983ae11-fe48-4c2c-9d75-2afc05246af2','登陳拾遺書臺覽杜工部留題慨然成詠（原署：「前權知尚書刑部郎中牛嶠。」）','牛嶠','唐','唐诗','tang','','[]','步出縣西郊，攀蘿登峭壁。',260,'全唐诗/poet.tang.50000.json','["步出縣西郊，攀蘿登峭壁。", "行到蘂珠宮，暫喜拋火宅。", "羽帔請焚脩，霜鐘扣空寂。", "山影落中流，波聲吞大澤。", "北廂引危檻，工部曾刻石。", "辭高謝康樂，吟久驚神魄。", "拾遺有書堂，荒榛堆瓦礫。", "二賢間世生，垂名空烜赫。", "逸足擬追風，祥鸞已𨭝翮。", "伊餘誠未學，（伊餘，應作「伊余」。", "）少被文章役。", "興來揮兔毫，欲競雕弧力。", "雖稱含香吏，猶是飄蓬客。", "薄命值亂離，經年避矛戟。", "今來略倚柱，不覺衝暝色。", "袁安憂國心，誰憐鬢雙白？", "（見《永樂大典》卷三一三四「九真」「陳」字「陳子昂」條引《潼川志》〖五函四十四冊〗。", "）（按：詩後原紀年時曰「光啟三年九月二十六日」。", "）。"]'),
('30affd7d-bb88-46b3-a5c9-a035a75f25d0','靈巖寺','周朴','唐','唐诗','tang','','[]','碧峯頂上開禪坐，縱目聊窮宇宙間。',233,'全唐诗/poet.tang.50000.json','["碧峯頂上開禪坐，縱目聊窮宇宙間。", "白日纔離東海底，清光先照戶窗間。", "（宋李俊甫《莆陽比提》卷七收此詩，題作《靈嚴上方》，「東海」作「滄海」。", "《全唐詩續補遺》卷十三據《莆風清籟集》卷五八《游蹤》收此詩，題作《靈巖廣化寺》，「戶窗間」作「戶窗前」，今刪彼存此。", "）（此詩見道光甲辰年侯官嚴鴻謨校刊《周太朴詩》。", "按詩集原爲明徐𤊹興公所編，嚴刊本於徐編增詩二首，此即其中一首，云據《莆風清籟集》增。", "又按：此詩《全唐詩》僅存「白日纔離東海底，清光先照戶窗間」兩句，此則其全璧也。", "）。"]'),
('60094198-ccfb-4dee-98b1-948833706177','又句','周朴','唐','唐诗','tang','','[]','子孫何處閒爲客，松柏被人伐作薪。',51,'全唐诗/poet.tang.50000.json','["子孫何處閒爲客，松柏被人伐作薪。", "（同前見《周太朴詩》，云據《他日州志》錄存。", "見《吟窗雜錄》卷二八。", "）。"]'),
('3977ecd5-147b-4a24-8624-3727372bb532','題善權寺石壁','李蠙','唐','唐诗','tang','','[]','四周寒暑鎮湖關，三臥漳濱帶病顏。',523,'全唐诗/poet.tang.50000.json','["四周寒暑鎮湖關，三臥漳濱帶病顏。", "報國雖當存死節，解龜終得遂生還。", "容華漸改心徒壯，志氣無成鬢早斑。", "從此使歸林藪去，更將餘奉買南山。", "（見海寧吳騫《拜經樓詩話》卷二第十七條。", "同治《增修宜興縣壹》卷十《藝文志》亦載之。", "）（又見《古今圖書集成·山川典》卷九九《善權洞部》。", "）（〖1〗《拜經樓詩話》卷二：「唐李蠙詩世不多見。", "宜興善卷二毅題石壁一首曰〖詩畧〗。", "蓋蠙太和時嘗見白龍於此，其詩尚有元和遺音。", "蠙本名虬，將赴舉，夢名上添一畫成虱字，及寤，曰：『虱者，蠙也。", "』乃更名，果登第。", "皆可補《全唐紀事》之遺。", "」望按：《全唐文》卷七八八收李蠙《請自出俸錢收贖善權寺事奏文》一篇，畧謂「寺在縣南五十里離墨山，是齊時建立。", "……寺內有洞府三所。", "號爲乾洞者，石室通明處可坐五百餘人，稍暗處，執炬驗入，不知深淺。", "……洞門直下便臨大水洞，潺湲宛轉，湍瀨實繁，於山腹內漫流入小水洞。", "小水洞亦是一石室，室內水泉無底，大旱不竭。", "洞門對齋堂廚庫，似非人境。", "洞內常有雲氣昇騰，云是龍神所居之處。", "臣大和中在此習業。", "……臣懷此冤憤近三十年。", "……今請自出俸錢依元買收贖，訪名僧主持，教化同力，卻造成善權寺。", "……」誠如此文所云，大和中李蠙曾於此習業，三十年後始出俸錢收贖，推其時當在壹宗咸通中。"]'),
('0b5b626b-770a-40e6-b6fc-2c8a2151a297','獻淮南崔相公','羅隱','唐','唐诗','tang','','[]','天臨黃閤如秋淨，日照洪鈞若晝清。',108,'全唐诗/poet.tang.50000.json','["天臨黃閤如秋淨，日照洪鈞若晝清。", "虎帳坐分真宰氣，象筵吹出泰階聲。", "雲霞自入淮王夢，風月誰含煬帝情。", "見說蓬萊百王發，玉皇吟出廣陵城。", "（此見《永樂大典》卷二七四四「八灰」「崔」字「崔某」條引《維揚志》〖四函三十四冊〗。", "）。"]'),
('57b87fad-735b-4b76-9b2f-e640e1b89bc2','旅夜懷故人','符蒙','唐','唐诗','tang','','[]','羸形對寒影，即此更何親。',80,'全唐诗/poet.tang.50000.json','["羸形對寒影，即此更何親。", "半夜枕前淚，窮秋鄉外身。", "雨餘嵐色動，風靜月華新。", "故友誰相憶？年來入夢頻。", "（見《永樂大典》卷三○○五「九真」「人」字〖五函四十二冊〗。", "）。"]'),
('018c9063-84aa-471b-85b1-11004cb2c14b','贈彭蟾處士','王貞白','唐','唐诗','tang','','["\u957f\u6c5f"]','不阻兵散亂，穿楊已疊雙。',81,'全唐诗/poet.tang.50000.json','["不阻兵散亂，穿楊已疊雙。", "文深李北海，詩淨賈長江。", "退隱斸山藥，醉眠憑酒缸。", "年年搜草澤，未便老書窗。", "（案彭蟾字東蟾，好學不仕，《全唐詩》卷五百四十六收彭蟾詩一首。", "）。"]'),
('5a4ed892-8f2f-4b1f-9ed0-da08f0ad3495','贈劉台處士','王貞白','唐','唐诗','tang','','[]','擺落塵埃深處隱，欲將麋鹿混高踨。',103,'全唐诗/poet.tang.50000.json','["擺落塵埃深處隱，欲將麋鹿混高踨。", "兵機不讓韓擒虎，笑癖微方陸士龍。", "月窟常留丹桂在，家山貪臥白雲重。", "尋址朝有詔徵遺逸，莫掛頭冠著澗松。", "（以上見《永樂大典》卷一三四五○「二寘」「處士」〖十四函一百三十七冊〗。", "）。"]'),
('66e19a81-2e81-4de6-8686-6541998342e3','戲贈鄉人','王貞白','唐','唐诗','tang','','[]','前年內展室考文華，咫尺天顏隔絳紗。',98,'全唐诗/poet.tang.50000.json','["前年內展室考文華，咫尺天顏隔絳紗。", "御榜早聞傳異國，鄉人猶似薄東家。", "中宵縱匣衝星劒，臨水難留上漢槎。", "明日春風動行色，惟愁重別故林花。", "（此見《永樂大典》卷三○○四「九真」「人」字〖五函四十一冊〗。", "）。"]'),
('5b380166-5cf7-45f5-942c-37bc4d7c8a9a','下地日侍陸侍郎御讌賦得落花（「下地日」，疑應作「下第日」。）','王貞白','唐','唐诗','tang','','[]','何處足落花，漂泥與藉沙。',48,'全唐诗/poet.tang.50000.json','["何處足落花，漂泥與藉沙。", "春深上林苑，日晚五侯家。", "遍地輕難掃，當風勢易斜。", "無心媿蜂蝶，來歲即榮華。"]'),
('4d6a9bf4-550f-45b1-a34a-f47fe17c5f49','昭陽落花','王貞白','唐','唐诗','tang','','[]','空樹落花時，宮嬪泣暮暉。',88,'全唐诗/poet.tang.50000.json','["空樹落花時，宮嬪泣暮暉。", "盡皆承雨露，爭不惜芳菲。", "殘蘂猶黏草，餘香尚惹衣。", "無言屬青鳥，青鳥自銜飛。", "（以上見《永樂大典》卷五八三九「十六麻」「花」字「落花」條〖七函六十一冊〗。", "）。"]'),
('c664d8c0-54d6-452a-8ec1-7fafd04f27d5','禮聶先生新安重圍先生能通兩軍之好及城開民皆復全也','王貞白','唐','唐诗','tang','','[]','李白辭翰苑，前山尋隱淪。',153,'全唐诗/poet.tang.50000.json','["李白辭翰苑，前山尋隱淪。", "不遇採芝翁，滿洞惟白雲。", "（原注：李白昔日曾於此山尋許宣平先生不遇。", "）我來禮先生，得與龜鶴親。", "學道須有緣，始逢天上人。", "四皓安漢室，先生存歙民。", "陰功數已滿，自合成天真。", "如何未上昇，應待玉皇迎。", "我願去浮名，隨師歸三清。", "（此見《永樂大典》卷一○四五九「四濟」「禮」字〖十一函一百四冊〗。", "）。"]'),
('f24eba13-96a1-41b8-ae09-3f113d6977b5','送建昌馮明府','王貞白','唐','唐诗','tang','','["\u5e90\u5c71"]','嘗聞陶彭澤，解印歸匡廬。',96,'全唐诗/poet.tang.50000.json','["嘗聞陶彭澤，解印歸匡廬。", "今見馮海昏，辭官還隱居。", "賢人五百年，間生信非虛。", "清風激貪冒，白雲同卷舒。", "家山列畫屏，綠水環庭除。", "秋清對吟尊，羲皇人不如。", "祇今建昌民，方話大馮君。", "何必遺愛碑，政聲人盡聞。"]'),
('a7a55746-b5cb-4487-91d2-fcf2f60ec0bc','贈潯陽馮明府','王貞白','唐','唐诗','tang','','["\u5e90\u5c71"]','政約人知懼，訟庭荒草生。',48,'全唐诗/poet.tang.50000.json','["政約人知懼，訟庭荒草生。", "日高諸吏散，風到七絃清。", "詩味匡山色，臥諳湓浦聲。", "柴桑已不遠，何苦念前程。"]'),
('4e23da36-2776-4f07-9f07-01606b728035','宛陵早秋臥病代書寄周明府','王貞白','唐','唐诗','tang','','[]','爲謝臨卭宰，時多闕附書。',48,'全唐诗/poet.tang.50000.json','["爲謝臨卭宰，時多闕附書。", "懶非嵇叔夜，疾比馬相如。", "溪雨凉生後，山亭月上初。", "懷君自有句，何必遺雙魚。"]'),
('9b566540-a338-40c1-9640-b8e0c95ed7c3','又一首','王貞白','唐','唐诗','tang','','[]','吾道豈便喪，時人自不容。',138,'全唐诗/poet.tang.50000.json','["吾道豈便喪，時人自不容。", "白頭傷久別，青眼憶相逢。", "萍迹風波急，荷衣霧露濃。", "空編太平頌，天子未登封。", "（以上均見《永樂大典》卷一一○○○「六姥」「府」字「明府」條〖十一函一百十冊〗。", "以上諸詩，《永樂大典》皆注明出王貞白《靈溪集》。", "《直齋書錄解題》卷十九著錄此集，共七卷，今不存。", "）。"]'),
('c0fbab60-43fa-4376-8578-b2e992540c5c','白鹿洞二首 一','王貞白','唐','唐诗','tang','','["\u60dc\u65f6", "\u52b1\u5fd7", "\u8bfb\u4e66"]','讀書不覺已春深，一寸光陰一寸金。',32,'全唐诗/poet.tang.50000.json','["讀書不覺已春深，一寸光陰一寸金。", "不是道人來引笑，周情孔思正追尋。"]'),
('8847f95a-13a2-486e-b1d1-9fc71ce52565','白鹿洞二首 二','王貞白','唐','唐诗','tang','','[]','一上西園避暑亭，芰荷香細午風輕。',88,'全唐诗/poet.tang.50000.json','["一上西園避暑亭，芰荷香細午風輕。", "眼前物物皆佳興，併作吟窩一味清。", "（此二首從清餘姚邵啟賢輯、武昌陶氏刊本《王貞白詩》中補得。", "邵氏序謂此二首系據家刻本續補，《全唐詩》所未收者。", "）。"]'),
('d1a18c35-c7c3-46cf-b19e-180158f9ba05','','裴說','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.50000.json','["。"]'),
('756487a8-b4dc-40b5-9c5b-776567e57182','重臺芙蓉','裴說','唐','唐诗','tang','','[]','衆芳凋落後，特地遇陽和。',84,'全唐诗/poet.tang.50000.json','["衆芳凋落後，特地遇陽和。", "一一開雖晚，重重得亦多。", "畧無幽鳥語，時有凍蜂過。", "日暮寒階畔，輕紅拂淺莎。", "（見《永樂大典》卷五四○「一東」「蓉」字「重臺芙蓉」條〖一函三冊〗。", "）。"]'),
('8cd8ac9f-ae9c-42ae-90e9-d5af21a0ce40','遊囊山','黃滔','唐','唐诗','tang','','[]','山有重嚢勢，門開兩徑斜。',66,'全唐诗/poet.tang.50000.json','["山有重嚢勢，門開兩徑斜。", "溪聲寒走澗，海色月流沙。", "庵外曾遊虎，堂中舊雨花。", "不知遺讖地，一一落誰家？", "（見黃鳴喬刻本《黃御史集》卷二。", "）。"]'),
('6cd8f66a-f2a9-4fd0-b959-1c868b91adae','和從兄御史延福里居','黃蟾','唐','唐诗','tang','','[]','天賜平安水北中，滿庭荆樹醉春風。',180,'全唐诗/poet.tang.50000.json','["天賜平安水北中，滿庭荆樹醉春風。", "縱覺塵世三公貴，何似吾家一脈通。", "花底輕風香撲散，門前細柳綠皆同。", "囘頭文館長安上，（原注：謂德溫兄。", "）外際思予甯有窮。", "（見《天壤閣叢書》本《莆陽黃御史集》附刻明崇禎本補附詩卷。", "）（按詩題下端原署「從弟蟾」三字。", "徐松《唐兩京城坊考》卷四「次南延福坊」有御史黃滔宅，即據《黃御史集》中《延福里居和林寬何紹餘酬寄》詩及黃蟾此詩爲證。", "）。"]'),
('71c12197-8a1f-4454-99ad-0f37ee5965ae','賀知章官至秘書監鏡湖山水上疏明皇放歸鄉土仍賜鏡湖山河五百里曹松題鏡湖詩曰','曹松','唐','唐诗','tang','','[]','小因良匠寫清光，照見越州年歲長。',68,'全唐诗/poet.tang.50000.json','["小因良匠寫清光，照見越州年歲長。", "裹許雲山更孤峭，一時宣賜賀知章。", "（見《永樂大典》卷二二六七「六模」「湖」字「鏡湖」條〖二函二十冊〗。", "）。"]'),
('e6109407-3ee5-4987-a1b6-3f99ea41fc2b','白菊（見《分門纂類唐歌詩》殘本第六冊《草本蟲魚類》卷五。按《全唐詩》卷七三四作羅紹威詩。紹威乃弘信之子。一作羅隱詩。）','羅弘信','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.50000.json','["空。"]'),
('7a9a9031-34a9-4faf-a2a3-a9cef5cfc4c1','柳（見《分門纂類唐歌詩》殘本第七冊《草本蟲魚類》卷八。按《全唐詩》卷七三四亦作羅紹威詩。）','羅弘信','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.50000.json','["空。"]'),
('6d784b6d-ae6c-4401-8dd0-46a4ac15fbf0','望山','盧士衡','唐','唐诗','tang','','[]','亂山難問主，相續碧嶙嶙。',78,'全唐诗/poet.tang.50000.json','["亂山難問主，相續碧嶙嶙。", "何處煙霞裏，猶眠經濟人。", "樓高看有意，雨過色彌新。", "待取科名了，終期隱此身。", "（見《分門纂類唐歌詩》殘本第二冊《天地山川類》卷二十二。", "）。"]'),
('fab8ab69-3ff7-4cc9-85db-c2ffd98ea6e7','硤石山','楊氏','唐','唐诗','tang','','[]','此山靄靄通雲煙，峭壁嵯峨勢分綿。',417,'全唐诗/poet.tang.50000.json','["此山靄靄通雲煙，峭壁嵯峨勢分綿。", "丹水流衍曲如帶，風皺羅紋聽管絃。", "鶯啼花開入禪意，擲筆臺前梵唄宣。", "遙想當年無遮會，紛紛散落雨花天。", "（見《山右金石記》。", "）（〖1〗《山右金石記》卷九《硤石山楊夫人摩崖詩刻》條引《鳯臺縣志》：石壁刻『唐天佑丙子歲六月十四日離府，至中旬巡祀到此，登陟硤石山，偶上先師擲筆臺，眺觀景象，爲詩上碣。", "弘農郡君夫人述。", "』按天佑丙子，晉稱天佑十一年〖望按：丙子，當是晉天祐十三年，公元九一六年〗。", "是年，李嗣昭立鐘開元寺以七月十三日，弘農郡君夫人遊硤石山則六月十四日。", "考唐制有郡君夫人、公侯伯子夫人，制同一二三四品，似屬嗣昭夫人楊氏。", "但嗣昭封隴西郡公，未封弘農，或因弘農華陰以楊氏族望爲稱也。", "又考楊氏善蓄財，嗣昭被梁兵圍夾城彌年，楊氏多助其軍用。", "子繼韜叛後入京，楊齎銀數十萬驗賂釋其罪。", "後與子繼忠家晉陽，餘貲猶鉅萬。", "晉高祖起義，貸其殖以賂契丹，後以繼忠爲刺史。", "楊氏平生積產，嗣昭三世皆賴。", "今復見其石刻筆蹟，直奇婦人也。", "）。"]'),
('93cdbdd2-c38d-4f32-aa16-2c7283a0e7ca','獻馮李二相公（題擬）','張義方','唐','唐诗','tang','','[]','雨處沙堤同日築，其如啓沃藉良謀。',64,'全唐诗/poet.tang.50000.json','["雨處沙堤同日築，其如啓沃藉良謀。", "民間有病誰開口，府下無人只點頭。", "（見《江南餘載》卷下，云「馮延巳、李建勳拜相，張義方獻詩。", "」）。"]'),
('91e4f6cb-3387-4429-bac8-8790d1b4fd58','謝賜待詔御苑（題擬）','李建勳','唐','唐诗','tang','','[]','御苑賜房令待詔，此身殊勝到蓬瀛。',125,'全唐诗/poet.tang.50000.json','["御苑賜房令待詔，此身殊勝到蓬瀛。", "禁中仙樂無時過，階下常人不敢行。", "疊穎弄芳秋氣落，叢柯聳翠露華清。", "天廚送食何功享，空詠康哉贊盛明。", "（見《江南餘載》卷下。", "）（《江南餘載》：李建勳罷相，元宗於西苑天全閣別置廳院待之，命右僕射孫晟因寓直焉。", "建勳進詩動云。", "）。"]'),
('e5e78e32-a625-4d91-8ead-86a5e6f41091','句','李建勳','唐','唐诗','tang','','[]','一人看上馬，雙節引還鄉。',81,'全唐诗/poet.tang.50000.json','["一人看上馬，雙節引還鄉。", "（同前。", "）（〖1〗《江南餘載》：宋齊丘出鎮洪州，詔賜錦袍，烈祖〖李昪〗親爲衣之。", "李建勳贈詩有「一人看上馬，雙節引還鄉」之句，時論榮之。", "）。"]'),
('5a757991-76ec-4b08-854d-b8ad7ba25ce0','獻詩（題擬）','李夷鄴','唐','唐诗','tang','','[]','偶憶昔年逢上巳，輕舟柳岸宴羣臣。',166,'全唐诗/poet.tang.50000.json','["偶憶昔年逢上巳，輕舟柳岸宴羣臣。", "人間蹇薄時提歎，天上風光日日新。", "玉帛已來諸國瑞，瑤池固有萬年春。", "賦詩飲酒平生事，腸斷金門願再親。", "（見《江南餘載》卷下。", "）（《江南餘載》：李夷鄴者，前唐諸孫，嗜酒不羈。", "保大初，以宗室賢才拜正卿，累經左降，逾年輒復舊官。", "元宗上巳開宴，夷鄴不在召中，乃獻詩曰云云。", "上賜御札曰：「我家有外狂宗正，快哉！」）。"]'),
('9f033536-fc5f-4970-90be-af38f17550de','','呂從慶','唐','唐诗','tang','','[]','（按《全唐詩》無呂從慶詩。',126,'全唐诗/poet.tang.50000.json','["（按《全唐詩》無呂從慶詩。", "今傳世之《豐溪存稿》，即呂從慶詩集也。", "此書有洪溪呂氏萃石山房本，有嘉慶癸酉歲從慶三十二世孫呂璽培重刊本，均未見。", "有同治癸酉六安西鄉流波䃥鎮弗措書屋重鐫本。", "此卷即自同治重鐫本錄出。", "集前有雍正甲寅年任啟運撰呂從慶傳，足資參攷。", "）。"]'),
('572dec6b-b8c3-4c87-8026-244a64c7c647','幽居','呂從慶','唐','唐诗','tang','','[]','茅茨何瀟瀟，邱園復寥廓。',72,'全唐诗/poet.tang.50000.json','["茅茨何瀟瀟，邱園復寥廓。", "黃冠此中居，眷言寄高託。", "理亂無聞聲，榮辱不相着。", "有書聊把娛，有酒自斟酌。", "侵晨課田桑，歸來日華薄。", "盤桓松竹間，鳥動殘雲落。"]'),
('3b846c76-6ea2-4653-8c27-4f5772a7f594','登糾峯頂','呂從慶','唐','唐诗','tang','','[]','盤盤糾峯嶺，不與羣峯同。',49,'全唐诗/poet.tang.50000.json','["盤盤糾峯嶺，不與羣峯同。", "我來值清秋，落葉飛蒼穹。", "洪濤湃松柏，烟雨交空濛。", "愛兹竟忘返，非關足力窮。", "。"]'),
('494ce632-6fbc-452b-a1f2-4bed6a0afd53','題畫','呂從慶','唐','唐诗','tang','','[]','怪石倚危巒，橫烟出深谷。',48,'全唐诗/poet.tang.50000.json','["怪石倚危巒，橫烟出深谷。", "其間有孤松，亭亭表蒼綠。", "擕笻者伊誰？頂髪髠且禿。", "請君過柴橋，臨流味幽獨。"]'),
('724ac895-0523-46fa-889f-f0ae305fbd3f','釣魚','呂從慶','唐','唐诗','tang','','[]','侵晨出門去，道遇村阿婆。',96,'全唐诗/poet.tang.50000.json','["侵晨出門去，道遇村阿婆。", "問我一竿竹，得魚日幾何？", "我志不在魚，毋問寡與多。", "行行至磯側，卸我青草蓑。", "落花向我舞，啼鳥向我歌。", "旁有垂楊枝，迎風翻阿那。", "我意殊自得，翛然眠綠坡。", "仰視霄漢間，還以永吟哦。"]'),
('80463774-9228-48dd-8cc9-bc56bf43278a','過金鷄石','呂從慶','唐','唐诗','tang','','[]','金鷄自天來，桑麻列青眼。',72,'全唐诗/poet.tang.50000.json','["金鷄自天來，桑麻列青眼。", "羣耳無一聰，昂冠復飛返。", "遺音此寂然，千秋意何限。", "所幸一片石，猶在田中坂。", "我來撫弄之，襟懷日以散。", "寄語塒中禽，爾徒博飱飯。"]'),
('d5835ac1-b36a-49d4-96e2-8beeb8c8db45','懷嚴子陵前輩','呂從慶','唐','唐诗','tang','','[]','舉世成薄俗，往往奔虛名。',48,'全唐诗/poet.tang.50000.json','["舉世成薄俗，往往奔虛名。", "一或滯草澤，其音多不平。", "先生挽風化，簪組輕浮萍。", "緬維富春渚，千秋有深情。"]'),
('4e782d96-e55f-4dc4-8c12-bfc52359b723','喜晴','呂從慶','唐','唐诗','tang','','[]','瞳瞳雲間日，兼旬不得明。',73,'全唐诗/poet.tang.50000.json','["瞳瞳雲間日，兼旬不得明。", "一朝雨勢歇，衆鳥喧新晴。", "南窗有老叟，喜極推枯枰。", "呼僮載樽酒，訪渠泉石盟。", "出門有佳趣，清風生綠萍。", "笑語途中泥，爾難濡我情。", "。"]'),
('d42000d1-fe4b-43dd-b6e0-90287c7b8978','獻題金鰲山','呂從慶','唐','唐诗','tang','','[]','金鰲騰騰高百丈，昔者曾遊東海浪。',128,'全唐诗/poet.tang.50000.json','["金鰲騰騰高百丈，昔者曾遊東海浪。", "女媧斷足奠坤輿，怒身化作安吳嶂。", "骨肉雖變魂魄鮮，千秋萬古生雲烟。", "閒花老樹滿馥郁，飛走異類爭蹁躚。", "草堂熟對忽詫異，念在神僊廣遊戲。", "琴高跨鯉如跨驢，初成乘龍較容易。", "我今自號釣魚郎，絲綸倍比任公長。", "願言活汝騎脚底，御風直造星辰傍。"]'),
('6cfd30c6-3e74-4389-9008-c3f5b8845b03','山中作','呂從慶','唐','唐诗','tang','','[]','人生自古少百年，彈琴飲酒須歡然。',64,'全唐诗/poet.tang.50000.json','["人生自古少百年，彈琴飲酒須歡然。", "老子於今得此趣，縱有塵事難糾纏。", "左安藥爐右茶具，失記朝來與朝去。", "偶因送客出前溪，便過溪橋拾詩句。"]'),
('e22dff99-7bf2-4587-a3c8-0d6849df25df','賊警','呂從慶','唐','唐诗','tang','','[]','兵火逾風疾，纔西已及東。',48,'全唐诗/poet.tang.50000.json','["兵火逾風疾，纔西已及東。", "蒼翁災海內，赤子哭途中。", "城闕兼旬閉，郵書徹旦通。", "不知調國者，何以慰時匆？"]'),
('dfa2c224-18bf-44c8-b5a9-a7db57142feb','行次歙州寓之','呂從慶','唐','唐诗','tang','','[]','乍入新安境，溪山覺可褒。',48,'全唐诗/poet.tang.50000.json','["乍入新安境，溪山覺可褒。", "賃房安食具，掃榻卸行絛。", "明識離鄉賤，强言避世高。", "君聽塗上客，多半說弓刀。"]'),
('0819a70f-825d-42ac-bc09-018ba13ddc1c','小園','呂從慶','唐','唐诗','tang','','[]','小園春色麗，花發兩三株。',49,'全唐诗/poet.tang.50000.json','["小園春色麗，花發兩三株。", "露笋抽泥立，風蘭狎石鋪。", "教兒棋正歇，得客酒重沽。", "意緒渾如此，詩腸老未枯。", "。"]'),
('ecf2f6e5-f366-45ac-829f-10c789bcb789','遊多寶寺','呂從慶','唐','唐诗','tang','','[]','探幽過小澗，夕照走全陰。',48,'全唐诗/poet.tang.50000.json','["探幽過小澗，夕照走全陰。", "倚杖娛閒睫，聞鐘寄遠心。", "竹光浮古趣，松籟捲寒音。", "城衲烹茶出，先供座佛歆。"]'),
('e9b29b83-e7f3-43d9-9a61-254d9a9c380e','村徑中即事','呂從慶','唐','唐诗','tang','','[]','寂剪茅簷外，溪流曲似繩。',48,'全唐诗/poet.tang.50000.json','["寂剪茅簷外，溪流曲似繩。", "飛蜓低復仰，啼鳥斷還仍。", "麥秀香聯畝，麻高影障塍。", "老夫無病痛，長此樂清礽。"]'),
('68212f05-3f7e-45f8-b552-7e04dcd20447','對月有感','呂從慶','唐','唐诗','tang','','[]','天開懸寶鏡，皓魄滿欄杆。',48,'全唐诗/poet.tang.50000.json','["天開懸寶鏡，皓魄滿欄杆。", "君自千秋照，人誰百歲看。", "夜香金鼎燼，春酒玉壺乾。", "吾意方蕭索，懷兹愈不安。"]'),
('9fd5df74-84a3-4c40-b66f-60cf9f1071b7','草堂坐雨','呂從慶','唐','唐诗','tang','','[]','夏來田久旱，秋雨偶然幷。',48,'全唐诗/poet.tang.50000.json','["夏來田久旱，秋雨偶然幷。", "嵐影經眸幻，檐聲滴耳清。", "幽花開小艷，憊黍轉餘精。", "還望潢池上，蕭然洗甲兵。"]'),
('22595106-56d3-4b4b-a5f4-5b1c670ca77e','偶興','呂從慶','唐','唐诗','tang','','[]','吾亦陶彭澤，從來懶折腰。',48,'全唐诗/poet.tang.50000.json','["吾亦陶彭澤，從來懶折腰。", "焚香懷落落，對酒意囂囂。", "世態雲多幻，人情雪易消。", "最佳猿共鶴，閒裏日相邀。"]'),
('a5125d9c-fe86-411b-a902-6a17cab209fb','溪西村','呂從慶','唐','唐诗','tang','','[]','入境聞鷄犬，悠悠古趣遐。',48,'全唐诗/poet.tang.50000.json','["入境聞鷄犬，悠悠古趣遐。", "紅邊花落瓣，綠際茗舒芽。", "深壑和烟窈，清溪避石斜。", "他時須結伴，松底泛流霞。"]'),
('3fd5e001-3153-44a0-a1ae-c3b1da9d1b47','冬盡','呂從慶','唐','唐诗','tang','','[]','一年惟臘在，忽忽又將央。',48,'全唐诗/poet.tang.50000.json','["一年惟臘在，忽忽又將央。", "雪重庭枝折，風輕徑蘂香。", "感時空有恨，留歲竟無方。", "老矣當樽客，他鄉作故鄉。"]'),
('b1041dd5-4cec-4685-950c-a0c199879dfd','平原','呂從慶','唐','唐诗','tang','','[]','碧天連野色，微雨濕蒿藜。',48,'全唐诗/poet.tang.50000.json','["碧天連野色，微雨濕蒿藜。", "鳥影松間沒，蟬聲柳外嘶。", "寺僧張遠蓋，田父把輕犁。", "逸趣紛紛入，都堪作畫題。"]'),
('ad121c6d-c2cd-4b48-aa3d-8b9bebecf14a','章氏幽居','呂從慶','唐','唐诗','tang','','[]','白屋烟霞內，花期了不愆。',48,'全唐诗/poet.tang.50000.json','["白屋烟霞內，花期了不愆。", "邱山情更好，泉石盟須堅。", "綠樹當簷裏，紅藤倚壁牽。", "主人閒處立，有客笑扶肩。"]'),
('c3385d36-1092-4360-a528-924e3da98e6c','憶弟從善','呂從慶','唐','唐诗','tang','','[]','弟貧居歙縣，兄老住豐溪。',48,'全唐诗/poet.tang.50000.json','["弟貧居歙縣，兄老住豐溪。", "大被身分寢，長繩足共覊。", "幅雲橫斷嶺，鈎月照斜谿。", "安得源源過，陶然樂黍鷄。"]'),
('0e1e85ad-7f3c-4559-8a73-f2db17287670','夏日即事','呂從慶','唐','唐诗','tang','','[]','結伴居山寺，超然見白雲。',48,'全唐诗/poet.tang.50000.json','["結伴居山寺，超然見白雲。", "境閒堪問道，客雅好論文。", "坐石惟看奕，行田或課耘。", "夜來塵俗語，不向夢中聞。"]'),
('a5f9605a-ec79-437d-81d9-9f842432800d','梅','呂從慶','唐','唐诗','tang','','[]','最愛橫溪曲，橫流一樹梅。',48,'全唐诗/poet.tang.50000.json','["最愛橫溪曲，橫流一樹梅。", "藏根惟愛石，落瓣不沾埃。", "臘裏孤清節，春間創闢材。", "調羹還有藉，青子百千枚。"]'),
('59a32830-79c2-4176-b0f9-c15f449dde45','薄暮步村徑','呂從慶','唐','唐诗','tang','','[]','竹裏荆扉掩，村前萬物幽。',48,'全唐诗/poet.tang.50000.json','["竹裏荆扉掩，村前萬物幽。", "飛蟲摶澗舞，鳴鵲抱巢修。", "川上漁歌斷，坡前牧課休。", "淡烟隨杖履，吾意自悠悠。"]'),
('c6264e8b-7f5b-4c8b-996e-6e88ada392af','避亂','呂從慶','唐','唐诗','tang','','[]','海內風光半血污，殺人聲過似樵蘇。',64,'全唐诗/poet.tang.50000.json','["海內風光半血污，殺人聲過似樵蘇。", "一身驅路忙如蟻，八口無家散若烏。", "栗里無蹤空悵望，桃源有夢失招呼。", "饑來野店供飱飯，敢怨匙前脫粟粗。"]'),
('9651de83-f3bd-4bba-b746-cd206f017493','春更書懷','呂從慶','唐','唐诗','tang','','[]','豐溪村內野人居，隱約南山對敝廬。',64,'全唐诗/poet.tang.50000.json','["豐溪村內野人居，隱約南山對敝廬。", "花下小橋春策蹇，竹中深徑夜歸漁。", "無名正可驕王謝，有句還能繼庾徐。", "醉罷濁醪鄰客散，一番清夢又蘧蘧。"]'),
('3a95c924-a94b-46e9-aed9-8869b68b238b','贈野僧','呂從慶','唐','唐诗','tang','','[]','有客逃禪住北岡，昔年支許意相當。',65,'全唐诗/poet.tang.50000.json','["有客逃禪住北岡，昔年支許意相當。", "清如細竹迎風灑，潔似孤松冒雪張。", "錫杖倚雪看遠岫，銅瓶汲月煑新湯。", "只今石畔雙扉掩，靜閱琅函日幾章。", "。"]'),
('1606e976-6a04-42fe-bcb8-9cd8a26153a7','永豐橋閒坐','呂從慶','唐','唐诗','tang','','[]','敝襪輕鞋緩足投，永豐橋上寄雙眸。',64,'全唐诗/poet.tang.50000.json','["敝襪輕鞋緩足投，永豐橋上寄雙眸。", "山沿東舍環西舍，水遶南疇赴北疇。", "村婦坐畦挑馬齒，野童蹲澗採鷄頭。", "娛閒不覺忘中飯，一點斜陽射竹樓。"]'),
('95be15f7-5e76-4eeb-bcc5-2754b6e0d55a','閱田禾','呂從慶','唐','唐诗','tang','','[]','村南村北稻花明，碧影清光夾望平。',64,'全唐诗/poet.tang.50000.json','["村南村北稻花明，碧影清光夾望平。", "節弄暑風輕拂拂，尖懸晚露澹盈盈。", "道傍嫗婦呼鷄返，坡外兒童跨犢行。", "獨坐小橋幽興滿，蟪蛄聲在柳梢鳴。"]'),
('9b0b585a-5ea2-4ec8-989d-ed1e52c57735','傳婆井','呂從慶','唐','唐诗','tang','','[]','古井無淵源，千秋自涵養。',24,'全唐诗/poet.tang.50000.json','["古井無淵源，千秋自涵養。", "日暮汲人來，洞然發清響。"]'),
('cac559e9-f8df-4a06-b0ff-e200c69a6972','葺豐溪橋成志喜一絕','呂從慶','唐','唐诗','tang','','[]','橫流架石梁，刻作永豐字。',24,'全唐诗/poet.tang.50000.json','["橫流架石梁，刻作永豐字。", "好渡杖藜翁，逍遙謂農事。"]'),
('e258fb90-7c0d-4673-9eb8-2e1a1789db9a','醉臥田間賴里人章氏子扶歸作詩以謝之','呂從慶','唐','唐诗','tang','','[]','荷鋤田澤畔，垂手引糢糊。',12,'全唐诗/poet.tang.50000.json','["荷鋤田澤畔，垂手引糢糊。"]'),
('75266368-3ac0-4a15-ab5a-4c2e92f43cc3','題英濟石','呂從慶','唐','唐诗','tang','','[]','怪石裏苔錢，高聳百餘尺。',24,'全唐诗/poet.tang.50000.json','["怪石裏苔錢，高聳百餘尺。", "我至輒呼名，依稀點危額。"]'),
('0df441d8-38c9-407d-9c0a-51361fca1f87','觀野燒','呂從慶','唐','唐诗','tang','','[]','烈烈西風裏，蓬蕪一掃空。',25,'全唐诗/poet.tang.50000.json','["烈烈西風裏，蓬蕪一掃空。", "雖留生意在，已廢半年功。", "。"]'),
('be8cf80d-9408-4ec8-aeae-76a37ec1b620','菊','呂從慶','唐','唐诗','tang','','[]','短籬偎曲徑，風雨困秋曦。',24,'全唐诗/poet.tang.50000.json','["短籬偎曲徑，風雨困秋曦。", "競惜芙蓉冷，何知更有伊。"]'),
('0edfc463-7f36-46d6-b23d-26b839973b3c','柵山','呂從慶','唐','唐诗','tang','','[]','鬱鬱長林障遠鄉，茸茸細草綠於秧。',32,'全唐诗/poet.tang.50000.json','["鬱鬱長林障遠鄉，茸茸細草綠於秧。", "好風吹拂閒烟靄，薰得斜暉滿徑香。"]'),
('be6c7961-f2f0-48e1-886c-9d27550c3343','漫興','呂從慶','唐','唐诗','tang','','[]','糾嶺豐溪許避秦，一坵一壑老遺民。',32,'全唐诗/poet.tang.50000.json','["糾嶺豐溪許避秦，一坵一壑老遺民。", "妻孥莫漫悲家計，留得黃冠未算貧。"]'),
('385b2d6f-c793-41ff-9393-660b039af9c0','馬蹄痕','呂從慶','唐','唐诗','tang','','[]','一泓流水舊多情，拂塵乘驄躍淺萍。',32,'全唐诗/poet.tang.50000.json','["一泓流水舊多情，拂塵乘驄躍淺萍。", "父老競傳遺跡在，不知仙客是何名。"]'),
('e9967663-5769-4fe8-818a-8d9a5db451f1','春日往柵山吟詩於驢子背上未即就誤入側徑爲叢莽所縛卒成之','呂從慶','唐','唐诗','tang','','[]','風生原野翠痕充，澗曲巒隈小徑通。',32,'全唐诗/poet.tang.50000.json','["風生原野翠痕充，澗曲巒隈小徑通。", "覔句未成垂首索，不知身掛莽林中。"]'),
('3537b123-de58-4b25-8f3d-7314effbe8a2','又','呂從慶','唐','唐诗','tang','','[]','隔絕羊腸已數旬，到來春靄正盈盈。',32,'全唐诗/poet.tang.50000.json','["隔絕羊腸已數旬，到來春靄正盈盈。", "山神擬欲求新句，牽住衣裳不放行。"]'),
('01200a90-c853-442b-9718-e331b49a883f','寄弟','呂從慶','唐','唐诗','tang','','[]','函罷家音又拆看，添書絕句報平安。',32,'全唐诗/poet.tang.50000.json','["函罷家音又拆看，添書絕句報平安。", "豐溪漁叟生涯定，明月清風一釣竿。"]'),
('453437ce-6f21-415f-a0fe-09958fa594c6','糾峯別業','呂從慶','唐','唐诗','tang','','[]','糾峯嶺半樹森然，伐竹編成翠底廛。',33,'全唐诗/poet.tang.50000.json','["糾峯嶺半樹森然，伐竹編成翠底廛。", "雜客不來塵思少，落花啼鳥自年年。", "。"]'),
('00cf58db-89e0-477e-b7c3-be9752977f5b','德山老人送茶至','呂從慶','唐','唐诗','tang','','[]','數株香苕產松坡，野老新分半兩多。',32,'全唐诗/poet.tang.50000.json','["數株香苕產松坡，野老新分半兩多。", "釣罷歸來兒說與，引瓢旋汲澗中波。"]'),
('21dacf0b-9fc7-4a11-b768-b744a35fa112','豐溪秋社','呂從慶','唐','唐诗','tang','','[]','稻熟瓜纍歲有仁，烹鷄割豕祀田神。',412,'全唐诗/poet.tang.50000.json','["稻熟瓜纍歲有仁，烹鷄割豕祀田神。", "分腥不覺歸來晚，一幅雲煙擁醉人。", "（〖1〗《四庫全書總目提要》謂：「其集歷代史志書目皆不著錄。", "此本爲乾隆庚申其裔孫積祚所刊，稱其從叔高祖元進所手錄，黃之雋、邵泰、儲大文皆爲之序，稱其湮沒八百年而始顯。", "然其書晚出，授受源流渺不可考，越宋、元、明至今，忽傳於世，論者頗以爲疑。", "」並舉用詞數條，以爲不似晚唐五代人語。", "且謂《春雪往柵山》一詩，題中有「敲詩驢子背上」語。", "實賈島咏推敲二字不定，見《唐摭言》，鄭綮言『詩思在灞橋風雪中驢子背上』，見《唐詩紀事》，在今日則爲故典，在唐末猶爲近事，不應從慶用之。", "且稱吟詩爲推敲，已屬割裂，至改爲敲詩，明以前人實無此語。", "按南高圖書館藏同治重鐫本此詩題作《春日往柵山吟詩於驢子背上未即就誤入側徑爲叢莽所縛卒成之》。", "無敲詩之語，是傳本有不同也。", "其餘用詞可疑者，又安知非輾轉抄刻中所致耶？", "至古籍之不顯于當世而復見於後代者，其例實繁，故仍錄存之，以俟海內方家之論定焉。", "）。"]'),
('d6b2b176-e116-4cbc-b73e-6c8996c80c88','贈陳郎（題擬）','韓熙載','唐','唐诗','tang','','[]','陳郎不著世儒衫，也好嬉游日笑談。',172,'全唐诗/poet.tang.50000.json','["陳郎不著世儒衫，也好嬉游日笑談。", "幸有葛巾與藜杖，從呼宮觀老都監。", "（見《江南餘載》卷上。", "）（〖1〗《江南餘載》：陳致堯雍熟於《開元禮》，官太常博士，國之大禮，皆折衷焉。", "與韓熙載最善。", "家無儋石之儲，然妾妓至數百，暇奏《霓裳羽衣》之聲，頗以帷簿取譏於時。", "二人左降者數矣，熙載詩〖詩不重錄〗云云。", "其廳中置大鈴，大署其旁曰：「無錢僱僕，客至請挽之。", "」）。"]'),
('d826e40d-7ca7-443e-8d3e-1afb61a0e471','','段義宗','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.50000.json','["。"]'),
('ebd1cbbd-4599-4a9a-a5fc-d8c09c115518','題大慈寺芍藥','段義宗','唐','唐诗','tang','','[]','浮花不與衆花同，爲感高僧護法功。',136,'全唐诗/poet.tang.50000.json','["浮花不與衆花同，爲感高僧護法功。", "繁影夜鋪方丈月，異香朝散講筵風。", "尋真自得心源靜，觀色非貪眼界空。", "好是芳馨堪供養，天教生在釋門中。", "（見後蜀何光遠《鑑誡錄》卷六。", "）（《知不足斎叢書》二十二集第一百七十冊。", "按《全唐詩》佚句卷僅存首二句。", "此首句「浮花」，《全唐詩》作「此花」。", "）。"]'),
('3e26e619-0333-434f-b830-ce9a366ca837','題三學院經樓','段義宗','唐','唐诗','tang','','[]','鷲嶺鷄園不可儔，叨陪龍象喜登遊。',113,'全唐诗/poet.tang.50000.json','["鷲嶺鷄園不可儔，叨陪龍象喜登遊。", "玉排複道珊瑚殿，金錯危欄翡翠樓。", "尚欲歸心求四諦，敢辭旋繞滿三周。", "羲和鞭撻金烏疾，欲網無由肯駐留？", "（同前《鑑誡錄》卷六。", "《全唐詩》佚句卷只存三、四句。", "此詩第四句「危欄」，《全唐詩》作「危椆」。", "）。"]'),
('a77db47b-0cb4-4b36-9d5f-21895ec65e78','又題','段義宗','唐','唐诗','tang','','[]','當今積善競修崇，七寶莊嚴作梵宮。',408,'全唐诗/poet.tang.50000.json','["當今積善競修崇，七寶莊嚴作梵宮。", "佛日明時齊舜日，皇風清處接慈風。", "一乘妙理應難測，萬刼良緣豈易窮。", "共恨塵勞非法侶，掉鞭歸去夕陽中。", "（同前《鑑誡錄》卷六。", "《全唐詩》亦無佚句。", "）（望按：《全唐詩》佚句卷共收段義宗佚詩六句，注云出《吟窗雜錄》。", "其中「浮花」兩句，即今補第一首中句；「玉排」二句，即今補第二首中句。", "另有「懸心秋夜月。", "萬里照鄉關」兩句，實非佚句，全詩已收入《全唐詩》，署名「布燮」。", "布燮，長和國人猶言宰相也，非人名，《全唐詩》與作者名等視之，失察矣。", "句中「鄉關」，《鑑譖錄》作「關山」。", "日本漢學家豐田穰氏所撰《全唐詩糾謬》〖見昭和二十三年即公元一九四八年養德社刊《唐詩研究》〗一文，中曾據我國後蜀何光遠《鑑誡錄》卷六《布燮朝》一條，稽之《全唐詩》，謂係《全唐詩》所未收，可以補佚云云。", "此文近承日友波多）（野太郎教授函贈，即以鮑氏刻《知不足齋叢書》本《鑑誡錄》校其原詩。", "畧誌顛末，深以得豐田氏論文啓迪之助爲感。", "）。"]'),
('af40f526-1f39-4069-b3bb-e01d2c233e68','','徐鉉','唐','唐诗','tang','','[]','（《全唐詩》編徐鉉詩爲六卷，以下二首及句均所未收，據《宋詩紀事》卷三錄補之。',40,'全唐诗/poet.tang.50000.json','["（《全唐詩》編徐鉉詩爲六卷，以下二首及句均所未收，據《宋詩紀事》卷三錄補之。", "）。"]'),
('a738430c-46ac-4928-abdd-ad43d22b2b62','吳王挽辭二首 一','徐鉉','唐','唐诗','tang','','[]','倏忽千齡盡，冥茫萬事空。',48,'全唐诗/poet.tang.50000.json','["倏忽千齡盡，冥茫萬事空。", "青松洛陽陌，白草建康宮。", "道德遺文在，興衰自古同。", "受恩無補報，反袂泣途窮。"]'),
('5faeff56-6a32-40a0-a23d-3060e471e473','吳王挽辭二首 二','徐鉉','唐','唐诗','tang','','[]','土德承餘烈，江南廣舊恩。',455,'全唐诗/poet.tang.50000.json','["土德承餘烈，江南廣舊恩。", "一朝人事變，千古信書存。", "哀挽周原道，銘旌鄭國門。", "此生雖未死，寂寞已消魂。", "（以上二首角《宋詩紀事》卷三。", "）（見《東軒筆錄》卷一、《宋朝事實類苑》卷三六。", "第一首第四句「白草」二字，《東軒筆錄》作「芳草」、《宋朝事實類苑》作「荒草」。", "）（〖1〗宋翟耆年《籀史》：「徐鉉鼎臣從李煜歸朝，爲銀青光祿大夫、右散騎常侍。", "太平興國中，李煜薨，詔侍臣撰煜神道碑。", "有欲中傷鉉者，奏曰：『吳王事，莫若徐鉉爲詳。", "』遂詔鉉撰。", "鉉泣曰：『臣舊事李煜，陛下容臣存故主之義，乃敢奉詔。", "』太宗許之。", "鉉但推言歷數有盡，天命有歸而已。", "其警句云：『東鄰搆禍，南箕扇疑，投杼致慈親之惑，乞火無鄰婦之詞。", "始勞因壘之師，終後塗山之會。", "』太宗覽之，稱歎不已。", "異日復得鉉所撰《吳王挽詞》，今傳者二首云云。", "鉉被詔撰《江南錄》，故有『信書』之句。", "東鄰謂錢俶也。", "」〖2〗望按：如《籀史》所載，知挽辭二首之作，已在入宋之後。", "以所涉李煜，曾是南唐之主，而徐鉉生活於五代者亦四十餘年，且《全唐詩》徐鉉卷亦收其仕宋後篇什，故仍援例錄補，俾成完帙。", "）。"]'),
('99296779-2df5-4d76-b1b0-c87f0bfbd95b','句 一','徐鉉','唐','唐诗','tang','','[]','落月依樓閣，歸雲擁殿廊。',52,'全唐诗/poet.tang.50000.json','["落月依樓閣，歸雲擁殿廊。", "（《宿山寺》，見《宋詩紀事》引宋釋文瑩《玉壺野史》。", "）（見《玉壺清話》卷八。", "）。"]'),
('f70d2979-1e74-4be4-b521-d42d265c4a99','句 二','徐鉉','唐','唐诗','tang','','[]','鐘山祠畔宿煙晴，玉澗橋邊碧樹春。',35,'全唐诗/poet.tang.50000.json','["鐘山祠畔宿煙晴，玉澗橋邊碧樹春。", "（見《景定建康志》卷十八《山川志》。）"]'),
('61ff052e-82c1-4f6b-99dd-c4341b985541','','范質','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.50000.json','["。"]'),
('37c5b00f-594e-4de1-a495-48555d8570a2','誡兒姪八百字','范質','唐','唐诗','tang','','["\u9ec4\u6cb3"]','（昨得謝課書，希於京秩之中更與遷轉。',316,'全唐诗/poet.tang.50000.json','["（昨得謝課書，希於京秩之中更與遷轉。", "余以諸兒姪輩生長以來，未諳外事，艱難損益，懵然莫知，因抒古詩一章曉之。", "）去年初釋褐，一命列蓬丘。", "（謂謝課。", "）青袍春草色，白紵棄如仇。", "適會龍飛慶，王澤天下流。", "爾得六品階，無乃太爲優。", "凡登進士第，四選昇校讐。", "歷官十五考，敘階與爾儔。", "如何志未滿，意欲陵（《紀事》「陵」作「凌」。", "）雲遊。", "若言品位卑，寄書來我求。", "省之再三歎，不覺淚盈眸。", "吾家本寒素，門地寡公侯。", "先子有令德，樂道尚憂游。", "生逢世多僻，委任信沉浮。", "仕宦不喜達，吏隱同莊周。", "積善有餘慶，清白爲貽謀。", "伊余奉家訓，孜孜務進修。", "夙夜事勤肅，言行思悔尤。", "出門擇交友，防慎畏薰蕕。", "省躬常懼玷，恐掇庭闈羞。", "童年志於學，不墮（《紀事》「墮」作「惰」。", "）爲箕裘。"]'),
('dc9eedb6-8892-423e-b96b-92f90cc73652','謝進士張翼投詩兩軸','王溥','唐','唐诗','tang','','[]','清河詩客本賢良，惠我新吟六十章。',113,'全唐诗/poet.tang.50000.json','["清河詩客本賢良，惠我新吟六十章。", "格調宛同羅給事，功夫深似賈司倉。", "登山始覺天高廣，到海方知浪渺茫。", "好去蟾宮是歸路，明年應折桂枝香。", "（見《宋詩紀事》引宋張齊賢《洛陽搢紳舊聞記》。", "）（見《洛陽縉紳舊聞記》卷一《陶副車求薦見忌》。", "）。"]'),
('7a842ac0-88c9-4cff-b32a-052ef720c1ec','詠牡丹','王溥','唐','唐诗','tang','','[]','棗花至小能成實，桑葉雖柔解吐絲。',71,'全唐诗/poet.tang.50000.json','["棗花至小能成實，桑葉雖柔解吐絲。", "堪笑牡丹如斗大，不成一事又空枝。", "（見《宋詩紀事》引《歷代吟譜》。", "見明刻本《吟窗雜錄》卷三十三《歷代吟譜》。", "）。"]'),
('cd6fc024-4b18-4f7e-a4c5-d4f60aebc5b5','','李昉','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.50000.json','["。"]'),
('6a8baf1f-0a09-4aab-bf12-f15ab3a28b8a','贈賈黃中（賈以七歲應童子舉）','李昉','唐','唐诗','tang','','[]','七歲神童古所難，賈家門戶有衣冠。',167,'全唐诗/poet.tang.50000.json','["七歲神童古所難，賈家門戶有衣冠。", "十人科第排頭上，五部經書誦舌端。", "見榜不知名字貴，登筵未識管弦歡。", "從今穩上青雲去，萬里誰能測羽翰。", "（見《宋詩紀事》引《聞見前錄》。", "）（見《邵多聞見錄》卷六。", "）（望按：賈黃中字媧民，南皮人。", "生後晉天福六年，卒宋太宗至道二年。", "《宋史》卷二六五有傳。", "詩註云「七歲應童子舉」，則時當晉天福十二年，尚未入宋也。", "）。"]'),
('1aa86ed4-14da-4c5a-a9c6-a0872cabdb12','仙客','李昉','唐','唐诗','tang','','[]','胎化仙禽性本殊，何人攜爾到京都。',164,'全唐诗/poet.tang.50000.json','["胎化仙禽性本殊，何人攜爾到京都。", "因加美號爲仙客，稱向閑庭伴野夫。", "警露秋聲雲多遠，翹沙晴影月中孤。", "青田萬里終歸去，暫處雞羣莫歎吁。", "（見《宋詩紀事》卷二。", "）（見《瀛奎律髓》卷二七。", "）（〖1〗《青箱雜記》〖宋吳處厚撰〗：「昉所畜五禽，名五客，仙客鶴，雪客鷺，閑客白鷴，隴客南客孔雀，西客鸚鵡，有詩云。", "」〖今本《青箱雜記》無此條。", "〗）。"]'),
('eaa78063-2d62-497b-ac47-ad72ffa5f2e0','耒陽杜工部墓（題擬）','孟賓于','唐','唐诗','tang','','[]','南遊何感思，更甚葉繽紛。',119,'全唐诗/poet.tang.50000.json','["南遊何感思，更甚葉繽紛。", "一夜耒江雨，百年工部文。", "青山當日見，白酒至今聞。", "惟有爲詩者，經過時弔君。", "（見錢謙益《箋注杜工部集唱酬題就是》引《耒陽祠志》。", "《增修詩話總龜》卷四三引劉斧《摭遺》引「一夜耒江雨，百年工部文」二句，稱爲「唐人詩」。", "）。"]'),
('99983eda-8625-46d0-a18b-1818355e59fa','贈徐鼎臣常侍','印粲','唐','唐诗','tang','','[]','不將才業暫時誇，人仰聲名遍海涯。',232,'全唐诗/poet.tang.50000.json','["不將才業暫時誇，人仰聲名遍海涯。", "月滿朝衣聽禁漏，更闌分直掃宮花。", "諫書未上先焚稾，御筆曾傳立草麻。", "見說下朝無一事，小池栽葦學僧家。", "（見《江南餘載》卷下。", "）（〖1〗《江南餘載》畧謂：徐鉉爲人忠厚，不以位貌驕人。", "有印粲者獻詩曰〖詩不重錄〗云云。", "望按：徐鉉有《印秀才至舒州見尋別後寄詩依韻和》及「和印先輩及第後獻座主朱舍人郊居之作」，則印粲於時已擢進士第矣。", "又按《歷代吟譜》錄印粲詩二句：「見說下朝無一事，小池栽葦學僧家。", "」標其題曰《贈徐鼎臣常侍》，蓋此詩之末二句也。", "）。"]'),
('a5536581-b613-4387-8ec9-718bc4f5003f','夜吟竇鞏集追思夷門題處已三稔矣悽然感興書之','張昭','唐','唐诗','tang','','[]','往歲記時梁苑夜，今宵題處洛城秋。',214,'全唐诗/poet.tang.50000.json','["往歲記時梁苑夜，今宵題處洛城秋。", "浮生瞥電人何在，懷舊傷心淚迸流。", "三徑竹風鄰笛怨，一庭霜月井[桐]（梧）愁。", "妻兒未會[余]（予）惆悵，只怪燈前不舉頭。", "（見《宋詩紀事》卷二。", "此詩出影宋刻《竇氏聯珠集》附錄，詩前有張昭跋：「鞏囁嚅，詩一何神妙，恨此少不見。", "其集，《聯珠》之最也。", "戊戌歲中元前一日夷門旅舍書，潛夫。", "」潛夫爲昭字。", "詩題中「夷門題處」，即指此跋。", "戊戌爲天福三年〖九三八〗，知詩作於天福六年〖九四一〗。", "有二處異文，今據改。", "）。"]'),
('08cacbb0-bbce-4675-9498-f1d68a22fb80','贈馬道士','李九齡','唐','唐诗','tang','','["\u534e\u5c71"]','水共逍遙雲共孤，混時言笑只佯愚。',131,'全唐诗/poet.tang.50000.json','["水共逍遙雲共孤，混時言笑只佯愚。", "經年但醉宜城酒，千里唯擔《華嶽圖》。", "尋野鶴來空碧洞，覔琴僧去渡重湖。", "人間再見知何日，乞取先生石轆轤。", "（見方回《瀛奎髓》卷四十八《仙逸類》。", "）（按《瀛奎律髓》原注云：「九齡，乾德五年進士第三人。", "」與《全唐詩》小傳作乾德二年者異。", "）。"]'),
('b82e4931-af00-4667-882f-900b181839c8','贈譚先生','楊徽之','唐','唐诗','tang','','[]','古觀重重遶翠微，杉松深處掩雙扉。',139,'全唐诗/poet.tang.50000.json','["古觀重重遶翠微，杉松深處掩雙扉。", "雲生萬壑投龍去，海隔三山放鶴歸。", "花洞宴游春日永，石壇朝禮曙星稀。", "每聽高論長生理，擬向塵中便拂衣。", "（見《瀛奎律髓》卷四十八《仙逸類》。", "此詩明李蔉所輯《宋藝圃集》作李九齡詩。", "按徽之又有《禁林讌會之什》一首見於《翰苑羣書》者，係入禋後所作，不收錄。", "）。"]'),
('df62d3fc-b5b9-458e-88e7-0a02cdc8f77a','句 一','楊徽之','唐','唐诗','tang','','[]','戍樓煙[自]（似）直，戰地雨長腥。',24,'全唐诗/poet.tang.50000.json','["戍樓煙[自]（似）直，戰地雨長腥。", "（《塞上》）。"]'),
('0fd2861d-9448-4bf5-a25d-7cf3b303c3f4','句 二','楊徽之','唐','唐诗','tang','','[]','春歸萬年樹，月滿九重城（《元夜》）。',18,'全唐诗/poet.tang.50000.json','["春歸萬年樹，月滿九重城（《元夜》）。"]'),
('1128d123-67da-4014-acb4-9033fa7d1fdf','句 三','楊徽之','唐','唐诗','tang','','[]','偶題嵓石雲生筆，閑遶庭松露濕衣。',23,'全唐诗/poet.tang.50000.json','["偶題嵓石雲生筆，閑遶庭松露濕衣。", "（《僧舍》）。"]'),
('85e015d0-cc48-4154-96fb-6d4dc7188cc2','句 四','楊徽之','唐','唐诗','tang','','[]','開盡菊花秋色老，落殘桐葉雨聲寒。',68,'全唐诗/poet.tang.50000.json','["開盡菊花秋色老，落殘桐葉雨聲寒。", "（《宿東林》以上八句並見《宋詩紀事》卷二。", "均見《玉壺清話》卷五、《澠水燕談錄》卷七，宋太宗曾書於御屏。）"]'),
('3a8e3553-61d2-479e-ab2a-28e76b1852a6','句（《吟窗雜錄》卷三一《歷代吟譜》引此二句，題作《秋夕詩》。）','卞震','唐','唐诗','tang','','[]','空囊萬里客，斜月一床寒。',34,'全唐诗/poet.tang.50000.json','["空囊萬里客，斜月一床寒。", "（見《宋詩紀事》引宋失名撰《歷代吟譜》。", "）。"]'),
('0b798467-b4ce-4553-85b5-19b2f049889f','','劉吉','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.50000.json','["。"]'),
('b3761e77-cfbc-4499-b6c1-392733bf4b27','句','劉吉','唐','唐诗','tang','','[]','一箭不中鵠，五湖歸釣魚。',192,'全唐诗/poet.tang.50000.json','["一箭不中鵠，五湖歸釣魚。", "（《贈隱者》。", "見《宋詩紀事》卷三引《歷代吟譜》。", "按《全唐詩》卷七百九十五作張塋詩句。", "云見地志。", "）（《增修詩話總龜》卷一引《叢苑》、《宋朝事實類苑》卷五五引《楊文公談苑》幷載劉吉此二句詩，並云其「有詩三百首，目爲《釣鼇集》，徐鉉爲序。", "其首篇《贈隱者》，……人多誦之」。", "《全唐詩》所收張塋，應張瑩，《淳熙三山志》卷二、卷三四收此二句爲其詩。", "二句似驗劉作爲近是。", "）。"]'),
('896c8677-c2c4-476a-b75e-405c1d708042','句','孟歸唐','唐','唐诗','tang','','["\u5e90\u5c71"]','練色有窮處，寒聲無斷（《江南野史》「斷」作「盡」。',168,'全唐诗/poet.tang.50000.json','["練色有窮處，寒聲無斷（《江南野史》「斷」作「盡」。", "）時。", "（《瀑布》。", "見宋馬令《南唐書》卷二十三《孟賓于傳》。", "亦見宋龍袞《江南野史》。", "）（〖1〗《南唐書》：〖孟賓于〗初歸江南，生子鱣歸唐，亦能詩。", "肄業廬山國學，嘗得《瀑布詩》云：「練色有窮處，寒聲無斷時。", "」隣房生亦得此聯，遂交爭之。", "助教不能辯，訟于江州。", "各以全篇意格定之，而歸唐爲勝。", "）。"]'),
('e728a021-50d1-4463-9796-255c1468a8ec','','錢惟治','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.50000.json','["。"]'),
('8c8d1b25-ec1c-492b-9215-6c60c13d6726','春日登大悲閣迴文（二首） 一','錢惟治','唐','唐诗','tang','','[]','聖主欽崇教，千光顯紺容。',48,'全唐诗/poet.tang.50000.json','["聖主欽崇教，千光顯紺容。", "映雲窗綺暖，籠月箔花重。", "淨剎香風遠，危闌碧霧濃。", "勝因良以詠，華國一斯逢。"]'),
('f2609daa-b8c5-47bc-982f-c00eb7331d8b','春日登大悲閣迴文（二首） 二','錢惟治','唐','唐诗','tang','','[]','碧天臨迥閣，晴雪點山屏。',126,'全唐诗/poet.tang.50000.json','["碧天臨迥閣，晴雪點山屏。", "夕烟侵冷箔，明月歛閑亭。", "（見《宋詩紀事》卷三引《冰川詩式》。", "）（均見明梁橋《冰川詩式》卷二，前首「危闌」作「危欄」，「華國」作「華閣」。", "）（〖1〗《湖州府志》：「吳越《迴文綬帶連環詩碑》，在法華寺，節度使錢惟治作，九十首。", "」）。"]'),
('2631be4e-9d41-4a60-960c-12f77c7e2454','贈趙叟（題擬）','何蒙','唐','唐诗','tang','','[]','桂枝輪卻正淒然，又被鸎聲聒晝眠。',122,'全唐诗/poet.tang.50000.json','["桂枝輪卻正淒然，又被鸎聲聒晝眠。", "唯有趙翁知仔細，相傳好語待來年。", "（見《江南餘載》卷上。", "）（〖1〗《江南餘載》：趙叟者，自保大之初至於開寶之季，嘗爲貢院門子，每歲放榜之後，或去或留，率慶慰之，若出於叟手然。", "進士何蒙目前叟詩曰〖詩不重錄〗云云。", "）。"]'),
('1a5dccf3-3c4f-4f6a-a03c-3be883d7b566','寄劉乙處士','詹敦仁','唐','唐诗','tang','','[]','音問相忘二十秋，天者我輩到南州。',203,'全唐诗/poet.tang.50000.json','["音問相忘二十秋，天者我輩到南州。", "無窮風月隨宜樂，有分溪山取次收。", "好語傳來如昨夢，離情欲剖帶春愁。", "何時載酒從東下，細與劉君敘昔遊。", "（見《永樂大典》卷一三四五○「二寘」「士」字「處士」條〖十四函一百三十七冊〗。", "）（按：劉乙字子黃，泉州人。", "仕閩爲鳯閣舍人，後棄祁隱安溪鳯髻山。", "《全唐詩》卷七百六十三收劉乙詩一首幷殘句二，又卷八百八十六補遺二首。", "《全唐詩》詹敦仁詩有《遺子訪劉乙》一首。", "劉乙生涯，於此約畧可窺。", "）。"]'),
('2a867366-bd79-4284-a969-1ac19b4988b4','琲訪劉君乙時已歿故將歸王令留之不可以書來囑作此篇示','詹敦仁','唐','唐诗','tang','','[]','劉郎蹤跡久荒凉，卜宅何妨處士鄉。',87,'全唐诗/poet.tang.50000.json','["劉郎蹤跡久荒凉，卜宅何妨處士鄉。", "壯志莫隨流俗變，老夫霜鬢已凝霜。", "（見《永樂大典》卷一三三四四「二寘」「示」字〖十四函一百三十七冊〗引詹敦仁《清隱集》。", "案：琲爲詹敦仁之子。", "）。"]'),
('a88092e3-8308-4374-bf39-872d7dfde773','入局吟','詹敦仁','唐','唐诗','tang','','[]','明命初頒得美除，慚惶下拜敢寧居？',45,'全唐诗/poet.tang.50000.json','["明命初頒得美除，慚惶下拜敢寧居？", "儒生不作于時計，（于時，疑當作「干時」。", "）且讀人間未見書。"]'),
('c62134b6-0324-4713-8978-c5fe4d834ae2','又一首（用前韻）','詹敦仁','唐','唐诗','tang','','[]','可恨名存實已除，蘭臺芸閣復誰居？',73,'全唐诗/poet.tang.50000.json','["可恨名存實已除，蘭臺芸閣復誰居？", "豕魚未識應多愧，尤恐在人成蠹書。", "（以上二詩見《永樂大典》卷一九七八二「一屋」。", "「局」字〖十八函一百七十八冊〗。", "）。"]'),
('257989b1-afe1-481c-a545-c4543505fccc','答高越（題擬）','陳曙','唐','唐诗','tang','','[]','罷修儒業學修真，養拙藏愚四十春。',346,'全唐诗/poet.tang.50000.json','["罷修儒業學修真，養拙藏愚四十春。", "到老不疎林裏鹿，平生未識日邊人。", "澗花發處千堆錦，巖雪鋪時萬樹銀。", "多謝朝賢遠相問，未聞雞得鳯爲鄰。", "（見《江南餘載》卷下。", "按《全唐詩》卷八百六十一作李夢符詩，題曰《答常學士》。", "詩中異處較多，對勘之下，以此爲勝，故仍錄而存之。", "）（〖1〗《江南餘載》：蜀人陳曙者，王氏末年避地淮南，隱於蘄州山中。", "鄉人祀神，曙不召亦必至，醉飽而後去。", "雖百神祀，曙能遍往也。", "其所居，屋一間，道書數卷而已，與蛇虎雜處而泰突無所忌。", "元宗遣中書舍人高越齎束帛徵之，三往不應。", "後移居鄂州，不知所終。", "越贈曙以新的。", "曙次韻答之。", "〖2〗按高越字仲遠，幽州人，仕吳，授秘書郎，累遷中書舍人，終勤政殿學士、戶部侍郎。", "《全唐詩》收越《咏鷹》一首，《江南餘載》卷上亦載之，惟題作《鷂子詩》，字句略有異同耳。", "）。"]'),
('3527a1f8-6fbe-4ea9-87f3-dbbbb46f5e53','題失','許堅','唐','唐诗','tang','','[]','祇應天上路，不爲下方開。',186,'全唐诗/poet.tang.50000.json','["祇應天上路，不爲下方開。", "道既學不得，仙從何處來。", "（〖1〗按此詩見宋鄭文寶撰《江南餘載》卷下，《知不足齋叢書》本。", "《全唐詩》卷七百五十七收許堅詩五首，又卷八百六十一仙卷亦收五首幷句，其中兩句曰「道既學不得，仙從何處來」。", "即此詩之後兩句，蓋《全唐詩》缺其前半。", "〖2〗《江南餘載》：許堅往來句曲廬阜之間，草裝布囊，或臥於野，或和衣浴澗中，蕭然不接人事，獨笑獨吟而已〖餘畧〗。", "）。"]'),
('a482d76d-7f96-4d93-a50e-e174bb85a956','竹山連句題潘氏書堂','顏真卿等','唐','唐诗','tang','','[]','（顏真卿、陸羽、李蕚、裴修、康造、湯清河、清晝、陸士修、房夔、顏粲、顏顓、顏須、韋介、李觀、房益、柳淡、顏峴、潘述）竹山招隱處，潘子讀書堂。',450,'全唐诗/poet.tang.50000.json','["（顏真卿、陸羽、李蕚、裴修、康造、湯清河、清晝、陸士修、房夔、顏粲、顏顓、顏須、韋介、李觀、房益、柳淡、顏峴、潘述）竹山招隱處，潘子讀書堂。", "（真卿）萬卷皆成袠，千竿不作行。", "（陸羽）練容飡沆瀣，濯足咏「滄浪」。", "（李萼）守道心自樂，下帷名益彰。", "（裴修）風來似秋興，花發勝河陽。", "（康造）支策曉雲近，援琴春日長。", "（湯清河）水田聊學稼，野圃試條桑。", "（清晝）巾折定因雨，履穿寧爲霜。", "（陸士修）解衣垂蕙帶，拂席坐藜牀。", "（房夔）檐宇馴輕翼，簪裾染衆芳。", "（顏粲）草生遽近砌，藤長稍依牆。", "（顏顓）魚樂憐清淺，禽閑熹頡行。", "（顏須。", "行當作「頏」）空園種桃李，遠墅於此牛羊。", "（韋介）讀《易》三時罷，圍碁百事忘。", "（李觀）境幽神自王，道在器猶藏（房益）晝歠山僧苟，宵傳野客觴。", "（柳淡）遙峯對枕席，麗藻映縑緗。", "（顏峴）偶得幽棲地，無心學鄭鄉。", "（潘述）（見《三長物齋叢書》本《顏魯公文集》卷十二，寧鄉黃本驥編訂。", "）（〖1〗連句詩後有黃本驥案語，曰：「連句，即聯句也。", "裴修，前梁縣尉。", "康造，會稽人，推官。", "湯清河，大理評事。", "房夔，河南人。"]'),
('4b7c86ac-39b5-454b-8287-896dee36029e','水名','宇文正','唐','唐诗','tang','','[]','江湖思舊好，河洛賞遺風。',75,'全唐诗/poet.tang.50000.json','["江湖思舊好，河洛賞遺風。", "共託金門暇，來遊白□□。", "竹霞開樽綠，桃花落□紅。", "故鄉渺天涯。", "應在□地□。", "（見影印本《新編纂圖增類羣書類要事林廣記》卷之七。", "）。"]'),
('d081a00f-aa81-4fd7-af7e-6e4f6dd3609e','','程傑','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.50000.json','["。"]'),
('178f0352-27d2-4711-8c73-91f03c96d7ff','芙蓉峯','程傑','唐','唐诗','tang','','["\u9ec4\u5c71"]','誰把芙蓉雲外栽，亭亭秀麗四時開。',55,'全唐诗/poet.tang.50000.json','["誰把芙蓉雲外栽，亭亭秀麗四時開。", "清宵皓月峯頭掛，宛似佳人對鏡臺。", "（見康熙十八年閔麟嗣撰《黃山志定本》卷六。", "）。"]'),
('8cb5796e-e914-4cea-b4cb-24a8a5428e38','頌裴長史歌（題擬）','無名氏','唐','唐诗','tang','','[]','賓朋何喧喧？日夜裴公門。',76,'全唐诗/poet.tang.50000.json','["賓朋何喧喧？日夜裴公門。", "願得裴公之一言，不須驅馬埒華軒。", "（按李白《上安沒裴長史書》有云：「故時人歌曰〖歌不重錄〗。", "白不知君侯何以得此聲于天壤之間。", "」）。"]'),
('63d9ddc9-4b20-4eef-bfcd-daa01ce578b0','青鸞鏡詩','無名氏','唐','唐诗','tang','','[]','月樣團圓水漾（《金石萃編》作「樣」。',341,'全唐诗/poet.tang.50000.json','["月樣團圓水漾（《金石萃編》作「樣」。", "）清，好將香閤（《萃編》作「閣」）伴閑身。", "青鸞不用羞孤影，開匣當如見故人。", "（〖1〗畢沅、阮元撰《山左金石志》卷五曰：「右鏡徑二寸八分，鼻鈕正書七言絕句一首曰〖詩不重錄〗。", "外折枝花四枝。", "按段若膺《四聲音韻表》，清在第十一部，身在第十二部。", "然《易·彖象傳》天命淵賢信民人賓，與形成貞寧生正平精清等字幷用，是二部古有相合。", "唐人首句押韻雖不必拘拘，然未有無故牽入者。", "此清字可込其未備。", "」〖2〗按此詩亦載王昶《金石萃編》卷一百十八，錄其按語如下：「按《山左金石志》跋此銘，謂首句清字與身人同韻，補段若膺《四聲音韻表》所未備。", "然七言律絕起句，晚唐五代多有借韻者。", "且真文庚青自古間有通用，顧氏寧人、毛氏大可於《唐韻正》及《古今通韻史》已詳載之，不足異也。", "」）。"]'),
('f57af99d-18fc-42d6-bbeb-7ec708c7ac6b','挽歌五首','無名氏','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.50000.json','["。"]'),
('86f3fa78-12d7-44f0-b425-7f429b8e2d12','挽歌五首 其一','無名氏','唐','唐诗','tang','','[]','高坐星文掩，人寰巷市忙。',48,'全唐诗/poet.tang.50000.json','["高坐星文掩，人寰巷市忙。", "三台投劍佩，四海哭煙霜。", "夕殿震號永，秋風曉更長。", "龍顏不可見，燒畫月更香。"]'),
('7ee7c794-1f47-46d0-bddc-d8e7ebffd2c8','挽歌五首 其二','無名氏','唐','唐诗','tang','','[]','憶別西凉日，來朝北闕時。',53,'全唐诗/poet.tang.50000.json','["憶別西凉日，來朝北闕時。", "舌官捧□殿，獨召上龍墀。", "寵極[孤]（狐）臣懼，恩深四表知。", "此由殉靈駕，血淚自雙垂。"]'),
('9a7f14e6-88bb-467f-b47d-afe17963af7c','挽歌五首 其三','無名氏','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','香[嚲]（𨭐）鬱金袍，求衣不重勞。',53,'全唐诗/poet.tang.50000.json','["香[嚲]（𨭐）鬱金袍，求衣不重勞。", "方張洞庭樂，休種閬山桃。", "鶴駕丹陵遠，龍驤碧落高。", "胡髯攀斷處，□搶高弓號。"]'),
('3240bf79-3118-4887-8f4f-623c58b93857','挽歌五首 其四','無名氏','唐','唐诗','tang','','[]','巢閣方瞻[鳯]（風），鳴郊忽酬麟。',53,'全唐诗/poet.tang.50000.json','["巢閣方瞻[鳯]（風），鳴郊忽酬麟。", "六宮悲晏駕，四嶽罷來巡。", "璽綬傳當璧，河山委大臣。", "自傷蒲柳質，不得扈龍輴。"]'),
('79c9ecd7-fe07-470f-bcfc-7f5ba6f7e94e','挽歌五首 其五','無名氏','唐','唐诗','tang','','[]','七載朝金殿，千秋遇聖君。',103,'全唐诗/poet.tang.50000.json','["七載朝金殿，千秋遇聖君。", "九夷瞻北極，萬國靡南熏。", "盛烈排軒后，崇淩壓□文。", "靈知河瀧士，興斷高鄉雲。", "（以上五詩從許國霖輯《敦煌雜錄》錄出。", "許氏擬頁原作《進上挽歌》，此省作《挽歌》。", "）（三處改動皆從趙遂之說。", "）。"]'),
('575dd05d-0c1e-4f1b-8814-a0a1834ba640','王昭君怨諸詞人連句','無名氏','唐','唐诗','tang','','[]','掖庭嬌幸在娥眉，爭用黃金寫艷姿。',321,'全唐诗/poet.tang.50000.json','["掖庭嬌幸在娥眉，爭用黃金寫艷姿。", "始言恩寵由君意，誰謂容顏信畫師。", "微軀一身入深宮，春華幾度落秋風。", "君恩不惜便衣處，妾貌應殊畫辟中。", "間道和親將我敞，選貌披圖遍宮掖。", "圖中容貌既不如，選後君王空海（望疑「悔」字之誤）惜。", "始知王意本相親，自恨舟（望疑「丹」字之誤）青每誤身。", "昔是宮中薄命妾，今成塞外斷腸人。", "九重恩愛應長謝，萬里關山愁遠嫁。", "飛來北地不勝春，月照南庭空度夜。", "夜中含涕獨嬋娟，遙念君邊與朔邊。", "毳幕不同羅帳日，氈裘非復錦衾年。", "長安高闕三千里，一望能令一心死。", "秋來懷抱既不堪，況復南飛雁聲起。", "（此詩見劉復《燉煌掇瑣》三四。", "題雖標連句，然不著諸詞人姓名，故仍以常詩視之。", "此詩又見於王重民《〈補全唐詩〉拾遺》。", "王輯本刊出於本書成書之後，故兩存之。", "）。"]'),
('b978ce7d-573d-483f-9a3e-da179dfd3b73','失題','無名氏','唐','唐诗','tang','','[]','東上波流西上船，桃源未必有真仙。',98,'全唐诗/poet.tang.50000.json','["東上波流西上船，桃源未必有真仙。", "干戈滿目家何在，寂寞空山聞杜鵑。", "（見《江南餘載》卷下。", "南唐開寶末詩也。", "）（〖1〗《江南餘載》：「開寶末，長老法倫夢金陵兵火四起，有書生朗吟曰〖詩不重錄〗」云云。", "）。"]'),
('65b7daff-fce8-4883-8715-910ac3bcbc0b','看南山','栖白','唐','唐诗','tang','','[]','抗蜀復臨秦，凝嵐萬古新。',78,'全唐诗/poet.tang.50000.json','["抗蜀復臨秦，凝嵐萬古新。", "峭連河漢地，氣爽市朝人。", "影裏天家桂，光中陸海珍。", "愛山兼戀此，偏柰與誰隣？", "（見《分門纂類唐歌詩》殘本第二冊《天地山川類》卷二十二。", "）。"]'),
('6f9cef0e-1879-42af-a31e-8b2ac163f449','七日禁中陪宴','仁貞','唐','唐诗','tang','','[]','入朝貴國慙下客，七日承恩作上賓。',86,'全唐诗/poet.tang.51000.json','["入朝貴國慙下客，七日承恩作上賓。", "更見鳯（一作「凰」）聲無妓態，風流變動一園（一作「國」）春。", "（此詩爲仁貞在日本國作。", "見金毓黻撰《渤海國志長編》卷十八引《文華秀麗集》上。", "）。"]'),
('f70bc793-6cea-4dea-82fb-4a9159d534a6','哭日本國內供奉大德靈仙和尚詩（幷序）','貞素','唐','唐诗','tang','','[]','不體（《類從》本作「航」。',362,'全唐诗/poet.tang.51000.json','["不體（《類從》本作「航」。", "〖又日本佛教全書〗本作「{舟巳}」。", "考云：「{舟巳}即那字。", "慧超《傳》多用此字。", "」）心淚（《類從》本作「渡」。", "）自涓，（望按：「此句原脫一字。", "」）情因法眼奄幽泉。", "明朝儻問滄波客，的說遺鞋白足還。", "（見《渤海國志長編》卷十八引《入唐求法巡禮行記》三。", "）（〖1〗按詩前有小注，曰「詩一首。", "在唐作」。", "蓋從當時渤海藩國言，故曰「在唐」也。", "又詩末題「大和二年四月十四日書」十字。", "〖2〗上海古籍出版社一九八六年出版顧承甫等點校本《入唐求來巡禮行記》，參據多種版本校勘，較精審。", "今錄異文如次：「公作而習之」，「作」作「僕」；「余之身期降物」，作「余亦身期絳物」；「入宗五臺」，「宗」作「室」；「青癡」，作「青瘀」；「仙大師己來日久」，「己」作「亡」；「位我之血」，「位」作「泣」；「不體心淚」，「體」作「航」。", "）。"]'),
('8b078a6d-7982-4aad-b729-fdc1f716f04f','元孚五十年前遊天台宿建公院登華頂攀琪樹觀石橋之險絕緬懷昔遊因爲絕句寄知建長老兼呈台州王司馬','元孚','唐','唐诗','tang','','[]','天生石月架空虛，樹綴龍髯子貫珠。',126,'全唐诗/poet.tang.51000.json','["天生石月架空虛，樹綴龍髯子貫珠。", "三十年前已攀折，建公曾到上方無。", "（見明陶宗儀《古刻叢鈔》。", "）（詩下原署曰「上都左街保壽寺文章應制內供奉大德元孚」。", "又《寶刻叢編》卷十五有《唐房田寺經藏院記》，云唐崔龜從撰，僧元孚書，會昌二年立。", "則元孚者，武宗提人也。", "）。"]'),
('5f2f84a2-ef74-4475-9d24-116376fed23a','','思託','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.51000.json','["。"]'),
('c1b7de91-e9b7-4ada-b55e-32b23a890da7','五言傷大和上傳燈逝[日本]','思託','唐','唐诗','tang','','[]','上德乘杯渡，金人道已東。',179,'全唐诗/poet.tang.51000.json','["上德乘杯渡，金人道已東。", "戒香餘散馥，慧炬復流風。", "月隱歸靈鷲，珠逃入梵宮。", "神飛生死表，遺教法門中。", "（〖1〗見同前書《唐大和上東征傳》。", "詩題下原署曰「日本國傳燈沙門思託」。", "〖汪向榮校注本《唐大和上東征傳》錄此詩題作《五言傷大和上傳燈逝日本》，署「傳燈沙門釋思託」。", "以「日本」二字歸詩題，是，今據補。", "思託爲鑒真弟子，《東征傳》中多次提及。", "〗餘參閱前元開詩附注。", "）。"]'),
('505ea7bb-b50e-49b9-9dc4-2cf0956e19c7','七言傷大和上','法進','唐','唐诗','tang','','[]','大師慈育契圓空，遠邁傳燈照海東。',245,'全唐诗/poet.tang.51000.json','["大師慈育契圓空，遠邁傳燈照海東。", "度物草（寸）籌盈石室，散流佛戒紹遺蹤。", "化畢分身歸淨國，娑婆誰復爲驗龍？", "（驗龍，汪向榮校注本《唐大和上東征傳》據日本觀智院本改爲「驅龍」。", "）（按詩題下原署「傳燈賢大法師大僧都沙門釋法進」十四字。", "詩亦見《唐大和上東征傳》。", "又按鑒真亡後，唐高鶴林亦曾作五言詩一首以悼之，詩亦載《唐大和尚東征傳》。", "高爲唐肅宗、代宗朝人，官都虞候冠軍大將軍試太常卿上柱國，因出使日本國，欲順訪東渡僧鑒真，至則鑒真已先亡故，詩蓋寄懷傷之意也。", "上野河世寧已收入《全唐詩逸》，兹不再錄。", "）。"]'),
('7553b547-5aeb-4ca9-bfaf-4f1da9d04677','咏紅芙蓉上宋使（「宋使」二字於此當脫「君」字。宋使君屢見於《禪月集》，《唐刺史考》考定爲宋震。）','貫休','唐','唐诗','tang','','[]','擘水苞金紫艷濃，乍觀疑在水仙宮。',87,'全唐诗/poet.tang.51000.json','["擘水苞金紫艷濃，乍觀疑在水仙宮。", "難驅顏色文章裏，合出天人池館中。", "芬馥靜生朱檻膩，動搖微映鷺鷥紅。", "臨川內史詩相似，搖仰清吟滿閣風。", "（見《唐歌詩》殘本六冊《草木蟲魚類》卷五。", "）。"]'),
('c2eb9620-c2a9-4a44-a26b-92a2f86ee10b','苔蘚','貫休','唐','唐诗','tang','','[]','嚴子釣臺邊不少，謝公山展上無多。',66,'全唐诗/poet.tang.51000.json','["嚴子釣臺邊不少，謝公山展上無多。", "（展，疑當作「屐」。", "）世間若也皆廉潔，金玉生根柰爾何？", "（見《唐歌詩》殘本六冊《草木蟲魚類》卷六。", "）。"]'),
('b0d2d9e8-5300-470e-a811-17896dd98087','長安柳','修睦','唐','唐诗','tang','','[]','雨重依依舞態低，任人攀折路東西。',56,'全唐诗/poet.tang.51000.json','["雨重依依舞態低，任人攀折路東西。", "何如渡□成林處，留得黃鸎到夜啼。", "（見《唐歌詩》殘本第七冊《草石蟲魚類》卷八。", "）。"]'),
('6e8755e8-f916-460c-acec-046b6ef9d1f6','傷悼前蜀廢國（《鑑誡錄》卷五錄此詩題作《傷廢國》。）','遠公','唐','唐诗','tang','','[]','樂極悲來數有涯，歌聲才歇便興嗟。',179,'全唐诗/poet.tang.51000.json','["樂極悲來數有涯，歌聲才歇便興嗟。", "牽羊廢主尋傾國，指鹿姦臣盡喪家。", "丹禁夜涼空鏁月，後庭春老謾開花。", "兩朝帝業都成夢，陵樹蒼蒼噪暮鴉。", "（見前蜀何光遠《鑑誡錄》卷五。", "日本漢學家豐田穰氏所撰《全唐詩糾謬》一文曾論及之，云《全唐詩》所未收。", "）（《增修詩話總龜》卷三十錄此詩，作「蜀僧遠國《傷蜀詩》」。", "詩中「指鹿」作「逐鹿」，「陵樹」作「林木」，均當以《鑑誡錄》爲長。", "）。"]'),
('df319db8-2859-4426-9b73-9bfd2666d06a','看牡丹（見《唐僧弘秀集》卷五。按《全唐詩》作僧謙光詩，題作《賞牡丹應教》。詩中「毳」字，《全唐詩》作「衲」，「趣」作「事」，）','文益','唐','唐诗','tang','','[]','空（「髪」作「鬢」，「是」作「似」，「曳」作「異」，「晚」作「曉」，「待」作「對」。',169,'全唐诗/poet.tang.51000.json','["空（「髪」作「鬢」，「是」作「似」，「曳」作「異」，「晚」作「曉」，「待」作「對」。", "謙光，金陵人，有才辯。", "〖《全唐詩續補遺》卷十五據《分門纂類唐歌詩》、《唐詩紀事》卷七六錄此則，今刪彼存外。", "《全唐詩》作謙光，所據爲陶岳《五代史補》卷五。", "另《大法眼文益禪師語錄》、《五燈會元》卷十、《苕溪漁隱叢話》卷五七、《釋氏稽古略》亦收作文益詩。", "〗）。"]'),
('319612a4-9849-44ca-a640-e4d3e6b84f4c','閑居','延壽','唐','唐诗','tang','','[]','閑居誰似我，退跡理難過。',107,'全唐诗/poet.tang.51000.json','["閑居誰似我，退跡理難過。", "要勢危身早，浮榮敗德多。", "雨催蟲出穴，寒逼鳥移窼。", "野徑無人翦，疏窗入薜蘿。", "（見《宋詩紀事》卷九十一。", "）（張靖龍云此詩見《讀畫齋叢書》本《南宋羣賢小集》收陳起輯《增廣聖宋高僧詩選後集》卷中。", "）。"]'),
('edfaed0d-3c6b-4bd9-8485-2133edb0ea57','','贊寧','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.51000.json','["。"]'),
('b61d1b85-3ea3-47cb-9329-8aec2d9896ca','寄題水月禪院（在洞庭山縹緲峯下，梁大同四年建，山有無礙泉。）','贊寧','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','參差峯岫晝雲昏，入望攀蘿濁浪奔。',200,'全唐诗/poet.tang.51000.json','["參差峯岫晝雲昏，入望攀蘿濁浪奔。", "震澤湧山來北岸，華陽連洞到東門。", "日生樹掛紅霞脚，風起波搖白石根。", "聞有上方僧住處，橘花林下採蘭蓀。", "（見《宋詩紀事》引《吳都志》。", "）（見《吳郡志》卷三三《郭外詩》，爲同題二首之一。", "《吳郡志》云：「水月禪院，在洞庭山縹緲峰下。", "……天祐四年，刺史曹珪以明月名之。", "皇朝祥符間，詔易今名。", "」贊寧卒於咸平四年〖據《釋氏疑年錄》〗，易名水月爲其身後事，詩題似應作《寄題明月禪院》。", "）。"]'),
('420576f2-8a90-4796-8562-864fd1dc92d5','居天柱山','贊寧','唐','唐诗','tang','','[]','四野豁家庭，柴門夜不扃。',87,'全唐诗/poet.tang.51000.json','["四野豁家庭，柴門夜不扃。", "水邊成半偈，月下了殘經。", "雖逐諸塵轉，終歸一念醒。", "未知斯旨者，萬役盡勞形。", "（《瀛奎律髓》卷四十七《釋梵類》。", "）（見陳起《增廣聖宋高僧詩選後集》卷上。", "）。"]'),
('6aa35a09-980c-4b7d-bf07-7f66b2f1adba','答贊寧','天目僧','唐','唐诗','tang','','[]','山中人事違，天眼中修定。',48,'全唐诗/poet.tang.51000.json','["山中人事違，天眼中修定。", "（天目，一名天眼。", "）我本無根株，只將筍爲命。", "（見釋贊寧所撰《筍譜》。", "）。"]'),
('ea7c1d0c-be78-45c7-a3f6-a970927913db','禪詩 一','無名僧','唐','唐诗','tang','','[]','座禪不亂意，觀色更無緣。',42,'全唐诗/poet.tang.51000.json','["座禪不亂意，觀色更無緣。", "三獨羅剎得成佛，不要流心再座禪。", "（原注云：「五言一首。", "」）。"]'),
('f4e3e899-e35e-4900-bbe6-8324e90b876f','禪詩 二','無名僧','唐','唐诗','tang','','[]','座得須不喜動，何要觀心了三界。',39,'全唐诗/poet.tang.51000.json','["座得須不喜動，何要觀心了三界。", "但觀性內所，不知意緣起。", "（原注云：「一首。", "」）。"]'),
('b40f48e4-4639-4712-baa1-c753efb3cdd8','禪詩 三','無名僧','唐','唐诗','tang','','[]','心平不用持戒，行直河須座。',55,'全唐诗/poet.tang.51000.json','["心平不用持戒，行直河須座。", "恩則普同婦子，義則上下漠然。", "苦口則是凉藥，依●定出黃蓮。", "菩薩向心如覓，天堂即在眼前。"]'),
('61db7025-509a-45b2-a16e-7b7c13b46982','禪詩 四','無名僧','唐','唐诗','tang','','[]','清蓮臺上見天唐，衆生真心禮肆芳。',142,'全唐诗/poet.tang.51000.json','["清蓮臺上見天唐，衆生真心禮肆芳。", "降摩處上夜放光，菩薩悲願遍什芳。", "（以上四首見伯二一二九卷，前三首抄於一處，第四首另抄。", "第三首第二句，似應作「行直何須坐禪」。", "第四句「漠然」，原卷作「嘆然」，疑應作「懽然」。", "第五句「涼藥」應作「良藥」。", "第四首中「肆芳」、「什芳」，通「四方」、「十方」。）"]'),
('144300f6-599b-4732-ba04-d1875e1ced48','禪詩 五','無名僧','唐','唐诗','tang','','[]','即日一千僧，住在寺山林。',54,'全唐诗/poet.tang.51000.json','["即日一千僧，住在寺山林。", "百鳥同科宿，相看見兄弟。", "（此首原注出伯二六三三卷。", "末句「兄弟」，疑應作「弟兄」。", "）。"]'),
('dd2a3c59-0ac1-4458-8e27-199743994400','','吳筠','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.51000.json','["。"]'),
('24a4a4fd-1081-4bff-9f4b-3a75188c68dc','酬劉侍御過草堂','吳筠','唐','唐诗','tang','','[]','疇昔隳世網，就閒棲遠林。',115,'全唐诗/poet.tang.51000.json','["疇昔隳世網，就閒棲遠林。", "豈謂軒車客，來過澗壑深。", "既懷康濟業，仍許隱淪心。", "靈液充甘飲，松風代鳴琴。", "晤言不可極，真興何愔愔。", "貽我方來偈，自然生玉音。", "予慙乏瓊玖，無以報兼金。", "他日思良會，含情時永吟。", "（見道士孟宗寶集虛編《洞霄詩集》。", "）。"]'),
('08f7c5ba-1754-4fcf-ba14-5152c831765e','酬劉侍御過草堂','吳筠','唐','唐诗','tang','','[]','弱冠涉儒黑，壯懷歸道真。',150,'全唐诗/poet.tang.51000.json','["弱冠涉儒黑，壯懷歸道真。", "棲遲高潁閒，得與巢由鄰。", "豺狼亂天紀，流蕩江海濱。", "江海非吾土，所賴吾同人。", "築堂依絕巘，閉關從隱淪。", "一過囂紛境，臥病逾三旬。", "皇靈垂矜卹，正氣澄心神。", "但感適起居，何堦答蒼旻。", "策羸返巖壑，情抱豁已伸。", "霜候變林薄，不能改松筠。", "彌見攝生理，邈然超世塵。", "寫懷簡同志，終古無緇磷。", "（同前。", "）。"]'),
('13b5eba9-949f-48d0-aa78-53b4c895e40a','大滌洞','白元鑒','唐','唐诗','tang','','[]','名山閟靈府，隱士此尋真。',298,'全唐诗/poet.tang.51000.json','["名山閟靈府，隱士此尋真。", "仙去空遺鼓，雲扃不見人。", "川源世上異，日月洞中春。", "欲出虛無境，應修有待身。", "（見《洞霄詩集》。", "）（〖1〗鄧牧《洞霄圖志》卷二《山水門·大滌山》條：「大滌山，在宮〖指洞霄宮〗北，凡四峯，於九鎖內最爲巨山。", "西洞據其領，石室出其半，天壇冠其顛，皆山中勝處也。", "是山以洞名之。", "舊志謂大可以洗滌塵心，故名大滌。", "……元同先生劍履瘞山下。", "」〖2〗又《洞霄圖志》卷三《洞府門·大滌洞》條：「大滌洞在宮西北半里。", "《茅君傳》云第三十四洞天，名大滌元蓋之天。", "周圍四百里，……相傳元同先生入游，見龍麟異境，花木鮮繁，自華陽而歸〖望按前文有云：與華陽林屋邃道通〗。", "洞門石鼓，廣可尋丈，扣之逄逄有聲。", "」）。"]'),
('4257aa95-5538-425b-88d1-62e03832bbaa','天壇','白元鑒','唐','唐诗','tang','','[]','天壇高百尺，只在翠微間。',176,'全唐诗/poet.tang.51000.json','["天壇高百尺，只在翠微間。", "碧蘚遺蹤古，青松白日閒。", "丹成人已化，雲去鶴應還。", "時有吹簫客，月明來故山。", "（同前。", "）（〖1〗《洞霄圖志》卷四《古跡門·昇天壇》條：「舊志云：在大滌山中峯之上，又名法象壇。", "上應天而圓，下應地而方，中應《易》卦而八角。", "許遠遊真君精研洞典，登其上而仙去，時天降白鹿下迎，故中峯名白鹿山。", "今山頂界松內數丈之地，草木弗植，是其遺址也。", "」）。"]'),
('ca15a98e-b398-43a2-b04f-b727ec29b56a','馴虎巖','白元鑒','唐','唐诗','tang','','[]','外身道不遠，異類自能馴。',271,'全唐诗/poet.tang.51000.json','["外身道不遠，異類自能馴。", "尚有相親獸，應無可棄人。", "溪邊同飲水，林下共棲真。", "寂寂空巖畔，千秋迹已陳。", "（同前。", "）（〖1〗《洞霄圖志》卷四《古跡門·伏虎巖》條：「伏虎巖，在宮山西南峻壁間，若環堵之室。", "南有路，自上而下，復陟厓磴，方至其所。", "藤蘿深密，怪禽晝啼，非有道之士，不可處也。", "昔郭真君伏虎於此。", "按《晉書》云：『葛洪何幼道偕訪之，目擊而已，各無所言，引嘯而退。", "』唐吳天師愛其遺跡，每游忘返，題詩巖上，今歲久昏剝，云：『郭生在童穉，已得方外心。", "絕跡遺世務，棲真入長林。", "元和感異類，猛獸懷德音。", "不憶固無情，斯言微且深。", "』末句蓋引真君與溫嶠問答語。", "」）。"]'),
('9efd5da6-28a0-4b97-b12a-9a3c48bebf12','石門','白元鑒','唐','唐诗','tang','','[]','靈關非世力，造化創元功。',54,'全唐诗/poet.tang.51000.json','["靈關非世力，造化創元功。", "屈曲穿丹壑，崢嶸倚碧空。", "煙蘿常蔽日，松竹自吟風。", "除卻幽人到，塵凡路不通。", "（同前。", "）。"]'),
('81316cf1-1878-44c7-bb7f-8f2d05a7caff','藥圃','白元鑒','唐','唐诗','tang','','[]','仙翁曾播植，瓊圃尚敷榮。',188,'全唐诗/poet.tang.51000.json','["仙翁曾播植，瓊圃尚敷榮。", "春日祥光滿，秋風瑞實成。", "黃精宜益壽，萱草足忘情。", "候採靈芝服，還應羽翼生。", "（同前。", "）（〖1〗《洞霄圖志》卷四《古跡門·藥圃》條：「藥圃，在來賢巖宜霜亭下，夏侯天師種藥於此。", "芝畦校塢，百藥之植，靡所不有。", "常施藥於廛市，隨緣深淺而與之。", "一日，樵者聞圃內有物大噑，隔籬窺見天師，策鞭乘一獸，似虎非虎，行疾如風，入東山而去。", "今四山產藥草六十餘種，圃跡猶存。", "」）。"]'),
('71d0d620-83b8-42fb-815b-f23cb95b93f6','撫掌泉','白元鑒','唐','唐诗','tang','','[]','直下碧千尋，蛟龍此隱身。',55,'全唐诗/poet.tang.51000.json','["直下碧千尋，蛟龍此隱身。", "無心能應物，拍手湧如神。", "夜鏡涵星斗，春盃薦藻蘋。", "終年丹竈於此，長給武陵人。", "（同前。", "）。"]'),
('d3f0030c-db42-4cae-ac19-8794aaceaa1c','講堂','白元鑒','唐','唐诗','tang','','[]','高蹤誰可繼，一室四無隣。',225,'全唐诗/poet.tang.51000.json','["高蹤誰可繼，一室四無隣。", "聽法空雲水，成功集鬼神。", "煙霞生戶牖，泉石障埃塵。", "越國今何在？空悲行路人。", "（同前。", "）（〖1〗《洞霄圖志》卷四《古跡門·葉天師講堂》條：「舊志載在山門外，天師役鬼神所建，制度宏巧，絕不類常工。", "開元中，天師講《道德》、《度人》諸經於此，有仙花靈鶴，自天而下。", "吳越高士，輻輳聽法，咸有所焐，願居弟子列者三百餘人。", "惟語以濟恤孤貧，感愧覆載，忠孝君親，重人性命，凈身心，絕奢侈，即爲道之根緒也。", "薦經兵火，遺跡不存，今移宮中爲演教堂。", "」）。"]'),
('3179a148-a28d-457d-82e1-080251d69b10','書樓','白元鑒','唐','唐诗','tang','','[]','業成人已去，陳迹自依然。',138,'全唐诗/poet.tang.51000.json','["業成人已去，陳迹自依然。", "竈有殘丹火，窗遺溢寶篇。", "懷賢驚異世，撫事感流年。", "早述《南華》理，遽應返化仙。", "（同前。", "）（〖1〗《洞霄圖志》卷四《古跡門·書樓》條：「一名垂象樓，暨天師所居。", "天師少好經史，著述不輟，其中卷秩，委積左右。", "……白元鑒有詩。", "其址亦在今道院內，爲精思流派。", "」）。"]'),
('7be775ba-bc8c-4990-a816-7bc29e4057cd','瀑布','白元鑒','唐','唐诗','tang','','[]','飛瀑下幽壑，令人夢寐清。',54,'全唐诗/poet.tang.51000.json','["飛瀑下幽壑，令人夢寐清。", "秋山匹練淨，寒谷萬珠明。", "映日添霞色，迎風作雨聲。", "潺湲聽莫厭，時得滌幽情。", "（同前。", "）。"]'),
('592a6c93-a6b8-42b1-83a8-8c0922aaee99','新池','白元鑒','唐','唐诗','tang','','[]','何人鑿碧沼，待我照衰容。',293,'全唐诗/poet.tang.51000.json','["何人鑿碧沼，待我照衰容。", "洗藥餘香在，開函古鏡空。", "心閒聞細溜，波靜臥喬松。", "欲問仙源路，無由見落紅。", "（同前。", "）（〖1〗《洞霄圖志》卷五《人物門·唐高道白威儀先生》條：「白元鑒，不詳其字，西川成都府人。", "高祖君敏，武德功臣。", "父洪演，高蹈不襲封，娶申屠氏，生一子，即先生也。", "玄宗幸蜀時，爲威儀道士，住上皇觀。", "志在絶俗，逍遙遐舉，周覽山川，訪前賢高蹈之躅，得餘杭天柱觀，止焉，四十年矣。", "元和十二載八月解化，瘞於天柱山大滌洞東北。", "嘗有《山中十咏》。", "贊曰：有志絕俗，白公威儀。", "自蜀來南，名山棲遲。", "元酒味淡，大音聲希。", "積四十年，無人見知。", "山中遺老，傳誦十詩。", "適興而已，不矜能之。", "」〖《知不足叢書本》〗）。"]'),
('3c0ef25c-2c29-43a4-980c-6216191f8b24','句','王仙喬','唐','唐诗','tang','','["\u8861\u5c71"]','鬱鬱家國盛，濟濟經道興。',312,'全唐诗/poet.tang.51000.json','["鬱鬱家國盛，濟濟經道興。", "（見廖侁撰、李沖昭述《南獄小錄》。", "南京圖書館藏手鈔本。", "）（〖1〗《南嶽小錄·九真觀》條：唐開元年間，有王天師仙喬。", "初，天師爲行者，道性沖昭，有非常之志。", "因將嶽中茶二百餘串，直入京國，每攜茶器於城門內施茶。", "忽一日，遇高力士，見而異之，問其所來。", "乃曰：「某是南嶽行者，今爲本住九真觀殿宇破落，特將茶來募施主耳。", "」於是力士上聞，玄宗召見，嘉歎久之，問曰：「爾有願否？", "」對曰：「鬱鬱家國盛，濟濟經道興。", "」〖《藝海珠塵》、《四庫全書》本「南嶽小錄」，此二句前皆有「願」字。", "〗上深加禮焉，俾於內殿披度，厚與金帛建置，令歸嶽中修剙觀宇，不數年而完全。", "道行愈高，聲流上國，尋有詔封爲天師，乾元二年三月三十日得道。", "）。"]'),
('3a9d500e-989f-4486-8837-f3fa35c21045','寓言（見韋莊《又玄集》卷下。按《全唐詩》卷七百二十三作李洞詩，詩與此同。又《全唐詩》卷八百五載元淳此詩前二句，今據《又玄集》，驗作元淳詩爲是。）','元淳','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.51000.json','["空。"]'),
('1a2ab870-3570-4393-9c47-e123e6ae3e83','書與胡咏之','呂巖','唐','唐诗','tang','','[]','濟世應須不世才，調羹重見用鹽梅。',132,'全唐诗/poet.tang.51000.json','["濟世應須不世才，調羹重見用鹽梅。", "種成白璧人何處，熟了黃粱夢未回。", "相府舊開延士閣，武夷新築望仙臺。", "青雞唱徹函關曉，好卷游幃歸去來。", "（見《宋詩紀事》卷九十引《墨莊漫錄》。", "）（見《墨莊漫錄》卷一，云爲元符初胡咏之在信州弋陽縣見道人所題詩，時人推測此道人「必爲呂翁」。", "）。"]'),
('1c84e73b-96fa-4883-85aa-21818c5cb5d9','題冢上亭','呂巖','唐','唐诗','tang','','[]','冢上爲亭鬼莫嗔，冢頭人即冢中人。',115,'全唐诗/poet.tang.51000.json','["冢上爲亭鬼莫嗔，冢頭人即冢中人。", "凭蘭莫起存亡意，除卻虛空總是塵。", "（同前引《西溪叢語》。", "）（見《西溪叢語》卷上。", "）（〖1〗《西溪叢語》〖宋姚寬撰〗：「襄漢隱者躬耕數畝，因古冢爲亭，往來題詩甚富。", "」一日，柱間得一絕。", "相傳呂翁作也。", "）。"]'),
('4916981a-a7fa-4b43-843e-88cc3e17f1cb','題崇元觀（在吉水縣）','呂巖','唐','唐诗','tang','','[]','褰裳嬾步尋真宿，清景一宵吟不足。',64,'全唐诗/poet.tang.51000.json','["褰裳嬾步尋真宿，清景一宵吟不足。", "月在碧潭風在松，何必洞天三十六。", "（同前引宋祝穆撰《方輿勝覽》。", "見《方輿勝覽》卷二十《吉州》。", "）。"]'),
('dd52be35-d17c-4bbb-a12b-f15d8e50606f','題靈石屋山','呂巖','唐','唐诗','tang','','["\u897f\u6e56"]','南塢數回泉石，西峯幾疊烟雲。',138,'全唐诗/poet.tang.51000.json','["南塢數回泉石，西峯幾疊烟雲。", "登攜孰以爲侶，顏寓李甲蕭耘。", "（同前《宋詩紀事》。", "）（〖1〗《竹坡詩話》〖宋周紫芝撰〗：「西湖諸寺，所存無幾，唯南山靈石，猶是舊屋。", "寺僧言，頃有數道人來丐食，拒而不與，乃題詩屋山而去。", "至今猶存，字畫頗類李北海。", "好事者釋之，乃是呂洞賓與三人來耳。", "」）。"]'),
('30acfef2-067a-4ff3-98ad-b846c25bc9ff','歸隱（《永樂大典》題作《偶題》）','陳摶','唐','唐诗','tang','','[]','十年蹤跡走紅塵，回首青山入夢頻。',365,'全唐诗/poet.tang.51000.json','["十年蹤跡走紅塵，回首青山入夢頻。", "紫陌縱榮爭及睡，朱門雖富（《大典》「富」作「貴」）不如貧。", "愁聞劍戟扶危主，悶聽（《大典》「聽」作「見」）笙歌聒醉人。", "攜取琴（《大典》「琴」作「舊」）書歸舊隱，野花啼鳥一般春。", "（見北京圖書館藏《永樂大典》卷一三四五○。", "二寘）。", "處士門。", "《宋詩紀事》卷五收陳詩七首。", "其《歸隱》一首與《大典》同。", "惟《大典》題作《偶題》。", "其《辭上歸進詩》，作於入宋之後，茲編不取。", "餘五首，一首複出。", "故但錄其四首。", "（又按此詩亦見元辛文房《唐才子傳》卷十。", "）（〖1〗邵伯溫《易學辨惑》云：摶隱居華陰山，自晉以後，每聞一朝革命，顰蹙數日。", "人有問者，瞪目不答。", "一日，乘驢過華陰市，聞太祖登極，大笑。", "問其故，曰：「天下自此定矣。", "」遁迹之初，作此詩云云，豈淺丈夫哉。", "〖見《五朝名臣言行錄》卷十引邵伯溫《易學辨惑》。", "此處錄文有刪節。", "〗）。"]'),
('063ca9c0-cf9f-46c8-9110-3d50dcf08405','石刻詩（幷序）','陳摶','唐','唐诗','tang','','[]','我謂浮榮真是幻，醉來捨轡謁高公。',152,'全唐诗/poet.tang.51000.json','["我謂浮榮真是幻，醉來捨轡謁高公。", "因聆玄論冥冥理，轉覺塵寰一夢中。", "（見《宋詩紀事》卷五引《老學庵筆記》。", "）（見《老學庵筆記》卷六。", "末附引文有刪節。", "）（〖1〗《老學菴筆記》：卭州天慶觀石刻希夷詩云云。", "末書太歲丁酉，蓋蜀孟昶時，當石晉天福中也。", "文與可跋云：「高公者，此觀都威儀何昌一也，希夷從之學鎖鼻術。", "」）。"]'),
('f96bc4cd-abf1-4a93-944a-e21836d1869f','贈張乖厓','陳摶','唐','唐诗','tang','','[]','自吳入蜀是尋常，歌舞筵中救火忙。',135,'全唐诗/poet.tang.51000.json','["自吳入蜀是尋常，歌舞筵中救火忙。", "乞得金陵養閑散，也須多謝鬢邊瘡。", "（見《宋詩紀事》卷五。", "）（見《湘山野錄》卷上、《夢溪筆談》卷二十。", "）（〖1〗《古今詩話》：「張忠定公少謁華山陳圖南，圖南贈詩一絕，始皆不喻其意。", "後忠定更鎮杭益，晚年發瘡於鬢，移守金陵，遂薨，悉如其言。", "」）。"]'),
('c7df8bbd-dcdc-469e-b106-b73309596010','訪毛女（見《宋詩紀事》引《翰府名談》。按《全唐詩》卷八百六十三作毛女正美詩。此詩第二句「又編栗葉作羅襦」，「作」，《全唐詩》作「代」。三句「有時問著秦宮事」，「著」，《全唐詩》作「卻」。四句「笑撚仙花望太虛」，「仙」，《全唐詩》作「山」。餘同。〗〖見《增修詩話總龜》卷四四引《翰府名談》。〗）','陳摶','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.51000.json','["空。"]'),
('8f606c00-4d7f-4e92-ac0c-a95fe81843c6','西峯','陳摶','唐','唐诗','tang','','[]','爲愛西峯好，吟頭盡日昂。',116,'全唐诗/poet.tang.51000.json','["爲愛西峯好，吟頭盡日昂。", "岩花紅作陣，溪水綠成行。", "幾夜礙新月，半山無夕陽。", "寄言嘉遯客，此處是仙鄉。", "（見《宋詩紀事》卷五引宋魏慶之撰《詩人玉屑》。", "）（見《詩人玉屑》卷二十《方外》，不注出處。", "又見《增修詩話總龜》卷四六引《翰府名談》。", "）。"]'),
('cc91ca1f-4d20-4cde-bb39-b44d00310288','題石水澗','陳摶','唐','唐诗','tang','','[]','銀河灑落翠光冷，一派迴環[湛]（淡）晚暉。',110,'全唐诗/poet.tang.51000.json','["銀河灑落翠光冷，一派迴環[湛]（淡）晚暉。", "幾恨卻爲頑石尵，琉璃滑處玉花飛。", "（見《宋詩紀事》卷五引明李蔉輯《宋藝圃集》。", "）（見《宋藝圃集》卷一，又見《增修詩話總龜》卷四四引《翰府名談》。", "「淡」，二書皆作「湛」，今據改。", "）。"]'),
('bd780dc1-6817-419c-b9b7-3d19b15ec70f','楊勛吟詩','楊勛','唐','唐诗','tang','','[]','聖主何曾識仲都，可憐社禝在須臾。',248,'全唐诗/poet.tang.51000.json','["聖主何曾識仲都，可憐社禝在須臾。", "市西便是神仙窟，何必乘楂汎五湖。", "（《全唐詩》卷八六三收此詩，作者作楊損，題作《臨刑賦》，殆據《萬首唐人絕句》卷六八收入。", "）（按宋人撰《新編分門古今類事》卷二載此詩，云：「楊勛者，前蜀後主乾德中，世號楊僕射，不知何處人，變化無常。", "爲後主召羣仙於薫風殿，刑部侍郎潘嬌奏其妖怪，帝命武士於相市戮之。", "隨刃化爲草，人未至所法處。", "僕射吟詩曰云云。", "其年冬，後主失國，果如其言，此亦可以知興廢之有前定也。", "」注云「出《洞微志》」。", "事雖不經，準《全唐詩》例，姑錄之以入神仙鬼怪卷。", "）。"]'),
('303adfbd-6f46-4527-b498-17380382ba8d','','崔致遠','唐','唐诗','tang','','[]','（案《全唐詩》無崔致遠詩。',97,'全唐诗/poet.tang.51000.json','["（案《全唐詩》無崔致遠詩。", "日本河世寧《全唐詩逸》卷中收致遠詩一首又句七聯。", "此六十首詩載致遠所著《桂苑筆耕集》〖有《四部叢刊》本〗。", "今即自《叢刊》本錄出，而以南京圖書館所藏高麗聚珍活字本校之。", "）。"]'),
('ea1e87e9-4157-4f02-a2e9-eda3b2cdd13c','七言記德詩三十首謹獻司徒相公 兵機','崔致遠','唐','唐诗','tang','','[]','惟將志業練《春秋》，早蓄雄心剗國讐。',34,'全唐诗/poet.tang.51000.json','["惟將志業練《春秋》，早蓄雄心剗國讐。", "二十年來天下事，漢皇高枕倚留侯。"]'),
('68a0cea7-b0fa-4f9d-a789-4a5fdf0efb5d','七言記德詩三十首謹獻司徒相公 筆法','崔致遠','唐','唐诗','tang','','[]','見說書窗暫臥龍，神傳妙訣助奇鋒。',68,'全唐诗/poet.tang.51000.json','["見說書窗暫臥龍，神傳妙訣助奇鋒。", "也知外國人爭學，惟恨無因乞手蹤。", "（原注：南朝蕭子雲〖高麗本作蘇子雲〗善書，百濟使人求手蹤，以爲國寶。", "）。"]'),
('c45e6575-88db-4fe6-afdd-14d0da7abe98','七言記德詩三十首謹獻司徒相公 性箴','崔致遠','唐','唐诗','tang','','[]','波澄性海見深源，理究希夷闢道門。',32,'全唐诗/poet.tang.51000.json','["波澄性海見深源，理究希夷闢道門。", "詞翰好傳雙美跡，何須更寫五千言。"]'),
('c7309f6b-0c15-48b7-8471-39f17c8a5a1c','七言記德詩三十首謹獻司徒相公 雪咏','崔致遠','唐','唐诗','tang','','[]','五色毫編六出花，三冬吟徹四方誇。',32,'全唐诗/poet.tang.51000.json','["五色毫編六出花，三冬吟徹四方誇。", "始知絕句勝聯句，從外芳名掩謝家。"]'),
('a56ce954-6356-48b3-83fc-34044dddad61','七言記德詩三十首謹獻司徒相公 射鵰','崔致遠','唐','唐诗','tang','','[]','能將一箭落雙鵰，萬里胡塵當日銷。',32,'全唐诗/poet.tang.51000.json','["能將一箭落雙鵰，萬里胡塵當日銷。", "永使威名振沙漠，犬戎無復吠唐堯。"]'),
('09de181e-e3f6-4e0c-b50a-9b931784cbcf','七言記德詩三十首謹獻司徒相公 安化','崔致遠','唐','唐诗','tang','','[]','班筆由起來不暗投，旋驅熊隼待封侯。',33,'全唐诗/poet.tang.51000.json','["班筆由起來不暗投，旋驅熊隼待封侯。", "郡名安化能宣化，更指河湟地欲收。"]'),
('b93e21c8-c606-4c7c-848c-b4ec4a7a1b37','七言記德詩三十首謹獻司徒相公 練兵','崔致遠','唐','唐诗','tang','','[]','隴水聲秋塞草閑，霍將軍暫入長安。',32,'全唐诗/poet.tang.51000.json','["隴水聲秋塞草閑，霍將軍暫入長安。", "太平天子憐才略，曾請陳兵盡日看。"]'),
('3d2faa0b-3d80-4bf3-9a25-694e452f68e1','七言記德詩三十首謹獻司徒相公 磻溪','崔致遠','唐','唐诗','tang','','[]','刻石書蹤妙入神，一廻窺覽一廻新。',94,'全唐诗/poet.tang.51000.json','["刻石書蹤妙入神，一廻窺覽一廻新。", "況能早逐王師業，桃李終成萬代春。", "（原注：伏覩相公《磻溪詩》云：「及到王師身已老，不知辛苦爲何人。", "」又《經虢縣詩》云：「手栽桃李十餘春，今日經過重建勳。", "」）。"]'),
('676e724a-586e-41fc-a445-1c9bad306b9e','七言記德詩三十首謹獻司徒相公 射虎','崔致遠','唐','唐诗','tang','','[]','鉅牙鉤爪礙王程，一箭摧班（高麗本班作斑。',41,'全唐诗/poet.tang.51000.json','["鉅牙鉤爪礙王程，一箭摧班（高麗本班作斑。", "）四海驚。", "白額前驅姜膽碎，方知破石是虛聲。"]'),
('d4801868-06ba-4d54-bb1d-0a42ec6833ce','七言記德詩三十首謹獻司徒相公 秦城','崔致遠','唐','唐诗','tang','','[]','遠提龍劍鎮龍庭，外戶從茲永罷扃。',32,'全唐诗/poet.tang.51000.json','["遠提龍劍鎮龍庭，外戶從茲永罷扃。", "掃盡邊塵更無事，暮天寒角醉吟聽。"]'),
('ea301b78-3764-45b4-b620-a51e4e2daf9f','七言記德詩三十首謹獻司徒相公 生祠','崔致遠','唐','唐诗','tang','','[]','古來難化是蠻夷，交趾何人得去思。',32,'全唐诗/poet.tang.51000.json','["古來難化是蠻夷，交趾何人得去思。", "萬代聖朝青史上，獨傳溪洞立生祠。"]'),
('3c500b99-0b91-4d3d-b12a-6bf03a98c713','七言記德詩三十首謹獻司徒相公 射鞭','崔致遠','唐','唐诗','tang','','[]','休說戟枝非易中，莫言楊葉是難穿。',32,'全唐诗/poet.tang.51000.json','["休說戟枝非易中，莫言楊葉是難穿。", "須看立節吵場上，永得安邊爲射鞭。"]'),
('fc0a913a-04fe-4c12-820f-4684616eb298','七言記德詩三十首謹獻司徒相公 安南','崔致遠','唐','唐诗','tang','','[]','西戎始定南蠻起，都護能摧驃信威。',32,'全唐诗/poet.tang.51000.json','["西戎始定南蠻起，都護能摧驃信威。", "萬里封疆萬戶口，一麾風雨盡收歸。"]'),
('aec92f8b-c404-4b93-ab89-876f6d9bae71','七言記德詩三十首謹獻司徒相公 天威徑','崔致遠','唐','唐诗','tang','','["\u534e\u5c71"]','鑿斷龍門猶勞身，擘分華嶽徒稱神。',32,'全唐诗/poet.tang.51000.json','["鑿斷龍門猶勞身，擘分華嶽徒稱神。", "如何劈開海山道，坐令八國爭來賓。"]'),
('ef63d15f-85ff-4aca-b70c-7c564f34b7ec','七言記德詩三十首謹獻司徒相公 岝口徑','崔致遠','唐','唐诗','tang','','[]','濟物能廻造化心，驅山偃海立功深。',32,'全唐诗/poet.tang.51000.json','["濟物能廻造化心，驅山偃海立功深。", "安南真得安南界，從此蠻兵不敢侵。"]'),
('7cf73256-ac19-4a7a-bef8-6960f83feb44','七言記德詩三十首謹獻司徒相公 收城碑','崔致遠','唐','唐诗','tang','','[]','功業已標征北賦，威名初建鎮南碑。',49,'全唐诗/poet.tang.51000.json','["功業已標征北賦，威名初建鎮南碑。", "終知不朽齊銅柱，況是儒宗綴色絲。", "（原注：碑，今度支裴僕射撰詞。", "）。"]'),
('68891b4c-8172-4b77-8e17-b899667f1827','七言記德詩三十首謹獻司徒相公 執金吾','崔致遠','唐','唐诗','tang','','[]','一陣風雷定八蠻，來趨雲陛悅天顏。',33,'全唐诗/poet.tang.51000.json','["一陣風雷定八蠻，來趨雲陛悅天顏。", "王孫仕宦多榮貴，心爲匡君不蹔閑。", "。"]'),
('c765f6ee-adfc-4fab-ba81-463d10f9a588','七言記德詩三十首謹獻司徒相公 天平','崔致遠','唐','唐诗','tang','','[]','海岱烟塵匝鄆城，遙揮一劍落攙搶。',32,'全唐诗/poet.tang.51000.json','["海岱烟塵匝鄆城，遙揮一劍落攙搶。", "征旗不動降旗盡，永使天平地亦平。"]'),
('1f7a81c4-b034-4004-9cc4-f79777c77286','七言記德詩三十首謹獻司徒相公 釣魚亭','崔致遠','唐','唐诗','tang','','[]','錦筵花下飛鸎鵡，羅袖風前唱《鷓鴣》。',96,'全唐诗/poet.tang.51000.json','["錦筵花下飛鸎鵡，羅袖風前唱《鷓鴣》。", "占得仙家詩酒興，閑吟烟月憶蓬壺。", "（原注：伏覩相公《在鄆州詩》：云：「酒滿金舡花滿枝，雙娥齊唱《鷓鴣詞》。", "」又《釣魚亭詩》云：「水急魚對釣，風吹柳易低。", "」）。"]'),
('b55de5fb-35e2-4bf8-bedb-751af81b7cd2','七言記德詩三十首謹獻司徒相公 相印','崔致遠','唐','唐诗','tang','','[]','早說休徵應佩刀，台星光接將星高。',32,'全唐诗/poet.tang.51000.json','["早說休徵應佩刀，台星光接將星高。", "欲迎霖雨歸龍闕，看滅妖氛展豹韜。"]'),
('e114bfdc-ab11-4ce3-a6e2-5459f41069a1','七言記德詩三十首謹獻司徒相公 西川','崔致遠','唐','唐诗','tang','','[]','遠持龍斾活龜城，威懾蒙王永罷兵。',32,'全唐诗/poet.tang.51000.json','["遠持龍斾活龜城，威懾蒙王永罷兵。", "應笑欒巴噀盃酒，雨師風伯自歸行。"]'),
('5bde778f-e3b8-4e7c-a0d4-4172395bcf3a','七言記德詩三十首謹獻司徒相公 平蠻','崔致遠','唐','唐诗','tang','','[]','卭峽關東蠻塵絕，平夷鎮扼蠻地裂。',32,'全唐诗/poet.tang.51000.json','["卭峽關東蠻塵絕，平夷鎮扼蠻地裂。", "又築羅城變錦城，蠻兵永滅功不滅。"]'),
('676adf7f-226f-4dc2-b9a6-65eb2ec9177e','七言記德詩三十首謹獻司徒相公 築城','崔致遠','唐','唐诗','tang','','[]','一心能感衆心齊，鐵甕高吞劍閣低。',32,'全唐诗/poet.tang.51000.json','["一心能感衆心齊，鐵甕高吞劍閣低。", "多上散花樓上望，江山供盡好詩題。"]'),
('011cf781-3fd0-4db4-9590-10220f2f2009','七言記德詩三十首謹獻司徒相公 荆南','崔致遠','唐','唐诗','tang','','[]','虎吼龍驤出峽來，福星才照陣雲開。',33,'全唐诗/poet.tang.51000.json','["虎吼龍驤出峽來，福星才照陣雲開。", "遙思屈宋忠魂在，應向風前奠前一杯。"]'),
('f705e773-404b-4151-926d-f0ba70d00c45','七言記德詩三十首謹獻司徒相公 漕運','崔致遠','唐','唐诗','tang','','[]','濟川已展爲舟業，煮海終成富國功。',32,'全唐诗/poet.tang.51000.json','["濟川已展爲舟業，煮海終成富國功。", "能與吾君緩宵旰，爲資心計四方通。"]'),
('9b581bca-fa71-4c9b-b8b7-a8461a8b4bd3','七言記德詩三十首謹獻司徒相公 浙西','崔致遠','唐','唐诗','tang','','[]','九江賊膽望風摧，萬戶愁眉向日開。',32,'全唐诗/poet.tang.51000.json','["九江賊膽望風摧，萬戶愁眉向日開。", "楚舞吳歌一何樂，相逢相賀相公來。"]'),
('bdd8e30f-a818-45aa-b46a-3b60855d53de','七言記德詩三十首謹獻司徒相公 降寇','崔致遠','唐','唐诗','tang','','[]','唯將德化欲銷兵，長笑成長平恣意坑。',33,'全唐诗/poet.tang.51000.json','["唯將德化欲銷兵，長笑成長平恣意坑。", "更想太丘行小惠，何如言下濟羣生。"]'),
('7a46e7b4-09a1-4921-afd1-bacafaf7ddc7','七言記德詩三十首謹獻司徒相公 淮南','崔致遠','唐','唐诗','tang','','[]','八郡榮超陶太尉，三邊靜掩霍嫖姚。',78,'全唐诗/poet.tang.51000.json','["八郡榮超陶太尉，三邊靜掩霍嫖姚。", "玉皇終日留金鼎，應待淮王手自調。", "（原注：劍南、荆南、淮南，乃天下名鎮，相公累移節制。", "西戎、南蠻、東鄙賊起，相公皆自討除。", "）。"]'),
('308b1b55-656b-4546-b865-823cbb69235a','七言記德詩三十首謹獻司徒相公 朝上清','崔致遠','唐','唐诗','tang','','[]','齊心不倦自朝真，豈爲修仙欲濟人。',32,'全唐诗/poet.tang.51000.json','["齊心不倦自朝真，豈爲修仙欲濟人。", "天上香風吹楚澤，江南江北鎮成春。"]'),
('1464483d-3c24-486a-b54b-f6a63ffd03b6','七言記德詩三十首謹獻司徒相公 陳情','崔致遠','唐','唐诗','tang','','[]','俗眼難窺冰雪姿，終朝共詠小山詞。',148,'全唐诗/poet.tang.51000.json','["俗眼難窺冰雪姿，終朝共詠小山詞。", "此身依托同鷄犬，他日昇天莫棄遺。", "（按以上三十首詩見《桂苑筆耕集》第十七卷，前有《獻詩啓》，畧謂：「如某者，跡自外方，藝唯下品。", "雖儒宮慕善，每嘗窺顏冉之牆，而筆陣爭雄，未得摩曹劉之壘。", "但以幸遊樂國，獲覩仁風，久貯懇誠，冀伸歌詠，輒獻紀德絕句詩三十首，謹封如別。", "」）。"]'),
('15e2d4fc-8ad2-418c-a389-80150482e184','陳情上太尉','崔致遠','唐','唐诗','tang','','[]','海內誰憐海外人，問津何處是通津。',64,'全唐诗/poet.tang.51000.json','["海內誰憐海外人，問津何處是通津。", "本求食祿非求利，只爲榮親不爲身。", "客路離愁江上雨，故園歸夢日邊春。", "濟川幸遇恩波廣，願濯凡纓十載塵。"]'),
('862f380a-486f-461d-8238-ab087b2f70e7','奉和座主尚書避難過維陽寵示絕句三首（「陽」，疑當作「揚」。） 一','崔致遠','唐','唐诗','tang','','[]','年年荆棘侵儒苑，處處烟塵滿戰場。',32,'全唐诗/poet.tang.51000.json','["年年荆棘侵儒苑，處處烟塵滿戰場。", "豈料今朝覲宣父，豁開凡眼睹文章。"]'),
('b93029df-0223-4f79-a052-bf564c253eec','奉和座主尚書避難過維陽寵示絕句三首（「陽」，疑當作「揚」。） 二','崔致遠','唐','唐诗','tang','','[]','亂時無事不悲傷，鸞鳯驚飛出帝鄉。',32,'全唐诗/poet.tang.51000.json','["亂時無事不悲傷，鸞鳯驚飛出帝鄉。", "應念浴沂諸弟子，每逢春色耿離腸。"]'),
('48b66b5e-4b22-4f7e-a35e-18ea6a5ffae1','奉和座主尚書避難過維陽寵示絕句三首（「陽」，疑當作「揚」。） 三','崔致遠','唐','唐诗','tang','','[]','濟川終望拯湮沉，喜捧清詞渲俗襟。',32,'全唐诗/poet.tang.51000.json','["濟川終望拯湮沉，喜捧清詞渲俗襟。", "唯根吟歸滄海去，泣珠何計報恩深。"]'),
('a5d189f2-cbb1-41ce-9d14-c302e0876f20','歸燕吟獻太尉','崔致遠','唐','唐诗','tang','','[]','秋去春來能守信，暖風凉雨飽相諳。',64,'全唐诗/poet.tang.51000.json','["秋去春來能守信，暖風凉雨飽相諳。", "再依大厦雖知許，久污雕梁却自慙。", "深避鷹鸇投海島，羨他鴛鷺戲江潭。", "只將名品齊黃雀，獨讓銜環意未甘。"]'),
('5f30e886-4571-49dc-8c19-72e2a72258a9','酬楊贍秀才送別','崔致遠','唐','唐诗','tang','','[]','海槎雖定隔年廻，衣錦還鄉愧不才。',86,'全唐诗/poet.tang.51000.json','["海槎雖定隔年廻，衣錦還鄉愧不才。", "暫別蕪城當葉落，遠尋蓬島趂花開。", "谷鸎遙想高飛去，（原注：時楊生有隨計〖高麗本計作行〗之計。", "）遼豕寧慙再獻來。", "好把壯心謀後會，廣陵風月待銜杯。"]'),
('dbc1a23d-aa5a-4528-97a5-0b8b99fb8e00','行次山陽續家太尉寄賜衣段令充歸覲續壽信物謹以詩謝','崔致遠','唐','唐诗','tang','','[]','自古雖誇晝錦行，長卿翁子占虛名。',65,'全唐诗/poet.tang.51000.json','["自古雖誇晝錦行，長卿翁子占虛名。", "既傳國信兼家信，不獨家榮國亦榮。", "萬里始成歸去計，一心先算却來程。", "望中遙想深恩處，三朵仙山目畔橫。", "。"]'),
('21071cc9-d7f0-4ad2-81b9-3f9cdbf7ee09','留別女道士','崔致遠','唐','唐诗','tang','','[]','每恨塵中厄宦塗，數年深喜識麻姑。',16,'全唐诗/poet.tang.51000.json','["每恨塵中厄宦塗，數年深喜識麻姑。"]'),
('ae8b6960-0bb3-497b-8490-7f9d1eaec273','酬進士楊贍送別','崔致遠','唐','唐诗','tang','','[]','海山遙望曉烟濃，百幅帆張萬里風。',32,'全唐诗/poet.tang.51000.json','["海山遙望曉烟濃，百幅帆張萬里風。", "悲莫悲兮兒女事，不須怊悵別離中。"]'),
('234ea344-0575-4702-9749-61f74961de20','楚州張尚書水郭相迎因以詩謝','崔致遠','唐','唐诗','tang','','[]','楚天蕭瑟碧雲秋，旟隼高飛訪葉舟。',32,'全唐诗/poet.tang.51000.json','["楚天蕭瑟碧雲秋，旟隼高飛訪葉舟。", "萬里乘槎從此去，預愁魂斷謝公樓。"]'),
('63beb744-b4e6-40e1-ba99-bf661b009483','酬吳巒秀才惜別二絕句 一','崔致遠','唐','唐诗','tang','','[]','榮祿危時未及親，莫嗟歧路蹔勞身。',32,'全唐诗/poet.tang.51000.json','["榮祿危時未及親，莫嗟歧路蹔勞身。", "今朝遠別無他語，一片心須不愧人。"]'),
('733b1199-7bd3-4f96-b0f1-46167069a460','酬吳巒秀才惜別二絕句 二','崔致遠','唐','唐诗','tang','','[]','殘日塞鴻高的的，暮烟汀樹遠依依。',32,'全唐诗/poet.tang.51000.json','["殘日塞鴻高的的，暮烟汀樹遠依依。", "此時回首情何限，天際孤帆窣浪飛。"]'),
('3dc991d6-7501-4970-8ff3-01b358d8d529','石峰（原注：中和甲辰年冬十月，奉使東泛，泊舟於大珠山下。凡所入目，命爲篇名，嘯月吟風，貯成十首寄高員外。）','崔致遠','唐','唐诗','tang','','[]','巉嵒絕頂欲摩天，海日初開一朶蓮。',64,'全唐诗/poet.tang.51000.json','["巉嵒絕頂欲摩天，海日初開一朶蓮。", "勢削不容凡樹木，格高唯惹好雲烟。", "點蘇寒影粧新雪，戞玉清音噴細泉。", "靜想蓬萊只如此，應當月夜會羣仙。"]'),
('40c0e94d-32ab-457d-81db-0db75bdbbb60','潮浪','崔致遠','唐','唐诗','tang','','[]','驟雪翻霜千萬重，往來弦望躡前蹤。',65,'全唐诗/poet.tang.51000.json','["驟雪翻霜千萬重，往來弦望躡前蹤。", "見君終更能懷信，慚我趨時盡放慵。", "石壁戰聲飛霹靂，雲峰倒影撼芙蓉。", "因思宗慤長風語，壯氣橫生憶臥龍。", "。"]'),
('4cb22265-1d7f-4cd9-88fd-7c631866d5f7','沙汀','崔致遠','唐','唐诗','tang','','[]','遠看還似雪花飛，弱質由來不自持。',64,'全唐诗/poet.tang.51000.json','["遠看還似雪花飛，弱質由來不自持。", "聚散只憑潮浪簸，高低況被海風吹。", "煙籠靜練入行絕，日射凝霜鶴步遲。", "別恨滿懷吟到夜，那堪又值月圓時。"]'),
('79d51d31-9ac0-4287-a0cc-f77f8f23679d','野燒','崔致遠','唐','唐诗','tang','','[]','望中旌斾忽繽紛，疑是橫行出塞軍。',64,'全唐诗/poet.tang.51000.json','["望中旌斾忽繽紛，疑是橫行出塞軍。", "猛焰燎空欺落日，狂煙遮野截歸雲。", "莫嫌牛馬皆妨牧，須喜狐狸盡喪羣。", "只恐風驅上山去，虛教玉石一時焚。"]'),
('30eca23c-a661-4186-8dc3-4949472201bc','杜鵑','崔致遠','唐','唐诗','tang','','[]','石罅根危葉易乾，風霜偏覺見摧殘。',64,'全唐诗/poet.tang.51000.json','["石罅根危葉易乾，風霜偏覺見摧殘。", "已饒野菊誇秋艷，應羨巖松保歲寒。", "可惜含芳臨碧海，誰能移植到朱欄。", "與凡草木還殊品，只恐樵夫一例看。"]'),
('974fe869-9efb-4358-91b3-61a2953e1653','海鷗','崔致遠','唐','唐诗','tang','','[]','慢隨花浪飄飄然，輕擺毛衣真水仙。',64,'全唐诗/poet.tang.51000.json','["慢隨花浪飄飄然，輕擺毛衣真水仙。", "出沒自由塵外境，往來□□洞中天。", "稻粱滋味好不識，風月性靈深可憐。", "想得漆園蝴蝶夢，只應如我對君眠。"]'),
('abc8a10b-edc0-4698-baf9-4470dc601150','山頂危石','崔致遠','唐','唐诗','tang','','[]','萬古天成勝琢磨，高高頂上立青螺。',64,'全唐诗/poet.tang.51000.json','["萬古天成勝琢磨，高高頂上立青螺。", "永無飛溜侵凌得，唯有閑雲撥觸多。", "峻影每先迎海日，危形長恐墜潮波。", "縱饒蘊玉誰回顧，舉世謀身笑卞和。"]'),
('476cd420-cfd7-4e75-a958-1530eaa29134','石上矮松','崔致遠','唐','唐诗','tang','','[]','不材終得老煙霞，澗底何如在海涯。',64,'全唐诗/poet.tang.51000.json','["不材終得老煙霞，澗底何如在海涯。", "日引暮陰齊島樹，風敲夜子落潮沙。", "自能盤石根長固，豈恨凌雲路尚賒。", "莫訝低顏無所愧，棟樑堪入晏嬰家。"]'),
('4bdbbc4d-109f-47bb-8e9a-69de07dbfdb8','紅葉樹','崔致遠','唐','唐诗','tang','','[]','白雲巖畔立仙姝，一簇烟蘿倚畫圖。',64,'全唐诗/poet.tang.51000.json','["白雲巖畔立仙姝，一簇烟蘿倚畫圖。", "麗色也知於世有，閑情長得似君無。", "宿粧含露疑垂泣，醉態迎風欲待扶。", "吟對寒林却惆悵，山中猶自辨榮枯。"]'),
('da536361-3d30-4161-b030-03ade0551043','石上流泉','崔致遠','唐','唐诗','tang','','[]','琴曲雖誇妙手彈，遠輪雲底響珊珊。',64,'全唐诗/poet.tang.51000.json','["琴曲雖誇妙手彈，遠輪雲底響珊珊。", "靜無纖垢侵金鏡，時有輕飔觸玉盤。", "嗚咽張良言未用，潺湲孫楚枕應寒。", "尋思堪惜清冷色，流入滄溟便一般。"]'),
('ec63aa14-f009-4f52-95b2-5bbce6f7c129','和友人除夜見寄','崔致遠','唐','唐诗','tang','','[]','與君相見且歌吟，莫恨流年挫壯心。',32,'全唐诗/poet.tang.51000.json','["與君相見且歌吟，莫恨流年挫壯心。", "幸得東風已迎路，好花時節到鷄林。"]'),
('c4717b79-d925-44ed-a7bc-9d5932154636','東風','崔致遠','唐','唐诗','tang','','[]','知爾新從海外來，曉窗吟坐思難裁。',32,'全唐诗/poet.tang.51000.json','["知爾新從海外來，曉窗吟坐思難裁。", "堪憐時復撼書幌，似報故園花欲開。"]'),
('edcdce30-f778-48fa-8482-2862ab54dedc','海邊春望','崔致遠','唐','唐诗','tang','','[]','鷗鷺分飛高復低，遠汀幽草欲萋萋。',32,'全唐诗/poet.tang.51000.json','["鷗鷺分飛高復低，遠汀幽草欲萋萋。", "此時千里萬里意，目極暮雲翻自迷。"]'),
('9ee221c8-60bd-4655-972b-27cd6b346be1','春曉閑望','崔致遠','唐','唐诗','tang','','[]','山面嬾雲風惱散，岸頭頑雪日欺銷。',33,'全唐诗/poet.tang.51000.json','["山面嬾雲風惱散，岸頭頑雪日欺銷。", "獨吟光景情何限，猶賴沙鷗伴寂寥。", "。"]'),
('63135aa0-9eb7-48d8-bfe5-9af7b767576d','海邊閑步','崔致遠','唐','唐诗','tang','','[]','潮波靜退步登沙，落日山頭簇暮霞。',32,'全唐诗/poet.tang.51000.json','["潮波靜退步登沙，落日山頭簇暮霞。", "春色不應長惱我，看看即醉故園花。"]'),
('a7e866e2-6a15-43a9-8158-1bed1fefd377','將歸海東巉山春望','崔致遠','唐','唐诗','tang','','[]','目極煙波浩渺間，曉烏飛處認鄉關。',64,'全唐诗/poet.tang.51000.json','["目極煙波浩渺間，曉烏飛處認鄉關。", "旅愁從此休凋鬢，行色偏能助破顏。", "浪蹙沙頭花撲岸，雲粧石頂葉籠山。", "寄言來往鴟夷子，誰把千金解買閑。"]'),
('79b9ff08-bbe9-497b-bef0-0abf929ef080','和金員外贈巉山清上人','崔致遠','唐','唐诗','tang','','[]','海畔雲菴倚碧螺，遠離塵日稱僧家。',32,'全唐诗/poet.tang.51000.json','["海畔雲菴倚碧螺，遠離塵日稱僧家。", "勸君休問芭蕉喻，看取春風撼浪花。"]'),
('227b0278-f5e6-4dd1-90fb-0b8b18024b6f','題海門蘭若柳','崔致遠','唐','唐诗','tang','','[]','廣陵城畔別蛾眉，豈料相逢在海涯。',366,'全唐诗/poet.tang.51000.json','["廣陵城畔別蛾眉，豈料相逢在海涯。", "只恐觀音菩薩惜，臨行不敢折纖枝。", "（〖1〗以上三十首詩見《桂苑筆耕集》第二十卷。", "〖2〗按南京圖書館藏有高麗活字印本《桂苑筆耕集》二十卷，前有高麗人洪奭周、徐有榘二序。", "特節錄徐有榘序中有涉崔致遠行事者如次，其文曰：「《桂苑筆耕集》二十卷，新羅孤雲崔公在唐淮南幙府時公私應酬之作，而東還之後，手編表進於朝者也。", "公名致遠，字海夫，孤雲其號也。", "湖南之沃溝〖新羅地名〗人。", "幼穎慧絶倫，年十二，從商舶入中原。", "十八舉進士第。", "久之，調溧水縣尉，任滿而罷。", "時值黃巢之亂，諸道得營都統高駢開府淮南，辟公爲都統巡官，凡表狀文告，皆出公手。", "其《討黃巢檄》，天下傳誦。", "奏除殿中侍御史，賜緋魚袋。", "後四年，充國信使東歸，事憲康王、定康王爲翰林學士、兵部侍郎，出爲武城太守。", "真聖時，契家入江陽郡伽倻山以終焉。", "葬在湖西之鴻山。", "……」）。"]'),
('adbcc6cf-2a4e-4dae-8442-a94f85d93c90','逢漢使入蕃略題四韻','慧超','唐','唐诗','tang','','[]','君恨西蕃遠，余嗟東路長。',48,'全唐诗/poet.tang.51000.json','["君恨西蕃遠，余嗟東路長。", "道荒宏雪嶺，險澗賊途倡。", "鳥飛驚峭嶷，人去□偏樑。", "平生不捫淚，今日灑千行。"]'),
('40b83bcf-3675-42ba-a651-17d24a1adfc4','冬日在吐火羅逢雪述懷','慧超','唐','唐诗','tang','','[]','冷雪牽冰合，寒風擘地烈。',245,'全唐诗/poet.tang.51000.json','["冷雪牽冰合，寒風擘地烈。", "巨海凍漫壇，江河凌崖囓。", "龍門絕瀑布。", "井口盤蛇結。", "伴火上𮌑（垓）歌，焉能度播蜜。", "（上詩見《大藏經》二○八九號《遊方記抄》中所載新羅僧慧超作《往五天竺國傳》，畧謂：「又從吐火羅國東行七日，至胡蜜王住城，當來於吐火羅國。", "逢漢使入蕃，略題四韻，取辭五言〖詩不重錄〗。", "冬日在吐火羅逢雪述懷，五言〖詩不重錄〗。", "此胡蜜王兵馬少弱，不能自護，見屬大𥦽所管。", "」云云。", "又曰：「過播蜜川，即至葱嶺鎮。", "」「開元十五年十一月上旬至安西。", "於時節度大使趙君……」云云。", "讀此則兩詩之作年可知矣。", "）。"]'),
('7405ece2-d677-4e8d-926e-3a3161f0e6cc','後記','孫望','唐','唐诗','tang','','[]','右《全唐詩補逸》二十卷。',610,'全唐诗/poet.tang.51000.json','["右《全唐詩補逸》二十卷。", "是稿初印於丙子歲（一九三六年），當時收詩止二百七十有奇，暫分七卷，名曰《全唐詩補逸初稿》。", "稱《初稿》者，蓋欲賡揚裒集，期畢功釐定於他日也。", "其明年而蘆溝變起，舉家流徙，奔走萬里，藏書既失，舊業盡廢，甯居之不遑，奚論撰輯。", "荏苒八載，抗戰勝利，始得復返金陵。", "顧政敝民窮，生事維艱，丁彼衰世，徒知騰議於私室，已無心於學問矣。", "及己丑歲（一九四九年）而雄旆南指，落葉東飄，日出曜景，積瘴煙銷，慶堯宇之得蘇，見山河之重締，薄海同歡，余寧獨異？", "自來南師，將三十年矣，生計豐足，心神怡暢，得黨政之關懷，承師友之相勉，於教學之餘，復得游心翰府，繼事蒐聚，雖四凶逞虐之日，猶未嘗或輟。", "積之既久，漸成卷帙，略加編次，合之舊稿，得詩近八百篇，離爲二十卷，仍其名曰《全唐詩補逸》。", "自維頭白齒脫，精力有竭，而唐詩散佚，遠不止外，倘假我以年，其增輯續補，願待來日，則茲編雖稱《全唐詩補逸》，仍以初稿目之可耳。", "惟昔丙子舊稿，收韋莊《秦婦吟》一首，又曾錄《雲謠集雜曲子》三十首及無名氏詞等爲一卷，今王重民氏《敦惶曲子詞集》及《補全唐詩》既悉數絬刊矣，故從刪。", "又《全唐詩》以日人朝衡及新羅公主金真德等雜於唐詩人之列，茲編則集日人及新羅人之與唐土人士有交往酬唱者，各自成卷，標以「友邦」之目，附於編末，意欲存當時文化交流之跡云爾。", "此則有異於《全唐詩》體制者。", "值茲付印之際，畧記前後過程如此。", "戊午歲（一九七八年）秋，孫望記於南京師範學院。"]'),
('7af62b5c-84bb-443c-8135-573e244cb6a2','前言','童養年','唐','唐诗','tang','','[]','唐詩體制繁複。',700,'全唐诗/poet.tang.51000.json','["唐詩體制繁複。", "前承樂府、古風，後啟律詩、雜言，抒情、說理、敍事、寫景，蔚爲大觀。", "上自達官，下至隱逸，文士筆述，民間口傳，遍地開花，豐富多彩。", "它在中國詩壇上，也在世界詩歌史上，都占有並將永久占有極其重要的地位。", "唐、宋、元至明中葉以前，唐詩選本多，而全集少。", "明中期以後，漸有人重視唐詩全集的編刻，便斷代分期出書，流傳極少。", "如隆慶時吳琯等《唐詩紀》，只成初唐、盛唐。", "至清康熙四十五、六年間，纔開始根據胡震亨《唐音統籤》及錢謙益、季振宜連接編輯的《全唐詩集》（只有稿本。", "初稿爲不同版本的詩集拼成，有抄有刻，我曾寫出目錄，留備參考。", "該稿現在台灣。", "清內府舊藏是重抄稿本。", "）綜合改編成爲現時仍在通行的《全唐詩》。", "《全唐詩》共九百卷，收詩五萬餘首。", "因時時急於求成，存在不少缺點錯誤。", "近代有不昳，如劉師培、李嘉言等提出勘誤和改編的意見，偶然也提到尚有可補之詩。", "日本河世寧能早在我國韓隆時期進行《全唐詩》的輯逸工作，雖然所輯有限，又多屬摘句，最後附李嶠幾首詩的校異，也還是值得歡迎的。", "近半個世紀中，有羅振玉、王重民，包括最近舒學等，單從敦惶遺書中先後輯出唐人遺詩共約一百八十首。", "只限於文士的雅言詩，而未收民間的口語詩，終令人對唐詩有不全之感。", "我在較長時期，對全漢至隋詩、全唐詩，都留心輯補，隨見隨鈔，各有積稿。", "現中華書局以《全唐詩》先行再版，廣徵補遺。", "最近一年多，我根據原輯加工，僅就手邊可利用的書，加以鈔補，五百五十餘人，詩一千餘首，摘句（一聯一韻作爲一句）二百三十以上，詞三十一首，編爲二十一卷。", "現時的工作以補爲主，但也以補帶校。", "如不事先反複細校，則又不知缺在何處。", "多卷集的大家、名家，比較難補，而零句比全詩更難補。"]'),
('e46ee976-110f-46cb-8f89-29d301cf0d42','爲秦王制詩','李淵','唐','唐诗','tang','','[]','（初太宗爲秦王，高祖制詩云云。',174,'全唐诗/poet.tang.51000.json','["（初太宗爲秦王，高祖制詩云云。", "帝於宮西造宅初成，高祖送玉璽以至帝所，縉紳先生相謂曰：「詩及玉璽。", "蓋奉國之祥瑞者歟。", "」○今按：《全唐詩凡例》引胡震亨謂唐初無五星聯聚之事，疑其僞託。", "曾見陜西鄠縣有大業三年鄭州刺史李淵爲子世民祈疾疏石刻拓本，孫星衍《訪碑錄》亦收載。", "）聖德合天地，五宿連珠見。", "和風拂世民，上下同歡宴。", "（《冊府元龜》二一《帝王部·徵應》）。"]'),
('7ffc844e-1191-4278-a4ee-6dbe5d1d3fe6','題龜峯山（在麻城縣）','李世民','唐','唐诗','tang','','[]','乾坤造化有神功，勝地安然氣象雄。',208,'全唐诗/poet.tang.51000.json','["乾坤造化有神功，勝地安然氣象雄。", "馬蹟印開蒼石上，龜頭橫插白雲中。", "山高每有神仙過，寺號能仁天子封。", "試劍石邊風拂拂，虎跑泉內水溶溶。", "龍吟南嶺崎山雨，虎嘯東林什子風。", "舍利塔中遺釋子，觀音崖上禮慈容。", "天開雲現瑠璃碧，日落霞明瑪瑙紅。", "巖畔芊芊羅漢草，領頭鬱鬱大夫松。", "望龜亭內迎仙客，噴雪崖前活水通。", "萬里黎民皆潤澤，一堂賢聖總虛空。", "遊山宰相書名字，採藥仙人留跡踪。", "任是丹青描不就，恍疑身世九霄宮。", "（《弘治黃州府志》七《藝文》）。"]'),
('07c124ac-a9c9-46e1-8a40-557d4089d026','遊石淙詩（幷序）','武曌','唐','唐诗','tang','','[]','若夫圓嶠方壺，涉滄波而靡際；金臺玉闕，陟玄圃而無階。',392,'全唐诗/poet.tang.51000.json','["若夫圓嶠方壺，涉滄波而靡際；金臺玉闕，陟玄圃而無階。", "惟聞《山海》之經，空覽《神仙》之記。", "爰有石淙者，即平樂澗也。", "爾其近接嵩領，俯屆箕峯，瞻少室兮若蓮，睇潁川兮如帶。", "既而躡崎嶇之山徑，蔭蒙密之藤蘿，洶湧洪湍，落虛潭而送響；高低翠壁，列幽澗而開筵。", "密葉舒帷，屏氛而蕩燠；疏松引吹，清麥候以含涼。", "就林藪而王心神，對煙霞具而滌塵累。", "森沈丘壑，即是桃源；淼漫平流，還浮竹箭。", "[紉]（網）薜荔而成帳，聳蓮石而如樓。", "洞口全開，溜千年之芳髓，山腰半坼，吐十里之香粳。", "無煩崑閬之遊，自然形勢之所。", "當使人題綵翰，各寫瓊篇，庶無滯於幽棲，冀不孤於泉石。", "各題四韻，咸賦七言。", "（《古今圖書集成·山川典》六○《嵩山部》○今按：此詩在《全唐詩》一般有詩序者，大都全錄，此係遺漏。", "現特補序，詩不重錄。", "又《圖書集成》推崇卷，作嵩山石淙侍宴應制者，有宋之問、沈佺期、蘇味道、李嶠諸人。", "）（據《金石萃編》卷六十三校改。", "）。"]'),
('f287f4d8-55d4-4555-a306-a6840d0242b6','','許敬宗','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.51000.json','["。"]'),
('9bab2f7e-6a2f-441b-b136-2cfc6e30a0ac','遼左雪中登樓','許敬宗','唐','唐诗','tang','','[]','歲杪崇朝雪，天涯絕塞城。',72,'全唐诗/poet.tang.51000.json','["歲杪崇朝雪，天涯絕塞城。", "凍雲連海色，枯木助風聲。", "懷古情無已，登樓賦未成。", "梅花南國思，笛裏暮愁生。", "（《古今圖書集成·職方典》一七四《奉天府部》）。"]'),
('601c69f3-9ada-4447-991f-f05c1e53cea3','白龜城','左匡政','唐','唐诗','tang','','[]','城堞千尋險，池隍十里餘。',65,'全唐诗/poet.tang.51000.json','["城堞千尋險，池隍十里餘。", "樓臺侵漢宇，鼓角動郊墟。", "羆虎三軍擁，壺漿萬戶舒。", "急須修表進，天意欲何如？", "（《嘉慶涇縣志》三十二《詞賦》）。"]'),
('87932516-f43e-4f80-91e7-57b6293da2c7','留題雲門（一作「秦望山」）','蕭翼','唐','唐诗','tang','','[]','絕頂高峯（一作「山」）路不分。',119,'全唐诗/poet.tang.51000.json','["絕頂高峯（一作「山」）路不分。", "嵐烟（一作「烟嵐」）長鎖綠苔紋。", "彌猴推落臨（一作「懸」）崖石。", "打破（一作「落」）下方遮日雲。", "（《萬首唐人絕句》十一、《古今圖書集成·山川典》一○五《秦望山部》）（北宋孔延之編《會稽掇獻總集》卷六已收此詩。", "）。"]'),
('02feaa51-8b36-43a0-b556-84fdcf675414','題雷威琴','歐陽詢','唐','唐诗','tang','','[]','合雅大樂，成文正音。',148,'全唐诗/poet.tang.51000.json','["合雅大樂，成文正音。", "徽絃一泛，山水俱深。", "（《西溪叢語》上）（《西溪叢語》云：「長兄伯聲云：昔至澠邑，獲一古琴，中題云〖略〗。", "雷威斷，歐陽詢書，陜郊處士魏野家藏。", "」同書復錄雷威大曆三年題字，知歐、雷並非同時之人。", "此詩如爲歐作，則詩題誤。", "頗疑「歐陽詢書」云云，僅指其字體爲歐書，而非必歐本人之作。", "）。"]'),
('9e0ad678-f0d1-4dae-8bb9-0b78d7bcef4d','過楊玄感墓','李百藥','唐','唐诗','tang','','[]','（《唐書》曰：天后西幸京師，路經楊玄感墓，上誦李百藥《過玄感墓詩》云云，歎曰：「百藥唯解綴文，不識大義。',119,'全唐诗/poet.tang.51000.json','["（《唐書》曰：天后西幸京師，路經楊玄感墓，上誦李百藥《過玄感墓詩》云云，歎曰：「百藥唯解綴文，不識大義。", "」○今按：兩《唐書·則天紀》、《百藥傳》均不載。", "）劍有萬人敵，文爲一代英。", "除昏志不遂，僭亂道難平。", "（《太平御覽》五五八《禮儀部》。", "）。"]'),
('f0fa57a2-9e65-477c-a972-85095a77a584','落成會詠二首（前一首《全唐詩》已收）','陳元光','唐','唐诗','tang','','[]','雲霄開岳鎮，日月列衙瞻。',96,'全唐诗/poet.tang.51000.json','["雲霄開岳鎮，日月列衙瞻。", "勝日當佳慶，清風去積炎。", "山畚遙獵虎，海舶近通鹽。", "龍澤覃江浦，螭坳耀斗蟾。", "文床堆玉笏，武座肅金簽。", "奇計繩陳美，明誠學孔兼。", "忠勤非一日，箴訓要三拈。", "千古清泉水，居官顯孝廉。"]'),
('8ca8db3e-61dd-4a49-8d41-cbee5e5f7785','半徑尋真','陳元光','唐','唐诗','tang','','[]','半徑尋仙蹟，危峯望帝州。',116,'全唐诗/poet.tang.51000.json','["半徑尋仙蹟，危峯望帝州。", "千山紅日媚，萬壑白雲浮。", "坐石花容笑，穿林鳥語愁。", "招呼玄鶴下，撚捋紫芝柔。", "鑄鼎龍歸洞，驚旗虎負丘。", "高棲謀未遂，勝景至須留。", "巖谷連聲應，漳湖合派流。", "飄然歌一曲，縹緲在瀛州。", "（以上《康熙漳浦縣志》十八《藝文》下）。"]'),
('78366817-ccaa-41a0-bee4-0f4fa30b8cd0','照鏡見白髪（聯句）','張九齡','唐','唐诗','tang','','[]','宿昔青雲志，蹉跎白髪年。',56,'全唐诗/poet.tang.51000.json','["宿昔青雲志，蹉跎白髪年。", "誰知明鏡裏，形影自相憐。", "（《萬首唐人絕句》補本一。", "又見《四部叢刊》影明本《張九齡集》）。"]'),
('30819655-6c47-408e-9254-2030d4fdfc7e','謝公樓','張九齡','唐','唐诗','tang','','[]','謝公樓上好醇酒，三百青蚨買一斗。',50,'全唐诗/poet.tang.51000.json','["謝公樓上好醇酒，三百青蚨買一斗。", "紅泥乍擘綠蟻浮，玉盌纔傾黃蜜剖。", "（《永樂大典》七八九一「樓」字韻）。"]'),
('594adf6e-4e2d-4337-ad31-04779d22200c','幸未央宮應制（補後四句）','宋之問','唐','唐诗','tang','','[]','登高省時物，懷古發宸聰。',228,'全唐诗/poet.tang.51000.json','["登高省時物，懷古發宸聰。", "鐘連長樂處，臺識未央中。", "（《文苑英華辨證》六《脫文》）（《文苑英華辨證》據宋之問集補此四句，原詩指《全唐詩》卷五三已收之《奉和幸長安故城未央宮應制》。", "詩云：「漢王未息戰，蕭相乃營宮。", "壯麗一朝盡，威靈千載空。", "皇明悵前跡，置酒宴羣公。", "寒輕綵仗外，春發幔城中。", "樂思回斜日，歌詞繼《大風》。", "今朝天子貴，不假叔孫通。", "」《文苑英華辨證》謂「春發幔城中」，集作「春發幔城東」，「《文苑》以『東』作『中』，遂脫四句。", "」四句應於「樂思」二句之前。", "）。"]'),
('74ac69c0-1a82-4b9d-8af6-7b85326af8c9','題雷琴（二首） 一','宋之問','唐','唐诗','tang','','[]','山虛水深，萬籟蕭蕭。',20,'全唐诗/poet.tang.51000.json','["山虛水深，萬籟蕭蕭。", "古無人蹤，惟石嶕峣。"]'),
('4aa5a708-b778-488a-8546-7494b7ca6e45','題雷琴（二首） 二','宋之問','唐','唐诗','tang','','[]','洛水多清泚，崧高有白雲。',177,'全唐诗/poet.tang.51000.json','["洛水多清泚，崧高有白雲。", "聖朝容隱逸，時得詠南薫。", "（《古今圖書集成》）（宋姚寬《西溪叢語》卷上云：「長兄伯聲云：洛中董氏蓄雷琴一張，中題云〖引前四言詩，略〗。", "狀其聲也。", "其外漆下隱有朱書云〖引後五言詩，略〗。", "此詩見《宋之問集》。", "」據此，應僅後首爲宋之問作。", "又此爲後人取宋詩題雷琴此擬題爲《題雷琴》，誤。", "雷琴因雷威所製而得名，雷威爲大曆間人，宋之问不及見。", "）。"]'),
('fc0677f7-e286-473b-bf22-7ab40e030049','錢','李嶠','唐','唐诗','tang','','[]','九府五銖世上珍，魯襃曾詠道通神。',55,'全唐诗/poet.tang.51000.json','["九府五銖世上珍，魯襃曾詠道通神。", "勸君覔得須知足，雖解榮人也辱人。", "（《古今圖書集成·食貨典》三五八《錢鈔部》）。"]'),
('1732b039-d9d1-4e72-9bed-c4fb2e83fdc8','玄武山聖水宴（幷序）','王勃','唐','唐诗','tang','','["\u6052\u5c71", "\u957f\u6c5f"]','玄武山有聖泉焉，浸淫歷數百千年，（「歷」字據陽熙晉《駱臨海集箋注》卷九補。',305,'全唐诗/poet.tang.51000.json','["玄武山有聖泉焉，浸淫歷數百千年，（「歷」字據陽熙晉《駱臨海集箋注》卷九補。", "陳熙晉云：「此序各本皆不載，今從《全唐文》錄出。", "」「子安在梓州所作詩文尚多，恐非駱文。", "」）垂巖沁湧，接磴分流，下瞰長江，沙堤石岸，咸古人遺迹也。", "茲乃青蘋綠芰，紫苔蒼蘚，遂使江湖思遠，寤寐寄託。", "既而崇巒左峙，石壑（一作「壁」）前縈，丹崿萬尋，碧潭千頃，松風唱響，竹露薫空。", "瀟瀟乎人間之難遇也，方欲以林壑爲天屬，琴罇爲日用。", "嗟乎！古今同逝（一作「代謝」。", "）方深川上之悲；少長偕遊，且盡山陰之樂。", "盍題芳什，共寫高情。", "詩得泉字。", "詩曰。", "（《古今圖書集成·坤輿典》三六《泉部》）（今按：《全唐詩》五六題作《聖泉宴》，有詩無序，故補序，詩不重錄。", "）。"]'),
('80abd93f-0cb6-44d5-86e6-dd11b36aea92','隴西行（十首） 一','王勃','唐','唐诗','tang','','[]','隴西多名家，子弟復豪華。',24,'全唐诗/poet.tang.51000.json','["隴西多名家，子弟復豪華。", "千金買駿馬，蹀躞長安斜。"]'),
('2db8a8d7-198b-41e8-b65a-17ba7a3e1ec9','隴西行（十首） 二','王勃','唐','唐诗','tang','','[]','彫弓侍羽林，寶劍照期門。',24,'全唐诗/poet.tang.51000.json','["彫弓侍羽林，寶劍照期門。", "南來射猛虎，西去獵平原。"]'),
('59d121cd-5dff-4222-8f7a-8bffa0af6437','隴西行（十首） 三','王勃','唐','唐诗','tang','','[]','既夕罷朝參，薄暮入終南。',24,'全唐诗/poet.tang.51000.json','["既夕罷朝參，薄暮入終南。", "田間遭罵詈，低語示乘驂。"]'),
('00d5a757-abbd-41ca-8f22-65b26a33d262','隴西行（十首） 四','王勃','唐','唐诗','tang','','[]','入被鑾輿寵，出視轅門勇。',24,'全唐诗/poet.tang.51000.json','["入被鑾輿寵，出視轅門勇。", "無勞豪吏猜，常侍當無恐。"]'),
('e49c6eec-9824-45ba-b8f0-69c8b8e4f0cd','隴西行（十首） 五','王勃','唐','唐诗','tang','','[]','充國出上邽，李廣出天水。',24,'全唐诗/poet.tang.51000.json','["充國出上邽，李廣出天水。", "門第倚崆峒，家世垂金紫。"]'),
('78122776-2f38-477c-8213-a52e45a3a079','隴西行（十首） 六','王勃','唐','唐诗','tang','','[]','麟閣圖良將，六郡名居上。',24,'全唐诗/poet.tang.51000.json','["麟閣圖良將，六郡名居上。", "天子重開邊，龍雲壘相向。"]'),
('50273723-cb2d-459d-8b59-69c537c56948','隴西行（十首） 七','王勃','唐','唐诗','tang','','[]','烽火照臨洮，榆塞馬蕭蕭。',24,'全唐诗/poet.tang.51000.json','["烽火照臨洮，榆塞馬蕭蕭。", "先鋒秦子弟，大將霍嫖姚。"]'),
('5a6b16be-bac3-42e7-9ef0-8571619faa8a','隴西行（十首） 八','王勃','唐','唐诗','tang','','[]','開壁左賢敗，夾戰樓蘭潰。',26,'全唐诗/poet.tang.51000.json','["開壁左賢敗，夾戰樓蘭潰。", "獻捷上明光，揚鞭歌《入塞》。"]'),
('7b726b08-ef6e-4e4f-94ab-8671c4b3d005','隴西行（十首） 九','王勃','唐','唐诗','tang','','[]','更欲奏屯田，不必勒燕然。',24,'全唐诗/poet.tang.51000.json','["更欲奏屯田，不必勒燕然。", "古人薄軍旅，千載謹邊關。"]'),
('502e7760-3ca9-4a0b-af20-0d1acb3b773d','隴西行（十首） 十','王勃','唐','唐诗','tang','','[]','少婦經年別，開簾知禮客。',111,'全唐诗/poet.tang.51000.json','["少婦經年別，開簾知禮客。", "門戶爾能持，歸來笑投策。", "（以上同上五六五《鞏昌府部》，又乾隆《直隸秦州新志》十一《藝文》於此《詩》）（乾隆《秦州新志》及乾隆《狄道州志》十三收外詩，連作一首。", "前書每二十字爲一行，或因此而析爲十首。）"]'),
('be256466-df94-4f60-a539-638112262786','自鄉[還]（遠）虢','王勃','唐','唐诗','tang','','[]','（王福畤之子，勔、勮、勃皆有才名，故杜易簡稱爲三珠樹。',209,'全唐诗/poet.tang.51000.json','["（王福畤之子，勔、勮、勃皆有才名，故杜易簡稱爲三珠樹。", "其後助、劼、勸，又皆以文顯。", "勃於兄弟之間極友愛，《自鄉[還]〖還〗虢》詩云云。", "觀此語意，豈兄弟有不相能者耶？", "及觀《誡功勁云》：「欲不可縱，爭不可常，勿輕小忿，將成大殃。", "」此二人者，似非處於禮義之域者。", "「《棠棣》廢」之語，疑爲此二人設也。", "）人生忽如客，骨肉知何常。", "願及百年內，花萼常相將。", "無使《棠棣》廢，取譬人無良。", "（《韻語陽秋》十）（據影宋本《韻語陽秋》校改。", "）。"]'),
('e7df153f-ef42-4906-b578-2d3052408080','述懷擬古詩','王勃','唐','唐诗','tang','','[]','僕生二十祀，有志十數年。',35,'全唐诗/poet.tang.51000.json','["僕生二十祀，有志十數年。", "下策圖富貴，上策懷神仙。", "（《韻語陽秋》十二）。"]'),
('6b7786e5-190f-4949-b67d-9a9f0783efe4','示知己（句）','王勃','唐','唐诗','tang','','[]','客書同十奏，臣劍已三奔。',18,'全唐诗/poet.tang.51000.json','["客書同十奏，臣劍已三奔。", "（同上。", "）。"]'),
('f2dc4d78-c398-4c08-b2c3-3757b7caa255','春日代情人','董思恭','唐','唐诗','tang','','[]','昔日管絃調，將人舞細腰。',111,'全唐诗/poet.tang.51000.json','["昔日管絃調，將人舞細腰。", "懸知今日恨，誰分昔時嬌。", "棄妾頻登隴，從軍幾度遼？", "可憐香草夜，空見落花朝。", "淚滴珠難盡，容殘玉易銷。", "償隨明月去，（「償」，趙遂之云當作「儻」。", "）莫道夢魂遙。", "（《永樂大典》三○○五人字韻引《玉臺後詠》）。"]'),
('435a676c-ae39-4638-8782-501c074ca3fc','座右銘（《陳伯玉集》未收）','陳子昂','唐','唐诗','tang','','[]','事父盡孝敬，事君端忠貞。',166,'全唐诗/poet.tang.51000.json','["事父盡孝敬，事君端忠貞。", "兄弟敦和睦，朋友篤信誠。", "從官重公慎，立身貴廉明。", "待士慕謙讓，蒞民尚寬平。", "理訟惟正直，察獄必審情。", "謗議不足怨，寵辱詎須驚？", "處[滿]（蒲）常憚溢，居高本慮傾。", "詩、禮固可學，鄭、衛不足聽。", "幸能修實操，何俟鈞虛聲？", "白珪玷可滅，黃金諾不輕。", "秦穆飲盗馬，楚客報絕纓。", "言行既無擇，存歿自揚名。", "（《文苑英華》七九○《銘》）。"]'),
('6be727e6-12f4-42f5-89d5-d53ac16e98be','送敬丞','張說','唐','唐诗','tang','','[]','嘉會良難永，芳罇此夜閑。',48,'全唐诗/poet.tang.51000.json','["嘉會良難永，芳罇此夜閑。", "別離三春暮，親愛相鄉間。", "落花已覆水，巖雲欲起山。", "庭蘭行可佩，采采贈河關。"]'),
('7989baaf-1343-40df-97fe-8395dd837484','見諸人送杜承詩因以成作（荆州作）','張說','唐','唐诗','tang','','[]','吳楚分江鎮，華容改舊城。',36,'全唐诗/poet.tang.51000.json','["吳楚分江鎮，華容改舊城。", "訝君來遠謁，知有去思情。", "風度沅湘險，煙還雲夢平。"]'),
('f38f9c7f-6b0d-43a7-b337-71223b3034be','幽州送隨軍入秦','張說','唐','唐诗','tang','','[]','楊子來戎幕，老夫欣主諾。',48,'全唐诗/poet.tang.51000.json','["楊子來戎幕，老夫欣主諾。", "歸路有光華，邊庭少咨度。", "雁知窮朔苦，人羨長安樂。", "獨將馬革心，同聲謝臺閣。"]'),
('6c09fb65-f4fb-4252-9c9d-eda5fce8172b','金庭觀（在嵊縣東南七十二里）','張說','唐','唐诗','tang','','[]','元珠道在豈難求，海變須教鬢不秋。',104,'全唐诗/poet.tang.51000.json','["元珠道在豈難求，海變須教鬢不秋。", "他日洞天三十六，碧桃花發共師遊。", "（《嘉慶浙江通志》二三一《寺觀》）（見《剡錄》卷八，幷云：「先天間，遣女道士投簡金庭觀，見許承瓢，遂持以進。", "」《寶慶待物續志》卷四引後二句。", "）。"]'),
('25da873e-0a7c-4abf-9c0b-3012313416f4','黃金臺','岑義','唐','唐诗','tang','','[]','雕牆峻字無不亡，薊城築宮國乃昌。',136,'全唐诗/poet.tang.51000.json','["雕牆峻字無不亡，薊城築宮國乃昌。", "屈身延士禮優異，四方英俊如雲翔。", "郭生馬喻真良策，亟卿拜樂卿爲上客。", "兵行旬日入臨淄，秦楚諸君咸辟易。", "夙心已雪先王耻，七十齊城祇餘二。", "君王先去主帥逃，嘆息後人非繼志。", "巍臺悲慘朔風號，不知騎劫何時招。", "（《古今圖書集成·職方典》二九《順天府部》）。"]'),
('9a00093a-06dc-472e-864c-f8a048e02fd1','從軍行','王寵','唐','唐诗','tang','','[]','空（〖1〗原列入「無世次」卷。',218,'全唐诗/poet.tang.51000.json','["空（〖1〗原列入「無世次」卷。", "檢《新唐書·宰相世系表》瑯琊王氏有王寵，其宜綝，相武后，曾孫璵，相肅宗。", "武后至肅宗間僅六、七十年，不至隔五世，其間必有誤。", "然王寵約爲開元前後人，殆無問題。", "故移入本卷。", "〖2〗〖《全唐詩》三八作王宏時，第九句「王」《文苑英華》作「皇」，「千」作「十」○《文苑英華》一九九《樂府》〗〖《全唐詩》卷三八錄王宏詩，係源自《初唐詩紀》卷五，《初唐詩紀》則引僞書《龍城錄》作宏傳，幷不足據。", "當從《文苑英華》歸王寵。", "〗）。"]'),
('867c66b6-1407-4310-ac30-5ff40b74194a','夏彈琴（《文苑英華》二一二《音樂》、《初學記》一六「樂」部）','劉希夷','唐','唐诗','tang','','[]','空（〖1〗《唐文粹》、《唐詩紀事》作劉希戩《彈琴》。',98,'全唐诗/poet.tang.51000.json','["空（〖1〗《唐文粹》、《唐詩紀事》作劉希戩《彈琴》。", "〖2〗今按：《全唐詩》七六九作劉戩，第二句「素琴」《英華》作「素絲」，第六句「泉魚」《英華》作「淵魚」，第十二句「荒岳」《英華》作「山丘」。", "）。"]'),
('cad99220-9010-44c4-9157-b6d32e30df1a','登樓','朱佐日','唐','唐诗','tang','','[]','空（〖1〗《唐詩紀事》、《全唐詩》二五三作王之渙，《全唐詩》二○三又作處士朱斌。',442,'全唐诗/poet.tang.51000.json','["空（〖1〗《唐詩紀事》、《全唐詩》二五三作王之渙，《全唐詩》二○三又作處士朱斌。", "〖2〗武后嘗吟詩云云，問是誰作，李嶠對曰：「御史朱佐日詩也。", "」賜綵百疋，轉侍御史。", "○《輿地紀勝》五《平江府·人物》、《中國人名大辭典》）（〖此詩作者凡有三說。", "其一爲王之渙作，題作《登鸛鵲樓》，以《文苑英華》卷三一二所收爲最早，宋執行所著《溫公續詩話》、《夢溪筆談》卷十五、《唐詩紀事》卷二六皆沿之，今人亦多從此說。", "其二爲朱斌作，以收詩迄止年代距王之渙去世僅隔二年〖天寶三載〗的芮挺章《國秀集》卷下爲最早，同書亦收有王之渙詩。", "其三即朱佐日作，除《輿地紀勝》外，又見於《記纂淵海》卷二十四及《吳郡志》卷二十二，《吳郡志》幷注明此條出自《翰林盛事》。", "《翰林盛事》爲唐人張著撰，約撰成於大曆、貞元間，今已佚，《郡齋讀書志》卷二、《直齋書錄解題》卷五均著錄。", "以三說出現的次第言，朱斌最早，朱佐日次之，王之渙爲最遲。", "《千唐誌齋藏誌》九○○頁有朱佐日墓誌，官武强縣尉，待物人，天寶十三載卒，年四十九，似爲另一人。", "〗）。"]'),
('0a51cad1-dec0-4c37-963b-4ecd77ca4d4c','七言','王梵志','唐','唐诗','tang','','[]','生時不共作榮華，死後隨車强叫喚。',32,'全唐诗/poet.tang.51000.json','["生時不共作榮華，死後隨車强叫喚。", "齊頭送到墓門迴，分你錢財各頭散。"]'),
('032abfdd-8c51-4bf4-b6dd-63b308ec6717','五言（八首） 一','王梵志','唐','唐诗','tang','','[]','我肉衆生肉，形殊姓不殊。',36,'全唐诗/poet.tang.51000.json','["我肉衆生肉，形殊姓不殊。", "元同一性命，只是別形軀。", "苦痛教他死，將來作己須。"]'),
('effdeedc-98d7-4832-86c7-7e2692660a88','五言（八首） 二','王梵志','唐','唐诗','tang','','[]','粗行出家兒，心中未平實。',48,'全唐诗/poet.tang.51000.json','["粗行出家兒，心中未平實。", "貧齋行則遲，富齋行則疾。", "貪他油煮䭔，我有波羅蜜。", "飽食不知慙，受罪無休日。"]'),
('30f7dcc5-def6-4390-b5a0-257b31454999','五言（八首） 三','王梵志','唐','唐诗','tang','','[]','不願大大富，不願大大貧。',82,'全唐诗/poet.tang.51000.json','["不願大大富，不願大大貧。", "昨日了今日，今日了明晨。", "此之大大因，[彼之大大身]。", "（此句據《說郛》卷一引《雲溪友議》補。", "）所願只如此，真成上上人。", "（今按：疑缺第五句。", "）。"]'),
('353c9d7d-7056-4780-800e-02c0c69b4144','五言（八首） 四','王梵志','唐','唐诗','tang','','[]','良田收百頃，兄弟猶工商。',132,'全唐诗/poet.tang.51000.json','["良田收百頃，兄弟猶工商。", "却是成憂惱，珠金虛滿堂。", "滿堂何所用？妻兒日夜忙。", "行坐聞人死，不解暫思量。", "貧兒二畝地，（自「貧兒二畝地」以下，張錫厚另作一首。", "此句《說郛》作「買得貧家地。", "」）乾枯十樹桑。", "桑下種粟麥，四時供父娘。", "圖謀未入手，祇是願饑荒。", "結得百家怨，此身終受殃。"]'),
('46f2b9b8-6a0d-4b1f-8d76-e4ed303b5d93','五言（八首） 五','王梵志','唐','唐诗','tang','','[]','本是尿屎袋，强將脂粉塗。',46,'全唐诗/poet.tang.51000.json','["本是尿屎袋，强將脂粉塗。", "（原注：「音茶。", "」）凡人無所識，喚作一團花。", "相牽入地獄，此最是寃家。"]'),
('70da9dfa-c9d0-4833-bc17-cd02b352fbce','五言（八首） 六','王梵志','唐','唐诗','tang','','[]','照面不用鏡，布施不須財。',24,'全唐诗/poet.tang.51000.json','["照面不用鏡，布施不須財。", "端坐念真相，此便是如來。"]'),
('74350f0b-aa7d-4912-8a7e-87a0e2d44ffa','五言（八首） 七','王梵志','唐','唐诗','tang','','[]','大皮裏大樹，小皮裏小木。',105,'全唐诗/poet.tang.51000.json','["大皮裏大樹，小皮裏小木。", "生兒不用多，了事一箇足。", "省得分田宅，無人橫煎蹙。", "但行平等心，天亦念孤獨。", "我身雖孤獨，（自「我身雖孤獨」以下，張錫厚作另一首。", "）未死先懷慮。", "家有五男兒，哭我無所據。", "哭我我不聞，不哭我亦去。"]'),
('052ae95a-1879-46ba-a16b-a2d81c997eca','五言（八首） 八','王梵志','唐','唐诗','tang','','[]','世間何物貴？無價是詩書。',71,'全唐诗/poet.tang.51000.json','["世間何物貴？無價是詩書。", "了了說仁義，愚夫都不知。", "深房禁婢妾，對客誇妻兒。", "青石甃行路，未知身死時。", "（以上五七言共九首，空虛錄自《雲谿友議》下）。"]'),
('eb1f2b57-0f1e-46eb-a846-779c320b7a53','兀然無事（原卷缺題，不分篇段，現將分爲十一首） 一','王梵志','唐','唐诗','tang','','[]','兀然無事改換，無事何須論一段。',39,'全唐诗/poet.tang.51000.json','["兀然無事改換，無事何須論一段。", "直心無散亂，他事不須斷。", "過去已過去，未來何用算。"]'),
('70f228a7-12ec-4807-94a0-bad185450534','兀然無事（原卷缺題，不分篇段，現將分爲十一首） 二','王梵志','唐','唐诗','tang','','[]','兀然無一事，何曾有人喚。',53,'全唐诗/poet.tang.51000.json','["兀然無一事，何曾有人喚。", "向外覓功夫，總是癡頑漢。", "糧不畜一粒，逢飯便知{嗎灬=廾}。", "世間多事人，相趁渾不反。"]'),
('2f9e81b8-a4ef-4e15-b2ae-fd35b7f36628','兀然無事（原卷缺題，不分篇段，現將分爲十一首） 三','王梵志','唐','唐诗','tang','','[]','我不樂生天，亦不愛福田。',48,'全唐诗/poet.tang.51000.json','["我不樂生天，亦不愛福田。", "饑來一鉢飯，困來展脚眠。", "愚人以爲笑，智者謂之然。", "非愚亦非智，不是玄中玄。"]'),
('4d470325-2d3e-4a16-b6ec-935f921cb873','兀然無事（原卷缺題，不分篇段，現將分爲十一首） 四','王梵志','唐','唐诗','tang','','[]','要去如是去，要住如住。',47,'全唐诗/poet.tang.51000.json','["要去如是去，要住如住。", "身披一破衲，脚著娘生袴。", "多言復多語，由來反相誤。", "若欲度衆生，無過且自度。"]'),
('130fa7c2-a043-4ced-b693-a4085944634e','兀然無事（原卷缺題，不分篇段，現將分爲十一首） 五','王梵志','唐','唐诗','tang','','[]','莫漫求真佛，真佛不可見。',48,'全唐诗/poet.tang.51000.json','["莫漫求真佛，真佛不可見。", "妙性及靈臺，何曾受薰鍊。", "心是無事心，面是娘生面。", "劫石可動搖，箇中無改變。"]'),
('4048b4a4-38de-4f82-8da3-10997d4a0b90','兀然無事（原卷缺題，不分篇段，現將分爲十一首） 六','王梵志','唐','唐诗','tang','','[]','無事何須讀文字，削除人我本，冥合箇中意。',46,'全唐诗/poet.tang.51000.json','["無事何須讀文字，削除人我本，冥合箇中意。", "種種勞筋骨，不如林中睡兀兀。", "舉頭見日出，乞飯從頭𢫫。"]'),
('4b255b4c-60ba-493f-a7d9-be760443d9c4','兀然無事（原卷缺題，不分篇段，現將分爲十一首） 七','王梵志','唐','唐诗','tang','','[]','將功用功，展轉冥蒙。',20,'全唐诗/poet.tang.51000.json','["將功用功，展轉冥蒙。", "取即不得，不取自通。"]'),
('9236205c-5729-49f4-aa1a-be2fe7a65df2','兀然無事（原卷缺題，不分篇段，現將分爲十一首） 八','王梵志','唐','唐诗','tang','','[]','吾有一言，絕慮忘緣。',20,'全唐诗/poet.tang.51000.json','["吾有一言，絕慮忘緣。", "巧說不得，只用心傳。"]'),
('2daed6b5-8f5b-4d2a-93b4-136f8f4cbc43','兀然無事（原卷缺題，不分篇段，現將分爲十一首） 九','王梵志','唐','唐诗','tang','','[]','更有一語，無過直與。',30,'全唐诗/poet.tang.51000.json','["更有一語，無過直與。", "細極毫末，大無方所。", "本自圓成，不勞機杼。"]'),
('13f89643-732b-4f43-8e77-d840a269c934','兀然無事（原卷缺題，不分篇段，現將分爲十一首） 十','王梵志','唐','唐诗','tang','','[]','世事悠悠，不如山丘。',60,'全唐诗/poet.tang.51000.json','["世事悠悠，不如山丘。", "青松蔽日，碧澗常秋。", "山雲當幕，夜月爲鉤。", "臥藤蘿下，塊石枕頭。", "不朝天子，豈羨王侯？", "生死無慮，更復何憂。"]'),
('d01f2cd7-8482-4630-a8ae-b5d336b95146','兀然無事（原卷缺題，不分篇段，現將分爲十一首） 十一','王梵志','唐','唐诗','tang','','["\u8861\u5c71"]','水月無形，我常只寧。',265,'全唐诗/poet.tang.51000.json','["水月無形，我常只寧。", "萬法皆爾，本自無生。", "兀然無事坐，春來草自青。", "（高士奇《江邨銷夏錄》卷二黃庭堅書梵志詩卷○董其昌題云：「黃文節公書，世多摹本，又多贋本。", "生平所見，以此卷爲灼然無疑。", "梵志詩較寒山更自奇崛，書亦近之。", "」）（此組詩，黃庭堅自跋不云爲王梵志作，至董其昌作跋時始斷爲王梵志作，實誤。", "此詩爲唐大曆間衡嶽僧明瓚〖即懶殘〗作，見《祖堂集》卷三、《景德傳燈錄》卷三十、《南嶽總勝集》卷下、《林間錄》等書。", "諸書異文較多，另參《全唐詩續拾》卷十五。", "另項楚對此有考證，文刊《中華文史論叢》。", "又原詩爲長詩一首，此處析爲十一首，亦未允。", "）。"]'),
('de212439-fa06-445d-a7b1-29158d24fd05','五言白話詩','缺名','唐','唐诗','tang','','[]','（原缺卷首。',117,'全唐诗/poet.tang.51000.json','["（原缺卷首。", "劉復云：「抄出者共四十六首。", "」現選錄二十六首張錫厚《王梵志詩校輯》云與劉復所見伯三二一一卷同一系統的敦煌遺書尚有斯五四四一、斯五六四一兩卷。", "其中斯五四四一卷題作「王梵志立詩集卷中」，因知伯三二一一卷諸詩亦應爲王梵志作。", "）。"]'),
('bde9c1db-2496-4d2a-b21b-7d47c48035dd','五言白話詩 一','缺名','唐','唐诗','tang','','[]','村頭語戶主，鄉頭無處得。',99,'全唐诗/poet.tang.51000.json','["村頭語戶主，鄉頭無處得。", "在縣用紙多，從吾相便貸。", "我命自貧窮，獨辨不可得。", "（「辨」，張錫厚改作「辧」。", "）合村看我面，此度必須得。", "後衙空手去，定是搦你勒。", "（「搦」，斯五四四一卷作「獨」，據張錫厚改。", "）。"]'),
('259b0b8c-1242-4dff-90c2-cfb9878813b5','五言白話詩 二','缺名','唐','唐诗','tang','','[]','人生一代間，貧富不覺老。',167,'全唐诗/poet.tang.51000.json','["人生一代間，貧富不覺老。", "王役逼駈駈，走多換行少。", "（「換行少」，斯五四四一卷作「緣行步」。", "）他家馬上坐，我身步擎草。", "種得果報緣，不須自煩惱。", "受報人中生，（自「受報人中生」以下，張錫厚另作一首。", "）本爲前身罪。", "今身不修福，癡愚膿血袋。", "病困臥着牀，慳心由不改。", "（「由」，斯五四四一卷作「猶」。", "）臨死命欲終，𢗞財不懺悔。", "身死妻後嫁，總將陪新壻。"]'),
('7d26aad1-0761-4492-904c-4ee637e64618','五言白話詩 三','缺名','唐','唐诗','tang','','[]','世間何物貴？只有我身是。',48,'全唐诗/poet.tang.51000.json','["世間何物貴？只有我身是。", "不見好出生，衣食穀米費。", "廣貪長命財，纏繩短命鬼。", "放頑鄰里行，元來不怕死。"]'),
('a25b2f1d-9fb6-474b-8d7a-ec7f61fdb5da','五言白話詩 四','缺名','唐','唐诗','tang','','[]','世間慵懶人，五分向有二。',257,'全唐诗/poet.tang.51000.json','["世間慵懶人，五分向有二。", "例着一草衫，兩膊成山字。", "出語觜頭高，（「觜」，斯五四四一卷作「嘴」。", "）詐作達官子。", "草舍元無床，無氊復無被。", "他家人定臥，日西展脚睡。", "諸人五更走，日高未肯起。", "朝庭數千人，（自「朝庭數千人」以下，張錫厚另作一首。", "項楚謂另作一首不當。", "）平章共傳戲。", "菜粥喫一𪲄，（「𪲄」，斯五四四一卷作「盔」。", "）街頭闊立地。", "（「濶」，項楚校作「閑」。", "）逢人若共語，荒說天下事。", "喚女作家生，將兒作奴使。", "妻即赤體行，尋常飢欲死。", "一羣病賴賊，（「賴」，張錫厚改「懶」，項楚校作「癩」。", "）却搦父母耻。", "日月甚寬恩，不照五逆鬼。"]'),
('0643ea93-5847-44d9-adca-3c4d121b04c5','五言白話詩 五','缺名','唐','唐诗','tang','','[]','家中漸漸貧，良由慵懶婦。',130,'全唐诗/poet.tang.51000.json','["家中漸漸貧，良由慵懶婦。", "長頭愛床坐，飽喫沒娑肚。", "頻年懃生兒，不肯收家具。", "飲酒五夫敵，不解縫衫袴。", "（「不解」，斯五六四一卷作「不能」。", "）事當好衣裳，得便走出去。", "不要男爲伴，心裏恒攀慕。", "東家能湼舌，西家好合[鬭]。", "兩家既不和，角眼相蛆姡。", "別覓好時對，趁却莫交住。", "。"]'),
('6bed3a0a-046c-48eb-9bd1-837f0dd6966e','五言白話詩 六','缺名','唐','唐诗','tang','','[]','用錢索新婦，當家有新故。',126,'全唐诗/poet.tang.51000.json','["用錢索新婦，當家有新故。", "兒替阿耶來，新婦替家母。", "替人既倒來，（「倒」，斯五六四一卷作「到」。", "）條錄相分付。", "新婦知家事，兒郎永門戶。", "（「永」，斯五六四一卷作「丞」，張錫厚改作「承」）好衣我須着，好食入我肚。", "我老妻亦老，替代不得住。", "語你夫妻道，我死還到汝。"]'),
('d934c0ad-1d67-42ac-8da6-d98026dfad2c','五言白話詩 七','缺名','唐','唐诗','tang','','[]','孝是前身緣，不由相放習。',60,'全唐诗/poet.tang.51000.json','["孝是前身緣，不由相放習。", "兒行不憶母，母恒行坐泣。", "兒行母亦征，項膇連腦急。", "聞道賊出來，母愁空有骨。", "兒迴見母面，顏色肥沒忽。"]'),
('133dff39-4b6b-4aaa-803a-601f145d7f54','五言白話詩 八','缺名','唐','唐诗','tang','','[]','聞道須鬼兵，逢頭即須搦。',88,'全唐诗/poet.tang.51000.json','["聞道須鬼兵，逢頭即須搦。", "欲似園中果，未熟亦須摘。", "老少總皆去，共同衆死厄。", "長命得八十，恰同寄住客。", "蹔在主人家，不久自分擘。", "喻若行路人，前後踏光陌。", "（「光」，戴密微校作「巷」。", "）。"]'),
('81a61b64-d797-43d3-b909-bc6ceb6cdb9d','五言白話詩 九','缺名','唐','唐诗','tang','','[]','自生還自死，煞活非關我。',36,'全唐诗/poet.tang.51000.json','["自生還自死，煞活非關我。", "續續生出來，世間無處坐。", "若不急抽却，眼看塞天破。"]'),
('b233c9b7-a231-4267-94c8-1654ae171327','五言白話詩 十','缺名','唐','唐诗','tang','','[]','天下惡官職，不過是府兵。',88,'全唐诗/poet.tang.51000.json','["天下惡官職，不過是府兵。", "四面有賊動，當日即須行。", "有緣重相見，業薄即隔生。", "逢賊被打煞，五品無人諍。", "生住無常界，（項楚云此句以下應移入下一首。", "）攘攘滿街行。", "只擬人間死，不肯佛邊生。"]'),
('a9de8f42-50c8-4702-859d-24ac85432ffe','五言白話詩 十一','缺名','唐','唐诗','tang','','[]','從頭捉將去，「頑骨」不心擎。',83,'全唐诗/poet.tang.51000.json','["從頭捉將去，「頑骨」不心擎。", "（「頑骨」二字據斯五六四一卷補。", "「擎」，斯五六四一卷作「驚」。", "）雖然畜兩眼，終是一雙盲。", "向前黑如漆，直掇入深坑。", "沉淪苦海裏，何日更逢明？。"]');
